import { api } from "@/lib/api";
import { useQuery } from "@tanstack/react-query";
import { useMemo, useRef, useState } from "react";

type Row = {
  id: number;
  number: string;
  client_name: string;
  created_at?: string;
  warehouse_name: string | null;
  expeditor_display: string | null;
  status: string;
  shipped_at: string | null;
  delivered_at?: string | null;
  qty: string;
};

export default function ShipmentInvoicesPage() {
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const hydrated = useAuthStoreHydrated();
  const [warehouseDraft, setWarehouseDraft] = useState("all");
  const [expeditorDraft, setExpeditorDraft] = useState("all");
  const [statusDraft, setStatusDraft] = useState("delivering");
  const [searchDraft, setSearchDraft] = useState("");
  const [warehouse, setWarehouse] = useState("all");
  const [expeditor, setExpeditor] = useState("all");
  const [status, setStatus] = useState("delivering");
  const [search, setSearch] = useState("");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [dateRangeOpen, setDateRangeOpen] = useState(false);
  const dateRangeAnchorRef = useRef<HTMLButtonElement>(null);

  const warehousesQ = useQuery({
    queryKey: ["shipment-invoices-warehouses", tenantSlug],
    enabled: Boolean(tenantSlug) && hydrated,
    queryFn: async () => {
      const { data } = await api.get<{ data: { id: number; name: string }[] }>(`/api/${tenantSlug}/warehouses`);
      return data.data ?? [];
    }
  });
  const expeditorsQ = useQuery({
    queryKey: ["shipment-invoices-expeditors", tenantSlug],
    enabled: Boolean(tenantSlug) && hydrated,
    queryFn: async () => {
      const { data } = await api.get<{ data: { id: number; fio: string }[] }>(`/api/${tenantSlug}/expeditors`);
      return data.data ?? [];
    }
  });

  const listQ = useQuery({
    queryKey: ["shipment-invoices", tenantSlug, warehouse, expeditor, status, search, dateFrom, dateTo],
    enabled: Boolean(tenantSlug) && hydrated,
    queryFn: async () => {
      const params = new URLSearchParams({ page: "1", limit: "100" });
      if (warehouse !== "all") params.set("warehouse_id", warehouse);
      if (expeditor !== "all") params.set("expeditor_id", expeditor);
      if (status !== "all") params.set("status", status);
      if (search.trim()) params.set("search", search.trim());
      if (dateFrom) params.set("date_from", dateFrom);
      if (dateTo) params.set("date_to", dateTo);
      const { data } = await api.get<{ data: Row[] }>(`/api/${tenantSlug}/orders?${params.toString()}`);
      return data.data ?? [];
    }
  });
  const rows = listQ.data ?? [];
  const filteredRows = useMemo(() => {
    if (!search.trim()) return rows;
    const needle = search.toLowerCase();
    return rows.filter((r) =>
      [r.number, r.client_name, r.warehouse_name ?? "", r.expeditor_display ?? "", r.status]
        .join(" ")
        .toLowerCase()
        .includes(needle)
    );
  }, [rows, search]);

  const statusBadgeClass = (v: string) => {
    if (v === "delivered") return "bg-emerald-100 text-emerald-700";
    if (v === "delivering") return "bg-sky-100 text-sky-700";
    if (v === "confirmed") return "bg-blue-100 text-blue-700";
    if (v === "cancelled") return "bg-rose-100 text-rose-700";
    return "bg-muted text-foreground";
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between gap-3">
        <h1 className="text-xl font-semibold">Отгрузочные накладные</h1>
        <div className="flex items-center gap-1 rounded-md border border-input bg-background px-1.5 py-1">
          <button type="button" className="inline-flex h-6 w-6 items-center justify-center rounded hover:bg-muted/50">
            <ChevronLeft className="h-3.5 w-3.5 text-muted-foreground" />
          </button>
          <button
            ref={dateRangeAnchorRef}
            type="button"
            className={cn(
              "inline-flex h-6 items-center gap-1 rounded px-2 text-[11px] hover:bg-muted/60",
              dateRangeOpen && "bg-primary/10 text-primary"
            )}
            onClick={() => setDateRangeOpen((o) => !o)}
          >
            <CalendarDays className="h-3.5 w-3.5" />
            {formatDateRangeButton(dateFrom, dateTo)}
          </button>
          <button type="button" className="inline-flex h-6 w-6 items-center justify-center rounded hover:bg-muted/50">
            <ChevronRight className="h-3.5 w-3.5 text-muted-foreground" />
          </button>
        </div>
      </div>

      <Card className="border-border/70 shadow-sm">
        <CardContent className="p-3">
          <div className="flex flex-col gap-2 lg:flex-row lg:items-center lg:justify-between">
            <div className="flex flex-wrap items-center gap-2">
              <select
                value={warehouseDraft}
                onChange={(e) => setWarehouseDraft(e.target.value)}
                className="h-8 w-[190px] rounded-md border border-input bg-background px-2 text-sm"
              >
                <option value="all">Склад</option>
                {(warehousesQ.data ?? []).map((w) => (
                  <option key={w.id} value={String(w.id)}>{w.name}</option>
                ))}
              </select>
              <select
                value={expeditorDraft}
                onChange={(e) => setExpeditorDraft(e.target.value)}
                className="h-8 w-[190px] rounded-md border border-input bg-background px-2 text-sm"
              >
                <option value="all">Экспедитор</option>
                {(expeditorsQ.data ?? []).map((ex) => (
                  <option key={ex.id} value={String(ex.id)}>{ex.fio}</option>
                ))}
              </select>
              <select
                value={statusDraft}
                onChange={(e) => setStatusDraft(e.target.value)}
                className="h-8 w-[190px] rounded-md border border-input bg-background px-2 text-sm"
              >
                <option value="all">Статус</option>
                <option value="new">Новый</option>
                <option value="confirmed">Подтвержден</option>
                <option value="delivering">Отгружен</option>
                <option value="delivered">Доставлен</option>
                <option value="cancelled">Отменен</option>
              </select>
            </div>
            <div className="flex items-center justify-end gap-2">
              <Button size="sm" variant="outline" className="h-8 w-8 px-0">
                <Filter className="h-3.5 w-3.5" />
              </Button>
              <Button
                size="sm"
                className="h-8 bg-teal-700 px-3 text-xs text-white hover:bg-teal-800"
                onClick={() => {
                  setWarehouse(warehouseDraft);
                  setExpeditor(expeditorDraft);
                  setStatus(statusDraft);
                  setSearch(searchDraft);
                }}
              >
                Применить
              </Button>
              <Button
                size="sm"
                variant="outline"
                className="h-8 w-8 px-0"
                onClick={() => {
                  setWarehouseDraft("all");
                  setExpeditorDraft("all");
                  setStatusDraft("delivering");
                  setSearchDraft("");
                  setWarehouse("all");
                  setExpeditor("all");
                  setStatus("delivering");
                  setSearch("");
                }}
              >
                <RotateCcw className="h-3.5 w-3.5" />
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      <DateRangePopover
        open={dateRangeOpen}
        onOpenChange={setDateRangeOpen}
        anchorRef={dateRangeAnchorRef}
        dateFrom={dateFrom}
        dateTo={dateTo}
        onApply={({ dateFrom: f, dateTo: t }) => {
          setDateFrom(f);
          setDateTo(t);
        }}
      />

      <Card>
        <CardContent className="p-0">
          {listQ.isLoading ? (
            <p className="p-4 text-sm text-muted-foreground">Загрузка…</p>
          ) : (
            <div className="overflow-x-auto">
              <div className="flex flex-wrap items-center justify-between gap-2 border-b px-3 py-2">
                <div className="flex items-center gap-2">
                  <select className="h-8 rounded-md border border-input bg-background px-2 text-xs">
                    <option>10</option>
                    <option>25</option>
                    <option>50</option>
                  </select>
                  <div className="relative">
                    <Search className="pointer-events-none absolute left-2 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground" />
                    <Input
                      value={searchDraft}
                      onChange={(e) => setSearchDraft(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === "Enter") setSearch(searchDraft);
                      }}
                      placeholder="Поиск"
                      className="h-8 w-[180px] pl-7 text-xs"
                    />
                  </div>
                  <Button size="sm" variant="outline" className="h-8 text-xs" onClick={() => setSearch(searchDraft)}>
                    Поиск
                  </Button>
                </div>
                <div className="flex items-center gap-2">
                  <Button size="sm" variant="outline" className="h-8 gap-1 text-xs">
                    <Settings2 className="h-3.5 w-3.5" />
                    Скачать
                  </Button>
                  <div className="text-xs text-muted-foreground">Всего: {filteredRows.length}</div>
                </div>
              </div>
              <table className="w-full min-w-[1220px] border-collapse text-sm">
                <thead className="app-table-thead text-left">
                  <tr>
                    <th className="px-3 py-2">ID</th>
                    <th className="px-3 py-2">Дата создания</th>
                    <th className="px-3 py-2">Склад</th>
                    <th className="px-3 py-2">Дата отгрузки</th>
                    <th className="px-3 py-2">Экспедитор</th>
                    <th className="px-3 py-2">Дата подтверждения</th>
                    <th className="px-3 py-2">Подтвержденная дата отправки</th>
                    <th className="px-3 py-2">Статус</th>
                    <th className="px-3 py-2">Отложенные задачи</th>
                    <th className="px-3 py-2">Подтверждение экспедитора</th>
                    <th className="px-3 py-2">Подтверждение складчика</th>
                    <th className="px-3 py-2">Подтверждение оператора</th>
                    <th className="px-3 py-2 text-right">Кол-во</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredRows.map((r) => (
                    <tr key={r.id} className="border-b border-border last:border-0">
                      <td className="px-3 py-2 font-mono text-xs">{r.number}</td>
                      <td className="px-3 py-2 text-xs text-muted-foreground">{r.created_at ? new Date(r.created_at).toLocaleString() : "—"}</td>
                      <td className="px-3 py-2">{r.warehouse_name ?? "—"}</td>
                      <td className="px-3 py-2">{r.shipped_at ? new Date(r.shipped_at).toLocaleString() : "—"}</td>
                      <td className="px-3 py-2">{r.expeditor_display ?? "—"}</td>
                      <td className="px-3 py-2">{r.delivered_at ? new Date(r.delivered_at).toLocaleString() : "—"}</td>
                      <td className="px-3 py-2">{r.shipped_at ? new Date(r.shipped_at).toLocaleString() : "—"}</td>
                      <td className="px-3 py-2">
                        <span className={`rounded px-2 py-1 text-xs ${statusBadgeClass(r.status)}`}>{r.status}</span>
                      </td>
                      <td className="px-3 py-2">Нет</td>
                      <td className="px-3 py-2">Да</td>
                      <td className="px-3 py-2">{r.status === "delivered" ? "Да" : "Нет"}</td>
                      <td className="px-3 py-2">{r.status === "delivered" ? "Да" : "Нет"}</td>
                      <td className="px-3 py-2 text-right tabular-nums">{r.qty}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {filteredRows.length === 0 ? (
                <p className="p-6 text-center text-sm text-muted-foreground">Отгрузочные накладные не найдены.</p>
              ) : null}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { downloadPriceMatrixTemplate } from "@/components/settings/prices/price-matrix-template";
import {
  flattenCategories,
  type PriceMatrixCategory,
  type PriceMatrixRow
} from "@/components/settings/prices/price-matrix-types";
import type { CategoryPanelMeta } from "@/components/settings/prices/price-matrix-category-panels";
import { api } from "@/lib/api";
import {
  firstMessagePerField,
  firstValidationUserHint,
  getZodFlattenFromApiErrorBody
} from "@/lib/api-validation-details";
import { getUserFacingError, withApiSupportLine } from "@/lib/error-utils";
import { countMatrixDraftChanges } from "@/lib/price-matrix-changes";
import {
  draftItemsFromMatrix,
  formatPriceDraftDisplay,
  parsePriceDraft
} from "@/lib/price-matrix-draft";
import { applyPercentToDraft } from "@/lib/price-matrix-percent";
import {
  buildSkuIndex,
  parsePriceMatrixXlsxRows,
  readXlsxMatrix,
  type PriceMatrixImportPreviewRow
} from "@/lib/price-matrix-import-parse";
import { STALE } from "@/lib/query-stale";
import { useAuthStore, useAuthStoreHydrated, useEffectiveRole } from "@/lib/auth-store";
import { isAdminOrOperatorLikeRole } from "@/lib/distribution-roles";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { isAxiosError } from "axios";
import { useCallback, useEffect, useMemo, useState } from "react";

export function usePriceMatrixPage() {
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const hydrated = useAuthStoreHydrated();
  const role = useEffectiveRole();
  const isAdmin = isAdminOrOperatorLikeRole(role);
  const qc = useQueryClient();

  const [kind, setKind] = useState<"sale" | "purchase">("sale");
  const [priceType, setPriceType] = useState("");
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<Set<number>>(new Set());
  const [effectiveAt, setEffectiveAt] = useState(() => new Date());
  const [bulk, setBulk] = useState("");
  const [draft, setDraft] = useState<Record<number, string>>({});
  const [msg, setMsg] = useState<string | null>(null);
  const [serverFieldErrs, setServerFieldErrs] = useState<Record<string, string>>({});
  const [templateLoading, setTemplateLoading] = useState(false);
  const [importOpen, setImportOpen] = useState(false);
  const [importRows, setImportRows] = useState<PriceMatrixImportPreviewRow[]>([]);
  const [importParseErr, setImportParseErr] = useState<string | null>(null);
  const [saveDialogOpen, setSaveDialogOpen] = useState(false);

  const categoryIdsArr = useMemo(
    () => [...selectedCategoryIds].sort((a, b) => a - b),
    [selectedCategoryIds]
  );

  const categoriesQ = useQuery({
    queryKey: ["product-categories", tenantSlug],
    enabled: Boolean(tenantSlug) && isAdmin,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: PriceMatrixCategory[] }>(
        `/api/${tenantSlug}/product-categories`
      );
      return data.data;
    }
  });

  const flatCats = useMemo(() => flattenCategories(categoriesQ.data ?? []), [categoriesQ.data]);

  const priceTypesQ = useQuery({
    queryKey: ["price-types", tenantSlug, kind],
    enabled: Boolean(tenantSlug) && isAdmin,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: string[] }>(`/api/${tenantSlug}/price-types?kind=${kind}`);
      return data.data;
    }
  });

  const matrixQ = useQuery({
    queryKey: ["price-matrix", tenantSlug, categoryIdsArr.join(","), priceType],
    enabled:
      Boolean(tenantSlug) && isAdmin && categoryIdsArr.length > 0 && priceType.length > 0,
    staleTime: STALE.detail,
    queryFn: async () => {
      const qs = new URLSearchParams({
        category_ids: categoryIdsArr.join(","),
        price_type: priceType
      });
      const { data } = await api.get<{ data: PriceMatrixRow[]; currency: string }>(
        `/api/${tenantSlug}/products/prices/matrix?${qs}`
      );
      return data;
    }
  });

  const matrixRows = matrixQ.data?.data ?? [];
  const currency = matrixQ.data?.currency ?? "UZS";

  const selectedCategoryLabels = useMemo(() => {
    const labelById = new Map(flatCats.map((c) => [c.id, c.label]));
    return categoryIdsArr.map((id) => labelById.get(id) ?? `Категория #${id}`);
  }, [categoryIdsArr, flatCats]);

  const categoryPanels = useMemo((): CategoryPanelMeta[] => {
    const labelById = new Map(flatCats.map((c) => [c.id, c.label]));
    const byCat = new Map<number, PriceMatrixRow[]>();
    for (const r of matrixRows) {
      const cid = r.category_id ?? 0;
      if (!cid) continue;
      const arr = byCat.get(cid) ?? [];
      arr.push(r);
      byCat.set(cid, arr);
    }
    const out: CategoryPanelMeta[] = [];
    for (const id of categoryIdsArr) {
      const rows = byCat.get(id) ?? [];
      out.push({
        id,
        label: labelById.get(id) ?? `Категория #${id}`,
        rows
      });
    }
    return out;
  }, [matrixRows, categoryIdsArr, flatCats]);

  const syncDraftFromRows = useCallback((rows: PriceMatrixRow[]) => {
    const next: Record<number, string> = {};
    for (const r of rows) {
      const raw = r.price ?? "";
      const parsed = parsePriceDraft(String(raw));
      next[r.product_id] = parsed.ok ? formatPriceDraftDisplay(parsed.value) : raw;
    }
    setDraft(next);
  }, []);

  useEffect(() => {
    syncDraftFromRows(matrixQ.data?.data ?? []);
  }, [matrixQ.data?.data, categoryIdsArr.join(","), priceType, syncDraftFromRows]);

  useEffect(() => {
    setPriceType("");
  }, [kind]);

  useEffect(() => {
    const list = priceTypesQ.data ?? [];
    if (priceType && list.length > 0 && !list.includes(priceType)) {
      setPriceType("");
    }
  }, [priceTypesQ.data, priceType]);

  const changeCount = useMemo(
    () => countMatrixDraftChanges(matrixRows, draft),
    [matrixRows, draft]
  );

  const saveMut = useMutation({
    mutationFn: async () => {
      if (!tenantSlug || categoryIdsArr.length === 0 || !priceType) throw new Error("bad");
      const items = draftItemsFromMatrix(matrixRows, draft);
      if (items.length === 0) throw new Error("EMPTY");
      const { data } = await api.patch<{
        ok: boolean;
        mode?: string;
        effective_at?: string;
      }>(`/api/${tenantSlug}/products/prices/matrix`, {
        price_type: priceType,
        currency,
        category_ids: categoryIdsArr,
        effective_at: effectiveAt.toISOString(),
        items
      });
      return data;
    },
    onMutate: () => {
      setServerFieldErrs({});
      setMsg(null);
    },
    onSuccess: async (data) => {
      await qc.invalidateQueries({ queryKey: ["price-matrix", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["finance-price-overview", tenantSlug] });
      setServerFieldErrs({});
      setSaveDialogOpen(false);
      if (data.mode === "scheduled" && data.effective_at) {
        const when = new Date(data.effective_at).toLocaleString("ru-RU");
        setMsg(`Rejalashtirildi: narxlar ${when} da qo‘llanadi.`);
      } else {
        setMsg("Saqlandi.");
      }
    },
    onError: (e: unknown) => {
      if (e instanceof Error && e.message === "EMPTY") {
        setServerFieldErrs({});
        setMsg("Kamida bitta narx kiriting.");
        return;
      }
      if (isAxiosError(e)) {
        const flat = getZodFlattenFromApiErrorBody(e.response?.data);
        if (flat) {
          const per = firstMessagePerField(flat);
          setServerFieldErrs(per);
          const top = flat.formErrors.map((s) => s.trim()).find(Boolean);
          const hint = firstValidationUserHint(flat);
          const line = top ?? hint ?? Object.values(per).find((m) => m.trim() !== "");
          setMsg(line ? withApiSupportLine(line, e) : getUserFacingError(e, "Saqlashda xato."));
          return;
        }
        setServerFieldErrs({});
      } else {
        setServerFieldErrs({});
      }
      setMsg(getUserFacingError(e, "Saqlashda xato."));
    }
  });

  function applyBulk() {
    const n = Number.parseFloat(String(bulk).replace(/\s/g, "").replace(",", "."));
    if (!Number.isFinite(n) || n < 0) return;
    const formatted = formatPriceDraftDisplay(n);
    const next = { ...draft };
    for (const r of matrixRows) {
      next[r.product_id] = formatted;
    }
    setDraft(next);
  }

  function applyPercent(factor: number) {
    setDraft((prev) => applyPercentToDraft(matrixRows, prev, factor));
  }

  function resetDraft() {
    syncDraftFromRows(matrixRows);
  }

  async function handleDownloadTemplate() {
    setImportParseErr(null);
    if (!priceType) {
      setImportParseErr("Avval narx turini tanlang.");
      return;
    }
    if (categoryIdsArr.length === 0) {
      setImportParseErr("Avval kamida bitta kategoriya belgilang.");
      return;
    }
    if (matrixRows.length === 0) {
      setImportParseErr("Tanlangan kategoriyalarda mahsulot yo‘q.");
      return;
    }
    setTemplateLoading(true);
    try {
      await downloadPriceMatrixTemplate(matrixRows, {
        priceType,
        categoryLabels: selectedCategoryLabels,
        draft,
        currency
      });
    } catch (e: unknown) {
      if (e instanceof Error && e.message === "PRICE_TYPE_REQUIRED") {
        setImportParseErr("Narx turini tanlang.");
        return;
      }
      setImportParseErr(getUserFacingError(e, "Shablon yuklab olishda xato."));
    } finally {
      setTemplateLoading(false);
    }
  }

  async function handleImportFile(file: File) {
    setImportParseErr(null);
    if (!priceType) {
      setImportParseErr("Narx turini tanlang.");
      return;
    }
    if (categoryIdsArr.length === 0) {
      setImportParseErr("Avval kamida bitta kategoriya belgilang.");
      return;
    }
    if (matrixRows.length === 0) {
      setImportParseErr("Tanlangan kategoriyalarda mahsulot yo‘q.");
      return;
    }
    try {
      const matrix = await readXlsxMatrix(file);
      const skuIndex = buildSkuIndex(matrixRows);
      const parsed = parsePriceMatrixXlsxRows(matrix, skuIndex);
      if (parsed.length === 0) {
        setImportParseErr("Faylda import qilinadigan qator yo‘q.");
        return;
      }
      setImportRows(parsed);
      setImportOpen(true);
    } catch (e: unknown) {
      setImportParseErr(getUserFacingError(e, "Excel o‘qishda xato."));
    }
  }

  async function handleImportSaved() {
    await qc.invalidateQueries({ queryKey: ["price-matrix", tenantSlug] });
    await qc.invalidateQueries({ queryKey: ["finance-price-overview", tenantSlug] });
    setMsg("Excel import saqlandi.");
  }

  const hasCategories = categoryIdsArr.length > 0;
  const toolbarEnabled = hasCategories && matrixRows.length > 0;

  return {
    tenantSlug,
    hydrated,
    isAdmin,
    kind,
    setKind,
    priceType,
    setPriceType,
    selectedCategoryIds,
    setSelectedCategoryIds,
    effectiveAt,
    setEffectiveAt,
    bulk,
    setBulk,
    draft,
    setDraft,
    msg,
    serverFieldErrs,
    templateLoading,
    importOpen,
    setImportOpen,
    importRows,
    importParseErr,
    saveDialogOpen,
    setSaveDialogOpen,
    categoryIdsArr,
    flatCats,
    priceTypes: priceTypesQ.data ?? [],
    categoryPanels,
    currency,
    matrixRows,
    matrixLoading: matrixQ.isLoading,
    changeCount,
    saveMut,
    applyBulk,
    applyPercent,
    resetDraft,
    handleDownloadTemplate,
    handleImportFile,
    handleImportSaved,
    hasCategories,
    toolbarEnabled
  };
}

"use client";

import { PageHeader } from "@/components/dashboard/page-header";
import { PageShell } from "@/components/dashboard/page-shell";
import { SettingsWorkspace } from "@/components/settings/settings-workspace";
import { Button } from "@/components/ui/button";
import { buttonVariants } from "@/components/ui/button-variants";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { useAuthStore, useAuthStoreHydrated } from "@/lib/auth-store";
import { formatNumberGrouped } from "@/lib/format-numbers";
import { STALE } from "@/lib/query-stale";
import { cn } from "@/lib/utils";
import { useQuery } from "@tanstack/react-query";
import { ChevronLeft, ChevronRight, Package, Search } from "lucide-react";
import Link from "next/link";
import { useEffect, useMemo, useState } from "react";

type PriceTypeEntry = {
  id: string;
  name: string;
  code: string | null;
  kind?: "sale" | "purchase";
  sort_order: number | null;
  active: boolean;
};

type TenantProfile = {
  references?: { price_type_entries?: PriceTypeEntry[] };
};

type ProductPrice = { price_type: string; price: string; currency: string };
type ProductRow = {
  id: number;
  sku: string;
  name: string;
  unit: string;
  category: { id: number; name: string } | null;
  prices?: ProductPrice[];
};

function priceKeyFromEntry(e: PriceTypeEntry): string {
  return (e.code?.trim() || e.name.trim()) || e.name;
}

function sortPriceCols(list: PriceTypeEntry[]): PriceTypeEntry[] {
  return [...list].sort((a, b) => {
    const ao = a.sort_order ?? 1e6;
    const bo = b.sort_order ?? 1e6;
    if (ao !== bo) return ao - bo;
    return a.name.localeCompare(b.name, "uz");
  });
}

export default function PriceListPage() {
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const hydrated = useAuthStoreHydrated();
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const [debounced, setDebounced] = useState("");
  const limit = 50;

  useEffect(() => {
    const t = window.setTimeout(() => setDebounced(search.trim()), 350);
    return () => window.clearTimeout(t);
  }, [search]);

  useEffect(() => {
    setPage(1);
  }, [debounced]);

  const profileQ = useQuery({
    queryKey: ["settings", "profile", tenantSlug, "price-list"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.profile,
    queryFn: async () => {
      const { data } = await api.get<TenantProfile>(`/api/${tenantSlug}/settings/profile`);
      return data;
    }
  });

  const priceColumns = useMemo(() => {
    const raw = profileQ.data?.references?.price_type_entries ?? [];
    return sortPriceCols(raw.filter((e) => e.active !== false));
  }, [profileQ.data]);

  const productsQ = useQuery({
    queryKey: ["products", tenantSlug, "price-list", page, limit, debounced],
    enabled: Boolean(tenantSlug) && profileQ.isSuccess,
    staleTime: STALE.list,
    queryFn: async () => {
      const params = new URLSearchParams();
      params.set("page", String(page));
      params.set("limit", String(limit));
      params.set("include_prices", "true");
      if (debounced.trim()) params.set("search", debounced.trim());
      const { data } = await api.get<{ data: ProductRow[]; total: number }>(
        `/api/${tenantSlug}/products?${params.toString()}`
      );
      return data;
    }
  });

  const rows = productsQ.data?.data ?? [];
  const total = productsQ.data?.total ?? 0;
  const totalPages = Math.max(1, Math.ceil(total / limit));

  const priceMapByProduct = useMemo(() => {
    const m = new Map<number, Map<string, ProductPrice>>();
    for (const p of rows) {
      const inner = new Map<string, ProductPrice>();
      for (const pr of p.prices ?? []) {
        inner.set(pr.price_type.trim(), pr);
      }
      m.set(p.id, inner);
    }
    return m;
  }, [rows]);

  if (!hydrated) {
    return (
      <PageShell>
        <p className="text-sm text-muted-foreground">Sessiya…</p>
      </PageShell>
    );
  }

  if (!tenantSlug) {
    return (
      <PageShell>
        <p className="text-sm text-destructive">
          <Link href="/login" className="underline">
            Kirish
          </Link>
        </p>
      </PageShell>
    );
  }

  return (
    <PageShell>
      <PageHeader
        title="Прайс-лист"
        description="Mahsulotlar va profildagi narx turlari ustunlari (product_prices)."
        actions={
          <div className="flex flex-wrap gap-2">
            <Link href="/settings/prices" className={cn(buttonVariants({ variant: "outline", size: "sm" }))}>
              ← Цена
            </Link>
            <Link href="/settings/prices/matrix" className={cn(buttonVariants({ variant: "secondary", size: "sm" }))}>
              Narx matritsasi
            </Link>
            <Link href="/settings/price-types" className={cn(buttonVariants({ variant: "outline", size: "sm" }))}>
              Narx turlari
            </Link>
          </div>
        }
      />

      <SettingsWorkspace>
        <div className="mb-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div className="relative max-w-md flex-1">
            <Search className="absolute left-2.5 top-1/2 size-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              className="pl-9"
              placeholder="SKU yoki nom bo‘yicha qidiruv…"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") setDebounced(search.trim());
              }}
            />
          </div>
          <p className="text-sm text-muted-foreground">
            Jami:{" "}
            <span className="font-medium text-foreground">{formatNumberGrouped(total, { maxFractionDigits: 0 })}</span>{" "}
            ta mahsulot
          </p>
        </div>

        {profileQ.isLoading ? (
          <div className="flex min-h-[240px] items-center justify-center rounded-xl border border-dashed border-muted-foreground/20 bg-muted/15">
            <p className="text-sm text-muted-foreground">Profil Загрузка…</p>
          </div>
        ) : priceColumns.length === 0 ? (
          <div className="flex min-h-[min(50vh,400px)] flex-col items-center justify-center rounded-xl border border-dashed border-amber-500/30 bg-amber-500/5 px-6 py-12 text-center">
            <p className="text-sm text-amber-800 dark:text-amber-200">
              Faol narx turi yo‘q.{" "}
              <Link href="/settings/price-types" className="underline">
                Narx turlarini
              </Link>{" "}
              sozlang.
            </p>
          </div>
        ) : productsQ.isLoading ? (
          <div className="flex min-h-[320px] items-center justify-center rounded-xl border border-dashed border-muted-foreground/20 bg-muted/15">
            <p className="text-sm text-muted-foreground">Mahsulotlar Загрузка…</p>
          </div>
        ) : productsQ.isError ? (
          <div className="rounded-lg border border-destructive/30 bg-destructive/5 px-4 py-8 text-center text-sm text-destructive">
            Yuklashda xato.{" "}
            <Button type="button" variant="outline" size="sm" className="ml-2" onClick={() => productsQ.refetch()}>
              Qayta
            </Button>
          </div>
        ) : total === 0 ? (
          <div className="flex min-h-[min(50vh,400px)] flex-col items-center justify-center rounded-xl border border-dashed border-muted-foreground/25 bg-muted/25 px-6 py-16 text-center">
            <Package className="mb-4 size-10 text-muted-foreground" strokeWidth={1.5} />
            <h2 className="text-lg font-semibold tracking-tight">Ma&apos;lumot yo&apos;q</h2>
            <p className="mt-2 max-w-md text-sm text-muted-foreground">
              Mahsulot qo‘shing yoki import qiling.
            </p>
            <div className="mt-6 flex flex-wrap justify-center gap-2">
              <Link href="/settings/products/excel" className={cn(buttonVariants({ size: "sm" }))}>
                Excel import
              </Link>
              <Link href="/products" className={cn(buttonVariants({ variant: "outline", size: "sm" }))}>
                Mahsulotlar
              </Link>
            </div>
          </div>
        ) : (
          <>
            <div className="overflow-x-auto rounded-lg border bg-card">
              <table className="w-max min-w-full border-collapse text-sm">
                <thead className="app-table-thead">
                  <tr className="border-b bg-muted/40 text-left">
                    <th className="whitespace-nowrap px-3 py-2 font-medium">SKU</th>
                    <th className="min-w-[12rem] px-3 py-2 font-medium">Nomi</th>
                    <th className="whitespace-nowrap px-3 py-2 font-medium text-muted-foreground">Birlik</th>
                    <th className="whitespace-nowrap px-3 py-2 font-medium text-muted-foreground">Kategoriya</th>
                    {priceColumns.map((col) => (
                      <th
                        key={col.id}
                        className="whitespace-nowrap px-3 py-2 text-right font-medium"
                        title={priceKeyFromEntry(col)}
                      >
                        <div className="max-w-[9rem] truncate">{col.name}</div>
                        <div className="text-[10px] font-normal text-muted-foreground">{priceKeyFromEntry(col)}</div>
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {rows.map((p) => {
                    const pmap = priceMapByProduct.get(p.id) ?? new Map();
                    return (
                      <tr key={p.id} className="border-b last:border-0 hover:bg-muted/20">
                        <td className="whitespace-nowrap px-3 py-2 font-mono text-xs">{p.sku}</td>
                        <td className="min-w-[12rem] px-3 py-2">{p.name}</td>
                        <td className="whitespace-nowrap px-3 py-2 text-muted-foreground">{p.unit}</td>
                        <td className="whitespace-nowrap px-3 py-2 text-muted-foreground">
                          {p.category?.name ?? "—"}
                        </td>
                        {priceColumns.map((col) => {
                          const key = priceKeyFromEntry(col);
                          const cell = pmap.get(key);
                          const num = cell ? Number.parseFloat(cell.price) : NaN;
                          return (
                            <td key={col.id} className="whitespace-nowrap px-3 py-2 text-right tabular-nums">
                              {cell && Number.isFinite(num) ? (
                                <>
                                  {formatNumberGrouped(num, { maxFractionDigits: 0 })}
                                  <span className="ml-1 text-[10px] text-muted-foreground">{cell.currency}</span>
                                </>
                              ) : (
                                <span className="text-muted-foreground">—</span>
                              )}
                            </td>
                          );
                        })}
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>

            <div className="mt-4 flex flex-wrap items-center justify-between gap-3">
              <p className="text-xs text-muted-foreground">
                Sahifa {page} / {totalPages} · {limit} ta/sahifa
              </p>
              <div className="flex items-center gap-2">
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  disabled={page <= 1 || productsQ.isFetching}
                  onClick={() => setPage((p) => Math.max(1, p - 1))}
                >
                  <ChevronLeft className="size-4" />
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  disabled={page >= totalPages || productsQ.isFetching}
                  onClick={() => setPage((p) => p + 1)}
                >
                  <ChevronRight className="size-4" />
                </Button>
              </div>
            </div>
          </>
        )}
      </SettingsWorkspace>
    </PageShell>
  );
}

"use client";

import { PageHeader } from "@/components/dashboard/page-header";
import { PageShell } from "@/components/dashboard/page-shell";
import { TableColumnSettingsDialog } from "@/components/data-table/table-column-settings-dialog";
import { Button } from "@/components/ui/button";
import { buttonVariants } from "@/components/ui/button-variants";
import { Card, CardContent } from "@/components/ui/card";
import { Dialog, DialogContent, DialogDescription, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useUserTablePrefs } from "@/hooks/use-user-table-prefs";
import { api } from "@/lib/api";
import { firstValidationUserHint, getZodFlattenFromApiErrorBody } from "@/lib/api-validation-details";
import { useAuthStore, useAuthStoreHydrated, useEffectiveRole } from "@/lib/auth-store";
import { getUserFacingError, withApiSupportLine } from "@/lib/error-utils";
import { downloadXlsxSheet } from "@/lib/download-xlsx";
import { formatNumberGrouped } from "@/lib/format-numbers";
import { STALE } from "@/lib/query-stale";
import { cn } from "@/lib/utils";
import { keepPreviousData, useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import type { AxiosError } from "axios";
import { FileSpreadsheet, Filter, LayoutGrid, RefreshCw, Search } from "lucide-react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import type { ReactNode } from "react";
import { useCallback, useEffect, useMemo, useState } from "react";

type TabKey = "journal" | "correction";

type JournalRow = {
  id: number;
  occurred_at: string;
  created_at: string;
  kind: string;
  warehouse_id: number;
  warehouse_name: string;
  created_by_name: string | null;
  total_qty_delta: string;
  total_volume_m3: string;
  total_amount: string;
  currency: string;
  comment: string | null;
  line_count: number;
  price_type: string | null;
};

type WorkspaceRow = {
  product_id: number;
  sku: string;
  name: string;
  unit: string;
  qty: string;
  reserved_qty: string;
  available_qty: string;
  price: string | null;
  currency: string | null;
};

type ProductCategoryRow = { id: number; name: string; is_active?: boolean };

const JOURNAL_TABLE_ID = "stock.warehouse_correction_journal.v1";
const JOURNAL_COLS = [
  { id: "occurred_at", label: "Дата" },
  { id: "created_by_name", label: "Создано" },
  { id: "kind", label: "Тип" },
  { id: "warehouse_name", label: "Склад" },
  { id: "total_qty_delta", label: "Кол-во" },
  { id: "total_volume_m3", label: "Объём" },
  { id: "total_amount", label: "Сумма" },
  { id: "comment", label: "Комментарий" }
] as const;
const JOURNAL_DEFAULT_ORDER = JOURNAL_COLS.map((c) => c.id);
const JOURNAL_NUMERIC = new Set(["total_qty_delta", "total_volume_m3", "total_amount"]);

function kindLabel(kind: string): string {
  return "Корректировка";
}

function parseNum(s: string): number {
  const n = Number.parseFloat(String(s).replace(/\s/g, "").replace(",", "."));
  return Number.isFinite(n) ? n : 0;
}

/** Sinxron maydonlar uchun qisqa matn (delta / fakt). */
function qtyToInputString(n: number): string {
  if (!Number.isFinite(n)) return "";
  const r = Math.round(n * 1e6) / 1e6;
  if (Math.abs(r - Math.round(r)) < 1e-9) return String(Math.round(r));
  const s = r.toFixed(6).replace(/\.?0+$/, "");
  return s === "-0" ? "0" : s;
}

/** Joriy qoldiq + korreksiya / fakt qatoridan delta. */
function resolveWorkspaceDelta(
  qty: number,
  productId: number,
  rowCorrection: Record<number, string>,
  rowFact: Record<number, string>
): { delta: number; hasInput: boolean } {
  const dStr = rowCorrection[productId]?.trim();
  const fStr = rowFact[productId]?.trim();
  if (dStr) {
    const d = Number.parseFloat(dStr.replace(",", "."));
    if (Number.isFinite(d)) return { delta: d, hasInput: true };
  }
  if (fStr) {
    const f = Number.parseFloat(fStr.replace(",", "."));
    if (Number.isFinite(f)) return { delta: f - qty, hasInput: true };
  }
  return { delta: 0, hasInput: false };
}

function formatDateTimeRu(iso: string): string {
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return iso;
  const pad = (x: number) => String(x).padStart(2, "0");
  return `${d.getFullYear()}.${pad(d.getMonth() + 1)}.${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

function colLabelJournal(id: string): string {
  return JOURNAL_COLS.find((c) => c.id === id)?.label ?? id;
}

function renderJournalCell(row: JournalRow, colId: string): ReactNode {
  switch (colId) {
    case "occurred_at":
      return (
        <span className="text-primary font-medium">{formatDateTimeRu(row.occurred_at)}</span>
      );
    case "created_by_name":
      return row.created_by_name ?? "—";
    case "kind":
      return kindLabel(row.kind);
    case "warehouse_name":
      return row.warehouse_name;
    case "total_qty_delta":
      return (
        <span
          className={cn(
            "tabular-nums",
            parseNum(row.total_qty_delta) < 0 && "text-destructive font-medium"
          )}
        >
          {formatNumberGrouped(row.total_qty_delta, { maxFractionDigits: 3 })}
        </span>
      );
    case "total_volume_m3":
      return (
        <span className="tabular-nums">
          {formatNumberGrouped(row.total_volume_m3, { maxFractionDigits: 6 })}
        </span>
      );
    case "total_amount":
      return (
        <span
          className={cn(
            "tabular-nums",
            parseNum(row.total_amount) < 0 && "text-destructive font-medium"
          )}
        >
          {formatNumberGrouped(row.total_amount, { minFractionDigits: 0, maxFractionDigits: 2 })}{" "}
          {row.currency}
        </span>
      );
    case "comment":
      return row.comment?.trim() ? row.comment : "—";
    default:
      return "—";
  }
}

export default function StockCorrectionPage() {
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const authHydrated = useAuthStoreHydrated();
  const role = useEffectiveRole();
  const router = useRouter();
  const searchParams = useSearchParams();
  const qc = useQueryClient();

  const tabParam = (searchParams.get("tab") as TabKey | null) ?? "journal";
  const tab: TabKey = tabParam === "correction" ? "correction" : "journal";

  const setTab = useCallback(
    (next: TabKey) => {
      const p = new URLSearchParams(searchParams.toString());
      p.set("tab", next);
      router.replace(`/stock/correction?${p.toString()}`);
    },
    [router, searchParams]
  );

  const journalPrefs = useUserTablePrefs({
    tenantSlug,
    tableId: JOURNAL_TABLE_ID,
    defaultColumnOrder: JOURNAL_DEFAULT_ORDER,
    defaultPageSize: 10,
    allowedPageSizes: [10, 20, 25, 50, 100]
  });
  const visibleJournalCols = journalPrefs.visibleColumnOrder;
  const [journalDialogOpen, setJournalDialogOpen] = useState(false);
  const [journalPage, setJournalPage] = useState(1);
  const [exportOpen, setExportOpen] = useState(false);
  const [exportBusy, setExportBusy] = useState(false);
  const journalPageSizes = [10, 20, 25, 50, 100] as const;

  const [jWarehouseId, setJWarehouseId] = useState("");
  const [jKind, setJKind] = useState<string>("");
  const [jSearch, setJSearch] = useState("");
  const [jDebounced, setJDebounced] = useState("");

  useEffect(() => {
    const t = window.setTimeout(() => setJDebounced(jSearch.trim()), 300);
    return () => window.clearTimeout(t);
  }, [jSearch]);

  useEffect(() => {
    setJournalPage(1);
  }, [jDebounced]);

  const [wWarehouseId, setWWarehouseId] = useState("");
  const [wPriceType, setWPriceType] = useState("");
  const [categorySearch, setCategorySearch] = useState("");
  const [categoryDebounced, setCategoryDebounced] = useState("");
  const [selectedCategoryId, setSelectedCategoryId] = useState<number | null>(null);
  const [rowCorrection, setRowCorrection] = useState<Record<number, string>>({});
  const [rowPrice, setRowPrice] = useState<Record<number, string>>({});
  /** Корр. rejimida: остаток после; инв. — реальный остаток (delta bilan sinxron). */
  const [rowFact, setRowFact] = useState<Record<number, string>>({});
  const [occurredAtLocal, setOccurredAtLocal] = useState("");
  const [wComment, setWComment] = useState("");
  const [wError, setWError] = useState<string | null>(null);

  const { data: warehouses = [] } = useQuery({
    queryKey: ["warehouses", tenantSlug],
    queryFn: async () => {
      const { data } = await api.get<{ data: { id: number; name: string }[] }>(
        `/api/${tenantSlug}/warehouses`
      );
      return data.data;
    },
    enabled: Boolean(tenantSlug) && role === "admin",
    staleTime: STALE.reference
  });

  const { data: journalResult, isFetching: journalFetching, refetch: refetchJournal } = useQuery({
    queryKey: [
      "stock-corrections",
      tenantSlug,
      jWarehouseId,
      jKind,
      jDebounced,
      journalPrefs.pageSize,
      journalPage
    ],
    queryFn: async () => {
      const params = new URLSearchParams();
      params.set("page", String(journalPage));
      params.set("limit", String(journalPrefs.pageSize));
      if (jWarehouseId) params.set("warehouse_id", jWarehouseId);
      if (jKind) params.set("kind", jKind);
      if (jDebounced) params.set("q", jDebounced);
      const { data } = await api.get<{ data: JournalRow[]; total: number }>(
        `/api/${tenantSlug}/stock/corrections?${params.toString()}`
      );
      return data;
    },
    enabled: Boolean(tenantSlug) && role === "admin" && tab === "journal",
    staleTime: STALE.list
  });

  const { data: priceTypes = [] } = useQuery({
    queryKey: ["correction-price-types", tenantSlug],
    queryFn: async () => {
      const { data } = await api.get<{ data: string[] }>(
        `/api/${tenantSlug}/stock/correction-price-types`
      );
      return data.data;
    },
    enabled: Boolean(tenantSlug) && role === "admin" && tab === "correction",
    staleTime: STALE.reference
  });

  useEffect(() => {
    if (categorySearch === "") {
      setCategoryDebounced("");
      return;
    }
    const t = window.setTimeout(() => setCategoryDebounced(categorySearch.trim()), 280);
    return () => window.clearTimeout(t);
  }, [categorySearch]);

  const { data: categoriesRaw = [] } = useQuery({
    queryKey: ["product-categories-correction", tenantSlug],
    queryFn: async () => {
      const { data } = await api.get<{ data: ProductCategoryRow[] }>(
        `/api/${tenantSlug}/product-categories`
      );
      return data.data.filter((c) => c.is_active !== false);
    },
    enabled:
      Boolean(tenantSlug) && role === "admin" && tab === "correction",
    staleTime: STALE.reference
  });

  const categoriesFiltered = useMemo(() => {
    const q = categoryDebounced.toLowerCase().trim();
    if (!q) return categoriesRaw;
    return categoriesRaw.filter((c) => c.name.toLowerCase().includes(q));
  }, [categoriesRaw, categoryDebounced]);

  const wid = Number.parseInt(wWarehouseId, 10);
  const {
    data: workspaceRows = [],
    isLoading: workspaceLoading,
    isFetching: workspaceFetching,
    isPlaceholderData: workspaceIsPlaceholder,
    isError: workspaceIsError,
    error: workspaceError,
    refetch: refetchWorkspace
  } = useQuery({
    queryKey: ["correction-workspace", tenantSlug, wWarehouseId, selectedCategoryId, wPriceType],
    queryFn: async () => {
      const params = new URLSearchParams();
      params.set("warehouse_id", wWarehouseId);
      params.set("category_id", String(selectedCategoryId));
      if (wPriceType.trim()) params.set("price_type", wPriceType.trim());
      const { data } = await api.get<{ data: WorkspaceRow[] }>(
        `/api/${tenantSlug}/stock/correction-workspace?${params.toString()}`
      );
      return data.data;
    },
    enabled:
      Boolean(tenantSlug) &&
      role === "admin" &&
      tab === "correction" &&
      Number.isFinite(wid) &&
      wid > 0 &&
      selectedCategoryId != null &&
      selectedCategoryId > 0,
    staleTime: STALE.detail,
    gcTime: 5 * 60_000,
    placeholderData: keepPreviousData
  });

  function workspaceErrorText(): string {
    type ErrBody = { error?: string; message?: string; details?: unknown };
    const ax = workspaceError as AxiosError<ErrBody> | undefined;
    const st = ax?.response?.status;
    const body = ax?.response?.data;
    const code = body?.error;
    if (st === 403) return "Ruxsat yo‘q (faqat administrator).";
    if (code === "BadWarehouse") return "Ombor topilmadi yoki boshqa tashkilotga tegishli.";
    if (code === "ValidationError") {
      const flat = getZodFlattenFromApiErrorBody(body);
      const hint = flat != null ? firstValidationUserHint(flat) : undefined;
      return hint
        ? `So‘rov tekshiruvi: ${hint}`
        : "Filtrlarni tekshiring (ombor, kategoriya).";
    }
    if (st === 400) return "So‘rov noto‘g‘ri yoki filtr tanlanmagan.";
    if (st === 404) return "API topilmadi — backend yangilanganligini tekshiring.";
    return getUserFacingError(workspaceError, "Ma’lumot yuklanmadi (tarmoq yoki server).");
  }

  useEffect(() => {
    if (!workspaceRows.length) return;
    setRowPrice((prev) => {
      const next = { ...prev };
      for (const r of workspaceRows) {
        if (next[r.product_id] === undefined && r.price != null) {
          next[r.product_id] = r.price.replace(/\s/g, "").replace(",", ".");
        }
      }
      return next;
    });
  }, [workspaceRows]);

  useEffect(() => {
    if (tab !== "correction") return;
    if (!occurredAtLocal) {
      const d = new Date();
      const pad = (n: number) => String(n).padStart(2, "0");
      setOccurredAtLocal(
        `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`
      );
    }
  }, [tab, occurredAtLocal]);

  const handleDeltaInput = useCallback((productId: number, qty: number, value: string) => {
    setRowCorrection((prev) => ({ ...prev, [productId]: value }));
    const t = value.trim();
    if (t === "") {
      setRowFact((prev) => {
        const n = { ...prev };
        delete n[productId];
        return n;
      });
      return;
    }
    const d = Number.parseFloat(t.replace(",", "."));
    if (!Number.isFinite(d)) return;
    setRowFact((prev) => ({ ...prev, [productId]: qtyToInputString(qty + d) }));
  }, []);

  const handleFactInput = useCallback((productId: number, qty: number, value: string) => {
    setRowFact((prev) => ({ ...prev, [productId]: value }));
    const t = value.trim();
    if (t === "") {
      setRowCorrection((prev) => {
        const n = { ...prev };
        delete n[productId];
        return n;
      });
      return;
    }
    const f = Number.parseFloat(t.replace(",", "."));
    if (!Number.isFinite(f)) return;
    setRowCorrection((prev) => ({ ...prev, [productId]: qtyToInputString(f - qty) }));
  }, []);

  const resetRowInputs = useCallback(() => {
    setRowCorrection({});
    setRowFact({});
    setWError(null);
  }, []);

  useEffect(() => {
    setWWarehouseId("");
    setJWarehouseId("");
    setSelectedCategoryId(null);
  }, [tenantSlug]);

  /** Korrektirovka / inventarizatsiya: ombor bo‘sh bo‘lsa, ro‘yxatdan birinchisini tanlash (xatosiz workspace so‘rovi). */
  useEffect(() => {
    if (tab !== "correction") return;
    if (wWarehouseId) return;
    const first = warehouses[0];
    if (first) setWWarehouseId(String(first.id));
  }, [tab, warehouses, wWarehouseId]);

  useEffect(() => {
    resetRowInputs();
  }, [selectedCategoryId, wWarehouseId, wPriceType, tab, resetRowInputs]);

  const bulkMutation = useMutation({
    mutationFn: async (payload: {
      kind: "correction";
      items: { product_id: number; delta: number; price_unit?: number | null }[];
    }) => {
      const wh = Number.parseInt(wWarehouseId, 10);
      const iso =
        occurredAtLocal && !Number.isNaN(new Date(occurredAtLocal).getTime())
          ? new Date(occurredAtLocal).toISOString()
          : new Date().toISOString();
      await api.post(`/api/${tenantSlug}/stock/corrections/bulk`, {
        warehouse_id: wh,
        kind: payload.kind,
        price_type: wPriceType.trim() || null,
        occurred_at: iso,
        comment: wComment.trim() || null,
        items: payload.items
      });
    },
    onSuccess: async () => {
      setWError(null);
      setWComment("");
      resetRowInputs();
      await qc.invalidateQueries({ queryKey: ["correction-workspace", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["stock", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["stock-corrections", tenantSlug] });
      setJournalPage(1);
      setTab("journal");
    },
    onError: (err) => {
      const ax = err as AxiosError<{ error?: string }>;
      const code = ax.response?.data?.error;
      const st = ax.response?.status;
      if (st === 403) {
        setWError("Saqlashga ruxsat yo‘q.");
        return;
      }
      if (code === "ValidationError") {
        const flat = getZodFlattenFromApiErrorBody(ax.response?.data);
        const hint = flat != null ? firstValidationUserHint(flat) : undefined;
        setWError(
          withApiSupportLine(
            hint != null && hint.trim() !== ""
              ? `So‘rov tekshiruvi: ${hint}`
              : "Ma’lumotlarni tekshiring (delta, ombor).",
            err
          )
        );
        return;
      }
      const map: Record<string, string> = {
        NegativeQty: "Qoldiq manfiy bo‘lib qoladi.",
        BelowReserved: "Qoldiq rezervdan past.",
        BadDelta: "Noto‘g‘ri delta.",
        BadWarehouse: "Ombor noto‘g‘ri.",
        BadProduct: "Mahsulot topilmadi.",
        TooManyLines: "Juda ko‘p qator (max 500).",
        EmptyItems: "Bo‘sh ro‘yxat."
      };
      setWError(map[code ?? ""] ?? `Saqlashda xato${st ? ` (${st})` : ""}. DB migratsiyasi qo‘llanganmi?`);
    }
  });

  const buildItemsFromWorkspace = useMemo(() => {
    return (): { product_id: number; delta: number; price_unit?: number | null }[] => {
      const out: { product_id: number; delta: number; price_unit?: number | null }[] = [];
      for (const r of workspaceRows) {
        const qty = parseNum(r.qty);
        const { delta, hasInput } = resolveWorkspaceDelta(
          qty,
          r.product_id,
          rowCorrection,
          rowFact
        );
        if (!hasInput || !Number.isFinite(delta) || delta === 0) continue;
        const avail = parseNum(r.available_qty);
        if (delta < 0 && delta < -avail - 1e-9) continue;
        const pRaw = rowPrice[r.product_id]?.trim();
        const price_unit =
          pRaw != null && pRaw !== "" && Number.isFinite(Number.parseFloat(pRaw.replace(",", ".")))
            ? Number.parseFloat(pRaw.replace(",", "."))
            : null;
        out.push({ product_id: r.product_id, delta, price_unit });
      }
      return out;
    };
  }, [workspaceRows, rowCorrection, rowFact, rowPrice]);

  const workspaceTotals = useMemo(() => {
    let sumDelta = 0;
    let sumAmount = 0;
    let linesTouched = 0;
    for (const r of workspaceRows) {
      const qty = parseNum(r.qty);
      const avail = parseNum(r.available_qty);
      const minDelta = -avail;
      const { delta, hasInput } = resolveWorkspaceDelta(
        qty,
        r.product_id,
        rowCorrection,
        rowFact
      );
      if (!hasInput || !Number.isFinite(delta) || delta === 0 || delta < minDelta - 1e-9) continue;
      linesTouched += 1;
      sumDelta += delta;
      const pStr = rowPrice[r.product_id] ?? "";
      const pu = Number.parseFloat(pStr.replace(",", "."));
      if (pStr.trim() !== "" && Number.isFinite(pu)) sumAmount += delta * pu;
    }
    return { sumDelta, sumAmount, linesTouched };
  }, [workspaceRows, rowCorrection, rowFact, rowPrice]);

  const journalTotal = journalResult?.total ?? 0;
  const journalPages = Math.max(1, Math.ceil(journalTotal / journalPrefs.pageSize));

  useEffect(() => {
    if (journalPage > journalPages) setJournalPage(journalPages);
  }, [journalPage, journalPages]);

  function handleSaveBulk() {
    const items = buildItemsFromWorkspace();
    if (!items.length) {
      setWError("Укажите корректировку или фактический остаток хотя бы в одной строке.");
      return;
    }
    bulkMutation.mutate({
      kind: "correction",
      items
    });
  }

  function exportJournalSummary() {
    const rows = journalResult?.data ?? [];
    const headers = visibleJournalCols.map(colLabelJournal);
    const lines = rows.map((row) =>
      visibleJournalCols.map((colId) => {
        if (colId === "occurred_at") return formatDateTimeRu(row.occurred_at);
        if (colId === "kind") return kindLabel(row.kind);
        if (colId === "total_qty_delta") return row.total_qty_delta;
        if (colId === "total_volume_m3") return row.total_volume_m3;
        if (colId === "total_amount") return `${row.total_amount} ${row.currency}`;
        const cell = renderJournalCell(row, colId);
        if (typeof cell === "string" || typeof cell === "number") return cell;
        return String(cell);
      })
    );
    downloadXlsxSheet(
      `korrektirovka_zhurnal_${new Date().toISOString().slice(0, 10)}.xlsx`,
      "Журнал",
      headers,
      lines
    );
    setExportOpen(false);
  }

  async function exportJournalDetailed() {
    const rows = journalResult?.data ?? [];
    if (!rows.length) return;
    setExportBusy(true);
    try {
      const headers = [
        "Дата (локальное время)",
        "Дата (ISO UTC)",
        "Тип документа",
        "Склад",
        "Кол-во Δ",
        "Объём",
        "Сумма",
        "Валюта",
        "Создано",
        "Комментарий",
        "ID документа"
      ];
      const lines = rows.map((row) => [
        formatDateTimeRu(row.occurred_at),
        new Date(row.occurred_at).toISOString(),
        kindLabel(row.kind),
        row.warehouse_name,
        row.total_qty_delta,
        row.total_volume_m3,
        row.total_amount,
        row.currency,
        row.created_by_name ?? "",
        row.comment ?? "",
        String(row.id)
      ]);
      downloadXlsxSheet(
        `korrektirovka_zhurnal_batafsil_${new Date().toISOString().slice(0, 10)}.xlsx`,
        "Журнал (детально)",
        headers,
        lines
      );
      setExportOpen(false);
    } finally {
      setExportBusy(false);
    }
  }

  if (!authHydrated) {
    return (
      <PageShell>
        <p className="text-muted-foreground text-sm">Загрузка…</p>
      </PageShell>
    );
  }

  if (!tenantSlug || role !== "admin") {
    return (
      <PageShell>
        <PageHeader title="Корректировка склада" description="Faqat administrator." />
        <Link className={cn(buttonVariants({ variant: "outline", size: "sm" }))} href="/stock">
          ← Ombor
        </Link>
      </PageShell>
    );
  }

  const journalRows = journalResult?.data ?? [];

  return (
    <PageShell>
      <PageHeader
        title="Корректировка склада"
        description="Журнал проведённых документов и ввод корректировки по дельте/факту."
      />

      <div className="mb-4 flex flex-wrap items-center gap-2">
        <Link className={cn(buttonVariants({ variant: "outline", size: "sm" }))} href="/stock">
          ← Склад
        </Link>
      </div>

      <div className="mb-4 flex flex-wrap gap-1 rounded-lg border border-border/60 bg-muted/30 p-1">
        {(
          [
            ["journal", "Журнал"],
            ["correction", "Корректировка склада"]
          ] as const
        ).map(([key, label]) => (
          <Button
            key={key}
            type="button"
            variant={tab === key ? "default" : "ghost"}
            size="sm"
            className={cn("flex-1 sm:flex-none", tab === key && "shadow-sm")}
            onClick={() => setTab(key)}
          >
            {label}
          </Button>
        ))}
      </div>

      {tab === "journal" ? (
        <Card className="border-border/80 overflow-hidden shadow-sm">
          <div className="border-border/60 border-b bg-gradient-to-r from-slate-200/90 via-slate-100/70 to-background px-4 py-2.5 dark:from-slate-900 dark:via-slate-950/80 dark:to-background">
            <h2 className="text-sm font-semibold">Журнал корректировок</h2>
            <p className="text-muted-foreground text-xs">Проведённые документы по складу</p>
          </div>
          <CardContent className="space-y-4 pt-6">
            <div className="flex flex-col gap-3 sm:flex-row sm:flex-wrap sm:items-end sm:justify-between">
              <div className="flex flex-wrap items-end gap-3">
                <div className="space-y-1.5">
                  <Label>Склад</Label>
                  <select
                    className="border-input bg-background h-10 min-w-[11rem] rounded-md border px-3 text-sm"
                    value={jWarehouseId}
                    onChange={(e) => {
                      setJWarehouseId(e.target.value);
                      setJournalPage(1);
                    }}
                  >
                    <option value="">Все</option>
                    {warehouses.map((w) => (
                      <option key={w.id} value={String(w.id)}>
                        {w.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <Label className="flex items-center gap-1">
                    <Filter className="size-3.5 opacity-70" />
                    Тип документа
                  </Label>
                  <div className="flex rounded-md border border-border/60 bg-background p-0.5">
                    <button
                      type="button"
                      className={cn(
                        "rounded px-3 py-1.5 text-xs font-medium transition-colors",
                        jKind === "" ? "bg-primary text-primary-foreground shadow-sm" : "hover:bg-muted/80"
                      )}
                      onClick={() => {
                        setJKind("");
                        setJournalPage(1);
                      }}
                    >
                      Все
                    </button>
                    <button
                      type="button"
                      className={cn(
                        "rounded px-3 py-1.5 text-xs font-medium transition-colors",
                        jKind === "correction"
                          ? "bg-primary text-primary-foreground shadow-sm"
                          : "hover:bg-muted/80"
                      )}
                      onClick={() => {
                        setJKind("correction");
                        setJournalPage(1);
                      }}
                    >
                      Корректировка склада
                    </button>
                  </div>
                </div>
              </div>
              <Button
                type="button"
                size="sm"
                className="bg-emerald-600 text-white hover:bg-emerald-700 dark:bg-emerald-600 dark:hover:bg-emerald-500"
                onClick={() => void refetchJournal()}
              >
                Применить
              </Button>
            </div>

            <div className="flex flex-wrap items-end gap-2 border-b border-border/50 pb-3">
              <div className="flex items-end gap-2 text-sm">
                <span className="pb-2 text-muted-foreground">На странице</span>
                <select
                  className="border-input bg-background h-9 rounded-md border px-2 text-sm"
                  value={journalPrefs.pageSize}
                  onChange={(e) => {
                    journalPrefs.setPageSize(Number.parseInt(e.target.value, 10));
                    setJournalPage(1);
                  }}
                >
                  {journalPageSizes.map((n) => (
                    <option key={n} value={n}>
                      {n}
                    </option>
                  ))}
                </select>
              </div>
              <Button
                type="button"
                variant="outline"
                size="icon"
                className="h-9 w-9"
                title="Столбцы"
                onClick={() => setJournalDialogOpen(true)}
              >
                <LayoutGrid className="size-4" />
              </Button>
              <div className="relative min-w-[12rem] max-w-xs flex-1">
                <Search className="text-muted-foreground absolute left-2.5 top-1/2 size-4 -translate-y-1/2" />
                <Input
                  className="h-9 pl-8"
                  placeholder="Поиск"
                  value={jSearch}
                  onChange={(e) => setJSearch(e.target.value)}
                />
              </div>
              <Button type="button" variant="outline" size="sm" onClick={() => setExportOpen(true)}>
                <FileSpreadsheet className="mr-1 size-4" />
                Excel
              </Button>
              <Button
                type="button"
                variant="outline"
                size="icon"
                className="h-9 w-9"
                onClick={() => void refetchJournal()}
              >
                <RefreshCw className={cn("size-4", journalFetching && "animate-spin")} />
              </Button>
            </div>

            <TableColumnSettingsDialog
              open={journalDialogOpen}
              onOpenChange={setJournalDialogOpen}
              title="Столбцы журнала"
              description="Порядок и видимость сохраняются в профиле."
              columns={[...JOURNAL_COLS]}
              columnOrder={journalPrefs.columnOrder}
              hiddenColumnIds={journalPrefs.hiddenColumnIds}
              saving={journalPrefs.saving}
              onSave={(next) => journalPrefs.saveColumnLayout(next)}
              onReset={() => journalPrefs.resetColumnLayout()}
            />

            <div className="overflow-x-auto rounded-lg border">
              <table className="w-full min-w-[720px] text-left text-sm">
                <thead className="app-table-thead text-xs">
                  <tr>
                    {visibleJournalCols.map((colId) => (
                      <th
                        key={colId}
                        className={cn(
                          "px-3 py-2.5",
                          JOURNAL_NUMERIC.has(colId) && "text-right"
                        )}
                      >
                        {colLabelJournal(colId)}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {journalRows.length === 0 ? (
                    <tr>
                      <td
                        colSpan={Math.max(1, visibleJournalCols.length)}
                        className="text-muted-foreground p-6 text-center"
                      >
                        Записей нет
                      </td>
                    </tr>
                  ) : (
                    journalRows.map((row) => (
                      <tr
                        key={row.id}
                        className="border-t border-border/50 even:bg-muted/15 hover:bg-muted/30"
                      >
                        {visibleJournalCols.map((colId) => (
                          <td
                            key={colId}
                            className={cn("px-3 py-2", JOURNAL_NUMERIC.has(colId) && "text-right")}
                          >
                            {renderJournalCell(row, colId)}
                          </td>
                        ))}
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>

            <div className="text-muted-foreground flex flex-wrap items-center justify-between gap-2 text-sm">
              <span>
                Показано{" "}
                {journalTotal === 0
                  ? "0 — 0"
                  : `${(journalPage - 1) * journalPrefs.pageSize + 1} — ${Math.min(journalPage * journalPrefs.pageSize, journalTotal)}`}{" "}
                / {journalTotal}
              </span>
              <div className="flex items-center gap-2">
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  disabled={journalPage <= 1}
                  onClick={() => setJournalPage((p) => Math.max(1, p - 1))}
                >
                  ←
                </Button>
                <span>
                  {journalPage} / {journalPages}
                </span>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  disabled={journalPage >= journalPages}
                  onClick={() => setJournalPage((p) => p + 1)}
                >
                  →
                </Button>
              </div>
            </div>
            <Dialog open={exportOpen} onOpenChange={setExportOpen}>
              <DialogContent className="gap-0 overflow-hidden border-0 p-0 shadow-lg sm:max-w-lg" showCloseButton>
                <div className="border-b bg-gradient-to-br from-primary/12 via-primary/5 to-background px-5 py-4">
                  <div className="flex gap-3">
                    <div className="flex size-11 shrink-0 items-center justify-center rounded-xl bg-primary/15 text-primary ring-1 ring-primary/20">
                      <FileSpreadsheet className="size-5" />
                    </div>
                    <div className="min-w-0 space-y-1 pr-6">
                      <DialogTitle className="text-base font-semibold leading-tight">Excel eksport</DialogTitle>
                      <DialogDescription className="text-xs leading-relaxed text-muted-foreground">
                        Joriy filtrlangan jurnal qatorlari eksport qilinadi. Fayl{" "}
                        <span className="font-medium text-foreground/80">.xlsx</span> formatida.
                      </DialogDescription>
                    </div>
                  </div>
                </div>
                <div className="space-y-2.5 p-4">
                  <button
                    type="button"
                    disabled={exportBusy || journalRows.length === 0}
                    onClick={() => exportJournalSummary()}
                    className={cn(
                      "flex w-full flex-col gap-0.5 rounded-xl border border-border/80 bg-card px-4 py-3.5 text-left shadow-sm transition-colors",
                      "hover:border-primary/35 hover:bg-muted/35",
                      "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                      "disabled:pointer-events-none disabled:opacity-45"
                    )}
                  >
                    <span className="text-sm font-medium">Umumiy ro‘yxat</span>
                    <span className="text-xs text-muted-foreground">
                      Ko‘rinib turgan ustunlar bo‘yicha jurnal ro‘yxati
                    </span>
                  </button>
                  <button
                    type="button"
                    disabled={exportBusy || journalRows.length === 0}
                    onClick={() => void exportJournalDetailed()}
                    className={cn(
                      "flex w-full flex-col gap-0.5 rounded-xl border border-border/80 bg-card px-4 py-3.5 text-left shadow-sm transition-colors",
                      "hover:border-primary/35 hover:bg-muted/35",
                      "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                      "disabled:pointer-events-none disabled:opacity-45"
                    )}
                  >
                    <span className="text-sm font-medium">
                      {exportBusy ? "Загрузка…" : "Batafsil (audit ustunlari)"}
                    </span>
                    <span className="text-xs text-muted-foreground">
                      Lokal/UTC vaqt, valuta, yaratuvchi va hujjat ID bilan
                    </span>
                  </button>
                  {journalRows.length === 0 ? (
                    <p className="rounded-lg bg-muted/50 px-3 py-2 text-center text-xs text-muted-foreground">
                      Eksport uchun jadvalda kamida bitta qator bo‘lishi kerak.
                    </p>
                  ) : null}
                </div>
              </DialogContent>
            </Dialog>
          </CardContent>
        </Card>
      ) : (
        <div className="border-border/80 bg-card overflow-hidden rounded-lg border shadow-sm">
          <div className="border-border/60 flex flex-col gap-2 border-b bg-gradient-to-r from-slate-200/90 via-slate-100/80 to-background px-4 py-3 dark:from-slate-900 dark:via-slate-950/90 dark:to-background sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h2 className="text-base font-semibold tracking-tight">
                Корректировка склада
              </h2>
              <p className="text-muted-foreground text-xs">
                Поля «корректировка» (Δ) и «остаток после» взаимно пересчитываются от текущего остатка.
              </p>
            </div>
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="shrink-0"
              disabled={!wWarehouseId || selectedCategoryId == null || workspaceLoading || workspaceFetching}
              onClick={() => void refetchWorkspace()}
            >
              <RefreshCw
                className={cn("mr-1.5 size-4", (workspaceLoading || workspaceFetching) && "animate-spin")} />
              Обновить таблицу
            </Button>
          </div>

          <div className="grid gap-0 lg:grid-cols-[minmax(240px,288px)_1fr]">
            <aside className="border-border/60 bg-muted/10 border-b lg:border-b-0 lg:border-r">
              <div className="text-muted-foreground border-border/50 border-b bg-muted/50 px-3 py-2 text-[11px] font-semibold uppercase tracking-wide">
                Категории
              </div>
              <div className="space-y-3 p-3">
                <p className="text-muted-foreground text-[11px] leading-snug">
                  Выберите <strong>категорию</strong> в списке ниже.
                </p>
                <div className="relative">
                  <Search className="text-muted-foreground absolute left-2 top-1/2 size-4 -translate-y-1/2" />
                  <Input
                    className="pl-8 text-sm"
                    placeholder="Поиск категории"
                    value={categorySearch}
                    onChange={(e) => setCategorySearch(e.target.value)}
                  />
                </div>
                <div className="max-h-[min(60vh,520px)] overflow-auto text-sm">
                  {categoriesFiltered.length === 0 ? (
                    <p className="text-muted-foreground p-2">Категории не найдены</p>
                  ) : (
                    <ul className="space-y-0.5">
                      {categoriesFiltered.map((c) => (
                        <li key={c.id}>
                          <button
                            type="button"
                            className={cn(
                              "hover:bg-muted/80 w-full rounded-r-md border-l-2 border-transparent py-1.5 pl-2 pr-2 text-left text-sm transition-colors",
                              selectedCategoryId === c.id &&
                                "border-primary bg-primary/10 font-medium text-foreground"
                            )}
                            onClick={() => setSelectedCategoryId(c.id)}
                          >
                            {c.name}
                          </button>
                        </li>
                      ))}
                    </ul>
                  )}
                </div>
              </div>
            </aside>

            <div className="min-w-0">
              <div className="border-border/50 flex flex-wrap items-end gap-3 border-b bg-background px-3 py-3">
                <div className="space-y-1.5">
                  <Label>Склад</Label>
                  <select
                    className="border-input bg-background h-10 min-w-[12rem] rounded-md border px-3 text-sm"
                    value={wWarehouseId}
                    onChange={(e) => setWWarehouseId(e.target.value)}
                  >
                    <option value="">—</option>
                    {warehouses.map((w) => (
                      <option key={w.id} value={String(w.id)}>
                        {w.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <Label>Тип цены</Label>
                  <select
                    className="border-input bg-background h-10 min-w-[12rem] rounded-md border px-3 text-sm"
                    value={wPriceType}
                    onChange={(e) => setWPriceType(e.target.value)}
                  >
                    <option value="">—</option>
                    {priceTypes.map((pt) => (
                      <option key={pt} value={pt}>
                        {pt}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="space-y-3 p-3">
              {!wWarehouseId || selectedCategoryId == null ? (
                <p className="text-muted-foreground text-sm">
                  Выберите <strong>склад</strong> и слева <strong>категорию</strong>.
                </p>
              ) : workspaceIsError ? (
                <div className="border-destructive/50 bg-destructive/5 space-y-2 rounded-lg border p-4 text-sm">
                  <p className="text-destructive font-medium">{workspaceErrorText()}</p>
                  <Button type="button" variant="outline" size="sm" onClick={() => void refetchWorkspace()}>
                    Qayta urinish
                  </Button>
                </div>
              ) : workspaceLoading || (workspaceFetching && workspaceRows.length === 0) ? (
                <p className="text-muted-foreground text-sm">Загрузка…</p>
              ) : workspaceRows.length === 0 ? (
                <div className="text-muted-foreground space-y-2 text-sm">
                  <p>
                    В выбранной <strong>категории</strong> нет активных товаров или они привязаны к другой
                    категории.
                  </p>
                  <p>Попробуйте другую категорию или поиск.</p>
                </div>
              ) : (
                <div
                  className={cn(
                    "overflow-x-auto rounded-md border border-border/80 shadow-sm transition-opacity",
                    workspaceIsPlaceholder && workspaceFetching && "pointer-events-none opacity-60"
                  )}
                >
                  <table className="w-full min-w-[1120px] text-left text-sm">
                    <thead className="app-table-thead sticky top-0 z-[1] text-xs">
                      <tr>
                        <th className="px-2 py-2.5">Код</th>
                        <th className="px-2 py-2.5">Наименование</th>
                        <th className="px-2 py-2.5 text-center">Ед.</th>
                        <th className="px-2 py-2.5 text-right">Остаток (текущий)</th>
                        <th className="px-2 py-2.5 text-right">Бронь</th>
                        <th className="px-2 py-2.5 text-right">Доступный</th>
                        <th className="px-2 py-2.5 text-right">Корректировка</th>
                        <th className="px-2 py-2.5 text-right">Остаток после корр.</th>
                        <th className="px-2 py-2.5 text-right">Цена</th>
                        <th className="px-2 py-2.5 text-right">Сумма корр.</th>
                      </tr>
                    </thead>
                    <tbody>
                      {workspaceRows.map((r) => {
                        const qty = parseNum(r.qty);
                        const avail = parseNum(r.available_qty);
                        const minDelta = -avail;
                        const { delta, hasInput } = resolveWorkspaceDelta(
                          qty,
                          r.product_id,
                          rowCorrection,
                          rowFact
                        );
                        const deltaInvalid =
                          hasInput && Number.isFinite(delta) && delta < minDelta - 1e-9;
                        const pStr = rowPrice[r.product_id] ?? "";
                        const pu = Number.parseFloat(pStr.replace(",", "."));
                        const sum =
                          hasInput &&
                          Number.isFinite(delta) &&
                          delta !== 0 &&
                          Number.isFinite(pu) &&
                          pStr.trim() !== ""
                            ? delta * pu
                            : null;
                        return (
                          <tr
                            key={r.product_id}
                            className="border-t border-border/50 even:bg-muted/20 hover:bg-muted/40"
                          >
                            <td className="px-2 py-1.5 font-mono text-xs">{r.sku}</td>
                            <td className="max-w-[200px] truncate px-2 py-1.5" title={r.name}>
                              {r.name}
                            </td>
                            <td className="text-muted-foreground px-2 py-1.5 text-center text-xs">
                              {r.unit}
                            </td>
                            <td className="px-2 py-1.5 text-right tabular-nums">
                              {formatNumberGrouped(r.qty, { maxFractionDigits: 3 })}
                            </td>
                            <td className="px-2 py-1.5 text-right tabular-nums">
                              {formatNumberGrouped(r.reserved_qty, { maxFractionDigits: 3 })}
                            </td>
                            <td className="px-2 py-1.5 text-right tabular-nums">
                              {formatNumberGrouped(r.available_qty, { maxFractionDigits: 3 })}
                            </td>
                            <td className="px-1 py-1">
                              <Input
                                className={cn(
                                  "h-8 text-right tabular-nums",
                                  deltaInvalid && "border-destructive"
                                )}
                                inputMode="decimal"
                                title={
                                  deltaInvalid
                                    ? `Мин. Δ ${formatNumberGrouped(minDelta, { maxFractionDigits: 3 })}`
                                    : undefined
                                }
                                value={rowCorrection[r.product_id] ?? ""}
                                onChange={(e) =>
                                  handleDeltaInput(r.product_id, qty, e.target.value)
                                }
                              />
                            </td>
                            <td className="px-1 py-1">
                              <Input
                                className={cn(
                                  "h-8 text-right tabular-nums",
                                  deltaInvalid && "border-destructive"
                                )}
                                inputMode="decimal"
                                value={rowFact[r.product_id] ?? ""}
                                onChange={(e) =>
                                  handleFactInput(r.product_id, qty, e.target.value)
                                }
                              />
                            </td>
                            <td className="px-1 py-1">
                              <Input
                                className="h-8 text-right tabular-nums"
                                inputMode="decimal"
                                value={rowPrice[r.product_id] ?? ""}
                                onChange={(e) =>
                                  setRowPrice((prev) => ({
                                    ...prev,
                                    [r.product_id]: e.target.value
                                  }))
                                }
                              />
                            </td>
                            <td className="px-2 py-1.5 text-right tabular-nums">
                              {sum != null && sum !== 0
                                ? formatNumberGrouped(sum, { maxFractionDigits: 2 })
                                : "—"}
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              )}

              {workspaceRows.length > 0 && !workspaceLoading && !workspaceIsError && wWarehouseId && selectedCategoryId != null ? (
                <div className="bg-muted/40 border-border/60 flex flex-wrap items-center justify-end gap-x-6 gap-y-1 rounded-md border px-3 py-2 text-sm">
                  <span className="text-muted-foreground">
                    Строк с изменением:{" "}
                    <strong className="text-foreground">{workspaceTotals.linesTouched}</strong>
                  </span>
                  <span className="text-muted-foreground">
                    Σ Δ:{" "}
                    <strong
                      className={cn(
                        "tabular-nums text-foreground",
                        workspaceTotals.sumDelta < 0 && "text-destructive",
                        workspaceTotals.sumDelta > 0 && "text-emerald-700 dark:text-emerald-400"
                      )}
                    >
                      {formatNumberGrouped(workspaceTotals.sumDelta, { maxFractionDigits: 3 })}
                    </strong>
                  </span>
                  <span className="text-muted-foreground">
                    Σ сумма:{" "}
                    <strong className="tabular-nums text-foreground">
                      {formatNumberGrouped(workspaceTotals.sumAmount, { maxFractionDigits: 2 })}
                    </strong>
                  </span>
                </div>
              ) : null}
              </div>

              <div className="border-border/60 bg-muted/15 flex flex-wrap items-end justify-end gap-3 border-t px-3 py-4">
                <div className="space-y-1.5">
                  <Label>Дата / время</Label>
                  <Input
                    type="datetime-local"
                    className="w-auto"
                    value={occurredAtLocal}
                    onChange={(e) => setOccurredAtLocal(e.target.value)}
                  />
                </div>
                <div className="min-w-[12rem] flex-1 space-y-1.5">
                  <Label>Комментарий</Label>
                  <Input
                    value={wComment}
                    onChange={(e) => setWComment(e.target.value)}
                    maxLength={2000}
                  />
                </div>
                <Button
                  type="button"
                  className="min-w-[8rem] bg-teal-600 text-white hover:bg-teal-700 dark:bg-teal-600 dark:hover:bg-teal-500"
                  disabled={
                    bulkMutation.isPending ||
                    !wWarehouseId ||
                    selectedCategoryId == null ||
                    selectedCategoryId <= 0 ||
                    workspaceLoading ||
                    workspaceFetching
                  }
                  onClick={handleSaveBulk}
                >
                  {bulkMutation.isPending ? "…" : "Сохранить"}
                </Button>
              </div>
              {wError ? (
                <p className="text-destructive px-3 pb-3 text-sm">{wError}</p>
              ) : null}
            </div>
          </div>
        </div>
      )}
    </PageShell>
  );
}

"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useVirtualizer } from "@tanstack/react-virtual";
import { type TableSortDir } from "@/components/ui/table-sort-button";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

interface AccessTableProps {
  items: Array<{
    id: number;
    code: string | null;
    full_name: string;
    login: string;
    role: string;
    position: string | null;
    is_active: boolean;
  }>;
  selectedIds: Set<number>;
  onToggleSelect: (id: number) => void;
  onToggleAll: () => void;
  isAllSelected: boolean;
  isLoading: boolean;
  onUserClick: (id: number) => void;
  itemHeight?: number;
}

export function AccessTable({
  items,
  selectedIds,
  onToggleSelect,
  onToggleAll,
  isAllSelected,
  isLoading,
  onUserClick,
  itemHeight = 40
}: AccessTableProps) {
  const parentRef = useRef<HTMLDivElement>(null);

  const rowVirtualizer = useVirtualizer({
    count: items.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => itemHeight,
    overscan: 10
  });

  const virtualItems = rowVirtualizer.getVirtualItems();

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-8">
        <p className="text-sm text-muted-foreground">Загрузка данных…</p>
      </div>
    );
  }

  if (items.length === 0) {
    return (
      <div className="flex items-center justify-center py-8">
        <p className="text-sm text-muted-foreground">Нет данных для отображения.</p>
      </div>
    );
  }

  return (
    <div ref={parentRef} className="flex-1 overflow-auto">
      <table className="w-full border-collapse">
        <thead className="sticky top-0 z-10 bg-background">
          <tr className="border-b border-border">
            <th className="w-12 px-2 py-2 text-center">
              <input
                type="checkbox"
                checked={isAllSelected}
                onChange={() => onToggleAll()}
                className="h-4 w-4 accent-teal-700"
              />
            </th>
            <th className="min-w-0 px-2 py-2 text-left text-xs font-medium text-muted-foreground">Пользователь</th>
            <th className="w-20 px-2 py-2 text-left text-xs font-medium text-muted-foreground">Роль</th>
            <th className="w-32 px-2 py-2 text-left text-xs font-medium text-muted-foreground">Должность</th>
            <th className="w-24 px-2 py-2 text-center text-xs font-medium text-muted-foreground">Статус</th>
            <th className="w-20 px-2 py-2 text-center text-xs font-medium text-muted-foreground">Действия</th>
          </tr>
        </thead>
        <tbody>
          {virtualItems.map((virtualRow) => {
            const item = items[virtualRow.index];
            if (!item) return null;
            const isSelected = selectedIds.has(item.id);
            return (
              <tr
                key={virtualRow.key}
                className={cn("border-b border-border/50 cursor-pointer", isSelected && "bg-teal-500/10")}
                data-index={virtualRow.index}
                style={{ height: virtualRow.size }}
                onClick={() => onUserClick(item.id)}
              >
                <td className="px-2 py-1.5 text-center" onClick={(e) => e.stopPropagation()}>
                  <input
                    type="checkbox"
                    checked={isSelected}
                    onChange={() => onToggleSelect(item.id)}
                    className="h-4 w-4 accent-teal-700"
                  />
                </td>
                <td className="min-w-0 px-2 py-1.5">
                  <span className="text-sm">
                    {item.code ? `[${item.code}] ` : ""}
                    {item.full_name || item.login}
                  </span>
                </td>
                <td className="px-2 py-1.5 text-xs">{item.role}</td>
                <td className="px-2 py-1.5 text-xs text-muted-foreground truncate">{item.position || "—"}</td>
                <td className="px-2 py-1.5 text-center">
                  <span
                    className={cn(
                      "inline-block rounded-md px-1.5 py-0.5 text-[10px] font-medium",
                      item.is_active ? "bg-emerald-600/15 text-emerald-800" : "bg-muted text-muted-foreground"
                    )}
                  >
                    {item.is_active ? "Активный" : "Неактивный"}
                  </span>
                </td>
                <td className="px-2 py-1.5 text-center" onClick={(e) => e.stopPropagation()}>
                  <Button size="sm" variant="ghost" className="h-6 px-1 text-xs">
                    →
                  </Button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

