                                <tr aria-hidden>
                                  <td
                                    colSpan={6}
                                    style={{ height: scopeDimPadTop, padding: 0, border: "none", lineHeight: 0 }}
                                  />
                                </tr>
                              ) : null}
                              {scopeDimVirtualItems.map((vi) => {
                                const u = displayCashUsers[vi.index];
