export function BonusRuleTemplateCheckbox({
  checked,
  muted = false,
  disabled,
  onChange,
  label,
  id
}: {
  checked: boolean;
  muted?: boolean;
  disabled?: boolean;
  onChange?: (checked: boolean) => void;
  label?: ReactNode;
  id?: string;
}) {
  const box = (
    <span
      className={cn(
        "grid h-5 w-5 shrink-0 place-items-center rounded-[5px] border text-white transition",
        checked
          ? "border-teal-600 bg-teal-600 dark:border-teal-500 dark:bg-teal-500"
          : muted
            ? "border-muted bg-muted/50"
            : "border-border bg-muted/30"
      )}
    >
      {checked ? (
        <svg className="h-3.5 w-3.5" viewBox="0 0 16 16" fill="none" aria-hidden>
          <path
            d="m3.5 8 3 3 6-6.5"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      ) : null}
    </span>
  );

  if (!onChange) return box;

  return (
    <label
      className={cn(
        "flex cursor-pointer items-center gap-2.5 text-sm",
        muted && !checked ? "text-muted-foreground/70" : "text-foreground/90",
        disabled && "cursor-not-allowed opacity-60"
      )}
    >
      <input
        id={id}
        type="checkbox"
        className="sr-only"
        checked={checked}
        disabled={disabled}
        onChange={(e) => onChange(e.target.checked)}
      />
      {box}
      {label ? <span>{label}</span> : null}
    </label>
  );
}

