}

const DEFAULT_HIDDEN = ["priority", "summary", "active"] as const;

export function BonusRulesListView({ activeOnly, variant = "bonuses" }: Props) {
  const isDiscounts = variant === "discounts";
  const listBase = isDiscounts ? "/settings/discount-rules" : "/settings/bonus-rules";
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const authHydrated = useAuthStoreHydrated();
  const qc = useQueryClient();
  const router = useRouter();
  const [page, setPage] = useState(1);
  const [columnDialogOpen, setColumnDialogOpen] = useState(false);
  const [searchInput, setSearchInput] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const [methodFilter, setMethodFilter] = useState<"all" | "auto" | "manual">("all");
  const [termFilter, setTermFilter] = useState<"all" | "expired" | "current" | "upcoming">("all");
  const [ruleIdFilter, setRuleIdFilter] = useState<"all" | string>("all");
  const [filtersVisible, setFiltersVisible] = useState(true);
  const [selectedIds, setSelectedIds] = useState<Set<number>>(new Set());
  const [focusedRowId, setFocusedRowId] = useState<number | null>(null);
  const [scopeRule, setScopeRule] = useState<BonusRuleRow | null>(null);

  const listColumns = useMemo(() => listColumnsForVariant(variant), [variant]);

  const bonusTableId = isDiscounts
    ? activeOnly
      ? "discount_rules.list.active.v3"
      : "discount_rules.list.inactive.v3"
    : activeOnly
      ? "bonus_rules.list.active.v4"
      : "bonus_rules.list.inactive.v4";
  const tablePrefs = useUserTablePrefs({
    tenantSlug,
    tableId: bonusTableId,
    defaultColumnOrder: listColumns.map((c) => c.id),
    defaultPageSize: 10,
    allowedPageSizes: [10, 25, 50, 100],
    defaultHiddenColumnIds: [...DEFAULT_HIDDEN]
  });

  const allowedColumnIds = useMemo(
    () => new Set<string>(listColumns.map((c) => c.id)),
    [listColumns]
  );
  const visibleDataColumns = useMemo(
    () => tablePrefs.visibleColumnOrder.filter((id) => allowedColumnIds.has(id)),
    [tablePrefs.visibleColumnOrder, allowedColumnIds]
  );

  useEffect(() => {
    const t = window.setTimeout(() => setDebouncedSearch(searchInput.trim()), 300);
    return () => window.clearTimeout(t);
  }, [searchInput]);

  useEffect(() => {
    setPage(1);
  }, [debouncedSearch, methodFilter, termFilter, ruleIdFilter, activeOnly, tablePrefs.pageSize, variant]);

  useEffect(() => {
    setRuleIdFilter("all");
  }, [variant]);

  const filterKey = activeOnly ? "active" : "inactive";

  const listParams = useMemo(() => {
    const params = new URLSearchParams({
      page: String(page),
      limit: String(tablePrefs.pageSize),
      is_active: activeOnly ? "true" : "false"
    });
    if (debouncedSearch) params.set("search", debouncedSearch);
    if (methodFilter === "auto") params.set("manual", "false");
    if (methodFilter === "manual") params.set("manual", "true");
    if (isDiscounts) {
      params.set("types", "sum,discount");
    } else {
      params.set("types", "qty");
    }
    if (termFilter === "expired") params.set("term", "expired");
    if (termFilter === "current") params.set("term", "current");
    if (termFilter === "upcoming") params.set("term", "upcoming");
    if (ruleIdFilter !== "all") params.set("rule_id", ruleIdFilter);
    return params.toString();
  }, [
    page,
    tablePrefs.pageSize,
    activeOnly,
    debouncedSearch,
    methodFilter,
    termFilter,
    ruleIdFilter,
    isDiscounts
  ]);

  const { data, isLoading, isError, error, isFetching, refetch } = useQuery({
    queryKey: ["bonus-rules", tenantSlug, variant, filterKey, listParams],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    placeholderData: keepPreviousData,
    queryFn: async () => {
      const { data: body } = await api.get<ListResponse>(`/api/${tenantSlug}/bonus-rules?${listParams}`);
      return body;
    }
  });

  const toggleMut = useMutation({
    mutationFn: async ({ id, is_active }: { id: number; is_active: boolean }) => {
      await api.patch(`/api/${tenantSlug}/bonus-rules/${id}/active`, { is_active });
    },
    onSuccess: async () => {
      await qc.invalidateQueries({ queryKey: ["bonus-rules", tenantSlug] });
    }
  });

  const shartOptionsParams = useMemo(() => {
    const p = new URLSearchParams({
      page: "1",
      limit: "500",
      is_active: activeOnly ? "true" : "false"
    });
    if (isDiscounts) p.set("types", "sum,discount");
    else p.set("types", "qty");
    return p.toString();
  }, [activeOnly, isDiscounts]);

  const { data: shartOptionsRows } = useQuery({
    queryKey: ["bonus-rules", tenantSlug, variant, filterKey, "shart-options", shartOptionsParams],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    queryFn: async () => {
      const { data: body } = await api.get<ListResponse>(`/api/${tenantSlug}/bonus-rules?${shartOptionsParams}`);
      return body.data;
    }
  });

  const shartOptionsSorted = useMemo(() => {
    const list = shartOptionsRows ?? [];
    return [...list].sort((a, b) => a.name.localeCompare(b.name, "ru"));
  }, [shartOptionsRows]);

  const rows = data?.data ?? [];

  const allOnPageSelected = rows.length > 0 && rows.every((r) => selectedIds.has(r.id));

  const toggleSelectAllOnPage = useCallback(() => {
    if (allOnPageSelected) {
      setSelectedIds((prev) => {
        const next = new Set(prev);
        for (const r of rows) next.delete(r.id);
        return next;
      });
    } else {
      setSelectedIds((prev) => {
        const next = new Set(prev);
        for (const r of rows) next.add(r.id);
        return next;
      });
    }
  }, [allOnPageSelected, rows]);

  const resetListFilters = useCallback(() => {
    setMethodFilter("all");
    setTermFilter("all");
    setRuleIdFilter("all");
    setSearchInput("");
  }, []);

  const exportCsv = useCallback(() => {
    if (!rows.length) return;
    const sep = ";";
    const headers = isDiscounts
      ? [
          "Название",
          "Тип скидки",
          "Значение (% или мин. сумма)",
          "Только ассортимент",
          "Один раз на клиента",
          "Действует с",
          "Действует до",
          "Метод",
          "Срок"
        ]
      : [
          "Название",
          "Тип бонуса",
          "Только ассортимент",
          "Один раз на клиента",
          "Действует с",
          "Действует до",
          "Метод",
          "Срок"
        ];
    const lines = rows.map((r) => {
      const tk = termKind(r);
      const termLabel = tk === "expired" ? "Истёк" : tk === "upcoming" ? "Ожидается" : "Действует";
      const skidkaValue =
        r.type === "discount"
          ? String(r.discount_pct ?? "—")
          : r.type === "sum"
            ? String(r.min_sum ?? "—")
            : "—";
      const base = [
        `"${r.name.replace(/"/g, '""')}"`,
        ...(isDiscounts
          ? [skidkaTypeLabel(r.type, r.discount_pct), skidkaValue]
          : [bonusTypeLabel(r.type)]),
        onlyByAssortment(r) ? "Да" : "Нет",
        r.once_per_client ? "Да" : "Нет",
        formatRuleDateTime(r.valid_from),
        formatRuleDateTime(r.valid_to),
        r.is_manual ? "Вручную" : "Авто",
        termLabel
      ];
      return base.join(sep);
    });
    const blob = new Blob(["\uFEFF" + [headers.join(sep), ...lines].join("\n")], {
      type: "text/csv;charset=utf-8"
    });
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = `${isDiscounts ? "skidki" : "bonusy"}-${filterKey}-${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(a.href);
  }, [rows, filterKey, isDiscounts]);

  const title = isDiscounts
    ? activeOnly
      ? "Скидки (активные)"
      : "Скидки (неактивные)"
    : activeOnly
      ? "Бонусы (активные)"
      : "Бонусы (неактивные)";

  return (
    <PageShell>
      <div className="mb-4 flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
        <div>
          <h1 className="text-xl font-semibold tracking-tight">{title}</h1>
          <p className="text-sm text-muted-foreground">
            {tenantSlug
              ? isDiscounts
                ? `Тенант: ${tenantSlug} · процентные скидки и мин. сумма (подарок); бонусы по штукам — отдельно`
                : `Тенант: ${tenantSlug} · только бонусы по количеству; сумма/скидка — в другом разделе`
              : isDiscounts
                ? "Правила: процент и минимальная сумма"
                : "Только бонусы по количеству"}
          </p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          {!isDiscounts ? (
            <>
              <Button type="button" variant="outline" size="sm" disabled title="Скоро">
                Категория бонуса
              </Button>
              <Button type="button" variant="outline" size="sm" disabled title="Скоро">
                Продлить бонусы
              </Button>
            </>
          ) : null}
          <Link className={cn(buttonVariants({ size: "sm" }))} href={`${listBase}/new`}>
            {isDiscounts ? "Создать скидку" : "Создать бонус"}
          </Link>
        </div>
      </div>

      <TableColumnSettingsDialog
        open={columnDialogOpen}
        onOpenChange={setColumnDialogOpen}
        title="Настройка столбцов"
        description={
          isDiscounts
            ? "Таблица скидок: видимые столбцы и порядок (отдельно от таблицы бонусов)."
            : "Таблица бонусов: видимые столбцы и порядок (отдельно от таблицы скидок)."
        }
        columns={[...listColumns]}
        columnOrder={tablePrefs.columnOrder}
        hiddenColumnIds={tablePrefs.hiddenColumnIds}
        saving={tablePrefs.saving}
        onSave={(next) => tablePrefs.saveColumnLayout(next)}
        onReset={() => tablePrefs.resetColumnLayout()}
      />

      {tenantSlug ? (
        <div className="orders-hub-section orders-hub-section--filters orders-hub-section--stack-tight mb-3">
          <Card className="rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
            <CardContent className="space-y-2 p-4 sm:p-5">
              <div className="flex flex-wrap items-center justify-between gap-2">
                <p className="text-xs font-semibold uppercase tracking-wide text-foreground/80">
                  {isDiscounts ? "Фильтр (скидки)" : "Фильтр (бонусы)"}
                </p>
                <div className="flex shrink-0 items-center gap-1">
                  <Button
                    type="button"
                    variant="outline"
                    size="icon"
                    className="h-9 w-9 border-teal-600/40 text-teal-700 hover:bg-teal-50 dark:hover:bg-teal-950/40"
                    title={filtersVisible ? "Скрыть фильтры" : "Показать фильтры"}
                    aria-expanded={filtersVisible}
                    onClick={() => setFiltersVisible((v) => !v)}
                  >
                    {filtersVisible ? <ChevronUp className="size-4" /> : <ChevronDown className="size-4" />}
                  </Button>
                  <Button
                    type="button"
                    variant="outline"
                    size="icon"
                    className="h-9 w-9 border-teal-600/40 text-teal-700 hover:bg-teal-50 dark:hover:bg-teal-950/40"
                    title="Сбросить фильтры"
                    onClick={resetListFilters}
                  >
                    <RotateCcw className="size-4" />
                  </Button>
                </div>
              </div>
              {filtersVisible ? (
                <div className="flex flex-wrap items-end gap-x-3 gap-y-3">
                  <div className="grid min-w-[9.5rem] max-w-[220px] flex-[1_1_9.5rem] gap-1.5">
                    <Label className="text-xs font-medium text-foreground/88">Способ применения</Label>
                    <select
                      className="flex h-9 w-full rounded-md border border-input bg-background px-2 text-sm text-foreground"
                      aria-label="Способ применения"
                      value={methodFilter}
                      onChange={(e) => setMethodFilter(e.target.value as typeof methodFilter)}
                    >
                      <option value="all">Все</option>
                      <option value="auto">Авто</option>
                      <option value="manual">Вручную</option>
                    </select>
                  </div>
                  <div className="grid min-w-[9.5rem] max-w-[220px] flex-[1_1_9.5rem] gap-1.5">
                    <Label className="text-xs font-medium text-foreground/88">Состояние срока</Label>
                    <select
                      className="flex h-9 w-full rounded-md border border-input bg-background px-2 text-sm text-foreground"
                      aria-label="Состояние срока"
                      value={termFilter}
                      onChange={(e) => setTermFilter(e.target.value as typeof termFilter)}
                    >
                      <option value="all">Все</option>
                      <option value="expired">Истёк срок</option>
                      <option value="current">Действует сейчас</option>
                      <option value="upcoming">Ещё не начался</option>
                    </select>
                  </div>
                  <div className="grid min-w-[12rem] max-w-[280px] flex-[1_1_12rem] gap-1.5">
                    <Label className="text-xs font-medium text-foreground/88">
                      {isDiscounts ? "Правило скидки" : "Правило бонуса"}
                    </Label>
                    <select
                      className="flex h-9 w-full rounded-md border border-input bg-background px-2 text-sm text-foreground"
                      aria-label={isDiscounts ? "Фильтр по правилу скидки" : "Фильтр по правилу бонуса"}
                      value={ruleIdFilter}
                      onChange={(e) => setRuleIdFilter(e.target.value === "all" ? "all" : e.target.value)}
                    >
                      <option value="all">{isDiscounts ? "Все скидки" : "Все бонусы"}</option>
                      {shartOptionsSorted.map((r) => (
                        <option key={r.id} value={String(r.id)}>
                          {r.name}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
              ) : null}
            </CardContent>
          </Card>
        </div>
      ) : null}

      {!authHydrated ? (
        <p className="text-sm text-muted-foreground">Загрузка сессии…</p>
      ) : !tenantSlug ? (
        <p className="text-sm text-destructive">
          Тенант не найден.{" "}
          <Link className="underline underline-offset-4" href="/login">
            Войти снова
          </Link>
        </p>
      ) : (
        <div className="orders-hub-section orders-hub-section--table mt-1">
          <Card className="overflow-hidden rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
            <CardContent className="p-0">
              <div
                className="table-toolbar flex flex-wrap items-end justify-between gap-3 border-b border-border/80 bg-muted/30 px-3 py-2 sm:px-4"
                role="toolbar"
                aria-label={
                  isDiscounts ? "Таблица скидок: строки и поиск" : "Таблица бонусов: строки и поиск"
                }
              >
                <div className="flex flex-wrap items-end gap-2">
                  <div className="grid gap-0.5">
                    <Label className="sr-only">Число строк на странице</Label>
                    <select
                      className="h-9 rounded-md border border-input bg-background px-2 text-sm text-foreground"
                      aria-label="Строк на странице"
                      value={String(tablePrefs.pageSize)}
                      onChange={(e) => tablePrefs.setPageSize(Number(e.target.value))}
                    >
                      {[10, 25, 50, 100].map((n) => (
                        <option key={n} value={String(n)}>
                          {n}
                        </option>
                      ))}
                    </select>
                  </div>
                  <Button
                    type="button"
                    variant="outline"
                    size="icon"
                    className="h-9 w-9 shrink-0"
                    title="Настройка столбцов"
                    onClick={() => setColumnDialogOpen(true)}
                  >
                    <LayoutGrid className="size-4" />
                  </Button>
                  <div className="relative min-w-[180px] max-w-xs flex-1">
                    <Search className="pointer-events-none absolute left-2.5 top-1/2 size-4 -translate-y-1/2 text-muted-foreground" />
                    <Input
                      className="h-9 bg-background pl-8 text-sm"
                      placeholder={isDiscounts ? "Название скидки…" : "Название бонуса…"}
                      value={searchInput}
                      onChange={(e) => setSearchInput(e.target.value)}
                      aria-label={isDiscounts ? "Поиск по названию скидки" : "Поиск по названию бонуса"}
                    />
                  </div>
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    className="h-9 shrink-0 gap-1"
                    onClick={() => exportCsv()}
                    disabled={!rows.length}
                  >
                    <Download className="size-3.5" />
                    Excel
                  </Button>
                  <Button
                    type="button"
                    variant="outline"
                    size="icon"
                    className="h-9 w-9 shrink-0"
                    title="Обновить"
                    onClick={() => void refetch()}
                    disabled={isFetching}
                  >
                    <RefreshCw className={cn("size-4", isFetching && "animate-spin")} />
                  </Button>
                </div>
                <div className="flex flex-wrap items-center gap-2 pb-0.5 text-xs text-muted-foreground sm:pb-0">
                  {data != null ? (
                    <>
                      Всего:{" "}
                      <span className="font-medium text-foreground">{data.total}</span>
                    </>
                  ) : null}
                </div>
              </div>

              {isLoading ? (
                <p className="px-4 py-6 text-sm text-muted-foreground">Загрузка…</p>
              ) : isError ? (
                <p className="px-4 py-6 text-sm text-destructive">
                  Ошибка: {getUserFacingError(error, "Не удалось связаться с API")}
                </p>
              ) : (
            <div className="overflow-x-auto rounded-lg border border-border/60 bg-card shadow-sm">
              <table className="w-full min-w-[1100px] text-left text-sm">
                <thead className="app-table-thead">
                  <tr>
                    <th className="w-10 px-2 py-2">
                      <input
                        type="checkbox"
                        className="rounded border-input"
                        checked={allOnPageSelected}
                        onChange={toggleSelectAllOnPage}
                        aria-label="Выбрать все на странице"
                      />
                    </th>
                    {visibleDataColumns.map((colId) => {
                      const meta = listColumns.find((c) => c.id === colId);
                      return (
                        <th key={colId} className="px-3 py-2 font-medium">
                          {meta?.label ?? colId}
                        </th>
                      );
                    })}
                    <th className="px-3 py-2 text-right font-medium">Действия</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.length === 0 ? (
                    <tr>
                      <td
                        colSpan={visibleDataColumns.length + 2}
                        className="px-3 py-8 text-center text-muted-foreground"
                      >
                        {activeOnly
                          ? isDiscounts
                            ? "Нет правил скидок"
                            : "Нет правил бонусов"
                          : isDiscounts
                            ? "Нет неактивных скидок"
                            : "Нет неактивных бонусов"}
                      </td>
                    </tr>
                  ) : (
                    rows.map((row) => {
                      const tk = termKind(row);
                      return (
                        <tr
                          key={row.id}
                          className={cn(
                            "border-b last:border-0",
                            focusedRowId === row.id && "bg-primary/5"
                          )}
                          onClick={() => setFocusedRowId(row.id)}
                        >
                          <td className="px-2 py-2" onClick={(e) => e.stopPropagation()}>
                            <input
                              type="checkbox"
                              className="rounded border-input"
                              checked={selectedIds.has(row.id)}
                              onChange={() => {
                                setSelectedIds((prev) => {
                                  const next = new Set(prev);
                                  if (next.has(row.id)) next.delete(row.id);
                                  else next.add(row.id);
                                  return next;
                                });
                              }}
                              aria-label={`Выбрать: ${row.name}`}
                            />
                          </td>
                          {visibleDataColumns.map((colId) => (
                            <td key={colId} className="px-3 py-2 align-middle">
                              {colId === "name" ? (
                                <span className="font-medium">{row.name}</span>
                              ) : colId === "type" ? (
                                <span className="text-muted-foreground">
                                  {isDiscounts ? skidkaTypeLabel(row.type, row.discount_pct) : bonusTypeLabel(row.type)}
                                </span>
                              ) : colId === "linked" ? (
                                tenantSlug ? (
                                  <div className="min-w-0" onClick={(e) => e.stopPropagation()}>
                                    <BonusRuleLinkedBonusesCell tenantSlug={tenantSlug} row={row} />
                                  </div>
                                ) : null
                              ) : colId === "only_assortment" ? (
                                <span>{onlyByAssortment(row) ? "Да" : "Нет"}</span>
                              ) : colId === "once_per_client" ? (
                                <span>{row.once_per_client ? "Да" : "Нет"}</span>
                              ) : colId === "valid_from" ? (
                                formatRuleDateTime(row.valid_from)
                              ) : colId === "valid_to" ? (
                                formatRuleDateTime(row.valid_to)
                              ) : colId === "method" ? (
                                row.is_manual ? (
                                  <Badge variant="warning">Вручную</Badge>
                                ) : (
                                  <Badge variant="success">Авто</Badge>
                                )
                              ) : colId === "term" ? (
                                termBadge(tk)
                              ) : colId === "priority" ? (
                                row.priority
                              ) : colId === "summary" ? (
                                <span className="font-mono text-xs">{ruleSummary(row)}</span>
                              ) : colId === "active" ? (
                                <input
                                  type="checkbox"
                                  checked={row.is_active}
                                  disabled={toggleMut.isPending}
                                  onChange={(e) => {
                                    e.stopPropagation();
                                    toggleMut.mutate({ id: row.id, is_active: e.target.checked });
                                  }}
                                  aria-label={`Активность: ${row.name}`}
                                />
                              ) : null}
                            </td>
                          ))}
                          <td className="px-3 py-2 text-right" onClick={(e) => e.stopPropagation()}>
                            <TableRowActionGroup className="justify-end" ariaLabel="Правило">
                              {!activeOnly ? (
                                <Button
                                  type="button"
                                  size="icon-sm"
                                  variant="ghost"
                                  className="text-emerald-600 hover:bg-emerald-500/10 hover:text-emerald-700"
                                  title="Активировать"
                                  aria-label="Активировать"
                                  disabled={toggleMut.isPending}
                                  onClick={() => toggleMut.mutate({ id: row.id, is_active: true })}
                                >
                                  <Power className="size-3.5" />
                                </Button>
                              ) : null}
                              <Button
                                type="button"
                                size="icon-sm"
                                variant="ghost"
                                className="text-muted-foreground hover:text-foreground"
                                title="Копировать в форму «Новое правило»"
                                aria-label="Копировать в форму нового правила"
                                disabled={!tenantSlug}
                                onClick={() => {
                                  if (!tenantSlug) return;
                                  writeBonusRuleCloneDraft(isDiscounts ? "discount" : "bonus", row);
                                  router.push(`${listBase}/new`);
                                }}
                              >
                                <Copy className="size-3.5" />
                              </Button>
                              <Button
                                type="button"
                                size="icon-sm"
                                variant="ghost"
                                className="text-muted-foreground hover:text-foreground"
                                title="Филиал, агенты, клиенты, направление"
                                aria-label="Привязка к заказу"
                                onClick={() => setScopeRule(row)}
                              >
                                <UserRound className="size-3.5" />
                              </Button>
                              <Link
                                href={`${listBase}/${row.id}/edit`}
                                className={cn(
                                  buttonVariants({ variant: "outline", size: "icon-sm" }),
                                  "text-muted-foreground hover:text-foreground"
                                )}
                                title="Редактировать"
                                aria-label="Редактировать"
                              >
                                <Pencil className="size-3.5" />
                              </Link>
                            </TableRowActionGroup>
                          </td>
                        </tr>
                      );
                    })
                  )}
                </tbody>
              </table>
            </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {tenantSlug ? (
        <BonusRuleOrderScopeDialog
          open={scopeRule != null}
          onOpenChange={(o) => {
            if (!o) setScopeRule(null);
          }}
          tenantSlug={tenantSlug}
          rule={scopeRule}
        />
      ) : null}

      {data && data.total > data.limit ? (
        <div className="mt-3 flex items-center gap-2">
          <Button
            type="button"
            variant="outline"
            size="sm"
            disabled={page <= 1}
            onClick={() => setPage((p) => p - 1)}
          >
            Назад
          </Button>
          <span className="text-sm text-muted-foreground">
            {page} / {Math.ceil(data.total / data.limit) || 1}
          </span>
          <Button
            type="button"
            variant="outline"
            size="sm"
            disabled={page * data.limit >= data.total}
            onClick={() => setPage((p) => p + 1)}
          >
            Вперёд
          </Button>
        </div>
      ) : null}
    </PageShell>
  );
}

"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { api } from "@/lib/api";
import { firstMessagePerField, firstValidationUserHint, getZodFlattenFromApiErrorBody } from "@/lib/api-validation-details";
import { getUserFacingError, withApiSupportLine } from "@/lib/error-utils";
import { formatGroupedInteger } from "@/lib/format-numbers";
import { STALE } from "@/lib/query-stale";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { TableSearchField } from "@/components/ui/table-search-field";
import { DEFAULT_TABLE_PAGE_SIZES } from "@/lib/table-page-sizes";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog";
import { cn } from "@/lib/utils";
import { downloadXlsxSheet } from "@/lib/download-xlsx";
import { TableColumnSettingsDialog } from "@/components/data-table/table-column-settings-dialog";
import { useUserTablePrefs } from "@/hooks/use-user-table-prefs";
import {
  RoleLinkPickerGrid,
  cloneRoleSets,
  emptySetsForRoles,
  linksFromRoleSets,
  setsFromRoleLinks,
  type RolePickerColumn
} from "@/components/role-link-picker/role-link-picker-grid";
import { ClipboardList, Clock, MapPin, Pencil, RefreshCw, Search, X } from "lucide-react";
import { isAxiosError } from "axios";

const CASH_DESK_TABLE_ID = "cash_desks.v1";

const COLUMN_IDS = [
  "closing",
  "name",
  "branch_name",
  "created_at",
  "roles",
  "user_total",
  "sort_order",
  "code",
  "location",
  "comment"
] as const;

const COLUMN_META = COLUMN_IDS.map((id) => ({
  id,
  label:
    {
      closing: "Статус закрытия",
      name: "Названия",
      branch_name: "Филиал",
      created_at: "Дата создания",
      roles: "Пользователи по ролям",
      user_total: "Всего пользователей",
      sort_order: "Сортировка",
      code: "Код",
      location: "Локация",
      comment: "Комментарий"
    }[id] ?? id
}));

const ROLE_LABELS: Record<string, string> = {
  agent: "Агент",
  cashier: "Кассир",
  manager: "Менеджер",
  operator: "Оператор",
  storekeeper: "Склад",
  supervisor: "Супервайзер",
  expeditor: "Экспедитор"
};

const CASH_ROLE_ORDER = [
  "agent",
  "cashier",
  "manager",
  "operator",
  "storekeeper",
  "supervisor",
  "expeditor"
] as const;

const CASH_ROLE_KEYS = [...CASH_ROLE_ORDER];

const CASH_ROLE_COLUMNS: RolePickerColumn[] = [
  { role: "agent", label: ROLE_LABELS.agent, pool: "agents" },
  { role: "cashier", label: ROLE_LABELS.cashier, pool: "operators" },
  { role: "manager", label: ROLE_LABELS.manager, pool: "operators" },
  { role: "operator", label: ROLE_LABELS.operator, pool: "operators" },
  { role: "storekeeper", label: ROLE_LABELS.storekeeper, pool: "operators" },
  { role: "supervisor", label: ROLE_LABELS.supervisor, pool: "supervisors" },
  { role: "expeditor", label: ROLE_LABELS.expeditor, pool: "expeditors" }
];

const TIMEZONES = [
  { value: "Asia/Tashkent", label: "Asia/Tashkent (+05:00)" },
  { value: "Asia/Samarkand", label: "Asia/Samarkand (+05:00)" },
  { value: "Europe/Moscow", label: "Europe/Moscow (+03:00)" },
  { value: "UTC", label: "UTC" }
];

type PickerUser = { id: number; name: string; login: string };

type CashDeskRow = {
  id: number;
  name: string;
  branch_name?: string | null;
  timezone: string;
  sort_order: number | null;
  code: string | null;
  comment: string | null;
  latitude: string | null;
  longitude: string | null;
  is_active: boolean;
  is_closed: boolean;
  accepts_client_payments?: boolean;
  accepts_discount_payments?: boolean;
  created_at: string;
  user_total: number;
  breakdown: { role: string; count: number }[];
  links: { link_role: string; user: PickerUser }[];
};

type PickersData = {
  agents: PickerUser[];
  operators: PickerUser[];
  supervisors: PickerUser[];
  expeditors: PickerUser[];
};

function emptyCashLinkSets() {
  return emptySetsForRoles(CASH_ROLE_KEYS);
}

type Props = { tenantSlug: string; canWrite: boolean };

export function CashDesksWorkspace({ tenantSlug, canWrite }: Props) {
  const qc = useQueryClient();
  const [tab, setTab] = useState<"active" | "inactive">("active");
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const [columnOpen, setColumnOpen] = useState(false);
  const [formOpen, setFormOpen] = useState(false);
  const [editing, setEditing] = useState<CashDeskRow | null>(null);
  const [shiftDesk, setShiftDesk] = useState<CashDeskRow | null>(null);
  const tablePrefs = useUserTablePrefs({
    tenantSlug,
    tableId: CASH_DESK_TABLE_ID,
    defaultColumnOrder: [...COLUMN_IDS],
    defaultPageSize: 10,
    allowedPageSizes: DEFAULT_TABLE_PAGE_SIZES
  });
  const limit = tablePrefs.pageSize;

  useEffect(() => {
    setPage(1);
  }, [tab, search, limit]);

  const listQ = useQuery({
    queryKey: ["cash-desks", tenantSlug, tab, page, limit, search],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    queryFn: async () => {
      const params = new URLSearchParams();
      params.set("is_active", tab === "active" ? "true" : "false");
      params.set("page", String(page));
      params.set("limit", String(limit));
      if (search) params.set("q", search);
      const { data } = await api.get<{
        data: CashDeskRow[];
        total: number;
        page: number;
        limit: number;
      }>(`/api/${tenantSlug}/cash-desks?${params.toString()}`);
      return data;
    }
  });

  const pickersQ = useQuery({
    queryKey: ["cash-desks-pickers", tenantSlug],
    enabled: Boolean(tenantSlug) && (formOpen || editing != null),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: PickersData }>(`/api/${tenantSlug}/cash-desks/pickers`);
      return data.data;
    }
  });

  const patchMut = useMutation({
    mutationFn: async (vars: { id: number; body: Record<string, unknown> }) => {
      await api.patch(`/api/${tenantSlug}/cash-desks/${vars.id}`, vars.body);
    },
    onSuccess: async () => {
      await qc.invalidateQueries({ queryKey: ["cash-desks", tenantSlug] });
    }
  });

  const rows = listQ.data?.data ?? [];
  const total = listQ.data?.total ?? 0;
  const from = total === 0 ? 0 : (page - 1) * limit + 1;
  const to = Math.min(page * limit, total);
  const totalPages = Math.max(1, Math.ceil(total / limit));

  const exportRows = useCallback(() => {
    const headers = COLUMN_META.filter((c) => tablePrefs.visibleColumnOrder.includes(c.id)).map((c) => c.label);
    const dataRows = rows.map((r) =>
      tablePrefs.visibleColumnOrder.map((colId) => {
        switch (colId) {
          case "closing":
            return r.is_closed ? "Закрыта" : "Открыта";
          case "name":
            return r.name;
          case "branch_name":
            return r.branch_name ?? "";
          case "created_at":
            return new Date(r.created_at).toLocaleString("ru-RU");
          case "roles":
            return r.breakdown.map((b) => `${ROLE_LABELS[b.role] ?? b.role}:${b.count}`).join("; ");
          case "user_total":
            return String(r.user_total);
          case "sort_order":
            return r.sort_order != null ? String(r.sort_order) : "";
          case "code":
            return r.code ?? "";
          case "location":
            return r.latitude && r.longitude ? `${r.latitude},${r.longitude}` : "";
          case "comment":
            return r.comment ?? "";
          default:
            return "";
        }
      })
    );
    downloadXlsxSheet(
      `kassy_${tab}_${new Date().toISOString().slice(0, 10)}.xlsx`,
      "Кассы",
      headers,
      dataRows
    );
  }, [rows, tab, tablePrefs.visibleColumnOrder]);

  return (
    <>
      <TableColumnSettingsDialog
        open={columnOpen}
        onOpenChange={setColumnOpen}
        title="Управление столбцами"
        description="Выберите видимые столбцы и порядок. Сохраняется для вашей учётной записи."
        columns={COLUMN_META}
        columnOrder={tablePrefs.columnOrder}
        hiddenColumnIds={tablePrefs.hiddenColumnIds}
        saving={tablePrefs.saving}
        onSave={(next) => tablePrefs.saveColumnLayout(next)}
        onReset={() => tablePrefs.resetColumnLayout()}
      />

      <div className="orders-hub-section orders-hub-section--table">
        <Card className="overflow-hidden rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
          <CardContent className="p-0">
            <div className="flex flex-wrap items-center justify-between gap-2 border-b border-border bg-muted/25 px-3 py-0 sm:px-4">
              <div className="flex gap-2">
                <button
                  type="button"
                  className={cn(
                    "-mb-px border-b-2 px-3 py-2 text-sm font-medium",
                    tab === "active" ? "border-primary text-primary" : "border-transparent text-muted-foreground"
                  )}
                  onClick={() => setTab("active")}
                >
                  Активный
                </button>
                <button
                  type="button"
                  className={cn(
                    "-mb-px border-b-2 px-3 py-2 text-sm font-medium",
                    tab === "inactive" ? "border-primary text-primary" : "border-transparent text-muted-foreground"
                  )}
                  onClick={() => setTab("inactive")}
                >
                  Не активный
                </button>
              </div>
              {canWrite ? (
                <div className="flex flex-wrap items-center gap-2 py-1">
                  <Button type="button" variant="outline" size="sm" onClick={() => setColumnOpen(true)}>
                    Столбцы
                  </Button>
                  <Button type="button" size="sm" onClick={() => setFormOpen(true)}>
                    Добавить
                  </Button>
                </div>
              ) : null}
            </div>

            <div className="table-toolbar flex flex-wrap items-end gap-2 border-b border-border/80 bg-muted/30 px-3 py-2 sm:px-4">
              <select
                className="h-9 rounded-md border border-input bg-background px-2 text-xs"
                value={limit}
                onChange={(e) => tablePrefs.setPageSize(Number.parseInt(e.target.value, 10))}
              >
                {DEFAULT_TABLE_PAGE_SIZES.map((n) => (
                  <option key={n} value={n}>
                    {n}
                  </option>
                ))}
              </select>
              <TableSearchField
                className="max-w-xs"
                onSearch={(q) => {
                  setSearch(q);
                  setPage(1);
                }}
              />
              <Button type="button" variant="outline" size="sm" className="h-9 text-xs" onClick={exportRows}>
                Excel
              </Button>
              <Button
                type="button"
                variant="ghost"
                size="icon-sm"
                className="h-9 w-9"
                onClick={() => void listQ.refetch()}
              >
                <RefreshCw className={cn("size-4", listQ.isFetching && "animate-spin")} />
              </Button>
            </div>

            <div className="overflow-x-auto">
          <table className="w-full min-w-[1100px] text-xs">
            <thead className="app-table-thead">
              <tr>
                {tablePrefs.visibleColumnOrder.map((colId) => {
                  const meta = COLUMN_META.find((c) => c.id === colId);
                  return (
                    <th key={colId} className="whitespace-nowrap px-2 py-2 text-left font-medium text-muted-foreground">
                      {meta?.label ?? colId}
                    </th>
                  );
                })}
                <th className="px-2 py-2 text-right font-medium text-muted-foreground"> </th>
              </tr>
            </thead>
            <tbody>
              {listQ.isLoading ? (
                <tr>
                  <td
                    colSpan={tablePrefs.visibleColumnOrder.length + 1}
                    className="px-3 py-8 text-center text-muted-foreground"
                  >
                    Загрузка…
                  </td>
                </tr>
              ) : rows.length === 0 ? (
                <tr>
                  <td
                    colSpan={tablePrefs.visibleColumnOrder.length + 1}
                    className="px-3 py-8 text-center text-muted-foreground"
                  >
                    Нет данных
                  </td>
                </tr>
              ) : (
                rows.map((r) => (
                  <tr key={r.id} className="border-t even:bg-muted/15">
                    {tablePrefs.visibleColumnOrder.map((colId) => (
                      <td key={colId} className="px-2 py-2 align-top">
                        {colId === "closing" ? (
                          <button
                            type="button"
                            className="text-left disabled:opacity-50"
                            disabled={!canWrite}
                            title={r.is_closed ? "Открыть" : "Закрыть"}
                            onClick={() =>
                              patchMut.mutate({ id: r.id, body: { is_closed: !r.is_closed } })
                            }
                          >
                            <ClipboardList
                              className={cn("size-5", r.is_closed ? "text-rose-500" : "text-emerald-600")}
                            />
                          </button>
                        ) : colId === "name" ? (
                          <span className="font-medium">{r.name}</span>
                        ) : colId === "branch_name" ? (
                          <span className="text-muted-foreground">{r.branch_name ?? "—"}</span>
                        ) : colId === "created_at" ? (
                          new Date(r.created_at).toLocaleString("ru-RU")
                        ) : colId === "roles" ? (
                          <div className="flex max-w-[14rem] flex-wrap gap-1">
                            {r.breakdown.slice(0, 3).map((b) => (
                              <span
                                key={b.role}
                                className="inline-block rounded-md bg-muted px-1.5 py-0.5 text-[10px]"
                              >
                                {ROLE_LABELS[b.role] ?? b.role} — ({formatGroupedInteger(b.count)})
                              </span>
                            ))}
                            {r.breakdown.length > 3 ? (
                              <span className="text-[10px] text-primary">ещё {r.breakdown.length - 3}</span>
                            ) : null}
                          </div>
                        ) : colId === "user_total" ? (
                          formatGroupedInteger(r.user_total)
                        ) : colId === "sort_order" ? (
                          r.sort_order ?? "—"
                        ) : colId === "code" ? (
                          r.code ?? "—"
                        ) : colId === "location" ? (
                          r.latitude && r.longitude ? (
                            <a
                              href={`https://www.openstreetmap.org/?mlat=${r.latitude}&mlon=${r.longitude}&zoom=16`}
                              target="_blank"
                              rel="noreferrer"
                              className="inline-flex text-primary"
                              title="Карта"
                            >
                              <MapPin className="size-4" />
                            </a>
                          ) : (
                            "—"
                          )
                        ) : colId === "comment" ? (
                          <span className="line-clamp-2 max-w-[12rem]">{r.comment ?? "—"}</span>
                        ) : null}
                      </td>
                    ))}
                    <td className="px-2 py-2 text-right">
                      <div className="flex justify-end gap-0.5">
                        <Button
                          type="button"
                          variant="ghost"
                          size="icon-sm"
                          title="Смены кассы"
                          onClick={() => setShiftDesk(r)}
                        >
                          <Clock className="size-4" />
                        </Button>
                        {canWrite ? (
                          <Button
                            type="button"
                            variant="ghost"
                            size="icon-sm"
                            title="Редактировать"
                            onClick={() => setEditing(r)}
                          >
                            <Pencil className="size-4" />
                          </Button>
                        ) : null}
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
            </div>

            <div className="table-content-footer flex flex-wrap items-center justify-between gap-2 border-t border-border/80 bg-muted/25 px-3 py-3 text-xs text-muted-foreground sm:px-4">
              <span>
                Показано {formatGroupedInteger(from)} - {formatGroupedInteger(to)} / {formatGroupedInteger(total)}
              </span>
              <div className="flex items-center gap-1">
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  className="h-7 px-2"
                  disabled={page <= 1}
                  onClick={() => setPage((p) => Math.max(1, p - 1))}
                >
                  ←
                </Button>
                <span className="tabular-nums">{formatGroupedInteger(page)}</span>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  className="h-7 px-2"
                  disabled={page >= totalPages}
                  onClick={() => setPage((p) => p + 1)}
                >
                  →
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <CashDeskFormDialog
        tenantSlug={tenantSlug}
        open={formOpen || editing != null}
        initial={editing}
        pickers={pickersQ.data}
        canWrite={canWrite}
        onClose={() => {
          setFormOpen(false);
          setEditing(null);
        }}
      />
      <CashDeskShiftsDialog
        tenantSlug={tenantSlug}
        desk={shiftDesk}
        canWrite={canWrite}
        onClose={() => setShiftDesk(null)}
      />
    </>
  );
}

type ShiftApiRow = {
  id: number;
  opened_at: string;
  closed_at: string | null;
  opening_float: string | null;
  closing_float: string | null;
  notes: string | null;
  opened_by: { id: number; name: string; login: string } | null;
  closed_by: { id: number; name: string; login: string } | null;
};

function CashDeskShiftsDialog({
  tenantSlug,
  desk,
  canWrite,
  onClose
}: {
  tenantSlug: string;
  desk: CashDeskRow | null;
  canWrite: boolean;
  onClose: () => void;
}) {
  const qc = useQueryClient();
  const open = Boolean(desk);
  const deskId = desk?.id;

  const listQ = useQuery({
    queryKey: ["cash-desk-shifts", tenantSlug, deskId],
    enabled: open && deskId != null,
    staleTime: STALE.list,
    queryFn: async () => {
      const { data } = await api.get<{ data: ShiftApiRow[] }>(
        `/api/${tenantSlug}/cash-desks/${deskId}/shifts?limit=40`
      );
      return data.data;
    }
  });

  const openShiftQ = useQuery({
    queryKey: ["cash-desk-shift-open", tenantSlug, deskId],
    enabled: open && deskId != null,
    staleTime: STALE.live,
    queryFn: async () => {
      const { data } = await api.get<{ data: ShiftApiRow | null }>(
        `/api/${tenantSlug}/cash-desks/${deskId}/shifts/open`
      );
      return data.data;
    }
  });

  const [openingFloat, setOpeningFloat] = useState("");
  const [closingFloat, setClosingFloat] = useState("");

  const openMut = useMutation({
    mutationFn: async () => {
      const n = openingFloat.trim() === "" ? null : Number.parseFloat(openingFloat.replace(",", "."));
      await api.post(`/api/${tenantSlug}/cash-desks/${deskId}/shifts/open`, {
        opening_float: n != null && Number.isFinite(n) ? n : null,
        notes: null
      });
    },
    onSuccess: async () => {
      setOpeningFloat("");
      await qc.invalidateQueries({ queryKey: ["cash-desk-shifts", tenantSlug, deskId] });
      await qc.invalidateQueries({ queryKey: ["cash-desk-shift-open", tenantSlug, deskId] });
      await qc.invalidateQueries({ queryKey: ["cash-desks", tenantSlug] });
    }
  });

  const closeMut = useMutation({
    mutationFn: async (shiftId: number) => {
      const n = closingFloat.trim() === "" ? null : Number.parseFloat(closingFloat.replace(",", "."));
      await api.post(`/api/${tenantSlug}/cash-desks/${deskId}/shifts/${shiftId}/close`, {
        closing_float: n != null && Number.isFinite(n) ? n : null,
        notes: null
      });
    },
    onSuccess: async () => {
      setClosingFloat("");
      await qc.invalidateQueries({ queryKey: ["cash-desk-shifts", tenantSlug, deskId] });
      await qc.invalidateQueries({ queryKey: ["cash-desk-shift-open", tenantSlug, deskId] });
      await qc.invalidateQueries({ queryKey: ["cash-desks", tenantSlug] });
    }
  });

  const active = openShiftQ.data;

  return (
    <Dialog open={open} onOpenChange={(v) => !v && onClose()}>
      <DialogContent className="max-h-[90vh] overflow-y-auto sm:max-w-lg">
        <DialogHeader>
          <DialogTitle>Смены — {desk?.name ?? ""}</DialogTitle>
        </DialogHeader>
        {active ? (
          <div className="space-y-2 rounded-md border border-emerald-500/40 bg-emerald-500/5 p-3 text-sm">
            <p className="font-medium text-emerald-700 dark:text-emerald-400">Смена открыта</p>
            <p className="text-xs text-muted-foreground">
              С {new Date(active.opened_at).toLocaleString("ru-RU")}
              {active.opened_by ? ` · ${active.opened_by.name}` : ""}
            </p>
            {canWrite ? (
              <div className="flex flex-wrap items-end gap-2 pt-2">
                <div className="space-y-1">
                  <Label className="text-xs">Остаток при закрытии</Label>
                  <Input
                    className="h-8 w-32 text-xs"
                    value={closingFloat}
                    onChange={(e) => setClosingFloat(e.target.value)}
                    placeholder="0"
                  />
                </div>
                <Button
                  type="button"
                  size="sm"
                  variant="secondary"
                  disabled={closeMut.isPending}
                  onClick={() => void closeMut.mutate(active.id)}
                >
                  Закрыть смену
                </Button>
              </div>
            ) : null}
          </div>
        ) : canWrite ? (
          <div className="space-y-2 rounded-md border p-3 text-sm">
            <p className="text-muted-foreground">Нет активной смены.</p>
            <div className="flex flex-wrap items-end gap-2">
              <div className="space-y-1">
                <Label className="text-xs">Наличные на открытии</Label>
                <Input
                  className="h-8 w-32 text-xs"
                  value={openingFloat}
                  onChange={(e) => setOpeningFloat(e.target.value)}
                  placeholder="0"
                />
              </div>
              <Button type="button" size="sm" disabled={openMut.isPending} onClick={() => void openMut.mutate()}>
                Открыть смену
              </Button>
            </div>
          </div>
        ) : (
          <p className="text-sm text-muted-foreground">Нет активной смены.</p>
        )}
        <div className="border-t pt-3">
          <p className="mb-2 text-xs font-medium text-muted-foreground">Последние смены</p>
          <ul className="max-h-48 space-y-2 overflow-y-auto text-xs">
            {(listQ.data ?? []).map((s) => (
              <li key={s.id} className="rounded border px-2 py-1.5">
                <span className="font-mono tabular-nums">{new Date(s.opened_at).toLocaleString("ru-RU")}</span>
                {s.closed_at ? (
                  <span className="text-muted-foreground">
                    {" "}
                    → {new Date(s.closed_at).toLocaleString("ru-RU")}
                  </span>
                ) : (
                  <span className="text-emerald-600"> · открыта</span>
                )}
              </li>
            ))}
          </ul>
        </div>
        <DialogFooter>
          <Button type="button" variant="outline" onClick={onClose}>
            Закрыть
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

function CashDeskFormDialog({
  tenantSlug,
  open,
  initial,
  pickers,
  canWrite,
  onClose
}: {
  tenantSlug: string;
  open: boolean;
  initial: CashDeskRow | null;
  pickers: PickersData | undefined;
  canWrite: boolean;
  onClose: () => void;
}) {
  const qc = useQueryClient();
  const [name, setName] = useState("");
  const [timezone, setTimezone] = useState("Asia/Tashkent");
  const [sortOrder, setSortOrder] = useState("");
  const [code, setCode] = useState("");
  const [comment, setComment] = useState("");
  const [lat, setLat] = useState("");
  const [lng, setLng] = useState("");
  const [active, setActive] = useState(true);
  const [cashDeskPurpose, setCashDeskPurpose] = useState<"client_payment" | "discount_payment">(
    "client_payment"
  );
  const [mapOpen, setMapOpen] = useState(false);
  const [linkSets, setLinkSets] = useState(() => emptyCashLinkSets());
  const [usersSubOpen, setUsersSubOpen] = useState(false);
  const [draftLinkSets, setDraftLinkSets] = useState(() => emptyCashLinkSets());
  const [userPickerSearch, setUserPickerSearch] = useState("");
  const [saveBanner, setSaveBanner] = useState<string | null>(null);
  const [fieldErr, setFieldErr] = useState<Record<string, string>>({});

  useEffect(() => {
    if (!open) {
      setUsersSubOpen(false);
      setSaveBanner(null);
      setFieldErr({});
      return;
    }
    if (initial) {
      setName(initial.name);
      setTimezone(initial.timezone);
      setSortOrder(initial.sort_order != null ? String(initial.sort_order) : "");
      setCode(initial.code ?? "");
      setComment(initial.comment ?? "");
      setLat(initial.latitude ?? "");
      setLng(initial.longitude ?? "");
      setActive(initial.is_active);
      setCashDeskPurpose(
        initial.accepts_discount_payments === true && initial.accepts_client_payments !== true
          ? "discount_payment"
          : "client_payment"
      );
      setMapOpen(Boolean(initial.latitude && initial.longitude));
      setLinkSets(
        setsFromRoleLinks(
          CASH_ROLE_KEYS,
          initial.links.map((l) => ({ link_role: l.link_role, user_id: l.user.id }))
        )
      );
    } else {
      setName("");
      setTimezone("Asia/Tashkent");
      setSortOrder("");
      setCode("");
      setComment("");
      setLat("");
      setLng("");
      setActive(true);
      setCashDeskPurpose("client_payment");
      setMapOpen(false);
      setLinkSets(emptyCashLinkSets());
    }
  }, [open, initial]);

  const selectedUserCount = useMemo(
    () => CASH_ROLE_KEYS.reduce((n, r) => n + (linkSets[r]?.size ?? 0), 0),
    [linkSets]
  );

  const saveMut = useMutation({
    mutationFn: async () => {
      const links = linksFromRoleSets(CASH_ROLE_KEYS, linkSets);
      const sortNum = sortOrder.trim() === "" ? null : Number.parseInt(sortOrder, 10);
      const latN = lat.trim() === "" ? null : Number.parseFloat(lat.replace(",", "."));
      const lngN = lng.trim() === "" ? null : Number.parseFloat(lng.replace(",", "."));
      const body = {
        name: name.trim(),
        timezone,
        sort_order: Number.isFinite(sortNum as number) ? sortNum : null,
        code: code.trim() || null,
        comment: comment.trim() || null,
        latitude: latN != null && Number.isFinite(latN) ? latN : null,
        longitude: lngN != null && Number.isFinite(lngN) ? lngN : null,
        is_active: active,
        accepts_client_payments: cashDeskPurpose === "client_payment",
        accepts_discount_payments: cashDeskPurpose === "discount_payment",
        links
      };
      if (initial) {
        await api.patch(`/api/${tenantSlug}/cash-desks/${initial.id}`, body);
      } else {
        await api.post(`/api/${tenantSlug}/cash-desks`, body);
      }
    },
    onMutate: () => {
      setSaveBanner(null);
      setFieldErr({});
    },
    onSuccess: async () => {
      setSaveBanner(null);
      setFieldErr({});
      await qc.invalidateQueries({ queryKey: ["cash-desks", tenantSlug] });
      onClose();
    },
    onError: (e: unknown) => {
      if (isAxiosError(e)) {
        const flat = getZodFlattenFromApiErrorBody(e.response?.data);
        if (flat) {
          setFieldErr(firstMessagePerField(flat));
          const hint = firstValidationUserHint(flat);
          setSaveBanner(
            hint
              ? withApiSupportLine(hint, e)
              : withApiSupportLine(getUserFacingError(e, "Saqlab bo‘lmadi."), e)
          );
          return;
        }
      }
      setSaveBanner(getUserFacingError(e, "Saqlab bo‘lmadi."));
    }
  });

  if (!canWrite) return null;

  return (
    <>
      <Dialog open={open} onOpenChange={(o) => !o && onClose()}>
        <DialogContent
          className={cn(
            "flex max-h-[96vh] w-full flex-col gap-0 overflow-x-hidden overflow-y-auto p-0",
            "!max-w-xl sm:!max-w-xl"
          )}
          showCloseButton
        >
          <DialogHeader className="shrink-0 border-b border-border px-5 pb-3 pt-4 pr-14 text-left">
            <DialogTitle className="text-base font-semibold">
              {initial ? "Редактировать" : "Добавить"}
            </DialogTitle>
          </DialogHeader>

          <div className="shrink-0 overflow-visible px-5 py-4">
            <div className="mx-auto grid w-full max-w-xl gap-5">
              {saveBanner ? (
                <p className="text-sm text-destructive" role="alert">
                  {saveBanner}
                </p>
              ) : null}
              <div className="grid gap-4 sm:grid-cols-2 sm:gap-x-6 sm:gap-y-0">
                <div className="grid min-w-0 gap-2">
                  <Label className="text-sm font-medium">Название *</Label>
                  <Input
                    value={name}
                    onChange={(e) => {
                      setName(e.target.value);
                      setFieldErr((p) => {
                        const n = { ...p };
                        delete n.name;
                        return n;
                      });
                    }}
                    className={cn("h-10", !name.trim() ? "border-destructive/60" : "")}
                  />
                  {fieldErr.name ? <p className="text-xs text-destructive">{fieldErr.name}</p> : null}
                </div>
                <div className="grid min-w-0 gap-2">
                  <Label className="text-sm font-medium">Часовой пояс</Label>
                  <select
                    className="flex h-10 w-full rounded-md border border-input bg-background px-3 text-sm shadow-sm"
                    value={timezone}
                    onChange={(e) => {
                      setTimezone(e.target.value);
                      setFieldErr((p) => {
                        const n = { ...p };
                        delete n.timezone;
                        return n;
                      });
                    }}
                  >
                    {TIMEZONES.map((tz) => (
                      <option key={tz.value} value={tz.value}>
                        {tz.label}
                      </option>
                    ))}
                  </select>
                  {fieldErr.timezone ? <p className="text-xs text-destructive">{fieldErr.timezone}</p> : null}
                </div>
              </div>

            <div className="rounded-lg border border-border bg-card p-4 shadow-sm sm:p-4">
              <p className="mb-2.5 text-sm text-muted-foreground">
                <span className="font-semibold text-foreground">Пользователи</span>
                {": "}
                {selectedUserCount}
              </p>
              <Button
                type="button"
                variant="outline"
                className="h-11 w-full border-2 border-teal-600/45 text-sm font-medium text-teal-800 shadow-none hover:bg-teal-50 dark:border-teal-500/50 dark:text-teal-300 dark:hover:bg-teal-950/40"
                onClick={() => {
                  setDraftLinkSets(cloneRoleSets(CASH_ROLE_KEYS, linkSets));
                  setUserPickerSearch("");
                  setUsersSubOpen(true);
                }}
              >
                Редактировать добавленных пользователей
              </Button>
            </div>
            <div className="grid gap-2">
              <Label className="text-sm font-medium">Сортировка</Label>
              <Input
                className="h-10"
                value={sortOrder}
                onChange={(e) => {
                  setSortOrder(e.target.value.replace(/[^\d-]/g, ""));
                  setFieldErr((p) => {
                    const n = { ...p };
                    delete n.sort_order;
                    return n;
                  });
                }}
              />
              {fieldErr.sort_order ? <p className="text-xs text-destructive">{fieldErr.sort_order}</p> : null}
            </div>
            <div className="grid gap-2">
              <div className="flex items-center justify-between gap-3">
                <Label className="text-sm font-medium">Код</Label>
                <span className="shrink-0 text-xs tabular-nums text-muted-foreground">{code.length} / 20</span>
              </div>
              <Input
                className="h-10"
                value={code}
                maxLength={20}
                onChange={(e) => {
                  setCode(e.target.value.toUpperCase().replace(/[^A-Z0-9_]/g, ""));
                  setFieldErr((p) => {
                    const n = { ...p };
                    delete n.code;
                    return n;
                  });
                }}
              />
              {fieldErr.code ? <p className="text-xs text-destructive">{fieldErr.code}</p> : null}
            </div>
            <div className="grid gap-2">
              <Label className="text-sm font-medium">Комментарий</Label>
              <textarea
                className="min-h-[88px] w-full rounded-md border border-input bg-background px-3 py-2.5 text-sm shadow-sm"
                value={comment}
                onChange={(e) => {
                  setComment(e.target.value);
                  setFieldErr((p) => {
                    const n = { ...p };
                    delete n.comment;
                    return n;
                  });
                }}
              />
              {fieldErr.comment ? <p className="text-xs text-destructive">{fieldErr.comment}</p> : null}
            </div>
            <div>
              <button
                type="button"
                className="text-left text-sm font-medium text-primary underline-offset-4 hover:underline"
                onClick={() => setMapOpen((v) => !v)}
              >
                {mapOpen ? "Скрыть местоположение" : initial ? "Изменить местоположение" : "Добавить местоположение"}
              </button>
            </div>
            {mapOpen ? (
              <div className="grid gap-3 rounded-lg border border-border bg-muted/20 p-3 sm:p-4">
                <div className="grid grid-cols-2 gap-3 sm:gap-4">
                  <div className="grid min-w-0 gap-1.5">
                    <Label className="text-xs font-medium">Широта</Label>
                    <Input
                      className="h-10"
                      value={lat}
                      onChange={(e) => {
                        setLat(e.target.value);
                        setFieldErr((p) => {
                          const n = { ...p };
                          delete n.latitude;
                          return n;
                        });
                      }}
                      placeholder="41.31"
                    />
                    {fieldErr.latitude ? <p className="text-xs text-destructive">{fieldErr.latitude}</p> : null}
                  </div>
                  <div className="grid min-w-0 gap-1.5">
                    <Label className="text-xs font-medium">Долгота</Label>
                    <Input
                      className="h-10"
                      value={lng}
                      onChange={(e) => {
                        setLng(e.target.value);
                        setFieldErr((p) => {
                          const n = { ...p };
                          delete n.longitude;
                          return n;
                        });
                      }}
                      placeholder="69.24"
                    />
                    {fieldErr.longitude ? <p className="text-xs text-destructive">{fieldErr.longitude}</p> : null}
                  </div>
                </div>
                {(() => {
                  const latNum = Number.parseFloat(String(lat).replace(",", "."));
                  const lngNum = Number.parseFloat(String(lng).replace(",", "."));
                  if (!Number.isFinite(latNum) || !Number.isFinite(lngNum)) return null;
                  return (
                    <iframe
                      title="map"
                      className="h-48 w-full rounded border"
                      src={`https://www.openstreetmap.org/export/embed.html?bbox=${lngNum - 0.02}%2C${latNum - 0.02}%2C${lngNum + 0.02}%2C${latNum + 0.02}&layer=mapnik&marker=${latNum}%2C${lngNum}`}
                    />
                  );
                })()}
              </div>
            ) : null}
            <label className="flex min-h-11 cursor-pointer items-center justify-between gap-4 rounded-lg border border-input bg-background px-4 py-2.5 text-sm shadow-sm">
              <span className="font-medium">Активный</span>
              <input
                type="checkbox"
                className="size-4 accent-teal-600"
                checked={active}
                onChange={(e) => setActive(e.target.checked)}
              />
            </label>
            <div className="grid gap-3 rounded-lg border border-border bg-muted/15 p-4">
              <p className="text-sm font-semibold text-foreground">Назначение кассы</p>
              <p className="text-xs text-muted-foreground">
                Касса используется либо для клиентских оплат, либо для оплаты скидки — не для обоих
                сразу.
              </p>
              <label className="flex min-h-10 cursor-pointer items-center gap-3 text-sm">
                <input
                  type="radio"
                  name="cash-desk-purpose"
                  className="size-4 accent-teal-600"
                  checked={cashDeskPurpose === "client_payment"}
                  onChange={() => setCashDeskPurpose("client_payment")}
                />
                <span>Для оплаты (клиентские платежи)</span>
              </label>
              <label className="flex min-h-10 cursor-pointer items-center gap-3 text-sm">
                <input
                  type="radio"
                  name="cash-desk-purpose"
                  className="size-4 accent-teal-600"
                  checked={cashDeskPurpose === "discount_payment"}
                  onChange={() => setCashDeskPurpose("discount_payment")}
                />
                <span>Для скидки (оплата скидки)</span>
              </label>
            </div>
            </div>
          </div>
          <DialogFooter className="mx-0 mb-0 shrink-0 flex-row justify-end gap-3 rounded-b-xl border-t border-border bg-background px-5 py-4 pb-5">
            <Button type="button" variant="outline" className="min-h-10 min-w-[7rem]" onClick={onClose}>
              Отмена
            </Button>
            <Button
              type="button"
              className="min-h-10 min-w-[7rem] bg-teal-600 text-white hover:bg-teal-700 dark:bg-teal-600 dark:hover:bg-teal-500"
              disabled={!name.trim() || saveMut.isPending}
              onClick={() => saveMut.mutate()}
            >
              {initial ? "Сохранить" : "Добавить"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={usersSubOpen} onOpenChange={setUsersSubOpen}>
        <DialogContent
          className={cn(
            "flex max-h-[min(92vh,720px)] w-[min(100vw-1.5rem,1180px)] flex-col gap-0 overflow-x-hidden overflow-y-auto p-0",
            "!max-w-[min(100vw-1.5rem,1180px)] sm:!max-w-[min(100vw-1.5rem,1180px)] z-[100]"
          )}
          showCloseButton
        >
          <DialogHeader className="shrink-0 border-b border-border bg-muted/20 px-4 pb-4 pt-5 pr-14 sm:pt-4">
            <div className="flex flex-col gap-3 text-left">
              <div className="min-w-0 pr-1">
                <DialogTitle className="text-lg font-semibold tracking-tight">Пользователи по ролям</DialogTitle>
                <p className="mt-1 max-w-3xl text-xs leading-relaxed text-muted-foreground">
                  Блоки по ролям; длинный список внутри блока с прокруткой. Один сотрудник — в одной колонке.
                </p>
              </div>
              <div className="w-full max-w-2xl">
                <div className="rounded-xl border border-border/90 bg-background p-1 shadow-sm ring-1 ring-black/[0.04] dark:ring-white/[0.07]">
                  <div className="relative flex items-center">
                    <Search
                      className="pointer-events-none absolute left-3.5 top-1/2 size-[1.125rem] -translate-y-1/2 text-muted-foreground"
                      aria-hidden
                    />
                    <Input
                      placeholder="Поиск по имени или логину"
                      value={userPickerSearch}
                      onChange={(e) => setUserPickerSearch(e.target.value)}
                      className={cn(
                        "h-11 w-full border-0 bg-transparent pl-11 text-sm shadow-none",
                        "placeholder:text-muted-foreground/70",
                        "focus-visible:ring-0 focus-visible:ring-offset-0",
                        userPickerSearch.trim() ? "pr-11" : "pr-4"
                      )}
                      aria-label="Поиск пользователей"
                    />
                    {userPickerSearch.trim() ? (
                      <button
                        type="button"
                        className="absolute right-2 top-1/2 z-10 flex size-8 -translate-y-1/2 items-center justify-center rounded-lg text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
                        aria-label="Очистить поиск"
                        onClick={() => setUserPickerSearch("")}
                      >
                        <X className="size-4 shrink-0" strokeWidth={2.25} />
                      </button>
                    ) : null}
                  </div>
                </div>
              </div>
            </div>
          </DialogHeader>
          <div className="flex flex-col bg-muted/10 px-3 pt-2 pb-1 sm:px-4">
            <RoleLinkPickerGrid
              roleOrder={CASH_ROLE_KEYS}
              columns={CASH_ROLE_COLUMNS}
              pickers={pickers}
              local={draftLinkSets}
              setLocal={setDraftLinkSets}
              search={userPickerSearch}
            />
          </div>
          <DialogFooter className="mx-0 mb-0 shrink-0 flex-col-reverse gap-2.5 rounded-b-xl border-t border-border bg-background px-5 pt-4 pb-5 sm:flex-row sm:justify-end sm:gap-3 sm:pb-5">
            <Button
              type="button"
              variant="outline"
              className="w-full min-h-10 sm:w-auto sm:min-w-[7.5rem]"
              onClick={() => setUsersSubOpen(false)}
            >
              Отмена
            </Button>
            <Button
              type="button"
              className="w-full min-h-10 bg-teal-600 text-white hover:bg-teal-700 sm:w-auto sm:min-w-[7.5rem] dark:bg-teal-600 dark:hover:bg-teal-500"
              onClick={() => {
                setLinkSets(cloneRoleSets(CASH_ROLE_KEYS, draftLinkSets));
                setUsersSubOpen(false);
              }}
            >
              Готово
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import { useMemo } from "react";
import {
  Area,
  AreaChart,
  Bar,
  BarChart,
  CartesianGrid,
  Cell,
  Legend,
  Line,
  LineChart,
  Pie,
  PieChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis
} from "recharts";
import { formatGroupedInteger, formatNumberGrouped } from "@/lib/format-numbers";

const PIE_FILL = ["#10b981", "#3b82f6", "#f59e0b", "#8b5cf6", "#ef4444", "#64748b", "#06b6d4", "#84cc16"];

function moneyTooltip(v: number) {
  return formatNumberGrouped(v, { maxFractionDigits: 0 }) + " сум";
}

type DayActivityProps = {
  ordersToday: number;
  ordersActive: number;
  paymentsToday: number;
  returnsToday: number;
};

export function DashboardDayActivityChart({ ordersToday, ordersActive, paymentsToday, returnsToday }: DayActivityProps) {
  const data = [
    { name: "Заказы", soni: ordersToday },
    { name: "В работе", soni: ordersActive },
    { name: "Платежи", soni: paymentsToday },
    { name: "Возвраты", soni: returnsToday }
  ];
  return (
    <ResponsiveContainer width="100%" height={220}>
      <BarChart data={data} margin={{ top: 8, right: 12, left: 0, bottom: 4 }}>
        <CartesianGrid strokeDasharray="3 3" className="stroke-border/60" />
        <XAxis dataKey="name" tick={{ fontSize: 11 }} className="text-muted-foreground" />
        <YAxis allowDecimals={false} tick={{ fontSize: 11 }} width={36} className="text-muted-foreground" />
        <Tooltip
          contentStyle={{ borderRadius: 8, fontSize: 12 }}
          formatter={(v: number) => [formatGroupedInteger(v), "Кол-во"]}
        />
        <Bar dataKey="soni" fill="var(--primary)" radius={[4, 4, 0, 0]} />
      </BarChart>
    </ResponsiveContainer>
  );
}

type TrendRow = { dateShort: string; orders: number; revenue: number };

export function ReportsTrendCharts({ rows }: { rows: TrendRow[] }) {
  if (rows.length === 0) return null;
  return (
    <div className="grid gap-4 lg:grid-cols-2">
      <ResponsiveContainer width="100%" height={280}>
        <LineChart data={rows} margin={{ top: 8, right: 12, left: 0, bottom: 0 }}>
          <CartesianGrid strokeDasharray="3 3" className="stroke-border/60" />
          <XAxis dataKey="dateShort" tick={{ fontSize: 10 }} interval="preserveStartEnd" />
          <YAxis allowDecimals={false} tick={{ fontSize: 11 }} width={36} />
          <Tooltip
            contentStyle={{ borderRadius: 8, fontSize: 12 }}
            formatter={(v: number) => [formatGroupedInteger(v), "Заказы"]}
          />
          <Line type="monotone" dataKey="orders" stroke="var(--primary)" strokeWidth={2} dot={false} name="Заказы" />
        </LineChart>
      </ResponsiveContainer>
      <ResponsiveContainer width="100%" height={280}>
        <AreaChart data={rows} margin={{ top: 8, right: 12, left: 0, bottom: 0 }}>
          <CartesianGrid strokeDasharray="3 3" className="stroke-border/60" />
          <XAxis dataKey="dateShort" tick={{ fontSize: 10 }} interval="preserveStartEnd" />
          <YAxis tick={{ fontSize: 11 }} width={44} tickFormatter={(v) => (v >= 1e6 ? `${(v / 1e6).toFixed(1)}M` : `${Math.round(v / 1000)}k`)} />
          <Tooltip
            contentStyle={{ borderRadius: 8, fontSize: 12 }}
            formatter={(v: number) => [moneyTooltip(v), "Выручка"]}
          />
          <Area type="monotone" dataKey="revenue" stroke="#10b981" fill="#10b981" fillOpacity={0.2} name="Выручка" />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}

type StatusSlice = { status: string; name: string; value: number };

export type ShareDonutSlice = StatusSlice & {
  share_pct?: number;
  orders_count?: number;
  line_qty?: number;
};

/** Доля продаж (сумма) — donut, высота по умолчанию для мониторинга */
export function SalesShareDonut({
  slices,
  height = 320,
  valueLabel = "Сумма, сум"
}: {
  slices: ShareDonutSlice[];
  height?: number;
  valueLabel?: string;
}) {
  if (slices.length === 0) {
    return (
      <div
        className="flex items-center justify-center rounded-lg border border-dashed border-border bg-muted/20 text-sm text-muted-foreground"
        style={{ height }}
      >
        Нет данных
      </div>
    );
  }
  return (
    <ResponsiveContainer width="100%" height={height}>
      <PieChart margin={{ top: 4, right: 4, bottom: 4, left: 4 }}>
        <Pie
          data={slices}
          dataKey="value"
          nameKey="name"
          cx="50%"
          cy="50%"
          innerRadius={height > 300 ? 72 : 56}
          outerRadius={height > 300 ? 108 : 88}
          paddingAngle={1}
          label={false}
        >
          {slices.map((row, i) => (
            <Cell
              key={row.status}
              fill={row.status === "empty" ? "#e2e8f0" : PIE_FILL[i % PIE_FILL.length]}
            />
          ))}
        </Pie>
        <Tooltip
          content={({ active, payload }) => {
            if (!active || !payload?.length) return null;
            const row = payload[0]?.payload as ShareDonutSlice;
            if (!row) return null;
            return (
              <div className="max-w-[220px] rounded-md border border-border bg-popover px-2.5 py-2 text-xs shadow-md">
                <div className="font-medium text-foreground">{row.name}</div>
                <div className="mt-1 text-muted-foreground">
                  {valueLabel}:{" "}
                  <span className="font-medium text-foreground">
                    {formatNumberGrouped(row.value, { maxFractionDigits: 0 })}
                  </span>
                </div>
                {row.share_pct != null ? (
                  <div className="text-muted-foreground">
                    Доля: <span className="font-medium text-foreground">{row.share_pct.toFixed(1)}%</span>
                  </div>
                ) : null}
                {row.orders_count != null ? (
                  <div className="text-muted-foreground">
                    Заказов: <span className="font-medium text-foreground">{formatGroupedInteger(row.orders_count)}</span>
                  </div>
                ) : null}
                {row.line_qty != null ? (
                  <div className="text-muted-foreground">
                    Кол-во (шт.):{" "}
                    <span className="font-medium text-foreground">{formatNumberGrouped(row.line_qty, { maxFractionDigits: 0 })}</span>
                  </div>
                ) : null}
              </div>
            );
          }}
        />
        <Legend wrapperStyle={{ fontSize: 11 }} />
      </PieChart>
    </ResponsiveContainer>
  );
}

type DailyRev = { day: string; revenue: number };

/** Одна линия: сумма продаж по дням месяца; cumulative — накопительный итог */
export function MonitoringDailyRevenueLine({ rows, cumulative = false }: { rows: DailyRev[]; cumulative?: boolean }) {
  const safeRows = rows.length > 0 ? rows : [{ day: "—", revenue: 0 }];
  const data = useMemo(() => {
    let run = 0;
    return safeRows.map((r) => {
      run += r.revenue;
      return {
        ...r,
        dayShort: r.day.length >= 10 ? r.day.slice(8, 10) : r.day,
