function exportEquipmentCsv(rows: EquipmentRow[], fileBase: string): void {
  const esc = (v: string) => `"${v.replaceAll('"', '""')}"`;
  const head = [
    "Тип инвентаря",
    "Код / SKU",
    "Имя клиента",
    "Агент",
    "Телефон",
    "Локация",
    "Территория",
    "Дата прикрепления",
    "Серийный номер",
    "Комментарий"
  ];
  const body = rows.map((r) => [
    r.inventory_type ?? "",
    r.equipment_kind ?? "",
    r.client_name ?? "",
    r.agent_name ?? "",
    r.client_phone ?? "",
    r.client_address ?? "",
    [r.region, r.zone, r.city].filter(Boolean).join(" / "),
    fmtDate(r.assigned_at),
    r.serial_number ?? "",
    r.note ?? ""
  ]);
  const csv = [head, ...body].map((row) => row.map((x) => esc(String(x))).join(";")).join("\n");
  const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `${fileBase}_${new Date().toISOString().slice(0, 10)}.csv`;
  a.click();
  URL.revokeObjectURL(url);
}

export function EquipmentWorkspace({ view = "equipment" }: { view?: "equipment" | "history" }) {
  const isHistory = view === "history";
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const [rows, setRows] = useState<EquipmentRow[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);
  const [page, setPage] = useState(1);
  const [columnDialogOpen, setColumnDialogOpen] = useState(false);

  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [search, setSearch] = useState("");
  const [inventoryType, setInventoryType] = useState("");
  const [agentId, setAgentId] = useState("");
  const [territory1, setTerritory1] = useState("");
  const [territory2, setTerritory2] = useState("");
  const [territory3, setTerritory3] = useState("");
  const [dateOpen, setDateOpen] = useState(false);
  const dateAnchorRef = useRef<HTMLButtonElement | null>(null);

  const [regionOptions, setRegionOptions] = useState<Array<{ value: string; label: string }>>([]);
  const [zoneOptions, setZoneOptions] = useState<string[]>([]);
  const [cityOptions, setCityOptions] = useState<Array<{ value: string; label: string }>>([]);
  const [typeOptions, setTypeOptions] = useState<string[]>([]);
  const [productOptions, setProductOptions] = useState<ProductOption[]>([]);
  const [clientOptions, setClientOptions] = useState<ClientOption[]>([]);
  const [addOpen, setAddOpen] = useState(false);
  const [addClientId, setAddClientId] = useState("");
  const [addProductId, setAddProductId] = useState("");
  const [addSerial, setAddSerial] = useState("");
  const [addInventoryNo, setAddInventoryNo] = useState("");
  const [addNote, setAddNote] = useState("");
  const [addSaving, setAddSaving] = useState(false);
  const [addError, setAddError] = useState<string | null>(null);
  const tablePrefs = useUserTablePrefs({
    tenantSlug,
    tableId: EQUIPMENT_TABLE_ID,
    defaultColumnOrder: EQUIPMENT_COLUMNS.map((c) => c.id),
    defaultPageSize: 30,
    allowedPageSizes: [10, 20, 30, 50, 100]
  });
  const limit = tablePrefs.pageSize;

  const agentOptions = useMemo(() => {
    const m = new Map<number, string>();
    for (const r of rows) {
      if (r.agent_id && r.agent_id > 0) m.set(r.agent_id, r.agent_name?.trim() || `Agent #${r.agent_id}`);
    }
    return Array.from(m.entries())
      .map(([id, label]) => ({ id: String(id), label }))
      .sort((a, b) => a.label.localeCompare(b.label, "ru"));
  }, [rows]);
  const effectiveTypeOptions = useMemo(() => {
    const s = new Set<string>();
    for (const t of typeOptions) {
      const v = t.trim();
      if (v) s.add(v);
    }
    for (const r of rows) {
      const a = (r.inventory_type ?? "").trim();
      if (a) s.add(a);
    }
    return Array.from(s).sort((a, b) => a.localeCompare(b, "ru"));
  }, [rows, typeOptions]);

  async function load(pageArg = page) {
    if (!tenantSlug) return;
    setLoading(true);
    try {
      const p = new URLSearchParams();
      p.set("page", String(pageArg));
      p.set("limit", String(limit));
      p.set("status", isHistory ? "all" : "active");
      if (dateFrom) p.set("date_from", dateFrom);
      if (dateTo) p.set("date_to", dateTo);
      if (search.trim()) p.set("search", search.trim());
      if (inventoryType.trim()) p.set("inventory_type", inventoryType.trim());
      if (agentId) p.set("agent_id", agentId);
      if (territory1) p.set("territory_1", territory1);
      if (territory2) p.set("territory_2", territory2);
      if (territory3) p.set("territory_3", territory3);
      const [{ data }, { data: refs }] = await Promise.all([
        api.get<EquipmentListResponse>(`/api/${tenantSlug}/equipment?${p.toString()}`),
        api.get<RefsResponse>(`/api/${tenantSlug}/clients/references`)
      ]);
      setRows(data.data ?? []);
      setTotal(typeof data.total === "number" ? data.total : 0);
      setPage(data.page ?? pageArg);
      setRegionOptions(refs.region_options ?? []);
      setZoneOptions(refs.zones ?? []);
      setCityOptions(refs.city_options ?? []);
      setTypeOptions(refs.equipment_filter_values ?? []);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if (tenantSlug) void load(1);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tenantSlug, limit, isHistory]);

  useEffect(() => {
    if (!tenantSlug || isHistory) return;
    void (async () => {
      try {
        const [{ data: p }, { data: c }] = await Promise.all([
          api.get<{ data: ProductOption[] }>(`/api/${tenantSlug}/products?page=1&limit=500&is_equipment=true`),
          api.get<{ data: ClientOption[] }>(`/api/${tenantSlug}/clients?page=1&limit=500&sort=name&order=asc`)
        ]);
        setProductOptions((p.data ?? []).map((x) => ({ id: x.id, name: x.name, sku: x.sku, is_active: x.is_active })));
        setClientOptions((c.data ?? []).map((x) => ({ id: x.id, name: x.name })));
      } catch {
        setProductOptions([]);
        setClientOptions([]);
      }
    })();
  }, [tenantSlug, isHistory]);

  const totalPages = Math.max(1, Math.ceil(total / limit));
  const columnLabelById = useMemo(
    () => Object.fromEntries(EQUIPMENT_COLUMNS.map((c) => [c.id, c.label])),
    []
  );
  function cellByColumnId(r: EquipmentRow, colId: string): string {
    switch (colId) {
      case "inventory_type":
        return r.inventory_type ?? "";
      case "equipment_kind":
        return r.equipment_kind ?? "—";
      case "client_name":
        return r.client_name ?? "";
      case "agent_name":
        return r.agent_name ?? "—";
      case "client_phone":
        return r.client_phone ?? "—";
      case "client_address":
        return r.client_address ?? "—";
      case "territory":
        return [r.region, r.zone, r.city].filter(Boolean).join(" / ") || "—";
      case "assigned_at":
        return fmtDate(r.assigned_at);
      case "serial_number":
        return r.serial_number ?? "—";
      case "note":
        return r.note ?? "—";
      default:
        return "—";
    }
  }
  function exportEquipmentExcel(rowsForExport: EquipmentRow[], fileBase: string): void {
    const visible = tablePrefs.visibleColumnOrder;
    const headers = visible.map((id) => columnLabelById[id] ?? id);
    const dataRows = rowsForExport.map((r) => visible.map((id) => cellByColumnId(r, id)));
    downloadXlsxSheet(`${fileBase}_${new Date().toISOString().slice(0, 10)}.xlsx`, "Оборудование", headers, dataRows);
  }

  function resetFilters() {
    setDateFrom("");
    setDateTo("");
    setSearch("");
    setInventoryType("");
    setAgentId("");
    setTerritory1("");
    setTerritory2("");
    setTerritory3("");
    void load(1);
  }

  async function createManualEquipment(): Promise<void> {
    if (!tenantSlug) return;
    setAddError(null);
    const clientId = Number(addClientId);
    const productId = Number(addProductId);
    if (!Number.isFinite(clientId) || clientId <= 0) return setAddError("Клиентni tanlang.");
    if (!Number.isFinite(productId) || productId <= 0) return setAddError("Mahsulotni tanlang.");
    const p = productOptions.find((x) => x.id === productId);
    if (!p) return setAddError("Tanlangan mahsulot topilmadi.");
    setAddSaving(true);
    try {
      await api.post(`/api/${tenantSlug}/clients/${clientId}/equipment`, {
        inventory_type: p.name,
        equipment_kind: p.sku || null,
        serial_number: addSerial.trim() || null,
        inventory_number: addInventoryNo.trim() || null,
        note: addNote.trim() || null
      });
      setAddOpen(false);
      setAddClientId("");
      setAddProductId("");
      setAddSerial("");
      setAddInventoryNo("");
      setAddNote("");
      await load(1);
    } catch {
      setAddError("Saqlashda xatolik bo‘ldi.");
    } finally {
      setAddSaving(false);
    }
  }

  return (
    <PageShell>
      <PageHeader
        title={isHistory ? "История перемещения оборудования" : "Оборудование"}
        description={isHistory ? "Inventory movement log, territory and serial tracking" : "Client equipment control and attachment"}
      />
      <Card className="border-border/80 shadow-sm">
        <CardContent className="space-y-3 p-3">
          <div className="flex flex-wrap items-center justify-between gap-2">
            <h2 className="text-lg font-semibold">
              {isHistory ? "История перемещения оборудования" : "Оборудование"}
            </h2>
            <div className="flex flex-wrap items-center gap-2">
              <button
                ref={dateAnchorRef}
                type="button"
                className="inline-flex h-8 min-w-[13.5rem] items-center justify-between rounded-md border border-input bg-background px-2.5 text-xs"
                onClick={() => setDateOpen((v) => !v)}
              >
                <span className="truncate">{formatDateRangeButton(dateFrom, dateTo)}</span>
                <CalendarDays className="h-3.5 w-3.5 shrink-0 text-muted-foreground" />
              </button>
              <Button
                className="h-8 bg-teal-600 px-3 text-xs text-white hover:bg-teal-700"
                onClick={() => void load(1)}
                disabled={loading}
              >
                Применить
              </Button>
            </div>
          </div>

          <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-5">
            <select className="h-8 rounded-md border bg-background px-2 text-xs" value={agentId} onChange={(e) => setAgentId(e.target.value)}>
              <option value="">Агент</option>
              {agentOptions.map((o) => (
                <option key={o.id} value={o.id}>
                  {o.label}
                </option>
              ))}
            </select>
            {effectiveTypeOptions.length > 0 ? (
              <select
                className="h-8 rounded-md border bg-background px-2 text-xs"
                value={inventoryType}
                onChange={(e) => setInventoryType(e.target.value)}
              >
                <option value="">Тип оборудования</option>
                {effectiveTypeOptions.map((v) => (
                  <option key={v} value={v}>
                    {v}
                  </option>
                ))}
              </select>
            ) : (
              <select
                className="h-8 rounded-md border bg-muted/30 px-2 text-xs text-muted-foreground"
                value=""
                disabled
              >
                <option value="">Тип оборудования (нет данных)</option>
              </select>
            )}
            <select className="h-8 rounded-md border bg-background px-2 text-xs" value={territory1} onChange={(e) => setTerritory1(e.target.value)}>
              <option value="">Область</option>
              {regionOptions.map((o) => (
                <option key={o.value} value={o.value}>
                  {o.label}
                </option>
              ))}
            </select>
            <select className="h-8 rounded-md border bg-background px-2 text-xs" value={territory2} onChange={(e) => setTerritory2(e.target.value)}>
              <option value="">Зона</option>
              {zoneOptions.map((z) => (
                <option key={z} value={z}>
                  {z}
                </option>
              ))}
            </select>
            <select className="h-8 rounded-md border bg-background px-2 text-xs" value={territory3} onChange={(e) => setTerritory3(e.target.value)}>
              <option value="">Город</option>
              {cityOptions.map((o) => (
                <option key={o.value} value={o.value}>
                  {o.label}
                </option>
              ))}
            </select>
          </div>
          {effectiveTypeOptions.length === 0 ? (
            <div className="rounded-md border border-amber-300/70 bg-amber-50 px-3 py-2 text-xs text-amber-900 dark:border-amber-600/40 dark:bg-amber-950/20 dark:text-amber-200">
              Типы оборудования не найдены. Сначала добавьте хотя бы одну запись оборудования с заполненным типом
              (или настройте справочник), после чего фильтр выбора станет доступен.
            </div>
          ) : null}
        </CardContent>
      </Card>

      <Card className="border-border/80 shadow-sm">
        <CardContent className="space-y-3 p-3">
          <div className="flex flex-wrap items-center justify-between gap-2">
            <h3 className="text-base font-semibold">Таблица</h3>
            <div className="flex flex-wrap gap-2">
              {!isHistory ? (
                <Link href="/clients/equipment/history" className="inline-flex h-8 items-center rounded-md border px-2.5 text-xs">
                  <History className="mr-1.5 h-3.5 w-3.5" />
                  История инвентаризации
                </Link>
              ) : null}
              {!isHistory ? (
                <Button className="h-8 bg-teal-600 px-3 text-xs text-white hover:bg-teal-700" onClick={() => setAddOpen(true)}>
                  <Plus className="mr-1.5 h-3.5 w-3.5" />
                  Добавить
                </Button>
              ) : null}
            </div>
          </div>

          <div className="space-y-2 rounded-md border border-border/70 bg-background p-2">
            <div className="flex flex-wrap items-center gap-2">
              <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => setColumnDialogOpen(true)}>
                <SlidersHorizontal className="h-3.5 w-3.5" />
              </Button>
              <select
                className="h-8 rounded-md border bg-background px-2 text-xs"
                value={String(limit)}
                onChange={(e) => tablePrefs.setPageSize(Number(e.target.value))}
              >
                <option value="10">10</option>
                <option value="20">20</option>
                <option value="30">30</option>
                <option value="50">50</option>
                <option value="100">100</option>
              </select>
              <div className="relative w-full min-w-[160px] max-w-[280px]">
                <Search className="pointer-events-none absolute left-2 top-2 h-3.5 w-3.5 text-muted-foreground" />
                <Input
                  className="h-8 w-full pl-7 text-xs"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  placeholder="Поиск"
                />
              </div>
              <Button
                variant="outline"
                className="h-8 text-xs"
                onClick={() => exportEquipmentExcel(rows, isHistory ? "equipment_history" : "equipment_list")}
              >
                <Download className="mr-1.5 h-3.5 w-3.5" />
                Excel
              </Button>
              <Button variant="ghost" className="h-8 text-xs" onClick={resetFilters}>
                <Filter className="mr-1 h-3.5 w-3.5" />
                Сброс
              </Button>
            </div>

            <div className="overflow-x-auto rounded-md border">
              <table className="w-full min-w-[1300px] text-sm">
                <thead>
                  <tr className="bg-muted/40 text-left text-[11px] text-muted-foreground">
                    {tablePrefs.visibleColumnOrder.map((colId) => (
                      <th key={colId} className="px-3 py-2">
                        {columnLabelById[colId] ?? colId}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {loading ? (
                    <tr>
                      <td className="px-3 py-8 text-center text-muted-foreground" colSpan={tablePrefs.visibleColumnOrder.length}>
                        Загрузка…
                      </td>
                    </tr>
                  ) : rows.length === 0 ? (
                    <tr>
                      <td className="px-3 py-10 text-center text-muted-foreground" colSpan={tablePrefs.visibleColumnOrder.length}>
                        Пусто
                      </td>
                    </tr>
                  ) : (
                    rows.map((r) => (
                      <tr key={r.id} className="border-t hover:bg-muted/20">
                        {tablePrefs.visibleColumnOrder.map((colId) => {
                          if (colId === "client_name") {
                            return (
                              <td key={colId} className="px-3 py-2">
                                <Link href={`/clients/${r.client_id}`} className="text-primary hover:underline">
                                  {r.client_name}
                                </Link>
                              </td>
                            );
                          }
                          return (
                            <td key={colId} className="px-3 py-2 text-xs">
                              {cellByColumnId(r, colId)}
                            </td>
                          );
                        })}
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>

          <div className="flex items-center justify-between gap-2 text-sm">
            <span className="text-muted-foreground">
              Всего: {total} • Стр. {page}/{totalPages}
            </span>
            <div className="flex items-center gap-2">
              <Button variant="outline" size="sm" disabled={page <= 1 || loading} onClick={() => void load(page - 1)}>
                Назад
              </Button>
              <Button variant="outline" size="sm" disabled={page >= totalPages || loading} onClick={() => void load(page + 1)}>
                Вперёд
              </Button>
            </div>
          </div>

          <DateRangePopover
            open={dateOpen}
            onOpenChange={setDateOpen}
            anchorRef={dateAnchorRef}
            dateFrom={dateFrom}
            dateTo={dateTo}
            onApply={({ dateFrom: df, dateTo: dt }) => {
              setDateFrom(df);
              setDateTo(dt);
            }}
          />
          <TableColumnSettingsDialog
            open={columnDialogOpen}
            onOpenChange={setColumnDialogOpen}
            title="Ustunlarni boshqarish"
            description="Ko‘rinadigan ustunlar va tartib. Sizning akkauntingiz uchun saqlanadi."
            columns={[...EQUIPMENT_COLUMNS]}
            columnOrder={tablePrefs.columnOrder}
            hiddenColumnIds={tablePrefs.hiddenColumnIds}
            saving={tablePrefs.saving}
            onSave={(next) => tablePrefs.saveColumnLayout(next)}
            onReset={() => tablePrefs.resetColumnLayout()}
          />
        </CardContent>
      </Card>

      {!isHistory ? (
        <Dialog open={addOpen} onOpenChange={setAddOpen}>
          <DialogContent className="sm:max-w-[560px]">
            <DialogHeader>
              <DialogTitle>Оборудованиеga qo‘shish</DialogTitle>
            </DialogHeader>
            <div className="space-y-3">
              <div className="space-y-1">
                <p className="text-xs text-muted-foreground">Клиент *</p>
                <select className="h-9 w-full rounded-md border bg-background px-2 text-sm" value={addClientId} onChange={(e) => setAddClientId(e.target.value)}>
                  <option value="">Клиентni tanlang</option>
                  {clientOptions.map((c) => (
                    <option key={c.id} value={String(c.id)}>
                      {c.name}
                    </option>
                  ))}
                </select>
              </div>
              <div className="space-y-1">
                <p className="text-xs text-muted-foreground">Маҳсулот (Продукт) *</p>
                <select className="h-9 w-full rounded-md border bg-background px-2 text-sm" value={addProductId} onChange={(e) => setAddProductId(e.target.value)}>
                  <option value="">Маҳсулотни tanlang</option>
                  {productOptions.map((p) => (
                    <option key={p.id} value={String(p.id)}>
                      {p.name} {p.sku ? `(${p.sku})` : ""} {!p.is_active ? "• неактив" : ""}
                    </option>
                  ))}
                </select>
              </div>
              <div className="grid gap-2 sm:grid-cols-2">
                <Input value={addSerial} onChange={(e) => setAddSerial(e.target.value)} placeholder="Серийный номер" />
                <Input value={addInventoryNo} onChange={(e) => setAddInventoryNo(e.target.value)} placeholder="Инв. номер" />
              </div>
              <Input value={addNote} onChange={(e) => setAddNote(e.target.value)} placeholder="Комментарий" />
              {addError ? <p className="text-xs text-destructive">{addError}</p> : null}
              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => setAddOpen(false)}>
                  Отмена
                </Button>
                <Button className="bg-teal-600 text-white hover:bg-teal-700" disabled={addSaving} onClick={() => void createManualEquipment()}>
                  {addSaving ? "Сохранение..." : "Сохранить"}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      ) : null}
    </PageShell>
  );
}

"use client";

import type { ClientMapControlsHandle, ClientMapPoint } from "@/components/clients/clients-leaflet-map";
import { ClientMapCategoryStats } from "@/components/clients/map/client-map-category-stats";
import { ClientMapFiltersPanel } from "@/components/clients/map/client-map-filters-panel";
import { ClientMapSelectedPanel } from "@/components/clients/map/client-map-selected-panel";
import { ClientMapPanelHeader } from "@/components/clients/map/client-map-ui";
import {
  ClientMapBottomLinks,
  ClientMapSearchToolbar,
  ClientMapZoomControls
} from "@/components/clients/map/client-map-toolbar";
import { PageShell } from "@/components/dashboard/page-shell";
import { api } from "@/lib/api";
import {
  applyClientMapFilters,
  computeCategoryCounts,
  INITIAL_CLIENT_MAP_FILTERS,
  type ClientMapFiltersState
} from "@/lib/client-map-filters";
import type { ClientRow } from "@/lib/client-types";
import { mergeRefSelectOptions } from "@/lib/ref-select-options";
import { buildZoneRegionCityCascadeOptions } from "@/lib/territory-client-filters";
import { STALE } from "@/lib/query-stale";
import { useAuthStore, useAuthStoreHydrated } from "@/lib/auth-store";
import { useQuery } from "@tanstack/react-query";
import dynamic from "next/dynamic";
import { useCallback, useMemo, useRef, useState } from "react";

const ClientsLeafletMapDynamic = dynamic(
  () =>
    import("@/components/clients/clients-leaflet-map").then((m) => ({
      default: m.ClientsLeafletMap
    })),
  {
    ssr: false,
    loading: () => (
      <div className="flex h-full min-h-[460px] items-center justify-center bg-muted">
        <p className="text-sm text-slate-500">Карта (Yandex) загружается…</p>
      </div>
    )
  }
);

function hasCoords(c: ClientRow): boolean {
  const lat = c.latitude != null && c.latitude !== "" ? parseFloat(c.latitude) : NaN;
  const lon = c.longitude != null && c.longitude !== "" ? parseFloat(c.longitude) : NaN;
  return !isNaN(lat) && !isNaN(lon) && lat >= -90 && lat <= 90 && lon >= -180 && lon <= 180;
}

type PanelSection = "filter" | "category";

type ClientRefOptionDto = { value: string; label: string };

type ClientReferencesResponse = {
  categories?: string[];
  client_type_codes?: string[];
  zones?: string[];
  regions?: string[];
  cities?: string[];
  category_options?: ClientRefOptionDto[];
  client_type_options?: ClientRefOptionDto[];
  city_options?: ClientRefOptionDto[];
  region_options?: ClientRefOptionDto[];
};

export function ClientMapWorkspace() {
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const authHydrated = useAuthStoreHydrated();
  const mapControlsRef = useRef<ClientMapControlsHandle | null>(null);

  const [draftFilters, setDraftFilters] = useState<ClientMapFiltersState>(INITIAL_CLIENT_MAP_FILTERS);
  const [appliedFilters, setAppliedFilters] = useState<ClientMapFiltersState>(INITIAL_CLIENT_MAP_FILTERS);
  const [searchDraft, setSearchDraft] = useState("");
  const [appliedSearch, setAppliedSearch] = useState("");
  const [selectedClientId, setSelectedClientId] = useState<number | null>(null);
  const [activeSection, setActiveSection] = useState<PanelSection>("filter");

  const clientsQ = useQuery({
    queryKey: ["clients", tenantSlug, "map", "gps"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    queryFn: async () => {
      const { data } = await api.get<{ data: ClientRow[]; total: number }>(
        `/api/${tenantSlug}/clients?page=1&limit=3500&map=1&has_coords=1&sort=name&order=asc`
      );
      return data;
    }
  });

  const refsQ = useQuery({
    queryKey: ["clients", tenantSlug, "references", "map"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<ClientReferencesResponse>(`/api/${tenantSlug}/clients/references`);
      return data;
    }
  });

  const agentsQ = useQuery({
    queryKey: ["agents", tenantSlug, "map"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{
        data: Array<{ id: number; fio: string; login: string; is_active: boolean }>;
      }>(`/api/${tenantSlug}/agents`);
      return data.data.filter((r) => r.is_active).map((r) => ({ id: r.id, name: r.fio, login: r.login }));
    }
  });

  const allClients = clientsQ.data?.data ?? [];
  const gpsTotal = clientsQ.data?.total ?? allClients.length;
  const refData = refsQ.data;

  const cityLabelByValue = useMemo(() => {
    const m: Record<string, string> = {};
    for (const o of refData?.city_options ?? []) {
      if (o?.value) m[o.value] = o.label || o.value;
    }
    return m;
  }, [refData?.city_options]);

  const regionLabelByValue = useMemo(() => {
    const m: Record<string, string> = {};
    for (const o of refData?.region_options ?? []) {
      if (o?.value) m[o.value] = o.label || o.value;
    }
    return m;
  }, [refData?.region_options]);

  const territoryCascade = useMemo(
    () =>
      buildZoneRegionCityCascadeOptions(refData, undefined, undefined, {
        zone: "",
        region: "",
        city: ""
      }),
    [refData]
  );

  const categorySelectOptions = useMemo(() => {
    if (!refData) return [];
    if (refData.category_options?.length) {
      return mergeRefSelectOptions("", refData.category_options, refData.categories);
    }
    return (refData.categories ?? []).map((v: string) => ({ value: v, label: v }));
  }, [refData]);

  const clientTypeSelectOptions = useMemo(() => {
    if (!refData) return [];
    if (refData.client_type_options?.length) {
      return mergeRefSelectOptions("", refData.client_type_options, refData.client_type_codes);
    }
    return (refData.client_type_codes ?? []).map((v: string) => ({ value: v, label: v }));
  }, [refData]);

  const clientTypeLabelByValue = useMemo(() => {
    const m = new Map<string, string>();
    for (const o of clientTypeSelectOptions) {
      m.set(o.value, o.label);
    }
    return m;
  }, [clientTypeSelectOptions]);

  const agentSelectOptions = useMemo(() => {
    const fromApi = (agentsQ.data ?? []).map((a) => ({
      value: String(a.id),
      label: a.name || a.login || `Agent #${a.id}`
    }));
    if (fromApi.length > 0) return fromApi;
    const m = new Map<number, string>();
    for (const c of allClients) {
      if (c.agent_id != null && c.agent_id > 0) {
        m.set(c.agent_id, c.agent_name?.trim() || `Agent #${c.agent_id}`);
      }
    }
    return [...m.entries()]
      .map(([id, label]) => ({ value: String(id), label }))
      .sort((a, b) => a.label.localeCompare(b.label, "ru"));
  }, [agentsQ.data, allClients]);

  const clientsWithGps = useMemo(() => allClients.filter(hasCoords), [allClients]);

  const filteredClients = useMemo(
    () =>
      applyClientMapFilters(clientsWithGps, appliedFilters, {
        regionLabelByValue,
        cityLabelByValue,
        search: appliedSearch
      }),
    [clientsWithGps, appliedFilters, regionLabelByValue, cityLabelByValue, appliedSearch]
  );

  const categoryStats = useMemo(() => computeCategoryCounts(clientsWithGps), [clientsWithGps]);

  const clientsWithCoords: ClientMapPoint[] = useMemo(
    () =>
      filteredClients
        .map((c) => ({
          ...c,
          city: c.city ? cityLabelByValue[c.city] ?? c.city : c.city,
          region: c.region ? regionLabelByValue[c.region] ?? c.region : c.region,
          lat: parseFloat(c.latitude!),
          lon: parseFloat(c.longitude!)
        }))
        .filter((c) => !isNaN(c.lat) && !isNaN(c.lon)),
    [filteredClients, cityLabelByValue, regionLabelByValue]
  );

  const selectedClient = useMemo(
    () => (selectedClientId != null ? clientsWithCoords.find((c) => c.id === selectedClientId) ?? null : null),
    [selectedClientId, clientsWithCoords]
  );

  const selectedClientTypeLabel = useMemo(() => {
    if (!selectedClient?.client_type_code) return undefined;
    return clientTypeLabelByValue.get(selectedClient.client_type_code.trim());
  }, [selectedClient, clientTypeLabelByValue]);

  const handleApplyFilters = useCallback(() => {
    setAppliedFilters({ ...draftFilters });
    setSelectedClientId(null);
  }, [draftFilters]);

  const handleResetFilters = useCallback(() => {
    setDraftFilters(INITIAL_CLIENT_MAP_FILTERS);
    setAppliedFilters(INITIAL_CLIENT_MAP_FILTERS);
    setSearchDraft("");
    setAppliedSearch("");
    setSelectedClientId(null);
  }, []);

  const handleFindOnMap = useCallback(() => {
    setAppliedSearch(searchDraft.trim());
    const q = searchDraft.trim().toLowerCase();
    if (!q) return;
    const found = clientsWithCoords.find(
      (c) =>
        c.name.toLowerCase().includes(q) ||
        (c.address && c.address.toLowerCase().includes(q)) ||
        (c.city && c.city.toLowerCase().includes(q)) ||
        (c.region && c.region.toLowerCase().includes(q))
    );
    if (found) {
      setSelectedClientId(found.id);
      mapControlsRef.current?.flyTo(found.lat, found.lon, 14);
    }
  }, [searchDraft, clientsWithCoords]);

  const onDraftChange = useCallback((patch: Partial<ClientMapFiltersState>) => {
    setDraftFilters((prev) => ({ ...prev, ...patch }));
  }, []);

  const displayedTotal = gpsTotal;

  if (!authHydrated) {
    return (
      <PageShell className="flex flex-1 items-center justify-center bg-transparent">
        <p className="text-sm text-slate-500">Загрузка сессии…</p>
      </PageShell>
    );
  }

  if (!tenantSlug) {
    return (
      <PageShell className="flex flex-1 items-center justify-center bg-transparent">
        <p className="text-sm text-destructive">Tenant не найден.</p>
      </PageShell>
    );
  }

  return (
    <PageShell className="flex min-h-0 flex-1 flex-col bg-transparent p-0 pb-0">
      <div className="shrink-0 px-4 pb-4 pt-5 sm:px-6">
        <h1 className="text-2xl font-bold text-slate-950">Клиенты на карте</h1>
        <p className="mt-1 text-base text-slate-400">
          Отображено клиентов на карте ({clientsQ.isLoading ? "…" : clientsWithCoords.length}
          {displayedTotal !== clientsWithCoords.length ? ` из ${displayedTotal}` : ""})
        </p>
      </div>

      {clientsQ.isLoading ? (
        <div className="flex flex-1 items-center justify-center py-24">
          <p className="text-sm text-slate-500">Загрузка клиентов…</p>
        </div>
      ) : clientsQ.isError ? (
        <div className="flex flex-1 items-center justify-center py-24">
          <p className="text-sm text-destructive">Не удалось загрузить клиентов.</p>
        </div>
      ) : (
        <div className="flex min-h-0 flex-1 flex-col gap-4 overflow-hidden px-4 pb-5 sm:px-6 lg:flex-row">
          <aside className="w-full shrink-0 overflow-hidden rounded-md bg-card shadow-sm lg:w-[300px]">
            <ClientMapPanelHeader
              open={activeSection === "filter"}
              title="Фильтр"
              onClick={() => setActiveSection("filter")}
            />
            {activeSection === "filter" ? (
              <ClientMapFiltersPanel
                draft={draftFilters}
                onDraftChange={onDraftChange}
                onApply={handleApplyFilters}
                onReset={handleResetFilters}
                agentOptions={agentSelectOptions}
                categoryOptions={categorySelectOptions}
                clientTypeOptions={clientTypeSelectOptions}
                zoneOptions={territoryCascade.zones}
                regionOptions={territoryCascade.regions}
                cityOptions={territoryCascade.cities}
              />
            ) : null}

            <ClientMapPanelHeader
              open={activeSection === "category"}
              title="Количество по категориям"
              onClick={() => setActiveSection("category")}
            />
            {activeSection === "category" ? <ClientMapCategoryStats rows={categoryStats} /> : null}
          </aside>

          <section className="relative min-h-[460px] min-w-0 flex-1 overflow-hidden rounded-md bg-muted">
            <ClientMapSearchToolbar
              searchQuery={searchDraft}
              onSearchChange={setSearchDraft}
              onFind={handleFindOnMap}
            />
            <ClientMapBottomLinks />
            <ClientMapZoomControls
              onZoomIn={() => mapControlsRef.current?.zoomIn()}
              onZoomOut={() => mapControlsRef.current?.zoomOut()}
              onReset={() => mapControlsRef.current?.resetView()}
            />

            {clientsWithCoords.length === 0 ? (
              <div className="flex h-full min-h-[460px] items-center justify-center">
                <p className="text-sm text-slate-500">
                  {allClients.length === 0 ? "Клиенты не найдены." : "Нет клиентов по выбранным фильтрам."}
                </p>
              </div>
            ) : (
              <ClientsLeafletMapDynamic
                clients={clientsWithCoords}
                selectedClientId={selectedClientId}
                fillHeight
                hideBuiltinControls
                mapControlsRef={mapControlsRef}
                onClientClick={(c) => setSelectedClientId(c.id)}
              />
            )}

            {selectedClient ? (
              <ClientMapSelectedPanel
                client={selectedClient}
                clientTypeLabel={selectedClientTypeLabel}
                onClose={() => setSelectedClientId(null)}
              />
            ) : null}
          </section>
        </div>
      )}
    </PageShell>
  );
}

"use client";

import { PageHeader } from "@/components/dashboard/page-header";
import { PageShell } from "@/components/dashboard/page-shell";
import { DateRangePopover, formatDateRangeButton } from "@/components/ui/date-range-popover";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { useAuthStore } from "@/lib/auth-store";
import { CalendarDays, Download, Upload } from "lucide-react";
import { useEffect, useRef, useState } from "react";

type ProductRow = { id: number; name: string; sku: string };
type CategoryRow = { id: number; name: string };
type AgentPick = { id: number; fio: string; code: string | null };
type PriceTypeRow = string;
type RefResponse = {
  region_options?: { value: string; label: string }[];
  zones?: string[];
  city_options?: { value: string; label: string }[];
};

type ProductViewRow = {
  stock_date: string;
  client_name: string;
  territory: string;
  agent_name: string | null;
  category_name: string | null;
  product_name: string;
  sku: string;
  quantity: string;
  sold_quantity: string;
  volume: string | null;
  amount: string;
  comment: string | null;
};

type CategoryViewRow = {
  stock_date: string;
  category_name: string;
  quantity: string;
  sold_quantity: string;
  amount: string;
  coverage_clients: number;
};

type ListResponse = {
  view: "products" | "categories";
  page: number;
  limit: number;
  total: number;
  kpi: { base_presence_rate: string; sales_coefficient: string };
  data: ProductViewRow[] | CategoryViewRow[];
};
type UploadResponse = { applied: number; errors: string[] };

function fmtDate(s: string): string {
  try {
    return new Date(s).toLocaleDateString("ru-RU");
  } catch {
    return s;
  }
}

export function RetailStockWorkspace() {
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const [loading, setLoading] = useState(false);
  const [rows, setRows] = useState<ProductViewRow[] | CategoryViewRow[]>([]);
  const [view, setView] = useState<"products" | "categories">("products");
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(30);
  const [total, setTotal] = useState(0);
  const [kpi, setKpi] = useState({ base_presence_rate: "0.00", sales_coefficient: "0.0000" });

  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [dateOpen, setDateOpen] = useState(false);
  const dateAnchorRef = useRef<HTMLButtonElement | null>(null);
  const [agentId, setAgentId] = useState("");
  const [categoryId, setCategoryId] = useState("");
  const [productId, setProductId] = useState("");
  const [priceType, setPriceType] = useState("");
  const [territory1, setTerritory1] = useState("");
  const [territory2, setTerritory2] = useState("");
  const [territory3, setTerritory3] = useState("");

  const [products, setProducts] = useState<ProductRow[]>([]);
  const [categories, setCategories] = useState<CategoryRow[]>([]);
  const [agents, setAgents] = useState<AgentPick[]>([]);
  const [priceTypes, setPriceTypes] = useState<PriceTypeRow[]>([]);
  const [regions, setRegions] = useState<Array<{ value: string; label: string }>>([]);
  const [zones, setZones] = useState<string[]>([]);
  const [cities, setCities] = useState<Array<{ value: string; label: string }>>([]);
  const [uploading, setUploading] = useState(false);
  const [uploadResult, setUploadResult] = useState<UploadResponse | null>(null);
  const fileRef = useRef<HTMLInputElement | null>(null);

  async function load(nextPage = page) {
    if (!tenantSlug) return;
    setLoading(true);
    try {
      const p = new URLSearchParams({
        page: String(nextPage),
        limit: String(limit),
        view
      });
      if (dateFrom) p.set("date_from", dateFrom);
      if (dateTo) p.set("date_to", dateTo);
      if (agentId.trim()) p.set("agent_id", agentId.trim());
      if (categoryId) p.set("category_id", categoryId);
      if (productId) p.set("product_id", productId);
      if (priceType.trim()) p.set("price_type", priceType.trim());
      if (territory1) p.set("territory_1", territory1);
      if (territory2) p.set("territory_2", territory2);
      if (territory3) p.set("territory_3", territory3);
      const { data } = await api.get<ListResponse>(`/api/${tenantSlug}/retail-stock?${p.toString()}`);
      setRows(data.data ?? []);
      setPage(data.page ?? nextPage);
      setTotal(data.total ?? 0);
      setKpi(data.kpi ?? { base_presence_rate: "0.00", sales_coefficient: "0.0000" });
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if (!tenantSlug) return;
    void (async () => {
      const [r1, r2, r3, r4, r5] = await Promise.all([
        api.get<{ data: ProductRow[] }>(`/api/${tenantSlug}/products?page=1&limit=500&is_active=true`),
        api.get<{ data: CategoryRow[] }>(`/api/${tenantSlug}/product-categories`),
        api.get<RefResponse>(`/api/${tenantSlug}/clients/references`),
        api.get<{ data: AgentPick[] }>(`/api/${tenantSlug}/agents?is_active=true`),
        api.get<{ data: PriceTypeRow[] }>(`/api/${tenantSlug}/price-types?kind=sale`)
      ]);
      setProducts(r1.data.data ?? []);
      setCategories(r2.data.data ?? []);
      setRegions(r3.data.region_options ?? []);
      setZones(r3.data.zones ?? []);
      setCities(r3.data.city_options ?? []);
      setAgents(r4.data.data ?? []);
      setPriceTypes(r5.data.data ?? []);
    })();
  }, [tenantSlug]);

  useEffect(() => {
    if (tenantSlug) void load(1);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tenantSlug, view, limit]);

  const totalPages = Math.max(1, Math.ceil(total / limit));

  async function downloadTemplate() {
    if (!tenantSlug) return;
    const res = await api.get(`/api/${tenantSlug}/retail-stock/template`, { responseType: "arraybuffer" });
    const blob = new Blob([res.data], {
      type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "retail-stock-template.xlsx";
    a.click();
    URL.revokeObjectURL(url);
  }

  async function uploadFile(file: File) {
    if (!tenantSlug) return;
    setUploading(true);
    setUploadResult(null);
    try {
      const fd = new FormData();
      fd.append("file", file);
      const { data } = await api.post<UploadResponse>(`/api/${tenantSlug}/retail-stock/upload`, fd);
      setUploadResult(data);
      await load(1);
    } finally {
      setUploading(false);
    }
  }

  async function exportExcel() {
    if (!tenantSlug) return;
    const p = new URLSearchParams({ view });
    if (dateFrom) p.set("date_from", dateFrom);
    if (dateTo) p.set("date_to", dateTo);
    if (agentId.trim()) p.set("agent_id", agentId.trim());
    if (categoryId) p.set("category_id", categoryId);
    if (productId) p.set("product_id", productId);
    if (priceType.trim()) p.set("price_type", priceType.trim());
    if (territory1) p.set("territory_1", territory1);
    if (territory2) p.set("territory_2", territory2);
    if (territory3) p.set("territory_3", territory3);
    const res = await api.get(`/api/${tenantSlug}/retail-stock/export?${p.toString()}`, {
      responseType: "arraybuffer"
    });
    const blob = new Blob([res.data], {
      type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `retail-stock-${view}.xlsx`;
    a.click();
    URL.revokeObjectURL(url);
  }

  const productRows = (rows as ProductViewRow[]) ?? [];
  const categoryRows = (rows as CategoryViewRow[]) ?? [];

  return (
    <PageShell>
      <PageHeader
        title="Остатки в торговых точках"
        description="Retail stock monitoring, shelf presence control, sell-through analytics"
      />

      <div className="grid gap-3 md:grid-cols-2">
        <Card><CardContent className="p-4"><p className="text-xs text-muted-foreground">Базовая представленность</p><p className="text-2xl font-semibold">{kpi.base_presence_rate}%</p></CardContent></Card>
        <Card><CardContent className="p-4"><p className="text-xs text-muted-foreground">Коффициент продажа</p><p className="text-2xl font-semibold">{kpi.sales_coefficient}</p></CardContent></Card>
      </div>

      <Card className="mt-3"><CardContent className="space-y-2 p-3">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <p className="text-sm font-medium">Фильтр</p>
          <div className="flex items-center gap-2">
            <button
              ref={dateAnchorRef}
              type="button"
              className="inline-flex h-9 min-w-[13.5rem] items-center justify-between rounded-md border border-input bg-background px-2.5 text-xs"
              onClick={() => setDateOpen((v) => !v)}
            >
              <span className="truncate">{formatDateRangeButton(dateFrom, dateTo)}</span>
              <CalendarDays className="h-3.5 w-3.5 shrink-0 text-muted-foreground" />
            </button>
            <Button onClick={() => void load(1)} disabled={loading}>Применить</Button>
          </div>
        </div>
        <div className="grid gap-2 md:grid-cols-3 xl:grid-cols-6">
        <select className="h-9 rounded-md border bg-background px-2 text-sm" value={agentId} onChange={(e) => setAgentId(e.target.value)}>
          <option value="">Агент</option>
          {agents.map((a) => <option key={a.id} value={String(a.id)}>{a.fio}</option>)}
        </select>
        <select className="h-9 rounded-md border bg-background px-2 text-sm" value={categoryId} onChange={(e) => setCategoryId(e.target.value)}>
          <option value="">Категория</option>
          {categories.map((c) => <option key={c.id} value={String(c.id)}>{c.name}</option>)}
        </select>
        <select className="h-9 rounded-md border bg-background px-2 text-sm" value={productId} onChange={(e) => setProductId(e.target.value)}>
          <option value="">Продукты</option>
          {products.map((p) => <option key={p.id} value={String(p.id)}>{p.name}</option>)}
        </select>
        <select className="h-9 rounded-md border bg-background px-2 text-sm" value={priceType} onChange={(e) => setPriceType(e.target.value)}>
          <option value="">Тип цены</option>
          {priceTypes.map((pt) => <option key={pt} value={pt}>{pt}</option>)}
        </select>
        <select className="h-9 rounded-md border bg-background px-2 text-sm" value={territory1} onChange={(e) => setTerritory1(e.target.value)}>
          <option value="">Область</option>
          {regions.map((r) => <option key={r.value} value={r.value}>{r.label}</option>)}
        </select>
        <select className="h-9 rounded-md border bg-background px-2 text-sm" value={territory2} onChange={(e) => setTerritory2(e.target.value)}>
          <option value="">Зона</option>
          {zones.map((z) => <option key={z} value={z}>{z}</option>)}
        </select>
        <select className="h-9 rounded-md border bg-background px-2 text-sm" value={territory3} onChange={(e) => setTerritory3(e.target.value)}>
          <option value="">Город</option>
          {cities.map((c) => <option key={c.value} value={c.value}>{c.label}</option>)}
        </select>
        </div>
      </CardContent></Card>

      <Card className="mt-3"><CardContent className="space-y-2 p-3">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <div className="flex gap-2">
            <Button variant={view === "products" ? "default" : "outline"} onClick={() => setView("products")}>По продуктам</Button>
            <Button variant={view === "categories" ? "default" : "outline"} onClick={() => setView("categories")}>По категории</Button>
          </div>
          <div className="flex flex-wrap gap-2">
            <Button variant="outline" onClick={downloadTemplate}>Скачать шаблон</Button>
            <Button variant="outline" onClick={() => fileRef.current?.click()} disabled={uploading}><Upload className="mr-1 h-3.5 w-3.5" />{uploading ? "Загрузка..." : "Загрузить шаблон"}</Button>
            <Button variant="outline" onClick={exportExcel}><Download className="mr-1 h-3.5 w-3.5" />Excel</Button>
            <input ref={fileRef} type="file" accept=".xlsx,.xls" className="hidden" onChange={(e) => { const f = e.target.files?.[0]; if (f) void uploadFile(f); }} />
          </div>
        </div>

        <div className="overflow-x-auto rounded-md border">
          {view === "products" ? (
            <table className="w-full min-w-[1400px] text-sm">
              <thead><tr className="bg-muted/40 text-left text-xs text-muted-foreground">
                <th className="px-3 py-2">Дата</th><th className="px-3 py-2">Клиент</th><th className="px-3 py-2">Территория</th><th className="px-3 py-2">Агент</th><th className="px-3 py-2">Категория продукта</th><th className="px-3 py-2">Продукт</th><th className="px-3 py-2">Код</th><th className="px-3 py-2">Кол-во</th><th className="px-3 py-2">Кол-во (продажа)</th><th className="px-3 py-2">Объем</th><th className="px-3 py-2">Сумма</th><th className="px-3 py-2">Комментарий</th>
              </tr></thead>
              <tbody>
                {loading ? <tr><td colSpan={12} className="px-3 py-8 text-center text-muted-foreground">Загрузка...</td></tr>
                  : productRows.length === 0 ? <tr><td colSpan={12} className="px-3 py-8 text-center text-muted-foreground">Пусто</td></tr>
                  : productRows.map((r, i) => <tr key={`${r.stock_date}-${r.client_name}-${r.product_name}-${i}`} className="border-t">
                    <td className="px-3 py-2 text-xs">{fmtDate(r.stock_date)}</td><td className="px-3 py-2 text-xs">{r.client_name}</td><td className="px-3 py-2 text-xs">{r.territory}</td><td className="px-3 py-2 text-xs">{r.agent_name ?? "—"}</td><td className="px-3 py-2 text-xs">{r.category_name ?? "—"}</td><td className="px-3 py-2 text-xs">{r.product_name}</td><td className="px-3 py-2 text-xs">{r.sku}</td><td className="px-3 py-2 text-xs">{r.quantity}</td><td className="px-3 py-2 text-xs">{r.sold_quantity}</td><td className="px-3 py-2 text-xs">{r.volume ?? "—"}</td><td className="px-3 py-2 text-xs">{r.amount}</td><td className="px-3 py-2 text-xs">{r.comment ?? "—"}</td>
                  </tr>)}
              </tbody>
            </table>
          ) : (
            <table className="w-full min-w-[900px] text-sm">
              <thead><tr className="bg-muted/40 text-left text-xs text-muted-foreground">
                <th className="px-3 py-2">Дата</th><th className="px-3 py-2">Категория</th><th className="px-3 py-2">Кол-во</th><th className="px-3 py-2">Кол-во (продажа)</th><th className="px-3 py-2">Сумма</th><th className="px-3 py-2">Покрытие ТТ</th>
              </tr></thead>
              <tbody>
                {loading ? <tr><td colSpan={6} className="px-3 py-8 text-center text-muted-foreground">Загрузка...</td></tr>
                  : categoryRows.length === 0 ? <tr><td colSpan={6} className="px-3 py-8 text-center text-muted-foreground">Пусто</td></tr>
                  : categoryRows.map((r, i) => <tr key={`${r.stock_date}-${r.category_name}-${i}`} className="border-t">
                    <td className="px-3 py-2 text-xs">{fmtDate(r.stock_date)}</td><td className="px-3 py-2 text-xs">{r.category_name}</td><td className="px-3 py-2 text-xs">{r.quantity}</td><td className="px-3 py-2 text-xs">{r.sold_quantity}</td><td className="px-3 py-2 text-xs">{r.amount}</td><td className="px-3 py-2 text-xs">{r.coverage_clients}</td>
                  </tr>)}
              </tbody>
            </table>
          )}
        </div>
        {uploadResult ? (
          <div className="rounded-md border border-border/70 bg-muted/20 px-3 py-2 text-xs text-muted-foreground">
            <p>Импорт: применено {uploadResult.applied} строк, ошибок: {uploadResult.errors.length}</p>
            {uploadResult.errors.length > 0 ? (
              <div className="mt-1 max-h-24 overflow-auto text-destructive">
                {uploadResult.errors.slice(0, 10).map((e, i) => (
                  <p key={`${i}-${e}`}>• {e}</p>
                ))}
                {uploadResult.errors.length > 10 ? <p>… и ещё {uploadResult.errors.length - 10}</p> : null}
              </div>
            ) : null}
          </div>
        ) : null}
        <div className="flex items-center justify-between text-xs text-muted-foreground">
          <span>Всего: {total} • Стр. {page}/{totalPages}</span>
          <div className="flex gap-2">
            <select className="h-8 rounded-md border bg-background px-2 text-xs" value={String(limit)} onChange={(e) => setLimit(Number(e.target.value))}>
              <option value="10">10</option><option value="20">20</option><option value="30">30</option><option value="50">50</option><option value="100">100</option>
            </select>
            <Button variant="outline" size="sm" disabled={page <= 1} onClick={() => void load(page - 1)}>Назад</Button>
            <Button variant="outline" size="sm" disabled={page >= totalPages} onClick={() => void load(page + 1)}>Вперёд</Button>
          </div>
        </div>
      </CardContent></Card>

      <DateRangePopover
        open={dateOpen}
        onOpenChange={setDateOpen}
        anchorRef={dateAnchorRef}
        dateFrom={dateFrom}
        dateTo={dateTo}
        onApply={({ dateFrom: df, dateTo: dt }) => {
          setDateFrom(df);
          setDateTo(dt);
        }}
      />
    </PageShell>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
