      {/* Info card */}
      {infoClient ? (
        <div className="vp-info vp-glass" style={{ left: infoPos.x, top: infoPos.y }}>
          <div className="vp-info-cover">
            <button className="vp-close-x" onClick={hideInfo}>
              ×
            </button>
            <h3>{infoClient.name}</h3>
            <p>{infoClient.address || "—"}</p>
