          <div className="vp-info-body">
            <div className="vp-info-row">
              <span>Telefon</span>
              <b>{infoClient.phone || "—"}</b>
            </div>
            <div className="vp-info-row">
              <span>Agent</span>
              <b>{agentLabel(infoClient.agent_id)}</b>
            </div>
            <div className="vp-info-row">
              <span>Tashrif kuni</span>
              <b>{clientVisitWeekdays(infoClient).map(weekdayName).join(", ") || "—"}</b>
            </div>
            <div className="vp-info-row">
              <span>Dastavchik</span>
              <b>{clientExpeditorName(infoClient)}</b>
            </div>
            <div className="vp-info-row">
              <span>Holat</span>
              <b style={{ color: clientColor(infoClient) }}>
                {isDebtor(infoClient) ? "Qarzdor" : infoClient.is_active ? "Aktiv" : "Nofaol"}
              </b>
            </div>
            <div className="vp-info-row">
              <span>Balans</span>
              <b>{fmtMoney(clientBalance(infoClient))}</b>
            </div>
            <div className="vp-info-actions">
              <button
                className={`vp-btn ${selectedIds.has(infoClient.id) ? "vp-danger" : "vp-primary"}`}
                onClick={() => toggleSelect(infoClient.id)}
              >
                {selectedIds.has(infoClient.id) ? "Belgilashdan olish" : "Belgilash"}
              </button>
              <button
                className="vp-btn"
                onClick={() =>
                  controlsRef.current?.panTo(parseFloat(infoClient.latitude!), parseFloat(infoClient.longitude!), 15)
                }
              >
                Markazga olish
              </button>
            </div>
          </div>
        </div>
      ) : null}

      {/* Toast */}
      {feedback ? <div className="vp-toast">{feedback}</div> : null}

      <AssignDialog
        kind={assignKind}
        onClose={() => setAssignKind(null)}
        selectedCount={selectedIds.size}
        agentOptions={agentOptions}
        expeditorOptions={expeditorOptions}
        pending={pending}
        onApply={(next) => {
          setPending((prev) => ({ ...prev, ...next }));
          setAssignKind(null);
        }}
      />
    </div>
  );
}

function AssignDialog({
  kind,
  onClose,
  selectedCount,
  agentOptions,
  expeditorOptions,
  pending,
  onApply
}: {
  kind: AssignKind | null;
  onClose: () => void;
  selectedCount: number;
  agentOptions: PickOption[];
  expeditorOptions: PickOption[];
  pending: PendingState;
  onApply: (next: Partial<PendingState>) => void;
}) {
  const [single, setSingle] = useState<string | null>(null);
  const [days, setDays] = useState<number[]>([]);

  useEffect(() => {
    if (!kind) return;
    if (kind === "agent") setSingle(pending.agentId);
    if (kind === "expeditor") setSingle(pending.expeditorId);
    if (kind === "days") setDays(pending.weekdays ?? []);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [kind]);

  const open = kind != null;
  const title =
    kind === "agent" ? "Agentni tanlash" : kind === "expeditor" ? "Dastavchikni tanlash" : "Tashrif kunlarini tanlash";
  const desc =
    kind === "days"
      ? "Bir nechta hafta kunini tanlash mumkin."
      : `Belgilangan klientlarga (${selectedCount}) bog‘lanadi.`;

  const options = kind === "agent" ? agentOptions : kind === "expeditor" ? expeditorOptions : [];
  const selectedSet = useMemo(() => new Set(single ? [single] : []), [single]);

  const handleApply = () => {
    if (kind === "agent") onApply({ agentId: single });
    else if (kind === "expeditor") onApply({ expeditorId: single });
    else if (kind === "days") onApply({ weekdays: days.length ? [...days].sort((a, b) => a - b) : null });
  };

  return (
    <Dialog open={open} onOpenChange={(v) => !v && onClose()}>
      <DialogContent className="z-[3000] flex max-h-[80vh] flex-col sm:max-w-lg">
        <DialogHeader>
          <DialogTitle>{title}</DialogTitle>
          <DialogDescription>{desc}</DialogDescription>
        </DialogHeader>

        {kind === "days" ? (
          <div className="flex flex-wrap gap-2 py-2">
            {WEEKDAYS.map((d) => (
              <button
                key={d.value}
                type="button"
                onClick={() =>
                  setDays((prev) =>
                    prev.includes(d.value) ? prev.filter((x) => x !== d.value) : [...prev, d.value]
                  )
                }
                className={`h-9 rounded-lg border px-3 text-sm font-semibold transition ${
                  days.includes(d.value)
                    ? "border-[#2563eb] bg-[#2563eb] text-white"
                    : "border-border bg-card text-slate-600 hover:border-[#2563eb]"
                }`}
              >
                {d.name}
              </button>
            ))}
          </div>
        ) : (
          <div className="min-h-0 flex-1 overflow-hidden py-1">
            <SearchablePickList
              options={options}
              selected={selectedSet}
              single
              onToggle={(v) => setSingle((prev) => (prev === v ? null : v))}
              searchPlaceholder={kind === "agent" ? "Agent qidirish…" : "Dastavchik qidirish…"}
              maxHeightClass="max-h-[52vh]"
            />
          </div>
        )}

        <DialogFooter className="gap-2 sm:gap-2">
          {kind !== "days" ? (
            <Button type="button" variant="outline" onClick={() => setSingle(null)}>
              Tanlovni tozalash
            </Button>
          ) : (
            <Button type="button" variant="outline" onClick={() => setDays([])}>
              Tozalash
            </Button>
          )}
          <Button type="button" variant="outline" onClick={onClose}>
            Bekor qilish
          </Button>
          <Button type="button" onClick={handleApply} className="bg-[#2563eb] hover:bg-[#1d4ed8]">
            Qo‘shish
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useEffect, useRef, type MutableRefObject } from "react";

export type VisitMapPoint = {
  id: number;
  lat: number;
  lon: number;
  name: string;
  color: string;
  initial: string;
};

export type VisitMapControls = {
  zoomIn: () => void;
  zoomOut: () => void;
  fitAll: () => void;
  panTo: (lat: number, lon: number, zoom?: number) => void;
  /** Koordinatani xarita konteyneriga nisbatan piksellarga o'giradi (lasso uchun). */
  project: (lat: number, lon: number) => { x: number; y: number } | null;
  setLassoActive: (active: boolean) => void;
};

type YEvent = { stopPropagation?: () => void };
type YProjection = { toGlobalPixels: (coords: [number, number], zoom: number) => [number, number] };
type YMapFull = {
  destroy: () => void;
  geoObjects: { add: (o: unknown) => void; removeAll: () => void };
  events: { add: (n: string, fn: (e: YEvent) => void) => void };
  behaviors: { enable: (n: string) => void; disable: (n: string) => void };
  options: { get: (k: string) => YProjection };
  converter: { globalToPage: (g: [number, number]) => [number, number] };
  getZoom: () => number;
  setZoom: (z: number, opts?: Record<string, unknown>) => void;
  panTo: (c: [number, number], opts?: Record<string, unknown>) => void;
  setBounds: (b: [[number, number], [number, number]], opts?: Record<string, unknown>) => void;
};
type YPlacemarkFull = {
  properties: { set: (o: Record<string, unknown>) => void };
  options: { set: (k: string, v: unknown) => void };
  events: { add: (n: string, fn: (e: YEvent) => void) => void };
};
type YClustererFull = {
  add: (items: unknown[]) => void;
  removeAll: () => void;
  options: { set: (k: string, v: unknown) => void };
};
type YmapsFull = {
  ready: (cb: () => void) => void;
  Map: new (el: HTMLElement, state: Record<string, unknown>, opts?: Record<string, unknown>) => YMapFull;
  Placemark: new (
    coords: [number, number],
    props?: Record<string, unknown>,
    opts?: Record<string, unknown>
  ) => YPlacemarkFull;
  Clusterer?: new (opts?: Record<string, unknown>) => YClustererFull;
  templateLayoutFactory: { createClass: (tpl: string) => unknown };
  util: { bounds: { fromPoints: (pts: [number, number][]) => [[number, number], [number, number]] } };
};

const YANDEX_LANG = "ru_RU";

function loadYmaps(): Promise<YmapsFull> {
  if (typeof window === "undefined") return Promise.reject(new Error("NoWindow"));
  if (window.ymaps) return Promise.resolve(window.ymaps as unknown as YmapsFull);
  if (window.__ymapsLoaderPromise) return window.__ymapsLoaderPromise as unknown as Promise<YmapsFull>;

  const rawKey = process.env.NEXT_PUBLIC_YANDEX_MAPS_API_KEY?.trim();
  const forceNoKey =
    process.env.NEXT_PUBLIC_YANDEX_MAPS_NO_API_KEY === "1" ||
    process.env.NEXT_PUBLIC_YANDEX_MAPS_NO_API_KEY === "true";
  const key =
    forceNoKey || !rawKey || rawKey === "undefined" || rawKey === "null" || rawKey.length < 10 ? "" : rawKey;
  const src = key
    ? `https://api-maps.yandex.ru/2.1/?apikey=${encodeURIComponent(key)}&lang=${YANDEX_LANG}`
    : `https://api-maps.yandex.ru/2.1/?lang=${YANDEX_LANG}`;

  const promise = new Promise<YmapsFull>((resolve, reject) => {
    const existing = document.querySelector<HTMLScriptElement>('script[data-yandex-maps="1"]');
    const onLoad = () => {
      if (window.ymaps) {
        (window.ymaps as unknown as YmapsFull).ready(() => resolve(window.ymaps as unknown as YmapsFull));
      } else reject(new Error("YandexMapsUnavailable"));
    };
    if (existing) {
      existing.addEventListener("load", onLoad);
      existing.addEventListener("error", () => reject(new Error("YandexMapsScriptError")));
      return;
    }
    const script = document.createElement("script");
    script.src = src;
    script.async = true;
    script.dataset.yandexMaps = "1";
    script.onload = onLoad;
    script.onerror = () => reject(new Error("YandexMapsScriptError"));
    document.head.appendChild(script);
  });
  window.__ymapsLoaderPromise = promise as unknown as Promise<never>;
  return promise;
}

/** «Клиенты на карте» dagi kabi standart Yandex iconka (teardrop pin). */
const MARKER_PRESET = "islands#blueIcon";
/** Belgilangan (tanlangan) klient uchun ajralib turadigan rang. */
const MARKER_SELECTED_COLOR = "#2563eb";

export function VisitPlannerYandexMap({
  points,
  selectedIds,
  clickSelectMode,
  onToggle,
  onInfo,
  onMapClick,
  controlsRef,
  onError
}: {
  points: VisitMapPoint[];
  selectedIds: Set<number>;
  clickSelectMode: boolean;
  onToggle: (id: number) => void;
  onInfo: (id: number) => void;
  onMapClick: () => void;
  controlsRef: MutableRefObject<VisitMapControls | null>;
  onError?: (message: string) => void;
}) {
  const hostRef = useRef<HTMLDivElement | null>(null);
  const ymapsRef = useRef<YmapsFull | null>(null);
  const mapRef = useRef<YMapFull | null>(null);
  const markersRef = useRef<Map<number, YPlacemarkFull>>(new Map());
  const markerColorRef = useRef<Map<number, string>>(new Map());
  const clustererRef = useRef<YClustererFull | null>(null);
  const didFitRef = useRef(false);

  // Eng so'nggi qiymatlar (xarita qayta yaratilmasdan handlerlarda ishlatish uchun)
  const pointsRef = useRef(points);
  const selectedRef = useRef(selectedIds);
  const clickModeRef = useRef(clickSelectMode);
  const cbRef = useRef({ onToggle, onInfo, onMapClick });
  pointsRef.current = points;
  selectedRef.current = selectedIds;
  clickModeRef.current = clickSelectMode;
  cbRef.current = { onToggle, onInfo, onMapClick };

  // Xaritani bir marta yaratish
  useEffect(() => {
    let cancelled = false;
    const host = hostRef.current;
    if (!host) return;

    void loadYmaps()
      .then((ymaps) => {
        if (cancelled || !host) return;
        ymaps.ready(() => {
          if (cancelled || !host || mapRef.current) return;
          ymapsRef.current = ymaps;
          const map = new ymaps.Map(
            host,
            { center: [41.3111, 69.2797], zoom: 11, controls: ["typeSelector", "fullscreenControl"] },
            { suppressMapOpenBlock: true, yandexMapDisablePoiInteractivity: true }
          );
          mapRef.current = map;
          map.events.add("click", () => cbRef.current.onMapClick());
          map.events.add("boundschange", () => cbRef.current.onMapClick());
          buildControls();
          renderMarkers();
          fitAll();
        });
      })
      .catch(() => onError?.("Yandex Maps yuklanmadi. Internet yoki API kalitni tekshiring."));

    return () => {
      cancelled = true;
      try {
        mapRef.current?.destroy();
      } catch {
        /* ignore */
      }
      mapRef.current = null;
      markersRef.current.clear();
      clustererRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  function project(lat: number, lon: number): { x: number; y: number } | null {
    const map = mapRef.current;
    const host = hostRef.current;
    if (!map || !host) return null;
    try {
      const projection = map.options.get("projection");
      const global = projection.toGlobalPixels([lat, lon], map.getZoom());
      const page = map.converter.globalToPage(global);
      const rect = host.getBoundingClientRect();
      return { x: page[0] - (rect.left + window.scrollX), y: page[1] - (rect.top + window.scrollY) };
    } catch {
      return null;
    }
  }

  function fitAll() {
    const map = mapRef.current;
    const ymaps = ymapsRef.current;
    if (!map || !ymaps) return;
    const pts = pointsRef.current.map((p) => [p.lat, p.lon] as [number, number]);
    if (pts.length === 0) return;
    try {
      map.setBounds(ymaps.util.bounds.fromPoints(pts), {
        checkZoomRange: true,
        zoomMargin: [80, 340, 120, 360]
      });
    } catch {
      /* ignore */
    }
  }

  function buildControls() {
    controlsRef.current = {
      zoomIn: () => mapRef.current && mapRef.current.setZoom(mapRef.current.getZoom() + 1, { duration: 150 }),
      zoomOut: () => mapRef.current && mapRef.current.setZoom(mapRef.current.getZoom() - 1, { duration: 150 }),
      fitAll,
      panTo: (lat, lon, zoom) => {
        const map = mapRef.current;
        if (!map) return;
        map.panTo([lat, lon], { duration: 280 });
        if (zoom) map.setZoom(zoom, { duration: 280 });
      },
      project,
      setLassoActive: (active) => {
        const map = mapRef.current;
        if (!map) return;
        if (active) map.behaviors.disable("drag");
        else map.behaviors.enable("drag");
      }
    };
  }

  /** «Клиенты на карте» dagi kabi klasterer (masshtabga qarab nuqtalarni soni bilan birlashtiradi). */
  function ensureClusterer(): YClustererFull | null {
    const map = mapRef.current;
    const ymaps = ymapsRef.current;
    if (!map || !ymaps || !ymaps.Clusterer) return null;
    if (!clustererRef.current) {
      const clusterer = new ymaps.Clusterer({
        preset: "islands#blueClusterIcons",
        groupByCoordinates: false,
        clusterDisableClickZoom: false,
        clusterOpenBalloonOnClick: false,
        gridSize: 64
      });
      clustererRef.current = clusterer;
      map.geoObjects.add(clusterer);
    }
    return clustererRef.current;
  }

  function renderMarkers() {
    const map = mapRef.current;
    const ymaps = ymapsRef.current;
    if (!map || !ymaps) return;
    const clusterer = ensureClusterer();
    if (clusterer) clusterer.removeAll();
    else map.geoObjects.removeAll();
    markersRef.current.clear();
    markerColorRef.current.clear();
    const marks: unknown[] = [];
    for (const p of pointsRef.current) {
      const selected = selectedRef.current.has(p.id);
      markerColorRef.current.set(p.id, p.color);
      const placemark = new ymaps.Placemark(
        [p.lat, p.lon],
        { hintContent: p.name },
        {
          preset: MARKER_PRESET,
          iconColor: selected ? MARKER_SELECTED_COLOR : p.color,
          zIndex: selected ? 999 : 20
        }
      );
      placemark.events.add("click", (e) => {
        e.stopPropagation?.();
        if (clickModeRef.current) cbRef.current.onToggle(p.id);
        else cbRef.current.onInfo(p.id);
      });
      placemark.events.add("contextmenu", (e) => {
        e.stopPropagation?.();
        cbRef.current.onToggle(p.id);
      });
      markersRef.current.set(p.id, placemark);
      marks.push(placemark);
    }
    if (clusterer) clusterer.add(marks);
    else for (const m of marks) map.geoObjects.add(m);
  }

  // Nuqtalar to'plami o'zgarsa — markerlarni qayta quramiz
  const pointsKey = points.map((p) => `${p.id}:${p.color}`).join("|");
  useEffect(() => {
    if (!mapRef.current) return;
    renderMarkers();
    if (!didFitRef.current && points.length > 0) {
      didFitRef.current = true;
      fitAll();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pointsKey]);

  // Tanlanganlar o'zgarsa — faqat marker rangi/holatini yangilaymiz
  useEffect(() => {
    for (const [id, marker] of markersRef.current) {
      const selected = selectedIds.has(id);
      marker.options.set("iconColor", selected ? MARKER_SELECTED_COLOR : (markerColorRef.current.get(id) ?? "#16a34a"));
      marker.options.set("zIndex", selected ? 999 : 20);
    }
  }, [selectedIds]);

  return <div ref={hostRef} className="vp-map" id="vp-map" />;
}

"use client";

import { FinanceSectionHeader } from "@/components/dashboard/finance/finance-section-header";
import { fmtFinanceCount, fmtFinanceMoney } from "@/components/dashboard/finance/format";
import type { FinanceTableColumn } from "@/components/dashboard/finance/table-columns";
import { Download, Search } from "lucide-react";
import { useEffect, useMemo, useState } from "react";

export type { FinanceTableColumn };
export { categoryTableColumns, territoryTableColumns } from "@/components/dashboard/finance/table-columns";

type SortDir = "asc" | "desc";

function sortRows<T>(
  rows: T[],
  columns: FinanceTableColumn<T>[],
  key: string,
  direction: SortDir
): T[] {
  const column = columns.find((c) => c.id === key) ?? columns[0];
  if (!column) return rows;
  return [...rows].sort((a, b) => {
    const first = column.sortValue ? column.sortValue(a) : String(column.value(a));
    const second = column.sortValue ? column.sortValue(b) : String(column.value(b));
    const mul = direction === "asc" ? 1 : -1;
    if (typeof first === "number" && typeof second === "number") return (first - second) * mul;
    return String(first).localeCompare(String(second), "ru") * mul;
  });
}

function escapeCsv(value: string | number) {
  const text = String(value).replace(/"/g, '""');
  return `"${text}"`;
}

function exportCsv<T>(fileName: string, columns: FinanceTableColumn<T>[], rows: T[]) {
  const header = columns.map((c) => escapeCsv(c.label)).join(",");
  const body = rows
    .map((row) =>
      columns.map((c) => escapeCsv(c.csvValue ? c.csvValue(row) : String(c.value(row)))).join(",")
    )
    .join("\n");
  const blob = new Blob([`${header}\n${body}`], { type: "text/csv;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = fileName;
  link.click();
  URL.revokeObjectURL(url);
}

function SortIcon({ active, direction }: { active: boolean; direction: SortDir }) {
  return (
    <span className={`text-[10px] ${active ? "text-teal-600" : "text-slate-300"}`}>
      {direction === "asc" ? "▲" : "▼"}
    </span>
  );
}

function FinanceTablePagination({
  page,
  pageCount,
  pageSize,
  total,
  onPageChange
}: {
  page: number;
  pageCount: number;
  pageSize: number;
  total: number;
  onPageChange: (page: number) => void;
}) {
  const start = total === 0 ? 0 : (page - 1) * pageSize + 1;
  const end = Math.min(page * pageSize, total);
  const pages = Array.from(new Set([1, page - 1, page, page + 1, pageCount])).filter(
    (value) => value >= 1 && value <= pageCount
  );

  return (
    <div className="mt-3 flex flex-col gap-3 text-sm font-medium text-slate-500 sm:flex-row sm:items-center sm:justify-between">
      <span>
        Показано {fmtFinanceCount(start)} - {fmtFinanceCount(end)} / {fmtFinanceCount(total)}
      </span>
      <div className="flex flex-wrap items-center gap-2">
        <button
          type="button"
          className="rounded-lg px-3 py-2 text-slate-500 hover:bg-muted"
          onClick={() => onPageChange(Math.max(1, page - 1))}
        >
          ‹
        </button>
        {pages.map((item, index) => {
          const previous = pages[index - 1];
          return (
            <span key={item} className="flex items-center gap-2">
              {previous && item - previous > 1 ? <span className="px-1 text-slate-400">...</span> : null}
              <button
                type="button"
                className={`h-9 min-w-9 rounded-lg px-3 font-bold transition ${
                  item === page
                    ? "bg-teal-600 text-white"
                    : "border border-border text-slate-700 hover:border-teal-300"
                }`}
                onClick={() => onPageChange(item)}
              >
                {item}
              </button>
            </span>
          );
        })}
        <button
          type="button"
          className="rounded-lg px-3 py-2 text-slate-500 hover:bg-muted"
          onClick={() => onPageChange(Math.min(pageCount, page + 1))}
        >
          ›
        </button>
      </div>
    </div>
  );
}

export function FinanceDataTable<T>({
  title,
  subtitle,
  data,
  columns,
  totals,
  searchKeys,
  exportFileName,
  minWidth
}: {
  title: string;
  subtitle?: string;
  data: T[];
  columns: FinanceTableColumn<T>[];
  totals?: Record<string, string>;
  searchKeys: Array<(row: T) => string>;
  exportFileName: string;
  minWidth: number;
}) {
  const [query, setQuery] = useState("");
  const [pageSize, setPageSize] = useState(10);
  const [page, setPage] = useState(1);
  const [sort, setSort] = useState<{ key: string; direction: SortDir }>({
    key: columns[0]?.id ?? "",
    direction: "asc"
  });

  const filtered = useMemo(() => {
    const normalized = query.trim().toLowerCase();
    if (!normalized) return data;
    return data.filter((row) => searchKeys.some((acc) => acc(row).toLowerCase().includes(normalized)));
  }, [data, query, searchKeys]);

  const sorted = useMemo(
    () => sortRows(filtered, columns, sort.key, sort.direction),
    [filtered, columns, sort]
  );
  const pageCount = Math.max(1, Math.ceil(sorted.length / pageSize));
  const safePage = Math.min(page, pageCount);
  const visibleRows = sorted.slice((safePage - 1) * pageSize, safePage * pageSize);

  useEffect(() => {
    setPage(1);
  }, [query, pageSize, data]);

  const handleSort = (key: string) => {
    setSort((cur) => ({
      key,
      direction: cur.key === key && cur.direction === "asc" ? "desc" : "asc"
    }));
  };

  return (
    <section className="rounded-2xl bg-card p-5 shadow-sm ring-1 ring-slate-200/70">
      <FinanceSectionHeader title={title} subtitle={subtitle} />
      <div className="mb-3 flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
        <div className="flex flex-wrap items-center gap-2">
          <button
            type="button"
            className="inline-flex h-10 items-center gap-2 rounded-lg border border-border bg-card px-3 text-sm font-semibold text-slate-700 transition hover:border-teal-300 hover:text-teal-700"
            onClick={() => exportCsv(exportFileName, columns, sorted)}
          >
            <Download className="h-4 w-4 text-emerald-600" />
            Excel
          </button>
          <select
            value={pageSize}
            onChange={(e) => setPageSize(Number(e.target.value))}
            className="h-10 rounded-lg border border-border bg-card px-3 text-sm font-semibold text-slate-700 outline-none focus:border-teal-500"
          >
            {[10, 20, 50].map((n) => (
              <option key={n} value={n}>
                {n}
              </option>
            ))}
          </select>
        </div>
        <label className="relative w-full lg:w-[320px]">
          <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
          <input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Поиск"
            className="h-10 w-full rounded-lg border border-border bg-card pl-9 pr-3 text-sm font-medium outline-none transition focus:border-teal-500 focus:ring-4 focus:ring-teal-100"
          />
        </label>
      </div>
      <div className="overflow-hidden rounded-xl border border-border">
        <div className="max-h-[560px] overflow-auto">
          <table className="w-full border-collapse text-sm" style={{ minWidth }}>
            <thead className="sticky top-0 z-10 bg-muted text-xs uppercase tracking-wide text-slate-500">
              <tr>
                {columns.map((col) => (
                  <th
                    key={col.id}
                    className={`border-b border-border px-3 py-3 text-right font-bold ${col.className ?? ""}`}
                  >
                    <button
                      type="button"
                      className="inline-flex items-center gap-1"
                      onClick={() => handleSort(col.id)}
                    >
                      {col.label}
                      <SortIcon active={sort.key === col.id} direction={sort.direction} />
                    </button>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {visibleRows.map((row, i) => (
                <tr
                  key={i}
                  className="border-b border-border/80 text-slate-700 transition hover:bg-teal-50/45"
                >
                  {columns.map((col) => (
                    <td
                      key={col.id}
                      className={`px-3 py-3 text-right tabular-nums ${col.className ?? ""}`}
                    >
                      {col.value(row)}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
            {totals ? (
              <tfoot className="sticky bottom-0 bg-muted font-black text-slate-700">
                <tr>
                  {columns.map((col) => (
                    <td
                      key={col.id}
                      className={`border-t border-border px-3 py-3 text-right tabular-nums ${col.className ?? ""}`}
                    >
                      {totals[col.id] ?? ""}
                    </td>
                  ))}
                </tr>
              </tfoot>
            ) : null}
          </table>
        </div>
      </div>
      <FinanceTablePagination
        page={safePage}
        pageCount={pageCount}
        pageSize={pageSize}
        total={sorted.length}
        onPageChange={setPage}
      />
    </section>
  );
}

