  } as const;
}

export type OrderCreateVm = ReturnType<typeof useOrderCreate>;

"use client";

import { Fragment } from "react";
import { ChevronDown, ChevronRight } from "lucide-react";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import { formatNumberGrouped } from "@/lib/format-numbers";
import type { PolkiLinesTableProps, PolkiPairRowModel } from "./types";
import { POLKI_TABLE_COLS } from "./constants";
import { formatPolkiPieceQty, polkiRowMaxReturnQty, polkiSplitTotal } from "./utils";
import { parsePolkiQty } from "./polki-bonus-balance.logic";
import { PolkiReturnBonusSummary } from "./polki-return-bonus-summary";
import { PolkiManualPeresortSelect } from "./view/polki-shelf-return/polki-manual-peresort-select";
import type { PolkiBonusCalcMode } from "./view/polki-shelf-return/polki-bonus-calc";

export function PolkiReturnLinesTable({
  canShowPolkiGrid,
  isPolkiByOrder,
  isPolkiFree,
  groupLinesByOrder = true,
  polkiLoading,
  polkiError,
  polkiSuccess,
  polkiRowsAllLength,
  polkiOrderGroups,
  polkiTotalQty,
  setPolkiTotalQty,
  polkiBonusToBalance,
  setPolkiBonusToBalance,
  polkiBonusCash,
  setPolkiBonusCash,
  mutationPending,
  polkiTotalReturnQtySum,
  polkiVolumeM3,
  polkiEstimatedSum,
  polkiDebtHintSum,
  polkiExpandedOrderId = null,
  setPolkiExpandedOrderId,
  polkiPeresortByPairKey = {},
  setPolkiPeresortByPairKey,
  polkiPeresortOptionsByProductId,
  polkiAutoBonusExplicitByPairKey = {},
  polkiAutoBonusDebtByPairKey = {},
  polkiAutoBonusPreviewLinesByProductId,
  polkiAutoBonusPreviewPending = false,
  polkiAutoBonusPreviewError = false,
  polkiBonusCalcMode = "auto"
}: PolkiLinesTableProps) {
  const polkiUsesAutoBonus = isPolkiFree || isPolkiByOrder;
  const tableColCount = groupLinesByOrder ? POLKI_TABLE_COLS : POLKI_TABLE_COLS - 1;
  const flatRowCount = polkiOrderGroups.reduce((a, g) => a + g.rows.length, 0);

  const toggleOrderGroup = (orderId: number) => {
    if (!setPolkiExpandedOrderId) return;
    setPolkiExpandedOrderId((prev) => (prev === orderId ? null : orderId));
  };

  return (
    <div className="overflow-hidden rounded-lg border border-teal-800/20 bg-card shadow-sm dark:border-teal-800/35">
      <div className="max-h-[min(75vh,920px)] min-h-[220px] overflow-auto">
        <table className="w-full min-w-[860px] border-collapse text-sm">
          <thead className="app-table-thead sticky top-0 z-[1] backdrop-blur-sm">
            <tr className="text-left text-xs font-semibold uppercase tracking-wide text-muted-foreground">
              {groupLinesByOrder ? <th className="min-w-[5rem] px-2 py-1.5">Заказ</th> : null}
              <th className="min-w-[9rem] px-2 py-1.5">Товар</th>
              <th
                className="min-w-[13rem] px-2 py-1.5"
                title={
                  polkiUsesAutoBonus
                    ? "Введите «всего к возврату» по строке (не больше «макс. всего»). Система разделит оплату и бонус по заказу; недостающий бонус — долг на баланс клиента."
                    : "Введите общее количество по строке (не больше «макс. всего» по заказу)."
                }
              >
                Дата · всего к возврату
              </th>
              <th
                className="min-w-[18rem] px-2 py-1.5"
                title="Бонус на склад, пересорт или сумма на баланс клиента"
              >
                Бонус / баланс
              </th>
              <th className="min-w-[3.5rem] px-2 py-1.5 text-right">m³</th>
            </tr>
          </thead>
          <tbody>
            {!canShowPolkiGrid ? (
              <tr>
                <td
                  colSpan={tableColCount}
                  className="px-3 py-8 text-center text-xs text-muted-foreground"
                >
                  Выберите клиента
                  {isPolkiByOrder ? " и отметьте заказы справа" : ""}.
                </td>
              </tr>
            ) : null}
            {canShowPolkiGrid && polkiLoading ? (
              <tr>
                <td
                  colSpan={tableColCount}
                  className="px-3 py-8 text-center text-sm text-muted-foreground"
                >
                  Загрузка контекста возврата…
                </td>
              </tr>
            ) : null}
            {canShowPolkiGrid && polkiError ? (
              <tr>
                <td
                  colSpan={tableColCount}
                  className="px-3 py-8 text-center text-sm text-destructive"
                >
                  Не удалось загрузить данные. Проверьте параметры и попробуйте снова.
                </td>
              </tr>
            ) : null}
            {canShowPolkiGrid && polkiSuccess && polkiRowsAllLength === 0 ? (
              <tr>
                <td
                  colSpan={tableColCount}
                  className="px-3 py-8 text-center text-xs text-muted-foreground"
                >
                  Нет позиций для возврата. Проверьте доставленные заказы клиента или снимите фильтр категории.
                </td>
              </tr>
            ) : null}
            {canShowPolkiGrid && polkiSuccess && polkiRowsAllLength > 0
              ? polkiOrderGroups.map((g) => {
                  const isOpen = groupLinesByOrder ? polkiExpandedOrderId === g.orderId : true;
                  const renderRow = (r: PolkiPairRowModel) => {
                      const pk = r.pair_key;
                      const totalRaw = polkiTotalQty[pk] ?? "";
                      const totalQ = parsePolkiQty(totalRaw);
                      const maxTot = polkiRowMaxReturnQty(r);
                      const totalOver = Boolean(totalRaw.trim()) && totalQ > maxTot;
                      const explicit = polkiUsesAutoBonus
                        ? polkiAutoBonusExplicitByPairKey[pk]
                        : undefined;
                      const previewLine = polkiUsesAutoBonus
                        ? polkiAutoBonusPreviewLinesByProductId?.get(r.product_id)
                        : undefined;
                      const { effPaid, effBonus } = explicit
                        ? { effPaid: explicit.paid, effBonus: explicit.bonus }
                        : polkiSplitTotal(r, totalQ);
                      const physBonus = effBonus;
                      const volU =
                        r.volume_m3 != null ? Number.parseFloat(String(r.volume_m3)) : NaN;
                      const lineVol =
                        Number.isFinite(volU) && effPaid + physBonus > 0
                          ? (effPaid + physBonus) * volU
                          : 0;
                      return (
                        <tr
                          key={pk}
                          className="border-b border-border/80 last:border-0 hover:bg-muted/25"
                        >
                          {groupLinesByOrder ? (
                            <td className="px-2 py-1.5 align-top font-mono text-[11px] text-muted-foreground">
                              #{r.order_id}
                            </td>
                          ) : null}
                          <td className="px-2 py-1.5 align-top">
                            <div className="font-medium leading-snug text-foreground text-[13px]">
                              {r.name}
                            </div>
                            <div className="mt-0.5 font-mono text-[11px] text-muted-foreground">
                              {[r.sku, r.unit].filter(Boolean).join(" · ")}
                            </div>
                          </td>
                          <td className="px-2 py-1.5 align-top">
                            <div className="mb-1 text-[11px] text-muted-foreground">
                              {groupLinesByOrder ? (
                                <>
                                  Продажа:{" "}
                                  <span className="font-medium text-foreground">{g.orderDate}</span>
                                </>
                              ) : null}
                              {r.unit_price_paid > 0 ? (
                                <span className="ml-1 tabular-nums">
                                  · {formatNumberGrouped(r.unit_price_paid, { maxFractionDigits: 2 })}
                                </span>
                              ) : null}
                            </div>
                            <div className="text-[10px] text-muted-foreground">
                              макс всего {formatNumberGrouped(maxTot, { maxFractionDigits: 0 })} шт (опл.{" "}
                              {formatNumberGrouped(r.max_paid, { maxFractionDigits: 0 })} + бон.{" "}
                              {formatNumberGrouped(r.max_bonus, { maxFractionDigits: 0 })})
                            </div>
                            <Input
                              type="number"
                              min={0}
                              step={1}
                              inputMode="numeric"
                              placeholder="0"
                              data-testid="oc-polki-total-qty"
                              data-oc-product-id={r.product_id}
                              className={cn(
                                "mt-1 h-8 w-full max-w-[7rem] tabular-nums text-sm",
                                totalOver && "border-destructive"
                              )}
                              value={totalRaw}
                              onChange={(e) => {
                                const raw = e.target.value.trim();
                                if (!raw) {
                                  setPolkiTotalQty((prev) => ({ ...prev, [pk]: "" }));
                                  return;
                                }
                                const digitsOnly = raw.replace(/[^\d]/g, "");
                                if (!digitsOnly) {
                                  setPolkiTotalQty((prev) => ({ ...prev, [pk]: "" }));
                                  return;
                                }
                                const n = parsePolkiQty(digitsOnly);
                                if (n > maxTot) {
                                  setPolkiTotalQty((prev) => ({
                                    ...prev,
                                    [pk]: formatPolkiPieceQty(maxTot)
                                  }));
                                  return;
                                }
                                setPolkiTotalQty((prev) => ({ ...prev, [pk]: digitsOnly }));
                              }}
                              onBlur={() => {
                                if (!totalRaw.trim()) return;
                                const n = parsePolkiQty(totalRaw);
                                if (n <= 0) {
                                  setPolkiTotalQty((prev) => ({ ...prev, [pk]: "" }));
                                  return;
                                }
                                const capped = n > maxTot ? maxTot : n;
                                setPolkiTotalQty((prev) => ({
                                  ...prev,
                                  [pk]: formatPolkiPieceQty(capped)
                                }));
                              }}
                              disabled={mutationPending || maxTot <= 0}
                            />
                          </td>
                          <td className="px-2 py-1.5 align-top">
                            {polkiUsesAutoBonus ? (
                              <>
                                <PolkiReturnBonusSummary
                                  row={r}
                                  pairKey={pk}
                                  polkiTotalQty={polkiTotalQty}
                                  explicit={explicit}
                                  previewLine={previewLine}
                                  previewDebtAmount={polkiAutoBonusDebtByPairKey[pk]}
                                  previewPending={polkiAutoBonusPreviewPending}
                                  previewError={polkiAutoBonusPreviewError}
                                />
                                {isPolkiByOrder &&
                                polkiBonusCalcMode === "manual" &&
                                setPolkiPeresortByPairKey ? (
                                  <PolkiManualPeresortSelect
                                    row={r}
                                    pairKey={pk}
                                    effBonus={effBonus}
                                    value={polkiPeresortByPairKey[pk]}
                                    disabled={mutationPending}
                                    optionsByProductId={polkiPeresortOptionsByProductId}
                                    onChange={(pkey, pid) =>
                                      setPolkiPeresortByPairKey((prev) => ({
                                        ...prev,
                                        [pkey]: pid
                                      }))
                                    }
                                  />
                                ) : null}
                              </>
                            ) : null}
                          </td>
                          <td className="px-2 py-1.5 text-right tabular-nums text-muted-foreground align-middle text-[13px]">
                            {lineVol > 0
                              ? formatNumberGrouped(lineVol, { maxFractionDigits: 4 })
                              : "0"}
                          </td>
                        </tr>
                      );
                  };

                  return (
                    <Fragment key={groupLinesByOrder ? g.orderId : "flat"}>
                      {groupLinesByOrder ? (
                        <tr
                          role="button"
                          tabIndex={0}
                          aria-expanded={isOpen}
                          className={cn(
                            "border-b border-teal-800/20 bg-teal-950/10 dark:bg-teal-950/25",
                            "cursor-pointer select-none transition-colors hover:bg-teal-950/20 dark:hover:bg-teal-950/40"
                          )}
                          onClick={() => toggleOrderGroup(g.orderId)}
                          onKeyDown={(e) => {
                            if (e.key === "Enter" || e.key === " ") {
                              e.preventDefault();
                              toggleOrderGroup(g.orderId);
                            }
                          }}
                        >
                          <td
                            colSpan={tableColCount}
                            className="px-2 py-2 text-[11px] font-semibold uppercase tracking-wide text-teal-900 dark:text-teal-100/90"
                          >
                            <span className="inline-flex items-center gap-2">
                              {isOpen ? (
                                <ChevronDown className="h-4 w-4 shrink-0 opacity-80" aria-hidden />
                              ) : (
                                <ChevronRight className="h-4 w-4 shrink-0 opacity-80" aria-hidden />
                              )}
                              <span>
                                Заказ {g.orderNumber} · {g.orderDate || "—"}
                              </span>
                              <span className="font-normal normal-case text-muted-foreground">
                                ({g.rows.length} поз.)
                              </span>
                            </span>
                          </td>
                        </tr>
                      ) : null}
                      {isOpen ? g.rows.map((row) => renderRow(row)) : null}
                    </Fragment>
                  );
                })
              : null}
            {canShowPolkiGrid &&
            polkiSuccess &&
            polkiRowsAllLength > 0 &&
            flatRowCount === 0 ? (
              <tr>
                <td
                  colSpan={tableColCount}
                  className="px-3 py-8 text-center text-xs text-muted-foreground"
                >
                  По поиску ничего не найдено.
                </td>
              </tr>
            ) : null}
          </tbody>
          {canShowPolkiGrid && polkiSuccess && !polkiLoading && flatRowCount > 0 ? (
            <tfoot>
              <tr className="border-t-2 border-border bg-muted/40 font-semibold">
                <td
                  className="px-2 py-2 text-foreground text-sm"
                  colSpan={groupLinesByOrder ? 3 : 2}
                >
                  Итого (на склад, шт · m³ · сумма на баланс)
                </td>
                <td className="px-2 py-2 text-center tabular-nums text-foreground text-sm">
                  {formatNumberGrouped(polkiTotalReturnQtySum, { maxFractionDigits: 0 })}
                </td>
                <td className="px-2 py-2 text-right tabular-nums text-foreground text-sm">
                  {formatNumberGrouped(polkiVolumeM3, { maxFractionDigits: 4 })}
                  <span className="ml-3 inline-block tabular-nums text-teal-800 dark:text-teal-200">
                    {polkiEstimatedSum > 0
                      ? formatNumberGrouped(polkiEstimatedSum, { maxFractionDigits: 0 })
                      : "—"}
                  </span>
                </td>
              </tr>
              {polkiDebtHintSum > 0 ? (
                <tr className="border-t border-border bg-amber-500/10 text-[11px] text-amber-950 dark:text-amber-100">
                  <td colSpan={tableColCount} className="px-2 py-1.5 font-medium">
                    {isPolkiFree ? (
                      <>
                        Долг бонус (на баланс при оформлении):{" "}
                        <span className="tabular-nums">
                          {formatNumberGrouped(polkiDebtHintSum, { maxFractionDigits: 0 })}
                        </span>{" "}
                        сум
                      </>
                    ) : (
                      <>
                        Суммарно «к долгу» по бонусу (компенсация меньше расчёта):{" "}
                        <span className="tabular-nums">
                          {formatNumberGrouped(polkiDebtHintSum, { maxFractionDigits: 0 })}
                        </span>{" "}
                        — оформите в карточке клиента / оплатах при необходимости.
                      </>
                    )}
                  </td>
                </tr>
              ) : null}
            </tfoot>
          ) : null}
        </table>
      </div>
    </div>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { PageShell } from "@/components/dashboard/page-shell";
import { apiBaseURL, resolveApiOrigin } from "@/lib/api";
import { getUserFacingError, isApiUnreachable } from "@/lib/error-utils";
import type { OrderCreateVm } from "../../hooks/use-order-create";
import { CompositionBlock } from "./composition-block";
import { PolkiInfoBanner } from "./info-banner";
import { ReturnHeaderBlock } from "./return-header-block";
import { ReturnParamsGrid } from "./return-params-grid";
import { ReturnSelectedOrderSummary } from "./return-selected-order-summary";

export function PolkiShelfReturnView({ vm }: { vm: OrderCreateVm }) {
  const {
    mutation,
    createCtxQ,
    localError,
    selectionNotice,
    hasClient,
    isPolkiByOrder,
    polkiOrderIds,
    hasWarehouse,
    polkiTotalReturnQtySum,
    polkiTotalBonusCashSum,
    hasPolkiBonusCashOverMax,
    hasPolkiQtyOverMax,
    stockReadyForLines,
    canShowPolkiGrid,
    canSubmit,
    polkiSubmitBlockedReason
  } = vm;

  const submitTitle = !canSubmit
    ? (polkiSubmitBlockedReason ?? "Заполните обязательные поля")
    : undefined;

  return (
    <PageShell className="max-w-none space-y-4 pb-8">
      {localError ? (
        <p className="text-sm text-destructive" role="alert">
          {localError}
        </p>
      ) : null}
      {selectionNotice ? (
        <p className="text-sm text-amber-700" role="status">
          {selectionNotice}
        </p>
      ) : null}

      {createCtxQ.isError ? (
        <div
          role="alert"
          className="rounded-lg border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm"
        >
          <p className="font-semibold text-destructive">Нет связи с API</p>
          <p className="mt-1 text-muted-foreground">
            {isApiUnreachable(createCtxQ.error) ? (
              <>
                Адрес:{" "}
                <code className="rounded bg-muted px-1 py-0.5 text-xs">
                  {apiBaseURL || resolveApiOrigin()}
                </code>
              </>
            ) : (
              getUserFacingError(createCtxQ.error, "Не удалось загрузить данные формы.")
            )}
          </p>
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="mt-3"
            onClick={() => void createCtxQ.refetch()}
          >
            Повторить
          </Button>
        </div>
      ) : null}

      <PolkiInfoBanner vm={vm} />

      <div className="space-y-4">
        <ReturnHeaderBlock vm={vm} />
        <ReturnParamsGrid vm={vm} />
        <ReturnSelectedOrderSummary vm={vm} />
        <CompositionBlock vm={vm} submitTitle={submitTitle} />
      </div>

      <p className="text-xs text-slate-500">
        После проведения — приход на склад возврата. Бонус по правилам; недостающий бонус — долг на баланс
        клиента («Балансы»). Количество по строке — не больше «макс. всего» из доставленных продаж.
      </p>

    </PageShell>
  );
}

"use client";

import { memo, useCallback, useMemo } from "react";
import { Check } from "lucide-react";
import { cn } from "@/lib/utils";
import {
  polkiCard,
  polkiChipActive,
  polkiChipBase,
  polkiChipCheck
} from "./polki-return-ui";

type Cat = { id: number; name: string };

const CategoryChip = memo(function CategoryChip({
  id,
  name,
  active,
  disabled,
  onToggle
}: {
  id: number;
  name: string;
  active: boolean;
  disabled: boolean;
  onToggle: (id: number) => void;
}) {
  return (
    <button
      type="button"
      title={name}
      disabled={disabled}
      onClick={() => onToggle(id)}
      className={cn(polkiChipBase, active && polkiChipActive)}
    >
      {active ? (
        <span className={polkiChipCheck} aria-hidden>
          <Check className="h-2.5 w-2.5 stroke-[3]" />
        </span>
      ) : null}
      <span className="truncate">{name}</span>
    </button>
  );
});

export const ReturnCategoryChips = memo(function ReturnCategoryChips({
  canShowPolkiGrid,
  categories,
  contextLoading,
  contextSuccess,
  contextEmpty,
  categoryFilterActive,
  selectedCategoryIds,
  disabled,
  onSelectAll,
  onToggleCategory
}: {
  canShowPolkiGrid: boolean;
  categories: Cat[] | null | undefined;
  contextLoading: boolean;
  contextSuccess: boolean;
  contextEmpty: boolean;
  categoryFilterActive: boolean;
  selectedCategoryIds: number[];
  disabled: boolean;
  onSelectAll: () => void;
  onToggleCategory: (id: number) => void;
}) {
  const selectedSet = useMemo(() => new Set(selectedCategoryIds), [selectedCategoryIds]);
  const allExplicit =
    categories != null && categories.length > 0 && selectedCategoryIds.length === categories.length;

  const handleToggle = useCallback(
    (id: number) => onToggleCategory(id),
    [onToggleCategory]
  );

  let body: React.ReactNode;
  if (!canShowPolkiGrid) {
    body = <p className="text-xs text-slate-500">Сначала выберите клиента и склад возврата.</p>;
  } else if (contextLoading || categories == null) {
    body = <p className="text-xs text-slate-500">Загрузка продаж для возврата…</p>;
  } else if (contextEmpty) {
    body = (
      <p className="text-xs text-amber-800">
        Нет доставленных продаж для возврата у этого клиента. Оформите и доставьте заказ, затем
        обновите страницу.
      </p>
    );
  } else if (categories.length === 0) {
    body = <p className="text-xs text-slate-500">Нет категорий в продажах для возврата.</p>;
  } else {
    body = (
      <div className="flex max-h-[min(280px,40vh)] flex-wrap gap-2.5 overflow-y-auto overscroll-contain pr-0.5">
        <button
          type="button"
          disabled={disabled}
          onClick={onSelectAll}
          className={cn(polkiChipBase, allExplicit && polkiChipActive)}
        >
          {allExplicit ? (
            <span className={polkiChipCheck} aria-hidden>
              <Check className="h-2.5 w-2.5 stroke-[3]" />
            </span>
          ) : null}
          Выбрать все
        </button>
        {categories.map((c) => (
          <CategoryChip
            key={c.id}
            id={c.id}
            name={c.name}
            active={selectedSet.has(c.id)}
            disabled={disabled}
            onToggle={handleToggle}
          />
        ))}
      </div>
    );
  }

  return (
    <div className={cn(polkiCard, !canShowPolkiGrid && "opacity-60")}>
      <h2 className="mb-3 text-[15px] font-semibold text-slate-800">Категории товаров</h2>
      {body}
    </div>
  );
});

"use client";

import { DiscountAlertIcon } from "@/components/orders/discount-alert-icon";
import type { OrderListRow } from "@/components/orders/order-detail-view";
import { bonusAlertLabel } from "@/lib/bonus-alert";
import { discountAlertLabel } from "@/lib/discount-alert";
import { OrderStatusDropdown } from "@/components/orders/orders-list/order-status-dropdown";
import { formatOrderListDateTime } from "@/lib/format-order-list-datetime";
import {
  formatOrderListDebtAsClientLiability,
  orderListExportCell,
  orderListTruncateCellClass
} from "@/lib/orders-list-columns";
import { formatNumberGrouped } from "@/lib/format-numbers";
import { orderTypeLabel } from "@/lib/order-types";
import { cn } from "@/lib/utils";
import { Copy } from "lucide-react";
import Link from "next/link";
import type { ReactNode } from "react";
import { useCallback } from "react";
import { parseNumField } from "./types";

async function copyText(text: string) {
  try {
    await navigator.clipboard?.writeText(text);
  } catch {
    /* ignore */
  }
}

/** Havola yonida — matn boshqa sahifaga, nusxa faqat ikonka orqali. */
function CopyBtn({ text, title }: { text: string; title: string }) {
  return (
    <button
      type="button"
      className="inline-flex rounded p-0.5 text-teal-600 opacity-60 transition-opacity hover:bg-teal-100 hover:opacity-100 dark:text-teal-400 dark:hover:bg-teal-950/50"
      title={title}
      aria-label={title}
      onClick={(e) => {
        e.stopPropagation();
        void copyText(text);
      }}
    >
      <Copy className="size-3 shrink-0" aria-hidden />
    </button>
  );
}

/** Oddiy matn — bosganda nusxa (ikonkasiz). */
function CopyableText({
  text,
  title = "Копировать",
  className
}: {
  text: string;
  title?: string;
  className?: string;
}) {
  return (
    <button
      type="button"
      className={cn(
        "inline cursor-copy border-0 bg-transparent p-0 text-inherit transition-colors",
        "hover:text-teal-700 dark:hover:text-teal-400",
        className
      )}
      title={title}
      aria-label={title}
      onClick={(e) => {
        e.stopPropagation();
        void copyText(text);
      }}
    >
      {text}
    </button>
  );
}

export type RenderOrderListCellArgs = {
  colId: string;
  order: OrderListRow;
  tenantSlug: string | null;
  effectiveRole: string | null | undefined;
  statusRowError: Record<number, string>;
  rowStatusPendingId: number | null;
  onStatusChange: (id: number, status: string) => void;
  onChangeShipDate?: (id: number) => void;
};

export function renderOrderListCell({
  colId,
  order,
  tenantSlug,
  effectiveRole,
  statusRowError,
  rowStatusPendingId,
  onStatusChange,
  onChangeShipDate
}: RenderOrderListCellArgs): ReactNode {
  switch (colId) {
    case "number":
      return null;
    case "source_order_number": {
      const nums = order.source_order_numbers ?? [];
      const ids = order.source_order_ids ?? [];
      if (nums.length === 0) return <span className="text-muted-foreground">—</span>;
      return (
        <div className="flex flex-col gap-0.5">
          {nums.map((num, i) => {
            const oid = ids[i];
            return (
              <div key={`${num}-${i}`} className="flex items-center gap-1">
                {oid != null ? (
                  <Link
                    href={`/orders/${oid}`}
                    className="text-teal-700 underline-offset-2 hover:underline dark:text-teal-400"
                    onClick={(e) => e.stopPropagation()}
                  >
                    {num}
                  </Link>
                ) : (
                  <CopyableText text={num} title="Копировать" className="text-foreground" />
                )}
                {oid != null ? <CopyBtn text={num} title="Копировать" /> : null}
              </div>
            );
          })}
        </div>
      );
    }
    case "request_source": {
      const src = orderListExportCell(order, "request_source");
      return src ? <span>{src}</span> : <span className="text-muted-foreground">—</span>;
    }
    case "order_type": {
      const t = order.order_type ?? "order";
      const isReturnType = t === "return" || t === "return_by_order";
      const label = orderTypeLabel(t);
      // «Исходный заказ» ustuni manba zakaz ID/raqamini ko'rsatadi — bu yerda
      // qavs ichidagi takror kerak emas. Matn ko'pi bilan 2 qator (chiroyli).
      return (
        <span
          className={cn(
            "block max-w-[8rem] leading-tight line-clamp-2",
            isReturnType ? "text-[#7c2d12] dark:text-orange-200" : "text-foreground"
          )}
          title={label}
        >
          {label}
        </span>
      );
    }
    case "created_at":
      return (
        <span className="whitespace-nowrap text-foreground">
          {formatOrderListDateTime(order.created_at) || "—"}
        </span>
      );
    case "list_created_at":
      return (
        <span className="whitespace-nowrap text-foreground">
          {formatOrderListDateTime(order.list_created_at ?? order.created_at) || "—"}
