      triggerClassName={triggerClassName}
      items={items}
      selectedValues={singleFilterSelection(value)}
      onChange={(next) => onChange(pickSingleFilterValue(next, value))}
      disabled={disabled}
      minPopoverWidth={minPopoverWidth}
      hidePopoverHeader
    />
  );
}

"use client";

import { TableColumnSettingsDialog } from "@/components/data-table/table-column-settings-dialog";
import { QueryErrorState } from "@/components/common/query-error-state";
import { OrderStatusDatetimeDialog } from "@/components/orders/orders-list/order-status-datetime-dialog";
import { OrdersListTableRow } from "@/components/orders/orders-list/orders-list-table-row";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { getUserFacingError } from "@/lib/error-utils";
import { formatGroupedInteger, formatNumberGrouped } from "@/lib/format-numbers";
import { OrdersExcelExportDialog } from "@/components/orders/orders-list/orders-excel-export-dialog";
import { ORDER_LIST_COLUMNS, orderListColumnThClass } from "@/lib/orders-list-columns";
import {
  orderMilestoneDatetimeDialogTitle,
  orderStatusDatetimeDialogTitle
} from "@/lib/order-status-datetime";
import { cn } from "@/lib/utils";
import { Input } from "@/components/ui/input";
import { ChevronLeft, ChevronRight, ListOrdered, Package, RefreshCw, Search } from "lucide-react";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { UseOrdersListPageResult } from "./use-orders-list-page";

/**
 * CURSOR / AI AGENT — DO NOT CHANGE expand/scroll layout without explicit user request.
 * Zakaz ochilganda gorizontal scroll siljishi: orders-list-expand-layout.ts va
 * OrdersListExpandedRow. Jadval min-w-[3200px] saqlanadi; panel alohida sticky qatlam.
 */
const ORDERS_TABLE_MIN_CLASS = "w-full min-w-[3200px] border-collapse text-xs";
/** Sahifada ko‘rsatiladigan qatorlar (API limit bilan bir xil) */
const ORDERS_LIST_PAGE_ROWS = 15;
/** Ustun nomlari qatori (sticky) */
const ORDERS_TABLE_HEADER_REM = 2.75;
/** Bir qator balandligi (py-2.5 + kontent) */
const ORDERS_TABLE_ROW_REM = 3.125;
const ORDERS_TABLE_SCROLL_CLASS =
  "orders-list-table-scroll scrollbar-none overflow-x-auto overflow-y-auto";
const ORDERS_TABLE_HEAD_CELL = "orders-list-table-th-sticky";

/** Scroll oynasi: har doim sahifa limiti (15) qator sig‘imi, ma’lumot kam bo‘lsa ham */
function ordersTableScrollMaxHeight(pageSize: number): string {
  const layoutRows = Math.max(1, Math.min(pageSize, 50));
  return `min(78vh, ${ORDERS_TABLE_HEADER_REM + layoutRows * ORDERS_TABLE_ROW_REM}rem)`;
}

type OrdersListTableProps = Pick<
  UseOrdersListPageResult,
  | "tenantSlug"
  | "authHydrated"
  | "filters"
  | "data"
  | "isLoading"
  | "isError"
  | "error"
  | "refetch"
  | "rows"
  | "orderListTotalPages"
  | "ordersFiltersApplied"
  | "tablePrefs"
  | "replaceOrdersQuery"
  | "columnDialogOpen"
  | "setColumnDialogOpen"
  | "selectedOrderIds"
  | "allOnPageSelected"
  | "toggleOrderSelect"
  | "toggleSelectAllOnPage"
  | "effectiveRole"
  | "statusRowError"
  | "rowStatusMut"
  | "milestoneAtMut"
  | "prefetchOrderDetail"
>;

type PendingStatusDialog =
  | { kind: "status"; orderId: number; status: string; orderType?: string | null }
  | { kind: "milestone"; orderId: number; milestone: string; orderType?: string | null };

export function OrdersListTable(props: OrdersListTableProps) {
  const {
    tenantSlug,
    authHydrated,
    filters,
    data,
    isLoading,
    isError,
    error,
    refetch,
    rows,
    orderListTotalPages,
    ordersFiltersApplied,
    tablePrefs,
    replaceOrdersQuery,
    columnDialogOpen,
    setColumnDialogOpen,
    selectedOrderIds,
    allOnPageSelected,
    toggleOrderSelect,
    toggleSelectAllOnPage,
    effectiveRole,
    statusRowError,
    rowStatusMut,
    milestoneAtMut,
    prefetchOrderDetail
  } = props;

  const rowStatusPendingId = rowStatusMut.isPending
    ? rowStatusMut.variables?.id ?? null
    : milestoneAtMut.isPending
      ? milestoneAtMut.variables?.id ?? null
      : null;

  const [pendingStatusDialog, setPendingStatusDialog] = useState<PendingStatusDialog | null>(null);
  const [expandedOrderId, setExpandedOrderId] = useState<number | null>(null);
  const [excelExportOpen, setExcelExportOpen] = useState(false);
  const [searchDraft, setSearchDraft] = useState(filters.search);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [expandPanelWidth, setExpandPanelWidth] = useState<number | null>(null);

  useEffect(() => {
    const el = scrollContainerRef.current;
    if (!el) return;
    const sync = () => setExpandPanelWidth(el.clientWidth);
    sync();
    const ro = new ResizeObserver(sync);
    ro.observe(el);
    return () => ro.disconnect();
  }, [rows.length, ordersFiltersApplied, isLoading]);

  useEffect(() => {
    setSearchDraft(filters.search);
  }, [filters.search]);

  useEffect(() => {
    setExpandedOrderId(null);
  }, [filters.page]);

  const tableScrollMaxHeight = useMemo(
    () => ordersTableScrollMaxHeight(tablePrefs.pageSize),
    [tablePrefs.pageSize]
  );

  const toggleExpand = useCallback(
    (id: number) => {
      const scrollEl = scrollContainerRef.current;
      const savedScrollLeft = scrollEl?.scrollLeft ?? 0;
      setExpandedOrderId((prev) => {
        const next = prev === id ? null : id;
        if (next != null) prefetchOrderDetail(next);
        return next;
      });
      queueMicrotask(() => {
        requestAnimationFrame(() => {
          if (scrollEl) scrollEl.scrollLeft = savedScrollLeft;
        });
      });
    },
    [prefetchOrderDetail]
  );

  const onStatusChange = (id: number, status: string) => {
    const order = rows.find((r) => r.id === id);
    setPendingStatusDialog({
      kind: "status",
      orderId: id,
      status,
      orderType: order?.order_type
    });
  };

  const onChangeShipDate = (id: number) => {
    const order = rows.find((r) => r.id === id);
    setPendingStatusDialog({
      kind: "milestone",
      orderId: id,
      milestone: "confirmed",
      orderType: order?.order_type
    });
  };

  const dialogPending =
    rowStatusMut.isPending || milestoneAtMut.isPending;

  if (!authHydrated) {
    return <p className="text-sm text-muted-foreground">Загрузка сессии…</p>;
  }
  if (!tenantSlug) {
    return (
      <p className="text-sm text-destructive">
        <a href="/login" className="underline">
          Войти снова
        </a>
      </p>
    );
  }

  return (
    <>
      <TableColumnSettingsDialog
        open={columnDialogOpen}
        onOpenChange={setColumnDialogOpen}
        title="Ustunlarni boshqarish"
        description="Ko‘rinadigan ustunlar va tartib. Sizning akkauntingiz uchun saqlanadi (server)."
        columns={ORDER_LIST_COLUMNS}
        columnOrder={tablePrefs.columnOrder}
        hiddenColumnIds={tablePrefs.hiddenColumnIds}
        saving={tablePrefs.saving}
        onSave={(next) => tablePrefs.saveColumnLayout(next)}
        onReset={() => tablePrefs.resetColumnLayout()}
      />

      <div className="orders-hub-section orders-hub-section--table">
        <Card className="rounded-lg border border-border bg-card shadow-sm">
          <CardContent className="p-0">
            <div
              className="table-toolbar flex flex-wrap items-center gap-2 border-b border-border bg-muted/20 px-3 py-2 sm:px-4"
              role="toolbar"
              aria-label="Таблица: поиск и экспорт"
            >
              <div className="relative min-w-[12rem] flex-1 sm:max-w-md">
                <Search
                  className="pointer-events-none absolute left-2.5 top-1/2 size-4 -translate-y-1/2 text-muted-foreground"
                  aria-hidden
                />
                <Input
                  type="search"
                  placeholder="Поиск по №, клиенту, комментарию…"
                  className="h-9 pl-9 text-sm"
                  value={searchDraft}
                  onChange={(e) => setSearchDraft(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter") {
                      replaceOrdersQuery({ search: searchDraft.trim(), page: 1 });
                    }
                  }}
                />
              </div>
              <label className="shrink-0 text-xs font-medium text-foreground/85">
                <span className="sr-only">Строк на странице</span>
                <select
                  className="h-9 rounded-md border border-input bg-background px-2 text-sm text-foreground"
                  value={tablePrefs.pageSize}
                  onChange={(e) => {
                    const n = Number(e.target.value);
                    tablePrefs.setPageSize(n);
                    replaceOrdersQuery({ page: 1 });
                  }}
                >
                  {[10, 15, 20, 30, 50, 100].map((n) => (
                    <option key={n} value={n}>
                      {n}
                    </option>
                  ))}
                </select>
              </label>
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="h-9 shrink-0 gap-1"
                onClick={() => setColumnDialogOpen(true)}
              >
                <ListOrdered className="h-4 w-4" />
                Колонки
              </Button>
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="h-9 shrink-0"
                disabled={rows.length === 0 || !tenantSlug}
                onClick={() => setExcelExportOpen(true)}
              >
                Excel
              </Button>
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="h-9 w-9 shrink-0 p-0"
                onClick={() => void refetch()}
                aria-label="Обновить"
              >
                <RefreshCw className="mx-auto h-4 w-4" />
              </Button>
              {data ? (
                <div
                  className="ml-auto flex shrink-0 items-center gap-2 border-l border-border/80 pl-2 sm:pl-3"
                  role="navigation"
                  aria-label="Страницы таблицы"
                >
                  <span className="whitespace-nowrap text-sm text-foreground/80">
                    Страница{" "}
                    <span className="font-medium tabular-nums text-foreground">
                      {formatGroupedInteger(Math.min(filters.page, orderListTotalPages))}
                    </span>{" "}
                    /{" "}
                    <span className="tabular-nums text-foreground">
                      {formatGroupedInteger(orderListTotalPages)}
                    </span>
                  </span>
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    className="h-9 w-9 shrink-0 p-0"
                    disabled={filters.page <= 1}
                    onClick={() => replaceOrdersQuery({ page: Math.max(1, filters.page - 1) })}
                    aria-label="Назад"
                  >
                    <ChevronLeft className="h-4 w-4" />
                  </Button>
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    className="h-9 w-9 shrink-0 p-0"
                    disabled={filters.page >= orderListTotalPages}
                    onClick={() => replaceOrdersQuery({ page: filters.page + 1 })}
                    aria-label="Далее"
                  >
                    <ChevronRight className="h-4 w-4" />
                  </Button>
                </div>
              ) : null}
            </div>

            {!ordersFiltersApplied ? (
              <div className="py-16 text-center text-muted-foreground">
                <Package className="mx-auto mb-3 size-12 text-muted-foreground/40" aria-hidden />
                <p className="text-lg font-medium text-foreground">Выберите фильтры</p>
                <p className="mt-1 text-sm">
                  Укажите период и условия, затем нажмите «Применить» — список заказов загрузится.
                </p>
              </div>
            ) : isLoading ? (
              <p className="px-3 py-6 text-sm text-muted-foreground sm:px-4">Загрузка…</p>
            ) : isError ? (
              <div className="p-4 sm:p-5">
                <QueryErrorState
                  message={getUserFacingError(error, "Zakazlarni yuklab bo'lmadi.")}
                  onRetry={() => void refetch()}
                />
              </div>
            ) : rows.length === 0 ? (
              <div className="py-16 text-center text-muted-foreground">
                <Package className="mx-auto mb-3 size-12 text-muted-foreground/40" aria-hidden />
                <p className="text-lg font-medium text-foreground">Заказы не найдены</p>
                <p className="mt-1 text-sm">
                  {data?.total === 0
                    ? "По выбранным фильтрам и периоду заказов нет. Измените условия или создайте новый заказ."
                    : "На этой странице нет строк — перейдите на другую страницу."}
                </p>
              </div>
            ) : (
              <>
                <div
                  ref={scrollContainerRef}
                  className={ORDERS_TABLE_SCROLL_CLASS}
                  style={{ maxHeight: tableScrollMaxHeight }}
                >
                  <table className={ORDERS_TABLE_MIN_CLASS}>
                    <thead className="app-table-thead">
                      <tr className="text-left font-medium text-muted-foreground">
                        <th className={cn("w-10 px-3 py-2", ORDERS_TABLE_HEAD_CELL)}>
                          <input
                            type="checkbox"
                            className="size-4 rounded border-input"
                            checked={allOnPageSelected}
                            onChange={toggleSelectAllOnPage}
                            aria-label="Joriy sahifadagi barcha zakazlarni tanlash"
                          />
                        </th>
                        {tablePrefs.visibleColumnOrder.map((colId) => {
                          const label =
                            ORDER_LIST_COLUMNS.find((c) => c.id === colId)?.label ?? colId;
                          const right =
                            colId === "qty" ||
                            colId === "volume_m3" ||
                            colId === "total_sum" ||
                            colId === "bonus_sum" ||
                            colId === "cumulative_bonus" ||
                            colId === "discount_sum" ||
                            colId === "balance" ||
                            colId === "debt" ||
                            colId === "client_id";
                          return (
                            <th
                              key={colId}
                              className={cn(
                                "px-3 py-2",
                                ORDERS_TABLE_HEAD_CELL,
                                orderListColumnThClass(colId),
                                right && "text-right"
                              )}
                            >
                              {label}
                            </th>
                          );
                        })}
                        <th
                          className={cn(
                            "sticky right-0 w-11 min-w-[2.75rem] px-2 py-2 text-center font-medium shadow-[inset_1px_0_0_hsl(var(--border))]",
                            ORDERS_TABLE_HEAD_CELL,
                            "orders-list-table-th-sticky-right"
                          )}
                        >
                          <span className="sr-only">Tafsilot</span>
                        </th>
                      </tr>
                    </thead>
                    <tbody>
                      {rows.map((o) => (
                        <OrdersListTableRow
                          key={o.id}
                          order={o}
                          tenantSlug={tenantSlug!}
                          visibleColumnOrder={tablePrefs.visibleColumnOrder}
                          selected={selectedOrderIds.has(o.id)}
                          expanded={expandedOrderId === o.id}
                          onToggleExpand={toggleExpand}
                          onToggleSelect={toggleOrderSelect}
                          effectiveRole={effectiveRole}
                          statusRowError={statusRowError}
                          rowStatusPendingId={rowStatusPendingId}
                          onStatusChange={onStatusChange}
                          onChangeShipDate={onChangeShipDate}
                          onPrefetchDetail={prefetchOrderDetail}
                          expandPanelWidth={expandPanelWidth}
                        />
                      ))}
                    </tbody>
                  </table>
                </div>
              </>
            )}
          </CardContent>
        </Card>
      </div>
      <OrderStatusDatetimeDialog
        open={pendingStatusDialog != null}
        onOpenChange={(open) => {
          if (!open && !dialogPending) setPendingStatusDialog(null);
        }}
        title={
          pendingStatusDialog?.kind === "milestone"
            ? orderMilestoneDatetimeDialogTitle()
            : pendingStatusDialog
              ? orderStatusDatetimeDialogTitle(
                  pendingStatusDialog.status,
                  pendingStatusDialog.orderType
                )
              : ""
        }
        isPending={dialogPending}
        onConfirm={(datetimeLocal) => {
          if (!pendingStatusDialog) return;
          const occurred_at = new Date(datetimeLocal).toISOString();
          if (pendingStatusDialog.kind === "milestone") {
            milestoneAtMut.mutate(
              {
                id: pendingStatusDialog.orderId,
                milestone: pendingStatusDialog.milestone,
                occurred_at
              },
              { onSuccess: () => setPendingStatusDialog(null) }
            );
          } else {
            rowStatusMut.mutate(
              {
                id: pendingStatusDialog.orderId,
                status: pendingStatusDialog.status,
                occurred_at
              },
              { onSuccess: () => setPendingStatusDialog(null) }
            );
          }
        }}
      />

      {tenantSlug ? (
        <OrdersExcelExportDialog
          open={excelExportOpen}
          onOpenChange={setExcelExportOpen}
          tenantSlug={tenantSlug}
          orders={rows}
          visibleColumnOrder={tablePrefs.visibleColumnOrder}
        />
      ) : null}
    </>
  );
}

"use client";

import type { OrderDetailRow } from "@/components/orders/order-detail-view";
import { useAuthStore, useAuthStoreHydrated, useEffectiveRole } from "@/lib/auth-store";
import { api } from "@/lib/api";
import {
  DEFAULT_NAKLADNOY_EXPORT_PREFS,
  loadNakladnoyExportPrefs,
  type NakladnoyExportPrefs,
  type NakladnoyTemplateId
} from "@/lib/order-nakladnoy";
import {
  applyOrderDetailToListCaches,
  patchOrderInOrdersListCaches,
  type OrdersListCacheBody
} from "@/lib/orders-list-cache";
import {
  ORDER_LIST_COLUMN_IDS,
  ORDER_LIST_DEFAULT_HIDDEN_COLUMN_IDS,
  ORDERS_LIST_TABLE_ID
} from "@/lib/orders-list-columns";
import { STALE } from "@/lib/query-stale";
import { useOrdersListReferenceData } from "./use-orders-list-reference-data";
import { useUserTablePrefs } from "@/hooks/use-user-table-prefs";
import { keepPreviousData, useQuery, useQueryClient } from "@tanstack/react-query";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import {
  buildOrdersSearchParams,
  DEFAULT_ORDERS_FILTER_VISIBILITY,
  defaultOrdersDayRange,
  ORDERS_FILTER_VISIBILITY_STORAGE_KEY,
  parseNumField,
  parseOrdersUrl,
  ordersListQueryReady,
  withDefaultOrdersDateRange,
  type OrdersFilterVisibility,
  type OrdersResponse,
  type OrdersUrlFilters
} from "./types";

export function useOrdersListPagePart1() {
  const searchParams = useSearchParams();
  const pathname = usePathname();
  const router = useRouter();
  const filters = useMemo(() => parseOrdersUrl(searchParams), [searchParams]);
  const ordersFiltersApplied = ordersListQueryReady(filters);
  const clientIdFromUrl = filters.client_id;

  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const authHydrated = useAuthStoreHydrated();
  const effectiveRole = useEffectiveRole();
  const qc = useQueryClient();

  const [columnDialogOpen, setColumnDialogOpen] = useState(false);
  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<number>>(() => new Set());
  const [bulkTargetStatus, setBulkTargetStatus] = useState("");
  const [bulkFeedback, setBulkFeedback] = useState<string | null>(null);
  const [downloadsOpen, setDownloadsOpen] = useState(false);
  const [nakladnoyTemplate, setNakladnoyTemplate] = useState<NakladnoyTemplateId>("nakladnoy_warehouse");
  const [nakladnoyPrefs, setNakladnoyPrefs] = useState<NakladnoyExportPrefs>(DEFAULT_NAKLADNOY_EXPORT_PREFS);
  const [nakladnoySettingsOpen, setNakladnoySettingsOpen] = useState(false);
  const [nakladnoyFeedback, setNakladnoyFeedback] = useState<string | null>(null);
  const [statusRowError, setStatusRowError] = useState<Record<number, string>>({});
  const [totalsPanelOpen, setTotalsPanelOpen] = useState(false);
  const [bulkExpeditorChoice, setBulkExpeditorChoice] = useState<string>("");
  const [bulkExpFeedback, setBulkExpFeedback] = useState<string | null>(null);
  const [bulkConsignmentFeedback, setBulkConsignmentFeedback] = useState<string | null>(null);
  const [filterVisibilityOpen, setFilterVisibilityOpen] = useState(false);
  const [filterVisibility, setFilterVisibility] = useState<OrdersFilterVisibility>(
    DEFAULT_ORDERS_FILTER_VISIBILITY
  );
  const ordersDateRangeAnchorRef = useRef<HTMLButtonElement>(null);
  const [ordersDateRangeOpen, setOrdersDateRangeOpen] = useState(false);
  const [ordersViewMode, setOrdersViewMode] = useState<"list" | "expeditor-summary">("list");
  const [filterDraft, setFilterDraft] = useState<OrdersUrlFilters>(() =>
    withDefaultOrdersDateRange(parseOrdersUrl(searchParams))
  );

  useEffect(() => {
    setFilterDraft(withDefaultOrdersDateRange(filters));
  }, [filters]);

  useEffect(() => {
    setNakladnoyPrefs(loadNakladnoyExportPrefs());
  }, []);

  useEffect(() => {
    try {
      const raw = window.localStorage.getItem(ORDERS_FILTER_VISIBILITY_STORAGE_KEY);
      if (!raw) return;
      const parsed = JSON.parse(raw) as Partial<OrdersFilterVisibility>;
      const { clientId: _omitClientId, ...parsedRest } = parsed as OrdersFilterVisibility & {
        clientId?: boolean;
      };
      setFilterVisibility({
        ...DEFAULT_ORDERS_FILTER_VISIBILITY,
        ...parsedRest,
        paymentLinkedType:
          parsed.paymentLinkedType ?? DEFAULT_ORDERS_FILTER_VISIBILITY.paymentLinkedType
      });
    } catch {
      setFilterVisibility(DEFAULT_ORDERS_FILTER_VISIBILITY);
    }
  }, []);

  useEffect(() => {
    try {
      window.localStorage.setItem(
        ORDERS_FILTER_VISIBILITY_STORAGE_KEY,
        JSON.stringify(filterVisibility)
      );
    } catch {
      // noop: localStorage unavailable
    }
  }, [filterVisibility]);

  const {
    canBulkCatalog,
    warehousesQ,
    agentsQ,
    expeditorsQ,
    productsFilterQ,
    productCategoriesQ,
    ordersProfileRefsQ,
    clientCategoryFilterOpts,
    tradeDirectionFilterOpts,
    priceTypeFilterOpts,
    buildTerritoryCascade,
    paymentMethodFilterOpts,
    paymentTypeFilterOpts,
    nakladnoyTypeFilterOpts
  } = useOrdersListReferenceData(tenantSlug, effectiveRole, filterDraft);

  const tablePrefs = useUserTablePrefs({
    tenantSlug,
    tableId: ORDERS_LIST_TABLE_ID,
    defaultColumnOrder: [...ORDER_LIST_COLUMN_IDS],
    defaultHiddenColumnIds: ORDER_LIST_DEFAULT_HIDDEN_COLUMN_IDS,
    defaultPageSize: 15,
    allowedPageSizes: [10, 15, 20, 30, 50, 100]
  });

  const replaceOrdersQuery = useCallback(
    (patch: Partial<OrdersUrlFilters>) => {
      const cur = parseOrdersUrl(searchParams);
      const next: OrdersUrlFilters = {
        status: patch.status !== undefined ? patch.status : cur.status,
        order_type: patch.order_type !== undefined ? patch.order_type : cur.order_type,
        page: patch.page !== undefined ? patch.page : cur.page,
        search: patch.search !== undefined ? patch.search : cur.search,
        warehouse_id: patch.warehouse_id !== undefined ? patch.warehouse_id : cur.warehouse_id,
        agent_id: patch.agent_id !== undefined ? patch.agent_id : cur.agent_id,
        expeditor_id: patch.expeditor_id !== undefined ? patch.expeditor_id : cur.expeditor_id,
        date_from: patch.date_from !== undefined ? patch.date_from : cur.date_from,
        date_to: patch.date_to !== undefined ? patch.date_to : cur.date_to,
        client_id: patch.client_id !== undefined ? patch.client_id : cur.client_id,
        product_id: patch.product_id !== undefined ? patch.product_id : cur.product_id,
        client_category:
          patch.client_category !== undefined ? patch.client_category : cur.client_category,
        client_region: patch.client_region !== undefined ? patch.client_region : cur.client_region,
        client_city: patch.client_city !== undefined ? patch.client_city : cur.client_city,
        client_zone: patch.client_zone !== undefined ? patch.client_zone : cur.client_zone,
        trade_direction:
          patch.trade_direction !== undefined ? patch.trade_direction : cur.trade_direction,
        date_mode: patch.date_mode !== undefined ? patch.date_mode : cur.date_mode,
        is_consignment: patch.is_consignment !== undefined ? patch.is_consignment : cur.is_consignment,
        product_category_id:
          patch.product_category_id !== undefined ? patch.product_category_id : cur.product_category_id,
        payment_type: patch.payment_type !== undefined ? patch.payment_type : cur.payment_type,
        payment_method_ref:
          patch.payment_method_ref !== undefined ? patch.payment_method_ref : cur.payment_method_ref,
        request_type_ref:
          patch.request_type_ref !== undefined ? patch.request_type_ref : cur.request_type_ref,
        visit_weekday: patch.visit_weekday !== undefined ? patch.visit_weekday : cur.visit_weekday,
        price_type: patch.price_type !== undefined ? patch.price_type : cur.price_type,
        discount_alert:
          patch.discount_alert !== undefined ? patch.discount_alert : cur.discount_alert,
        bonus_alert: patch.bonus_alert !== undefined ? patch.bonus_alert : cur.bonus_alert,
        order_alert: patch.order_alert !== undefined ? patch.order_alert : cur.order_alert
      };
      const qs = buildOrdersSearchParams(next).toString();
      router.replace(qs ? `${pathname}?${qs}` : pathname, { scroll: false });
    },
    [pathname, router, searchParams]
  );

  const applyFilterDraft = useCallback(() => {
    const next = withDefaultOrdersDateRange({ ...filterDraft, page: 1 });
    setFilterDraft(next);
    const qs = buildOrdersSearchParams(next).toString();
    router.replace(qs ? `${pathname}?${qs}` : pathname, { scroll: false });
  }, [filterDraft, pathname, router]);

  const resetFilterDraft = useCallback(() => {
    const { date_from, date_to } = defaultOrdersDayRange();
    const empty: OrdersUrlFilters = {
      status: "",
      order_type: "",
      page: 1,
      search: "",
      warehouse_id: "",
      agent_id: "",
      expeditor_id: "",
      date_from,
      date_to,
      client_id: "",
      product_id: "",
      client_category: "",
      client_region: "",
      client_city: "",
      client_zone: "",
      trade_direction: "",
      date_mode: "order",
      is_consignment: "",
      product_category_id: "",
      payment_type: "",
      payment_method_ref: "",
      request_type_ref: "",
      visit_weekday: "",
      price_type: "",
      discount_alert: "",
      bonus_alert: "",
      order_alert: ""
    };
    setFilterDraft(empty);
    replaceOrdersQuery(empty);
  }, [replaceOrdersQuery]);

  const { data, isLoading, isFetching, isError, error, refetch, isPlaceholderData } = useQuery({
    queryKey: [
      "orders",
      tenantSlug,
      filters.page,
      filters.search,
      filters.status,
      filters.order_type,
      filters.client_id,
      filters.warehouse_id,
      filters.agent_id,
      filters.expeditor_id,
      filters.date_from,
      filters.date_to,
      filters.date_mode,
      filters.is_consignment,
      filters.product_category_id,
      filters.payment_type,
      filters.payment_method_ref,
      filters.request_type_ref,
      filters.product_id,
      filters.client_category,
      filters.client_region,
      filters.client_city,
      filters.client_zone,
      filters.trade_direction,
      filters.visit_weekday,
      filters.price_type,
      filters.discount_alert,
      filters.bonus_alert,
      filters.order_alert,
      tablePrefs.pageSize
    ],
    enabled: Boolean(tenantSlug) && ordersFiltersApplied,
    staleTime: STALE.list,
    placeholderData: keepPreviousData,
    queryFn: async () => {
      const f = filters;
      const params = new URLSearchParams({
        page: String(f.page),
        limit: String(tablePrefs.pageSize)
      });
      if (f.search.trim()) params.set("q", f.search.trim());
      if (f.status.trim()) params.set("status", f.status.trim());
      if (f.order_type) params.set("order_type", f.order_type);
      if (f.client_id) params.set("client_id", f.client_id);
      if (f.warehouse_id) params.set("warehouse_id", f.warehouse_id);
      if (f.agent_id) params.set("agent_id", f.agent_id);
      if (f.expeditor_id) params.set("expeditor_id", f.expeditor_id);
      if (f.date_from) params.set("date_from", f.date_from);
      if (f.date_to) params.set("date_to", f.date_to);
      if (f.product_id) params.set("product_id", f.product_id);
      if (f.client_category) params.set("client_category", f.client_category);
      if (f.client_region) params.set("client_region", f.client_region);
      if (f.client_city) params.set("client_city", f.client_city);
      if (f.client_zone) params.set("client_zone", f.client_zone);
      if (f.trade_direction) params.set("trade_direction", f.trade_direction);
      if (f.visit_weekday) params.set("visit_weekday", f.visit_weekday);
      if (f.price_type) params.set("price_type", f.price_type);
      if (f.date_mode) params.set("date_mode", f.date_mode);
      if (f.is_consignment === "true") params.set("is_consignment", "true");
      if (f.is_consignment === "false") params.set("is_consignment", "false");
      if (f.product_category_id) params.set("product_category_id", f.product_category_id);
      if (f.payment_type.trim()) params.set("payment_type", f.payment_type.trim());
      if (f.payment_method_ref.trim()) {
        params.set("payment_method_ref", f.payment_method_ref.trim());
      }
      if (f.request_type_ref.trim()) {
        params.set("request_type_ref", f.request_type_ref.trim());
      }
      if (f.discount_alert.trim()) {
        params.set("discount_alert", f.discount_alert.trim());
      }
      if (f.bonus_alert.trim()) {
        params.set("bonus_alert", f.bonus_alert.trim());
      }
      if (f.order_alert.trim()) {
        params.set("order_alert", f.order_alert.trim());
      }
      const { data: body } = await api.get<OrdersResponse>(
        `/api/${tenantSlug}/orders?${params.toString()}`
      );
      return body;
    }
  });

  const rows = data?.data ?? [];

  const expeditorSummaryRows = useMemo(() => {
    const map = new Map<
      string,
      { expeditor: string; orders: number; qty: number; total: number; delivered: number; delivering: number }
    >();
    for (const r of rows) {
      const exp = (r.expeditor_display ?? r.expeditors ?? "—").trim() || "—";
      const cur = map.get(exp) ?? {
        expeditor: exp,
        orders: 0,
        qty: 0,
        total: 0,
        delivered: 0,
        delivering: 0
      };
      cur.orders += 1;
      cur.qty += parseNumField(r.qty);
      cur.total += parseNumField(r.total_sum);
      if (r.status === "delivered") cur.delivered += 1;
      if (r.status === "delivering") cur.delivering += 1;
      map.set(exp, cur);
    }
    return Array.from(map.values()).sort(
      (a, b) => b.orders - a.orders || a.expeditor.localeCompare(b.expeditor, "ru")
    );
  }, [rows]);

  const orderListTotalPages = useMemo(() => {
    if (!data) return 1;
    const lim = data.limit > 0 ? data.limit : tablePrefs.pageSize;
    return Math.max(1, Math.ceil(data.total / lim));
  }, [data, tablePrefs.pageSize]);

  const prefetchOrderDetail = useCallback(
    (orderId: number) => {
      if (!tenantSlug) return;
      void qc.prefetchQuery({
        queryKey: ["order", tenantSlug, orderId],
        staleTime: STALE.detail,
        queryFn: async () => {
          const { data: body } = await api.get<OrderDetailRow>(`/api/${tenantSlug}/orders/${orderId}`);
          return body;
        }
      });
    },
    [qc, tenantSlug]
  );

  return {
    searchParams,
    pathname,
    router,
    filters,
    filterDraft,
    setFilterDraft,
    clientIdFromUrl,
    tenantSlug,
    authHydrated,
    effectiveRole,
    qc,
    columnDialogOpen,
    setColumnDialogOpen,
    selectedOrderIds,
    setSelectedOrderIds,
    bulkTargetStatus,
    setBulkTargetStatus,
    bulkFeedback,
    setBulkFeedback,
    downloadsOpen,
    setDownloadsOpen,
    nakladnoyTemplate,
    setNakladnoyTemplate,
    nakladnoyPrefs,
    setNakladnoyPrefs,
    nakladnoySettingsOpen,
    setNakladnoySettingsOpen,
    nakladnoyFeedback,
    setNakladnoyFeedback,
    statusRowError,
    setStatusRowError,
    totalsPanelOpen,
    setTotalsPanelOpen,
    bulkExpeditorChoice,
    setBulkExpeditorChoice,
    bulkExpFeedback,
    setBulkExpFeedback,
    bulkConsignmentFeedback,
    setBulkConsignmentFeedback,
    filterVisibilityOpen,
    setFilterVisibilityOpen,
    filterVisibility,
    setFilterVisibility,
    ordersDateRangeAnchorRef,
    ordersDateRangeOpen,
    setOrdersDateRangeOpen,
    ordersViewMode,
    setOrdersViewMode,
    canBulkCatalog,
    tablePrefs,
    replaceOrdersQuery,
    applyFilterDraft,
    resetFilterDraft,
    ordersFiltersApplied,
    data,
    isLoading,
    isFetching,
    isOrdersListTotalStale: isFetching && isPlaceholderData,
    isError,
    error,
    refetch,
    rows,
    expeditorSummaryRows,
    orderListTotalPages,
    warehousesQ,
    agentsQ,
    expeditorsQ,
    productsFilterQ,
    productCategoriesQ,
    ordersProfileRefsQ,
    clientCategoryFilterOpts,
    tradeDirectionFilterOpts,
    priceTypeFilterOpts,
    buildTerritoryCascade,
    paymentMethodFilterOpts,
    paymentTypeFilterOpts,
    nakladnoyTypeFilterOpts,
    prefetchOrderDetail,
    patchOrderInOrdersListCaches,
    applyOrderDetailToListCaches
  };
}

export type OrdersListPagePart1 = ReturnType<typeof useOrdersListPagePart1>;

"use client";

import type { OrderDetailRow } from "@/components/orders/order-detail-view";
import { api } from "@/lib/api";
import { downloadOrdersNakladnoyXlsx } from "@/lib/order-nakladnoy";
import type { OrdersListCacheBody } from "@/lib/orders-list-cache";
import { useMutation } from "@tanstack/react-query";
import { useCallback, useMemo } from "react";
import {
  buildPaymentPrefillFromSelection,
  formatConsignmentBulkFeedback,
  ordersMutationFeedback,
  rowStatusPatchError,
  type BulkConsignmentResponse,
  type BulkExpeditorResponse,
  type BulkOrderStatusResponse
} from "./types";
import type { OrdersListPagePart1 } from "./use-orders-list-page.part1";

export function useOrdersListPagePart2(p1: OrdersListPagePart1) {
  const {
    tenantSlug,
    qc,
    rows,
    selectedOrderIds,
    setSelectedOrderIds,
    setBulkFeedback,
    setBulkTargetStatus,
    setNakladnoyFeedback,
    setBulkExpFeedback,
    setBulkConsignmentFeedback,
    setBulkExpeditorChoice,
    statusRowError,
    setStatusRowError,
    nakladnoyTemplate,
    nakladnoyPrefs,
    patchOrderInOrdersListCaches,
    applyOrderDetailToListCaches
  } = p1;

  const selectedRows = useMemo(
    () => rows.filter((r) => selectedOrderIds.has(r.id)),
    [rows, selectedOrderIds]
  );

  const selectionTotals = useMemo(() => {
    let qty = 0;
    let total = 0;
    let discount = 0;
    let bonusQty = 0;
    let debt = 0;
    for (const r of selectedRows) {
      qty += Number.parseFloat(String(r.qty).replace(/\s/g, "").replace(",", ".")) || 0;
      total += Number.parseFloat(String(r.total_sum).replace(/\s/g, "").replace(",", ".")) || 0;
      discount += Number.parseFloat(String(r.discount_sum ?? "0").replace(/\s/g, "").replace(",", ".")) || 0;
      bonusQty += Number.parseFloat(String(r.bonus_qty ?? "0").replace(/\s/g, "").replace(",", ".")) || 0;
      if (r.debt != null && r.debt !== "") {
        debt += Number.parseFloat(String(r.debt).replace(/\s/g, "").replace(",", ".")) || 0;
      }
    }
    return { count: selectedRows.length, qty, total, discount, bonusQty, debt };
  }, [selectedRows]);

  const paymentPrefill = useMemo(
    () => buildPaymentPrefillFromSelection(rows, selectedOrderIds),
    [rows, selectedOrderIds]
  );

  const rowStatusMut = useMutation({
    mutationFn: async ({
      id,
      status,
      occurred_at
    }: {
      id: number;
      status: string;
      occurred_at?: string;
    }) => {
      const { data } = await api.patch<OrderDetailRow>(`/api/${tenantSlug}/orders/${id}/status`, {
        status,
        ...(occurred_at ? { occurred_at } : {})
      });
      return data;
    },
    onMutate: async ({ id, status }) => {
      await qc.cancelQueries({ queryKey: ["orders", tenantSlug] });
      const snapshots = qc.getQueriesData<OrdersListCacheBody>({ queryKey: ["orders", tenantSlug] });
      patchOrderInOrdersListCaches(qc, tenantSlug, id, (r) => ({ ...r, status }));
      return { snapshots };
    },
    onSuccess: (detail) => {
      applyOrderDetailToListCaches(qc, tenantSlug, detail);
      setStatusRowError((prev) => {
        const n = { ...prev };
        delete n[detail.id];
        return n;
      });
    },
    onError: (err: unknown, { id }, context) => {
      if (context?.snapshots) {
        for (const [key, data] of context.snapshots) {
          qc.setQueryData(key, data);
        }
      }
      setStatusRowError((prev) => ({ ...prev, [id]: rowStatusPatchError(err) }));
    },
    onSettled: (_data, _err, { id }) => {
      void qc.invalidateQueries({ queryKey: ["order", tenantSlug, id] });
    }
  });

  const nakladnoyMut = useMutation({
    mutationFn: async (payload: {
      template: typeof nakladnoyTemplate;
      prefs: typeof nakladnoyPrefs;
      format?: "xlsx" | "pdf";
      warehouseLayout?: import("@/lib/bulk-export-templates").WarehouseLayoutId;
      expeditorLoadingLayout?: import("@/lib/bulk-export-templates").ExpeditorLoadingLayoutId;
      fallbackFilename?: string;
    }) => {
      await downloadOrdersNakladnoyXlsx({
        tenantSlug: tenantSlug!,
        orderIds: Array.from(selectedOrderIds),
        template: payload.template,
        prefs: payload.prefs,
        format: payload.format ?? "xlsx",
        warehouseLayout: payload.warehouseLayout,
        expeditorLoadingLayout: payload.expeditorLoadingLayout,
        fallbackFilename: payload.fallbackFilename
      });
    },
    onSuccess: (_data, vars) => {
      setNakladnoyFeedback(vars.format === "pdf" ? "PDF fayl yuklab olindi." : "Excel fayl yuklab olindi.");
    },
    onError: (err: unknown) => {
      setNakladnoyFeedback(ordersMutationFeedback(err, "Nakladnoyni yuklab bo‘lmadi."));
    }
  });

  const bulkConsignmentMut = useMutation({
    mutationFn: async (payload: {
      order_ids: number[];
      is_consignment: boolean;
      consignment_due_date?: string | null;
      skipped_ineligible?: number;
    }) => {
      const { skipped_ineligible = 0, ...body } = payload;
      const { data } = await api.post<BulkConsignmentResponse>(
        `/api/${tenantSlug}/orders/bulk/consignment`,
        body
      );
      return { ...data, skipped_ineligible };
    },
    onSuccess: (res) => {
      void qc.invalidateQueries({ queryKey: ["orders", tenantSlug] });
      setBulkConsignmentFeedback(formatConsignmentBulkFeedback(res));
    },
    onError: (err: unknown) => {
      setBulkConsignmentFeedback(ordersMutationFeedback(err, "Не удалось изменить консигнацию."));
    }
  });

  const bulkExpeditorMut = useMutation({
    mutationFn: async (payload: { order_ids: number[]; expeditor_user_id: number | null }) => {
      const { data } = await api.post<BulkExpeditorResponse>(
        `/api/${tenantSlug}/orders/bulk/expeditor`,
        payload
      );
      return data;
    },
    onSuccess: (res) => {
      void qc.invalidateQueries({ queryKey: ["orders", tenantSlug] });
      const n = res.failed.length;
      setBulkExpFeedback(
        n === 0
          ? `${res.updated.length} ta zakaz yangilandi.`
          : `${res.updated.length} ta OK, ${n} ta xato.`
      );
      setBulkExpeditorChoice("");
    },
    onError: (err: unknown) => {
      setBulkExpFeedback(ordersMutationFeedback(err, "Ekspeditorni yangilab bo‘lmadi."));
    }
  });

  const milestoneAtMut = useMutation({
    mutationFn: async ({
      id,
      milestone,
      occurred_at
    }: {
      id: number;
      milestone: string;
      occurred_at: string;
    }) => {
      const { data } = await api.patch<OrderDetailRow>(
        `/api/${tenantSlug}/orders/${id}/milestone-at`,
        { milestone, occurred_at }
      );
      return data;
    },
    onSuccess: (detail) => {
      applyOrderDetailToListCaches(qc, tenantSlug, detail);
      setStatusRowError((prev) => {
        const n = { ...prev };
        delete n[detail.id];
        return n;
      });
    },
    onError: (err: unknown, { id }) => {
      setStatusRowError((prev) => ({ ...prev, [id]: rowStatusPatchError(err) }));
    },
    onSettled: (_data, _err, { id }) => {
      void qc.invalidateQueries({ queryKey: ["order", tenantSlug, id] });
      void qc.invalidateQueries({ queryKey: ["orders", tenantSlug] });
    }
  });

  const bulkStatusMut = useMutation({
    mutationFn: async (payload: {
      order_ids: number[];
      status: string;
      occurred_at?: string;
    }) => {
      const { data } = await api.post<BulkOrderStatusResponse>(
        `/api/${tenantSlug}/orders/bulk/status`,
        payload
      );
      return data;
    },
    onSuccess: (res) => {
      void qc.invalidateQueries({ queryKey: ["orders", tenantSlug] });
      setSelectedOrderIds(new Set());
      setBulkTargetStatus("");
      if (res.failed.length > 0) {
        setBulkFeedback(
          `Yangilandi: ${res.updated.length}. O‘tmadi: ${res.failed.length} (ID: ${res.failed
            .slice(0, 8)
            .map((f) => f.id)
            .join(", ")}${res.failed.length > 8 ? "…" : ""})`
        );
      } else {
        setBulkFeedback(null);
      }
    },
    onError: (err: unknown) => {
      setBulkFeedback(ordersMutationFeedback(err, "Guruh holatini o‘zgartirib bo‘lmadi."));
    }
  });

  const allOnPageSelected = rows.length > 0 && rows.every((o) => selectedOrderIds.has(o.id));

  const toggleOrderSelect = useCallback(
    (id: number) => {
      setSelectedOrderIds((prev) => {
        const n = new Set(prev);
        if (n.has(id)) n.delete(id);
        else n.add(id);
        return n;
      });
      setBulkFeedback(null);
      setNakladnoyFeedback(null);
      setBulkConsignmentFeedback(null);
    },
    [setBulkConsignmentFeedback, setBulkFeedback, setNakladnoyFeedback, setSelectedOrderIds]
  );

  const toggleSelectAllOnPage = useCallback(() => {
    setSelectedOrderIds((prev) => {
      const n = new Set(prev);
      const ids = rows.map((o) => o.id);
      if (allOnPageSelected) {
        ids.forEach((id) => n.delete(id));
      } else {
        ids.forEach((id) => n.add(id));
      }
      return n;
    });
    setBulkFeedback(null);
    setNakladnoyFeedback(null);
    setBulkConsignmentFeedback(null);
  }, [
    allOnPageSelected,
    rows,
    setBulkConsignmentFeedback,
    setBulkFeedback,
    setNakladnoyFeedback,
    setSelectedOrderIds
  ]);

  const clearSelection = useCallback(() => {
    setSelectedOrderIds(new Set());
    setBulkTargetStatus("");
    setBulkFeedback(null);
    setBulkExpeditorChoice("");
    setBulkExpFeedback(null);
    setBulkConsignmentFeedback(null);
    p1.setDownloadsOpen(false);
    p1.setNakladnoySettingsOpen(false);
    p1.setTotalsPanelOpen(false);
    setNakladnoyFeedback(null);
  }, [p1, setBulkExpFeedback, setBulkExpeditorChoice, setBulkFeedback, setBulkTargetStatus, setNakladnoyFeedback, setSelectedOrderIds]);

  return {
    selectedRows,
    selectionTotals,
    paymentPrefill,
    rowStatusMut,
    milestoneAtMut,
    nakladnoyMut,
    bulkExpeditorMut,
    bulkConsignmentMut,
    bulkStatusMut,
    allOnPageSelected,
    toggleOrderSelect,
    toggleSelectAllOnPage,
    clearSelection,
    statusRowError
  };
}

