type StaffPick = { id: number; fio: string; code?: string | null };

function readTerritoryFilter(f: EprFilterState, field: ClientTerritoryFilterField): string {
  switch (field) {
    case "zone":
      return f.territoryZone;
    case "region":
      return f.territoryRegion;
    case "city":
      return f.territoryCity;
    case "district":
      return f.territoryDistrict;
    default:
      return "";
  }
}

/** GET /payments `sort_by` — «Срок» (`term`) bo‘yicha bazada alohida maydon yo‘q */
const EPR_SORTABLE_COLUMN_IDS = new Set<string>([
  "payment_id",
  "paid_at",
  "expeditor",
  "client_name",
  "territory",
  "agent",
  "consignment",
  "order_id",
  "amount",
  "payment_type",
  "trade_direction",
  "note",
  "last_change",
  "changed_by"
]);

type EprPaymentRequestSortKey =
  | "payment_id"
  | "paid_at"
  | "expeditor"
  | "client_name"
  | "territory"
  | "agent"
  | "consignment"
  | "order_id"
  | "amount"
  | "payment_type"
  | "trade_direction"
  | "note"
  | "last_change"
  | "changed_by";

const EPR_SORT_DEFAULT: { sortBy: EprPaymentRequestSortKey; sortDir: "asc" | "desc" } = {
  sortBy: "paid_at",
  sortDir: "desc"
};

function defaultSortDirForColumn(colId: string): "asc" | "desc" {
  const descFirst = new Set([
    "payment_id",
    "paid_at",
    "amount",
    "order_id",
    "consignment",
    "last_change"
  ]);
  return descFirst.has(colId) ? "desc" : "asc";
}

function buildListQuery(
  f: EprFilterState,
  args: {
    page: number;
    limit: number;
    sortBy: EprPaymentRequestSortKey;
    sortDir: "asc" | "desc";
    archive: boolean;
  }
): string {
  const p = new URLSearchParams();
  p.set("page", String(args.page));
  p.set("limit", String(args.limit));
  p.set("entry_kind", "payment");
  p.set("date_field", "created_at");
  if (f.dateFrom.trim()) p.set("date_from", f.dateFrom.trim());
  if (f.dateTo.trim()) p.set("date_to", f.dateTo.trim());
  if (f.dealType !== "both") p.set("deal_type", f.dealType);
  p.set("application_channel", f.tab);
  if (args.archive) p.set("payment_status", "deleted");
  else if (f.status) p.set("payment_status", f.status);
  if (f.expeditorIds.length > 0) p.set("expeditor_user_ids", f.expeditorIds.join(","));
  if (f.agentIds.length > 0) p.set("agent_ids", f.agentIds.join(","));
  if (f.paymentType.trim() && f.paymentType !== "__all__") p.set("payment_type", f.paymentType.trim());
  if (f.tradeDirection.trim() && f.tradeDirection !== "__all__") p.set("trade_direction", f.tradeDirection.trim());
  if (f.territoryZone.trim()) p.set("territory_zone", f.territoryZone.trim());
  if (f.territoryRegion.trim()) p.set("territory_region", f.territoryRegion.trim());
  if (f.territoryCity.trim()) p.set("territory_city", f.territoryCity.trim());
  if (f.territoryDistrict.trim()) p.set("territory_district", f.territoryDistrict.trim());
  if (f.search.trim()) p.set("search", f.search.trim());
  p.set("sort_by", args.sortBy);
  p.set("sort_dir", args.sortDir);
  return p.toString();
}

function workflowStatusLabel(status: string | null | undefined): string {
  switch (status) {
    case "pending_confirmation":
      return "Ожидание подтверждения";
    case "confirmed":
      return "Подтверждено";
    case "rejected":
      return "Отклонено";
    case "deleted":
      return "Удалено";
    default:
      return status?.trim() || "—";
  }
}

function isEprRowSelectable(row: PaymentListApiRow, isAdmin: boolean, archiveView: boolean): boolean {
  if (archiveView) {
    // Arxivda faqat admin va faqat «удалённые» (deleted_at bor) qatorlar tiklanadi.
    return isAdmin && (row.workflow_status === "deleted" || row.deleted_at != null);
  }
  if (row.workflow_status === "pending_confirmation") return true;
  if (isAdmin && row.workflow_status === "confirmed") return true;
  return false;
}

function fmtDateShort(iso: string | null | undefined): string {
  if (!iso) return "—";
  const d = new Date(iso);
  const day = String(d.getDate()).padStart(2, "0");
  const month = String(d.getMonth() + 1).padStart(2, "0");
  const year = d.getFullYear();
  return `${day}.${month}.${year}`;
}

export function ExpeditorPaymentRequestsWorkspace() {
  const router = useRouter();
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const hydrated = useAuthStoreHydrated();
  const role = useEffectiveRole();
  const qc = useQueryClient();
  const canAct = isAdminOrOperatorLikeRole(role);
  const isAdmin = role === "admin";

  const [applied, setApplied] = useState<EprFilterState>(() => defaultEprFilters());
  const [draft, setDraft] = useState<EprFilterState>(() => defaultEprFilters());
  const [page, setPage] = useState(1);
  const [sortBy, setSortBy] = useState<EprPaymentRequestSortKey>(EPR_SORT_DEFAULT.sortBy);
  const [sortDir, setSortDir] = useState<"asc" | "desc">(EPR_SORT_DEFAULT.sortDir);
  const [selected, setSelected] = useState<Set<number>>(() => new Set());
  const [columnDialogOpen, setColumnDialogOpen] = useState(false);
  const [pageSettingsOpen, setPageSettingsOpen] = useState(false);
  const [deleteModalOpen, setDeleteModalOpen] = useState(false);
  const [archiveView, setArchiveView] = useState(false);
  const [restoreBusy, setRestoreBusy] = useState(false);
  const [restoreModalOpen, setRestoreModalOpen] = useState(false);
  const [restoreComment, setRestoreComment] = useState("");
  const [nowTick, setNowTick] = useState(() => Date.now());
  const headerCheckboxRef = useRef<HTMLInputElement | null>(null);

  useEffect(() => {
    const h = setInterval(() => setNowTick(Date.now()), 30_000);
    return () => clearInterval(h);
  }, []);

  const tablePrefs = useUserTablePrefs({
    tenantSlug,
    tableId: EXPEDITOR_PAYMENT_REQUESTS_TABLE_ID,
    defaultColumnOrder: DEFAULT_EXPEDITOR_PAYMENT_REQUEST_COLUMN_ORDER,
    defaultPageSize: 10,
    allowedPageSizes: [10, 20, 30, 50],
    defaultHiddenColumnIds: [...DEFAULT_HIDDEN_EXPEDITOR_PAYMENT_REQUEST_COLUMNS]
  });

  const allowedColIds = useMemo(() => new Set(EXPEDITOR_PAYMENT_REQUEST_COLUMNS.map((c) => c.id)), []);
  const visibleDataColumns = useMemo(
    () => tablePrefs.visibleColumnOrder.filter((id) => allowedColIds.has(id)),
    [tablePrefs.visibleColumnOrder, allowedColIds]
  );

  const expeditorsQ = useQuery({
    queryKey: ["expeditors", tenantSlug, "payment-requests"],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: StaffPick[] }>(`/api/${tenantSlug}/expeditors?is_active=true`);
      return data.data ?? [];
    }
  });

  const agentsQ = useQuery({
    queryKey: ["agents", tenantSlug, "payment-requests"],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: StaffPick[] }>(`/api/${tenantSlug}/agents?is_active=true`);
      return data.data ?? [];
    }
  });

  const filterOptQ = useQuery({
    queryKey: ["agents-filter-options", tenantSlug, "expeditor-requests"],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: { trade_directions: string[] } }>(
        `/api/${tenantSlug}/agents/filter-options`
      );
      return data.data;
    }
  });

  const clientRefsQ = useQuery({
    queryKey: ["clients-references", tenantSlug, "expeditor-requests"],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{
        regions?: string[];
        cities?: string[];
        districts?: string[];
        zones?: string[];
        region_options?: { value: string; label: string }[];
        city_options?: { value: string; label: string }[];
      }>(`/api/${tenantSlug}/clients/references`);
      return data;
    }
  });

  const territoryOptsQ = useQuery({
    queryKey: ["client-balances-territory-options", tenantSlug, "expeditor-requests"],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: ClientBalanceTerritoryOptions }>(
        `/api/${tenantSlug}/client-balances/territory-options`
      );
      return data.data;
    }
  });

  const profileQ = useQuery({
    queryKey: ["settings", "profile", tenantSlug, "expeditor-requests-methods"],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.profile,
    queryFn: async () => {
      const { data } = await api.get<{
        references?: {
          payment_types?: string[];
          payment_method_entries?: ProfilePaymentMethodEntry[];
          trade_directions?: string[];
          territory_levels?: string[];
          territory_nodes?: TerritoryNode[];
        };
      }>(`/api/${tenantSlug}/settings/profile`);
      return data.references ?? {};
    }
  });

  const territoryFilterSpecs = useMemo(
    () => buildClientTerritoryFilterLevels(profileQ.data?.territory_levels),
    [profileQ.data?.territory_levels]
  );

  const payFilterOpts = useMemo(
    () => paymentMethodSelectOptions(profileQ.data, profileQ.data?.payment_types),
    [profileQ.data]
  );

  const paymentTypeLabelByValue = useMemo(() => {
    const m = new Map<string, string>();
    for (const o of payFilterOpts) m.set(o.value, o.label);
    return m;
  }, [payFilterOpts]);

  const tradeDirectionOptions = useMemo(() => {
    const s = new Set<string>();
    for (const x of filterOptQ.data?.trade_directions ?? []) {
      const t = x.trim();
      if (t) s.add(t);
    }
    for (const x of profileQ.data?.trade_directions ?? []) {
      const t = x.trim();
      if (t) s.add(t);
    }
    return Array.from(s).sort((a, b) => a.localeCompare(b, "ru"));
  }, [filterOptQ.data?.trade_directions, profileQ.data?.trade_directions]);

  const tradeDirectionFilterOptions = useMemo(
    () => tradeDirectionOptions.map((td) => ({ value: td, label: td })),
    [tradeDirectionOptions]
  );

  const expeditorFilterOptions = useMemo(
    () =>
      (expeditorsQ.data ?? []).map((e) => ({
        value: String(e.id),
        label: e.code ? `${e.fio} (${e.code})` : e.fio,
        searchText: `${e.fio} ${e.code ?? ""}`
      })),
    [expeditorsQ.data]
  );

  const agentFilterOptions = useMemo(
    () =>
      (agentsQ.data ?? []).map((a) => ({
        value: String(a.id),
        label: a.code ? `${a.fio} (${a.code})` : a.fio,
        searchText: `${a.fio} ${a.code ?? ""}`
      })),
    [agentsQ.data]
  );

  const listQ = useQuery({
    queryKey: [
      "expeditor-payment-requests",
      tenantSlug,
      applied,
      page,
      tablePrefs.pageSize,
      sortBy,
      sortDir,
      archiveView
    ],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.list,
    queryFn: async () => {
      const qs = buildListQuery(applied, {
        page,
        limit: tablePrefs.pageSize,
        sortBy,
        sortDir,
        archive: archiveView
      });
      const { data } = await api.get<PaymentListApiResponse>(`/api/${tenantSlug}/payments?${qs}`);
      return data;
    }
  });

  const switchArchiveView = useCallback((next: boolean) => {
    setArchiveView(next);
    setPage(1);
    setSelected(new Set());
  }, []);

  const handleSortColumnClick = useCallback((colId: string) => {
    if (!EPR_SORTABLE_COLUMN_IDS.has(colId)) return;
    const key = colId as EprPaymentRequestSortKey;
    setPage(1);
    setSelected(new Set());
    setSortBy((prev) => {
      if (prev === key) {
        setSortDir((d) => (d === "asc" ? "desc" : "asc"));
        return prev;
      }
      setSortDir(defaultSortDirForColumn(colId));
      return key;
    });
  }, []);

  const [rejectBusy, setRejectBusy] = useState(false);
  const [deleteBusy, setDeleteBusy] = useState(false);
  const [returnBusy, setReturnBusy] = useState(false);
  const [returnModalOpen, setReturnModalOpen] = useState(false);
  const [returnReason, setReturnReason] = useState("");
  const [returnDurationMin, setReturnDurationMin] = useState(30);

  const applyFilters = useCallback(() => {
    setApplied({ ...draft });
    setPage(1);
    setSelected(new Set());
  }, [draft]);

  const resetFilters = useCallback(() => {
    const d = defaultEprFilters();
    setDraft(d);
    setApplied(d);
    setPage(1);
    setSelected(new Set());
    setSortBy(EPR_SORT_DEFAULT.sortBy);
    setSortDir(EPR_SORT_DEFAULT.sortDir);
  }, []);

  const setTab = (tab: SourceTab) => {
    setDraft((d) => ({ ...d, tab }));
    setApplied((a) => ({ ...a, tab }));
    setPage(1);
    setSelected(new Set());
  };

  const toggleRow = (id: number) => {
    setSelected((prev) => {
      const n = new Set(prev);
      if (n.has(id)) n.delete(id);
      else n.add(id);
      return n;
    });
  };

  const rows = listQ.data?.data ?? [];
  const total = listQ.data?.total ?? 0;
  const selectableOnPage = useMemo(
    () => rows.filter((r) => isEprRowSelectable(r, isAdmin, archiveView)).map((r) => r.id),
    [rows, isAdmin, archiveView]
  );
  const allSelectableSelected =
    selectableOnPage.length > 0 && selectableOnPage.every((id) => selected.has(id));

  const toggleAllPage = () => {
    if (selectableOnPage.length === 0) return;
    const allSel = selectableOnPage.every((id) => selected.has(id));
    setSelected((prev) => {
      const n = new Set(prev);
      if (allSel) for (const id of selectableOnPage) n.delete(id);
      else for (const id of selectableOnPage) n.add(id);
      return n;
    });
  };

  const selectedRows = useMemo(
    () => rows.filter((r) => selected.has(r.id)),
    [rows, selected]
  );
  const allSelectedPending =
    selectedRows.length > 0 && selectedRows.every((r) => r.workflow_status === "pending_confirmation");
  const allSelectedConfirmed =
    selectedRows.length > 0 && selectedRows.every((r) => r.workflow_status === "confirmed");
  const deleteActionEnabled =
    canAct &&
    selected.size > 0 &&
    !rejectBusy &&
    !deleteBusy &&
    (allSelectedPending || (isAdmin && allSelectedConfirmed));

  const pageTotalAmount = useMemo(() => {
    let sum = 0;
    for (const r of rows) {
      sum += Number.parseFloat(r.amount) || 0;
    }
    return sum;
  }, [rows]);

  const isPartialSelected =
    selected.size > 0 && !allSelectableSelected && selectableOnPage.some((id) => selected.has(id));

  useEffect(() => {
    if (headerCheckboxRef.current) {
      headerCheckboxRef.current.indeterminate = isPartialSelected;
    }
  }, [isPartialSelected]);

  useEffect(() => {
    setSelected((prev) => {
      if (prev.size === 0) return prev;
      const valid = new Set(rows.map((r) => r.id));
      let changed = false;
      const next = new Set<number>();
      for (const id of prev) {
        if (valid.has(id)) next.add(id);
        else changed = true;
      }
      return changed ? next : prev;
    });
  }, [rows]);

  const territoryFilterOptions = useMemo(
    () =>
      territoryFilterSpecs.map((spec) => {
        const opts = buildPaymentTerritorySelectOptions(
          spec.field,
          clientRefsQ.data,
          territoryOptsQ.data,
          profileQ.data?.territory_nodes,
          readTerritoryFilter(draft, spec.field)
        );
        return {
          key:
            spec.field === "zone"
              ? "territoryZone"
              : spec.field === "region"
                ? "territoryRegion"
                : spec.field === "city"
                  ? "territoryCity"
                  : "territoryDistrict",
          label: spec.label,
          options: opts.map((o) => ({ value: o.value, label: o.label })),
          value: readTerritoryFilter(draft, spec.field)
        };
      }),
    [territoryFilterSpecs, clientRefsQ.data, territoryOptsQ.data, profileQ.data?.territory_nodes, draft]
  );

  const handleBulkDelete = useCallback(() => {
    if (allSelectedPending) {
      const reason = window.prompt("Причина отклонения (необязательно):") ?? "";
      void (async () => {
        setRejectBusy(true);
        try {
          for (const id of Array.from(selected)) {
            await api.post(`/api/${tenantSlug}/payments/${id}/reject`, {
              reason: reason.trim() || undefined
            });
          }
          setSelected(new Set());
          void qc.invalidateQueries({ queryKey: ["expeditor-payment-requests", tenantSlug] });
          void qc.invalidateQueries({ queryKey: ["payments", tenantSlug] });
        } finally {
          setRejectBusy(false);
          setDeleteModalOpen(false);
        }
      })();
      return;
    }
    if (isAdmin && allSelectedConfirmed) {
      const reason = window.prompt("Причина удаления в архив (обязательно для аудита):") ?? "";
      if (!reason.trim()) {
        window.alert("Укажите причину.");
        return;
      }
      void (async () => {
        setDeleteBusy(true);
        try {
          for (const id of Array.from(selected)) {
            const sp = new URLSearchParams();
            sp.set("cancel_reason_ref", reason.trim().slice(0, 128));
            await api.delete(`/api/${tenantSlug}/payments/${id}?${sp.toString()}`);
          }
          setSelected(new Set());
          void qc.invalidateQueries({ queryKey: ["expeditor-payment-requests", tenantSlug] });
          void qc.invalidateQueries({ queryKey: ["payments", tenantSlug] });
        } finally {
          setDeleteBusy(false);
          setDeleteModalOpen(false);
        }
      })();
    }
  }, [
    allSelectedConfirmed,
    allSelectedPending,
    isAdmin,
    qc,
    selected,
    tenantSlug
  ]);

  // Xato to'lovni ekspeditorga qaytarish (pending → rad; tasdiqlangan → bekor + qarz qayta ochiladi).
  const returnActionEnabled =
    canAct &&
    selected.size > 0 &&
    !rejectBusy &&
    !deleteBusy &&
    !returnBusy &&
    (allSelectedPending || (isAdmin && allSelectedConfirmed));

  const handleReturnToExpeditor = useCallback(() => {
    if (!returnActionEnabled) return;
    setReturnReason("");
    setReturnDurationMin(30);
    setReturnModalOpen(true);
  }, [returnActionEnabled]);

  const confirmReturnToExpeditor = useCallback(() => {
    if (!returnActionEnabled) return;
    const reason = returnReason.trim();
    const duration = Math.min(1440, Math.max(1, Math.round(returnDurationMin) || 30));
    void (async () => {
      setReturnBusy(true);
      try {
        for (const id of Array.from(selected)) {
          await api.post(`/api/${tenantSlug}/payments/${id}/return-to-expeditor`, {
            reason: reason || undefined,
            duration_minutes: duration
          });
        }
        setSelected(new Set());
        setReturnModalOpen(false);
        void qc.invalidateQueries({ queryKey: ["expeditor-payment-requests", tenantSlug] });
        void qc.invalidateQueries({ queryKey: ["payments", tenantSlug] });
      } finally {
        setReturnBusy(false);
      }
    })();
  }, [returnActionEnabled, returnReason, returnDurationMin, selected, tenantSlug, qc]);

  // Arxivdagi (удалённые) to'lovlarni tiklash — faqat admin.
  const restoreActionEnabled =
    isAdmin && archiveView && selected.size > 0 && !restoreBusy;

  const handleRestore = useCallback(() => {
    if (!restoreActionEnabled) return;
    setRestoreComment("");
    setRestoreModalOpen(true);
  }, [restoreActionEnabled]);

  const confirmRestore = useCallback(() => {
    const comment = restoreComment.trim();
    if (!comment) return;
    void (async () => {
      setRestoreBusy(true);
      try {
        for (const id of Array.from(selected)) {
          await api.post(`/api/${tenantSlug}/payments/${id}/restore`, { comment });
        }
        setSelected(new Set());
        setRestoreModalOpen(false);
        void qc.invalidateQueries({ queryKey: ["expeditor-payment-requests", tenantSlug] });
        void qc.invalidateQueries({ queryKey: ["payments", tenantSlug] });
      } finally {
        setRestoreBusy(false);
      }
    })();
  }, [restoreComment, selected, tenantSlug, qc]);

  const exportXlsx = useCallback(async () => {
    if (!rows.length) return;
    await downloadXlsxSheet(
      `expeditor-payment-requests-${applied.dateFrom}_${applied.dateTo}.xlsx`,
      "Заявки",
      [
        "ID оплаты",
        "Дата оплаты",
        "Экспедитор",
        "Клиенты",
        "Территория",
        "Агент",
        "Консигнация",
        "Заказ ID",
        "Сумма",
        "Способ оплаты",
        "Статус",
        "Срок",
        "Направление торговли",
        "Комментарий",
        "Дата последнего изменения",
        "Кто изменил"
      ],
      rows.map((r) => [
        r.id,
        r.paid_at?.slice(0, 10) ?? r.created_at?.slice(0, 10) ?? "",
        r.expeditor_name ?? "",
        r.client_name,
        [r.client_region, r.client_city, r.client_district].filter(Boolean).join(" / "),
        r.agent_name ?? "",
        r.consignment ? "да" : "нет",
        r.order_number ?? "",
        r.amount,
        paymentTypeLabelByValue.get(r.payment_type) ?? r.payment_type,
        workflowStatusLabel(r.workflow_status),
        "—",
        r.trade_direction ?? "",
        r.note ?? "",
        r.confirmed_at ?? r.created_at ?? "",
        r.deleted_by_name ?? "—"
      ]),
      { colWidths: [10, 12, 16, 22, 22, 14, 10, 12, 12, 14, 18, 8, 16, 28, 18, 14] }
    );
  }, [applied.dateFrom, applied.dateTo, paymentTypeLabelByValue, rows]);

  if (!hydrated) return <p className="text-sm text-muted-foreground">Загрузка сессии…</p>;
  if (!tenantSlug) {
    return (
      <p className="text-sm text-destructive">
        <Link href="/login" className="underline">
          Войти
        </Link>
      </p>
    );
  }

  const dataColSpan = 1 + visibleDataColumns.length;

  const renderPaymentRequestDataCell = (r: PaymentListApiRow, colId: string) => {
    switch (colId) {
      case "payment_id":
        return (
          <td key={colId} className="whitespace-nowrap border-b border-border px-2 py-2 font-medium text-slate-700">
            <Link href={`/payments/${r.id}`} className="text-[#063b36] hover:underline">
              {r.id}
            </Link>
          </td>
        );
      case "paid_at":
        return (
          <td key={colId} className="whitespace-nowrap border-b border-border px-2 py-2 text-slate-600">
            {fmtDateShort(r.paid_at)}
          </td>
        );
      case "expeditor":
        return (
          <td key={colId} className="max-w-[140px] px-2 py-2 text-xs">
            <span className="flex items-center gap-1">
              {r.created_via_mobile ? (
                <Smartphone
                  className="size-3.5 shrink-0 text-teal-600"
                  aria-label="Создано в мобильном приложении"
                />
              ) : null}
              <span className="truncate">{r.expeditor_name ?? "—"}</span>
            </span>
          </td>
        );
      case "client_name":
        return (
          <td key={colId} className="max-w-[140px] truncate whitespace-nowrap border-b border-border px-2 py-2">
            <Link
              href={`/clients/${r.client_id}`}
              className="inline-flex items-center gap-1 text-[#063b36] hover:underline"
            >
              {r.client_name}
              <ExternalLink className="size-3 text-slate-400" />
            </Link>
          </td>
        );
      case "territory":
        return (
          <td key={colId} className="max-w-[160px] truncate px-2 py-2 text-xs text-muted-foreground">
            {[r.client_region, r.client_city, r.client_district].filter(Boolean).join(" / ") || "—"}
          </td>
        );
      case "agent":
        return (
          <td key={colId} className="max-w-[100px] truncate px-2 py-2 text-xs">
            {r.agent_name ?? "—"}
          </td>
        );
      case "consignment":
        return (
          <td key={colId} className="whitespace-nowrap border-b border-border px-2 py-2 text-xs">
            {r.consignment ? (
              <span className="font-medium text-amber-600">Да</span>
            ) : (
              <span className="text-slate-500">Нет</span>
            )}
          </td>
        );
      case "order_id":
        return (
          <td key={colId} className="whitespace-nowrap border-b border-border px-2 py-2 text-xs">
            {r.order_number ? (
              <Link
                href={r.order_id ? `/orders/${r.order_id}` : "#"}
                className="inline-flex items-center gap-1 text-[#063b36] hover:underline"
              >
                {r.order_number}
                <ExternalLink className="size-3 text-slate-400" />
              </Link>
            ) : (
              <span className="text-slate-300">—</span>
            )}
          </td>
        );
      case "amount":
        return (
          <td key={colId} className="whitespace-nowrap border-b border-border px-2 py-2 text-right tabular-nums font-semibold text-slate-800">
            {formatNumberGrouped(r.amount, { minFractionDigits: 0, maxFractionDigits: 0 })}
          </td>
        );
      case "payment_type":
        return (
          <td key={colId} className="max-w-[100px] truncate border-b border-border px-2 py-2 text-xs text-slate-600">
            {paymentTypeLabelByValue.get(r.payment_type) ?? r.payment_type}
          </td>
        );
      case "workflow_status": {
        const pending = r.workflow_status === "pending_confirmation";
        const rejected = r.workflow_status === "rejected";
        return (
          <td key={colId} className="whitespace-nowrap border-b border-border px-2 py-2 text-xs">
            <span
              className={cn(
                "inline-flex rounded-full px-2 py-0.5 font-medium",
                pending && "bg-amber-50 text-amber-700",
                r.workflow_status === "confirmed" && "bg-emerald-50 text-emerald-700",
                rejected && "bg-red-50 text-red-700",
                !pending && r.workflow_status !== "confirmed" && !rejected && "bg-muted text-slate-600"
              )}
            >
              {workflowStatusLabel(r.workflow_status)}
            </span>
          </td>
        );
      }
      case "term": {
        const expMs = r.return_expires_at ? new Date(r.return_expires_at).getTime() : null;
        if (r.workflow_status === "rejected" && expMs != null) {
          const remMin = Math.ceil((expMs - nowTick) / 60_000);
          if (remMin > 0) {
            return (
              <td key={colId} className="whitespace-nowrap px-2 py-2 text-xs">
                <span className="inline-flex items-center gap-1 rounded-full bg-amber-50 px-2 py-0.5 font-medium text-amber-700">
                  <Clock className="size-3" />
                  {remMin} мин
                </span>
              </td>
            );
          }
          return (
            <td key={colId} className="whitespace-nowrap px-2 py-2 text-xs text-slate-400">
              истекает…
            </td>
          );
        }
        return (
          <td key={colId} className="px-2 py-2 text-xs text-muted-foreground">
            —
          </td>
        );
      }
      case "trade_direction":
        return (
          <td key={colId} className="max-w-[120px] truncate px-2 py-2 text-xs">
            {r.trade_direction ?? "—"}
          </td>
        );
      case "note":
        return (
          <td
            key={colId}
            className="max-w-[180px] truncate px-2 py-2 text-xs text-muted-foreground"
            title={r.note ?? ""}
          >
            {r.note ?? "—"}
          </td>
        );
      case "last_change":
        return (
          <td key={colId} className="whitespace-nowrap px-2 py-2 text-xs text-muted-foreground">
            {(r.confirmed_at ?? r.created_at)?.slice(0, 19).replace("T", " ") ?? "—"}
          </td>
        );
      case "changed_by":
        return (
          <td key={colId} className="max-w-[100px] truncate px-2 py-2 text-xs text-muted-foreground">
            {r.deleted_by_name ?? "—"}
          </td>
        );
      default:
        return null;
    }
  };

  const thClassForCol = (colId: string) =>
    cn(
      "px-2 py-2.5",
      colId === "amount" && "text-right",
      colId === "note" && "min-w-[140px]"
    );

  const amountColIndex = visibleDataColumns.indexOf("amount");

  return (
    <EprPageLayout>
      <div className="flex flex-wrap items-center justify-between gap-4">
        <h1 className="text-xl font-semibold text-slate-800">Заявки на оплату экспедиторов</h1>
        <div className="flex flex-wrap items-center gap-2">
          <EprTabBar active={draft.tab} onChange={setTab} />
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-9 gap-2 border-border shadow-sm"
            onClick={() => setPageSettingsOpen(true)}
          >
            <Settings className="size-4" />
            Настройки
          </Button>
        </div>
      </div>

      <EprFiltersPanel
        draft={draft}
        expeditorOptions={expeditorFilterOptions}
        agentOptions={agentFilterOptions}
        paymentMethodOptions={payFilterOpts.map((o) => ({ value: o.value, label: o.label }))}
        tradeDirectionOptions={tradeDirectionFilterOptions}
        territoryOptions={territoryFilterOptions}
        onDraftChange={(patch) => {
          setDraft((d) => {
            let next = { ...d, ...patch };
            if ("territoryZone" in patch) {
              next = { ...next, territoryRegion: "", territoryCity: "", territoryDistrict: "" };
            } else if ("territoryRegion" in patch) {
              next = { ...next, territoryCity: "", territoryDistrict: "" };
            } else if ("territoryCity" in patch) {
              next = { ...next, territoryDistrict: "" };
            }
            return next;
          });
        }}
        onApply={applyFilters}
        onReset={resetFilters}
      />

      <section className="overflow-hidden rounded-xl border border-border bg-card shadow-sm" aria-label="Таблица заявок">
        <div className="flex flex-wrap items-center gap-2 border-b border-border px-4 py-3">
            <div className="flex min-w-0 flex-1 flex-wrap items-center gap-2">
              <div className="flex items-center rounded-lg border border-border bg-card p-0.5 text-xs shadow-sm">
                <button
                  type="button"
                  onClick={() => switchArchiveView(false)}
                  className={cn(
                    "rounded-md px-3 py-1.5 font-medium transition",
                    !archiveView ? "bg-[#063b36] text-white shadow" : "text-slate-600 hover:bg-muted"
                  )}
                >
                  Заявки
                </button>
                <button
                  type="button"
                  onClick={() => switchArchiveView(true)}
                  className={cn(
                    "inline-flex items-center gap-1 rounded-md px-3 py-1.5 font-medium transition",
                    archiveView ? "bg-[#063b36] text-white shadow" : "text-slate-600 hover:bg-muted"
                  )}
                  title="Удалённые оплаты (архив)"
                >
                  <Trash2 className="size-3.5" />
                  Удалённые
                </button>
              </div>
              <Button
                type="button"
                variant="ghost"
                size="icon"
                className="size-9 text-slate-500"
                title="Колонки таблицы"
                onClick={() => setColumnDialogOpen(true)}
              >
                <Columns3 className="size-4" />
              </Button>
              <select
                className={cn(
                  filterPanelSelectClassName,
                  "h-9 w-[4.5rem] min-w-0 max-w-none shrink-0 bg-card text-sm dark:bg-background"
                )}
                value={String(tablePrefs.pageSize)}
                onChange={(e) => {
                  const n = Number.parseInt(e.target.value, 10) || 10;
                  tablePrefs.setPageSize(n);
                  setPage(1);
                }}
                aria-label="Строк на странице"
              >
                {[10, 20, 30, 50].map((n) => (
                  <option key={n} value={String(n)}>
                    {n}
                  </option>
                ))}
              </select>
              <div className="relative min-w-0 w-full max-w-xl flex-1 sm:min-w-[12rem]">
                <Search className="pointer-events-none absolute top-2.5 left-2.5 size-4 text-muted-foreground" />
                <Input
                  className="h-9 pl-9"
                  placeholder="Поиск"
                  value={draft.search}
                  onChange={(e) => setDraft((d) => ({ ...d, search: e.target.value }))}
                  onKeyDown={(e) => {
                    if (e.key === "Enter") applyFilters();
                  }}
                />
              </div>
            </div>
            <div className="flex shrink-0 flex-wrap items-center justify-end gap-2">
              <Button
                type="button"
                size="sm"
                className="h-9 gap-1 bg-green-600 px-3 text-white hover:bg-green-700"
                onClick={() => void exportXlsx()}
              >
                <Download className="size-3.5" />
                Excel
              </Button>
              <Button
                type="button"
                variant="outline"
                size="icon"
                className="size-9 shrink-0"
                title="Обновить"
                onClick={() => void listQ.refetch()}
              >
                <RefreshCw className={cn("size-4", listQ.isFetching && "animate-spin")} />
              </Button>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full min-w-[1280px] border-collapse text-xs">
              <thead className="bg-muted text-slate-500">
                <tr className="h-[74px]">
                  <th className="sticky left-0 w-8 border-b border-border bg-muted px-2 py-2">
                    <input
                      ref={headerCheckboxRef}
                      type="checkbox"
                      checked={allSelectableSelected}
                      onChange={toggleAllPage}
                      disabled={!canAct || selectableOnPage.length === 0}
                      className="accent-teal-600"
                      aria-label="Выбрать все на странице"
                    />
                  </th>
                  {visibleDataColumns.map((colId) => {
                    const def = EXPEDITOR_PAYMENT_REQUEST_COLUMNS.find((c) => c.id === colId);
                    const sortable = EPR_SORTABLE_COLUMN_IDS.has(colId);
                    const active = sortable && sortBy === colId;
                    return (
                      <th
                        key={colId}
                        className={cn(
                          "border-b border-border px-2 py-2 text-left font-medium whitespace-nowrap",
                          thClassForCol(colId),
                          sortable && "p-0"
                        )}
                      >
                        {sortable ? (
                          <button
                            type="button"
                            className={cn(
                              "group flex h-[74px] w-full min-w-0 items-center gap-1 px-2 py-2 text-left font-medium",
                              colId === "amount" && "justify-end text-right"
                            )}
                            onClick={() => handleSortColumnClick(colId)}
                          >
                            <span className="min-w-0 flex-1 truncate">{def?.label ?? colId}</span>
                            {active ? (
                              sortDir === "asc" ? (
                                <ArrowUp className="size-3.5 shrink-0 text-teal-600 dark:text-teal-400" aria-hidden />
                              ) : (
                                <ArrowDown className="size-3.5 shrink-0 text-teal-600 dark:text-teal-400" aria-hidden />
                              )
                            ) : (
                              <ArrowUpDown
                                className="size-3.5 shrink-0 opacity-35 group-hover:opacity-70"
                                aria-hidden
                              />
                            )}
                          </button>
                        ) : (
                          <span className="block px-2 py-2">{def?.label ?? colId}</span>
                        )}
                      </th>
                    );
                  })}
                </tr>
              </thead>
              <tbody>
                {listQ.isFetching && !listQ.data ? (
                  <tr>
                    <td colSpan={dataColSpan} className="px-3 py-10 text-center text-muted-foreground">
                      Загрузка…
                    </td>
                  </tr>
                ) : rows.length === 0 ? (
                  <tr>
                    <td colSpan={dataColSpan} className="px-4 py-10 text-center text-slate-400">
                      {archiveView
                        ? "Удалённых оплат за выбранный период нет."
                        : "Нет данных. Измените фильтр или создайте новую заявку."}
                    </td>
                  </tr>
                ) : (
                  rows.map((r) => {
                    const isSelected = selected.has(r.id);
                    const isSelectable = canAct && isEprRowSelectable(r, isAdmin, archiveView);
                    return (
                      <tr
                        key={r.id}
                        className={cn(
                          "group h-[76px] hover:bg-muted",
                          isSelected && isSelectable && "bg-cyan-50/70"
                        )}
                      >
                        <td className="sticky left-0 bg-inherit border-b border-border px-2 py-2">
                          {isSelectable ? (
                            <input
                              type="checkbox"
                              checked={isSelected}
                              onChange={() => toggleRow(r.id)}
                              className="accent-[#063b36]"
                              aria-label={`Выбрать ${r.id}`}
                            />
                          ) : (
                            <span className="inline-block w-4" />
                          )}
                        </td>
                        {visibleDataColumns.map((colId) => renderPaymentRequestDataCell(r, colId))}
                      </tr>
                    );
                  })
                )}
                {rows.length > 0 && amountColIndex >= 0 ? (
                  <tr className="bg-muted font-semibold text-slate-700">
                    <td colSpan={amountColIndex + 1} className="border-t border-border px-2 py-2 text-right">
                      Итого
                    </td>
                    <td className="border-t border-border px-2 py-2 text-right tabular-nums">
                      {formatNumberGrouped(pageTotalAmount, { minFractionDigits: 0, maxFractionDigits: 0 })} UZS
                    </td>
                    <td
                      colSpan={Math.max(0, visibleDataColumns.length - amountColIndex - 1)}
                      className="border-t border-border"
                    />
                  </tr>
                ) : null}
              </tbody>
            </table>
          </div>

          {!archiveView && applied.status === "pending_confirmation" && total === 0 && !listQ.isFetching ? (
            <div className="border-t border-amber-100 bg-amber-50/80 px-4 py-3 text-xs text-amber-800">
              Нет заявок в статусе «Ожидание подтверждения». Экспедитор создаёт их в мобильном приложении при
              приёме оплаты; после подтверждения они переходят в «Подтверждено».
            </div>
          ) : null}

          {total > 0 ? (
            <div className="border-t border-border px-4 py-3">
              <TemplatePagination
                page={page}
                pageSize={tablePrefs.pageSize}
                total={total}
                onPageChange={setPage}
                onPageSizeChange={(n) => {
                  tablePrefs.setPageSize(n);
                  setPage(1);
                }}
                pageSizeOptions={[10, 20, 30, 50]}
              />
            </div>
          ) : null}
      </section>

      {archiveView ? (
        <EprRestoreActionBar
          selectedCount={selected.size}
          total={total}
          restoreDisabled={!restoreActionEnabled}
          restoreHint={!isAdmin ? "Восстановление доступно только администратору" : undefined}
          onRestore={handleRestore}
          onClear={() => setSelected(new Set())}
        />
      ) : (
        <EprFloatingActionBar
          selectedCount={selected.size}
          total={total}
          confirmDisabled={!canAct || !allSelectedPending || selected.size === 0}
          deleteDisabled={!deleteActionEnabled}
          returnDisabled={!returnActionEnabled}
          confirmHint={
            !allSelectedPending && selected.size > 0
              ? "Подтверждение только для статуса «Ожидание подтверждения»"
              : undefined
          }
          returnHint={
            selected.size > 0 && !allSelectedPending && !(isAdmin && allSelectedConfirmed)
              ? "Возврат доступен для «Ожидание подтверждения» (и подтверждённых — для админа)"
              : undefined
          }
          onConfirm={() => {
            if (!allSelectedPending || selected.size === 0) return;
            router.push(`/expeditor-payment-requests/confirm?ids=${Array.from(selected).join(",")}`);
          }}
          onDelete={() => {
            if (!deleteActionEnabled) return;
            setDeleteModalOpen(true);
          }}
          onReturn={handleReturnToExpeditor}
          onClear={() => setSelected(new Set())}
        />
      )}

      <EprBulkDeleteModal
        open={deleteModalOpen}
        count={selected.size}
        busy={rejectBusy || deleteBusy}
        onClose={() => setDeleteModalOpen(false)}
        onConfirm={handleBulkDelete}
      />

      <Dialog open={returnModalOpen} onOpenChange={(o) => !returnBusy && setReturnModalOpen(o)}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Вернуть экспедитору на исправление</DialogTitle>
            <DialogDescription>
              Оплата ({selected.size}) будет возвращена экспедитору. Долг по заказу снова откроется,
              а у экспедитора появится таймер на исправление. Если он не исправит оплату за
              отведённое время, возврат отменяется.
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-2">
            <div className="space-y-2">
              <Label htmlFor="epr-return-reason" className="text-xs text-muted-foreground">
                Причина (необязательно)
              </Label>
              <textarea
                id="epr-return-reason"
                rows={3}
                value={returnReason}
                onChange={(e) => setReturnReason(e.target.value)}
                placeholder="Например: неверная сумма или способ оплаты"
                className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:ring-2 focus-visible:ring-ring"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="epr-return-duration" className="text-xs text-muted-foreground">
                Время на исправление
              </Label>
              <select
                id="epr-return-duration"
                className={cn(filterPanelSelectClassName, "h-10 w-full max-w-none bg-background")}
                value={String(returnDurationMin)}
                onChange={(e) => setReturnDurationMin(Number(e.target.value) || 30)}
              >
                <option value="5">5 минут</option>
                <option value="10">10 минут</option>
                <option value="15">15 минут</option>
                <option value="30">30 минут</option>
                <option value="60">1 час</option>
                <option value="120">2 часа</option>
                <option value="240">4 часа</option>
                <option value="480">8 часов</option>
                <option value="1440">24 часа</option>
              </select>
            </div>
          </div>
          <div className="flex justify-end gap-2">
            <Button
              type="button"
              variant="outline"
              disabled={returnBusy}
              onClick={() => setReturnModalOpen(false)}
            >
              Отмена
            </Button>
            <Button
              type="button"
              className="bg-amber-500 text-white hover:bg-amber-600"
              disabled={returnBusy || selected.size === 0}
              onClick={confirmReturnToExpeditor}
            >
              {returnBusy ? "Возврат…" : "Вернуть экспедитору"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={restoreModalOpen} onOpenChange={(o) => !restoreBusy && setRestoreModalOpen(o)}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Восстановить оплату</DialogTitle>
            <DialogDescription>
              Выбранные оплаты ({selected.size}) будут восстановлены из архива. Баланс клиента и
              распределения будут пересчитаны. Укажите причину восстановления — она сохранится в истории.
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-2">
            <div className="space-y-2">
              <Label htmlFor="epr-restore-comment" className="text-xs text-muted-foreground">
                Причина восстановления
              </Label>
              <textarea
                id="epr-restore-comment"
                rows={3}
                value={restoreComment}
                onChange={(e) => setRestoreComment(e.target.value)}
                placeholder="Например: оплата удалена по ошибке"
                className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:ring-2 focus-visible:ring-ring"
              />
            </div>
          </div>
          <div className="flex justify-end gap-2">
            <Button
              type="button"
              variant="outline"
              disabled={restoreBusy}
              onClick={() => setRestoreModalOpen(false)}
            >
              Отмена
            </Button>
            <Button
              type="button"
              className="bg-teal-700 text-white hover:bg-teal-800"
              disabled={restoreBusy || selected.size === 0 || !restoreComment.trim()}
              onClick={confirmRestore}
            >
              {restoreBusy ? "Восстановление…" : "Восстановить"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      <div className="text-right">
        <Link href="/payments" className="text-xs text-[#063b36] hover:underline">
          Все оплаты
        </Link>
      </div>

      {draft.tab !== "expeditor" ? (
        <p className="text-xs text-muted-foreground">
          Канал «{draft.tab}» — серверная эвристика по полям оплаты / агента / примечания.
        </p>
      ) : null}

      <Dialog open={pageSettingsOpen} onOpenChange={setPageSettingsOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Настройки страницы</DialogTitle>
            <DialogDescription>
              Размер страницы и столбцы таблицы сохраняются для вашей учётной записи.
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-2">
            <div className="space-y-2">
              <Label htmlFor="epr-page-size" className="text-xs text-muted-foreground">
                Строк на странице
              </Label>
              <select
                id="epr-page-size"
                className={cn(filterPanelSelectClassName, "h-10 w-full max-w-none bg-background")}
                value={String(tablePrefs.pageSize)}
                onChange={(e) => {
                  const n = Number.parseInt(e.target.value, 10) || 10;
                  tablePrefs.setPageSize(n);
                  setPage(1);
                }}
              >
                {[10, 20, 30, 50].map((n) => (
                  <option key={n} value={String(n)}>
                    {n}
                  </option>
                ))}
              </select>
            </div>
            <Button
              type="button"
              variant="secondary"
              className="w-full sm:w-auto"
              onClick={() => {
                setPageSettingsOpen(false);
                setColumnDialogOpen(true);
              }}
            >
              Управление столбцами…
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      <TableColumnSettingsDialog
        open={columnDialogOpen}
        onOpenChange={setColumnDialogOpen}
        title="Управление столбцами"
        description="Видимые столбцы и порядок сохраняются для вашей учётной записи."
        columns={EXPEDITOR_PAYMENT_REQUEST_COLUMNS}
        columnOrder={tablePrefs.columnOrder}
        hiddenColumnIds={tablePrefs.hiddenColumnIds}
        saving={tablePrefs.saving}
        onSave={(next) => tablePrefs.saveColumnLayout(next)}
        onReset={() => tablePrefs.resetColumnLayout()}
      />
    </EprPageLayout>
  );
}

"use client";

import {
  ClientsTemplateSelectField,
  type TemplateSelectOption
} from "@/components/clients/clients-template-select-field";
import { DateRangePopover, formatDateRangeButton } from "@/components/ui/date-range-popover";
import { joinMultiFilterValues, uiFromSingleValue } from "@/lib/client-filter-select-value";
import { ChevronLeft, ChevronRight, RotateCcw } from "lucide-react";
import { useRef, useState } from "react";
import type { DealType, EprFilterState, StatusFilter } from "./expeditor-payment-requests-types";

function shiftYmd(ymd: string, deltaMonths: number): string {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(ymd)) return ymd;
  const [y, m, d] = ymd.split("-").map(Number);
  const dt = new Date(y, m - 1 + deltaMonths, d);
  const pad = (n: number) => String(n).padStart(2, "0");
  return `${dt.getFullYear()}-${pad(dt.getMonth() + 1)}-${pad(dt.getDate())}`;
}

type Props = {
  draft: EprFilterState;
  expeditorOptions: TemplateSelectOption[];
  agentOptions: TemplateSelectOption[];
  paymentMethodOptions: TemplateSelectOption[];
  tradeDirectionOptions: TemplateSelectOption[];
  territoryOptions: { key: string; label: string; options: TemplateSelectOption[]; value: string }[];
  onDraftChange: (patch: Partial<EprFilterState>) => void;
  onApply: () => void;
  onReset: () => void;
};

export function EprFiltersPanel({
  draft,
  expeditorOptions,
  agentOptions,
  paymentMethodOptions,
  tradeDirectionOptions,
  territoryOptions,
  onDraftChange,
  onApply,
  onReset
}: Props) {
  const dateAnchorRef = useRef<HTMLButtonElement>(null);
  const [dateOpen, setDateOpen] = useState(false);

  const dateLabel =
    draft.dateFrom && draft.dateTo
      ? formatDateRangeButton(draft.dateFrom, draft.dateTo)
      : "Выберите период";

  const statusOptions: TemplateSelectOption[] = [
    { value: "", label: "Все" },
    { value: "pending_confirmation", label: "Ожидание подтверждения" },
    { value: "confirmed", label: "Подтверждено" },
    { value: "rejected", label: "Отклонено" }
  ];

  return (
    <section className="mb-4 rounded-2xl bg-card px-5 py-4 shadow-sm">
      <div className="mb-3 flex flex-wrap items-center justify-between gap-3">
        <h2 className="text-xl font-semibold text-slate-800">Фильтр</h2>

        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-3 rounded-xl border border-border bg-card px-3 py-2 text-xs text-slate-600">
            <span className="text-[11px] text-slate-500">Тип заявки</span>
            {(
              [
                ["regular", "Обычная"],
                ["consignment", "Для консигнации"],
                ["both", "Обе"]
              ] as const
            ).map(([value, label]) => (
              <label key={value} className="flex cursor-pointer items-center gap-1.5 text-slate-600">
                <input
                  type="radio"
                  name="epr_deal_type"
                  className="size-3.5 accent-teal-700"
                  checked={draft.dealType === value}
                  onChange={() => onDraftChange({ dealType: value as DealType })}
                />
                <span className="text-xs">{label}</span>
              </label>
            ))}
          </div>

          <div className="flex h-10 items-center overflow-hidden rounded-xl border border-border bg-card text-xs text-slate-700">
            <button
              type="button"
              className="h-full px-3 text-slate-400 hover:bg-muted"
              onClick={() => {
                if (!draft.dateFrom || !draft.dateTo) return;
                onDraftChange({
                  dateFrom: shiftYmd(draft.dateFrom, -1),
                  dateTo: shiftYmd(draft.dateTo, -1)
                });
              }}
              aria-label="Предыдущий период"
            >
              <ChevronLeft className="size-4" />
            </button>
            <button
              ref={dateAnchorRef}
              type="button"
              className="flex h-full min-w-[200px] flex-col items-start justify-center px-3 text-left leading-tight"
              onClick={() => setDateOpen(true)}
            >
              <span className="text-[10px] text-slate-400">Дата</span>
              <span className="font-medium text-slate-700">{dateLabel}</span>
            </button>
            <button
              type="button"
              className="h-full px-3 text-slate-400 hover:bg-muted"
              onClick={() => {
                if (!draft.dateFrom || !draft.dateTo) return;
                onDraftChange({
                  dateFrom: shiftYmd(draft.dateFrom, 1),
                  dateTo: shiftYmd(draft.dateTo, 1)
                });
              }}
              aria-label="Следующий период"
            >
              <ChevronRight className="size-4" />
            </button>
          </div>
          <DateRangePopover
            open={dateOpen}
            onOpenChange={setDateOpen}
            anchorRef={dateAnchorRef}
            dateFrom={draft.dateFrom}
            dateTo={draft.dateTo}
            onApply={({ dateFrom, dateTo }) => onDraftChange({ dateFrom, dateTo })}
          />

          <button
            type="button"
            onClick={onReset}
            className="grid size-10 place-items-center rounded-xl border border-border bg-card text-slate-500 hover:bg-muted"
            title="Сбросить"
          >
            <RotateCcw className="size-4" />
          </button>
          <button
            type="button"
            onClick={onApply}
            className="h-10 rounded-xl bg-teal-700 px-6 text-sm font-semibold text-white hover:bg-teal-800"
          >
            Применить
          </button>
        </div>
      </div>

      <div className="flex flex-wrap items-start gap-3">
        <div className="w-[170px]">
          <ClientsTemplateSelectField
            label="Экспедитор"
            multi
            options={expeditorOptions}
            values={draft.expeditorIds.map(String)}
            onChange={(v) =>
              onDraftChange({
                expeditorIds: v.map((x) => Number.parseInt(x, 10)).filter((n) => Number.isFinite(n) && n > 0)
              })
            }
          />
        </div>
        <div className="w-[170px]">
          <ClientsTemplateSelectField
            label="Направление торговли"
            options={tradeDirectionOptions}
            values={uiFromSingleValue(draft.tradeDirection)}
            onChange={(v) => onDraftChange({ tradeDirection: v[0]?.trim() ?? "" })}
          />
        </div>
        <div className="w-[170px]">
          <ClientsTemplateSelectField
            label="Способ оплаты"
            options={paymentMethodOptions}
            values={uiFromSingleValue(draft.paymentType)}
            onChange={(v) => onDraftChange({ paymentType: v[0]?.trim() ?? "" })}
          />
        </div>
        <div className="w-[170px]">
          <ClientsTemplateSelectField
            label="Статус"
            searchable={false}
            options={statusOptions}
            values={uiFromSingleValue(draft.status)}
            onChange={(v) => onDraftChange({ status: (v[0]?.trim() ?? "") as StatusFilter })}
          />
        </div>
        <div className="w-[170px]">
          <ClientsTemplateSelectField
            label="Агент"
            multi
            options={agentOptions}
            values={draft.agentIds.map(String)}
            onChange={(v) =>
              onDraftChange({
                agentIds: v.map((x) => Number.parseInt(x, 10)).filter((n) => Number.isFinite(n) && n > 0)
              })
            }
          />
        </div>
        {territoryOptions.map((t) => (
          <div key={t.key} className="w-[170px]">
            <ClientsTemplateSelectField
              label={t.label}
              options={t.options}
              values={uiFromSingleValue(t.value)}
              onChange={(v) => onDraftChange({ [t.key]: v[0]?.trim() ?? "" } as Partial<EprFilterState>)}
            />
          </div>
        ))}
      </div>
    </section>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { formatGroupedInteger } from "@/lib/format-numbers";
import { cn } from "@/lib/utils";
import { Magnet } from "lucide-react";
import Link from "next/link";
import { useState } from "react";
import { OrderPaymentStatusBadge } from "./order-payment-status-badge";
import { parseAmountInput, sumExisting } from "./order-payment-utils";
import type { OrderCashInPaymentMethod, PaymentOrderRow } from "./types";

type Props = {
  orders: PaymentOrderRow[];
  paymentMethods: OrderCashInPaymentMethod[];
  onUpdateDraft: (orderId: number, methodId: string, value: number) => void;
  onFillCellFromOrderAmount?: (orderId: number, methodId: string) => void;
  disabled?: boolean;
};

function formatCell(value: number): string {
  return value > 0 ? formatGroupedInteger(value) : "";
}

const TH = "px-4 py-3 text-xs font-medium text-muted-foreground whitespace-nowrap";
const TD = "px-4 py-2.5 align-middle whitespace-nowrap";
/** Input + magnit — barcha to‘lov ustunlarida bir xil */
const PAYMENT_CELL_INNER = "mx-auto flex w-[8.75rem] items-center justify-end gap-1.5";

export function OrderPaymentTable({
  orders,
  paymentMethods,
  onUpdateDraft,
  onFillCellFromOrderAmount,
  disabled
}: Props) {
  const [editingId, setEditingId] = useState<number | null>(null);

  if (paymentMethods.length === 0) {
    return (
      <p className="px-4 py-8 text-center text-sm text-muted-foreground">
        В настройках нет активных способов оплаты. Добавьте их в разделе «Настройки» → «Финансы».
      </p>
    );
  }

  const colSpan = 5 + paymentMethods.length + 1;

  return (
    <div className="overflow-x-auto">
      <table className="w-full table-fixed border-separate border-spacing-0 text-sm">
        <colgroup>
          <col className="w-[11rem]" />
          <col className="w-[4.5rem]" />
          <col className="w-[7.5rem]" />
          <col className="w-[6.75rem]" />
          <col className="w-[6.75rem]" />
          {paymentMethods.map((m) => (
            <col key={m.id} className="w-[9.25rem]" />
          ))}
          <col className="w-[6.25rem]" />
        </colgroup>
        <thead className="border-b border-border bg-muted/40">
          <tr>
            <th className={cn(TH, "text-left")}>Названия</th>
            <th className={cn(TH, "text-left")}>Заказ ID</th>
            <th className={cn(TH, "text-left")}>Статус заказа</th>
            <th className={cn(TH, "text-right")}>Сумма заказа</th>
            <th className={cn(TH, "text-right")}>Остаток долга</th>
            {paymentMethods.map((m) => (
              <th
                key={m.id}
                className={cn(TH, "text-center")}
                title={`${m.name}${m.currency_code ? ` · ${m.currency_code}` : ""}`}
              >
                <span
                  className={cn(
                    "inline-flex max-w-full items-center justify-center gap-1.5 truncate",
                    m.color && "gap-1.5"
                  )}
                >
                  {m.color ? (
                    <span
                      className="inline-block size-2 shrink-0 rounded-full"
                      style={{ backgroundColor: m.color }}
                      aria-hidden
                    />
                  ) : null}
                  <span className="truncate">{m.name}</span>
                </span>
              </th>
            ))}
            <th className={cn(TH, "text-right")}>Не оплачено</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-border/60">
          {orders.map((order, rowIdx) => (
            <tr
              key={order.id}
              className={cn(
                "transition-colors hover:bg-muted/30",
                order.hasError ? "bg-red-50/50 dark:bg-red-950/20" : "bg-teal-50/30 dark:bg-teal-950/15"
              )}
            >
              <td className={cn(TD, "max-w-[11rem]")}>
                <Link
                  href={`/clients/${order.clientId}`}
                  className="block truncate font-medium text-teal-700 hover:underline dark:text-teal-400"
                  title={order.clientName}
                >
                  {order.clientName}
                </Link>
              </td>
              <td className={TD}>
                <Link
                  href={`/orders/${order.id}`}
                  className="text-foreground hover:text-teal-700 hover:underline dark:hover:text-teal-400"
                >
                  {order.id}
                </Link>
              </td>
              <td className={TD}>
                <OrderPaymentStatusBadge status={order.status} />
              </td>
              <td className={cn(TD, "text-right tabular-nums")}>
                {formatGroupedInteger(order.orderAmount)}
              </td>
              <td className={cn(TD, "text-right tabular-nums")}>
                {formatGroupedInteger(order.debt)}
              </td>
              {paymentMethods.map((m, colIdx) => {
                const existing = order.existingByType[m.payment_type] ?? 0;
                const draft = order.draftByMethodId[m.id] ?? 0;
                return (
                  <td key={m.id} className={TD}>
                    <div className={PAYMENT_CELL_INNER}>
                      <div className="flex min-w-0 flex-1 flex-col items-end gap-0.5">
                        <input
                          type="text"
                          inputMode="decimal"
                          disabled={disabled}
                          data-testid={
                            colIdx === 0 && rowIdx === 0 ? "new-payment-amount" : undefined
                          }
                          value={formatCell(draft)}
                          onChange={(e) =>
                            onUpdateDraft(order.id, m.id, parseAmountInput(e.target.value))
                          }
                          onFocus={() => setEditingId(order.id)}
                          onBlur={() => setEditingId(null)}
                          className={cn(
                            "h-8 w-full min-w-0 max-w-[6.25rem] rounded-md border px-2 py-1 text-right text-sm tabular-nums outline-none transition-colors",
                            editingId === order.id && colIdx === 0
                              ? "border-teal-500 ring-1 ring-teal-500/40"
                              : "border-input bg-background"
                          )}
                          aria-label={`${m.name}, заказ ${order.id}`}
                        />
                        {existing > 0 ? (
                          <span
                            className="text-[10px] tabular-nums text-muted-foreground"
                            title="Уже оплачено"
                          >
                            +{formatGroupedInteger(existing)}
                          </span>
                        ) : null}
                      </div>
                      {onFillCellFromOrderAmount ? (
                        <Button
                          type="button"
                          variant="outline"
                          size="icon"
                          className="size-7 shrink-0 border-teal-200 text-teal-700 hover:bg-teal-50 dark:border-teal-800 dark:text-teal-300 dark:hover:bg-teal-950/50"
                          disabled={disabled}
                          title="Подставить остаток по заказу в эту ячейку"
                          aria-label={`Подставить сумму заказа ${order.id}, ${m.name}`}
                          onClick={() => onFillCellFromOrderAmount(order.id, m.id)}
                        >
                          <Magnet className="size-3.5" aria-hidden />
                        </Button>
                      ) : null}
                    </div>
                  </td>
                );
              })}
              <td
                className={cn(
                  TD,
                  "text-right font-medium tabular-nums",
                  order.unpaid > 0 ? "text-red-600 dark:text-red-400" : "text-foreground"
                )}
              >
                {formatGroupedInteger(order.unpaid)}
              </td>
            </tr>
          ))}
          {orders.length === 0 ? (
            <tr>
              <td colSpan={colSpan} className="px-4 py-12 text-center text-muted-foreground">
                Нет заказов для оплаты
              </td>
            </tr>
          ) : null}
        </tbody>
      </table>
    </div>
  );
}

"use client";

import { PageHeader } from "@/components/dashboard/page-header";
import { PageShell } from "@/components/dashboard/page-shell";
import { api } from "@/lib/api";
import { useAuthStoreHydrated } from "@/lib/auth-store";
import { getUserFacingError } from "@/lib/error-utils";
import { STALE } from "@/lib/query-stale";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import axios from "axios";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { useCallback, useEffect, useMemo, useState } from "react";
import { OrderPaymentFilterBar } from "./order-payment-filter-bar";
import { OrderPaymentStatistics } from "./order-payment-statistics";
import { OrderPaymentTable } from "./order-payment-table";
import {
  buildContextQuery,
  contextOrderToRow,
  defaultPaidAtLocal,
  fillCellDraftFromOrderAmount,
  prefillDraftFromTotalAmount,
  recomputeRowTotals,
  sumDraft,
  sumExisting,
  sumTotalPaid,
  toIsoFromLocal,
  type OrderCashInContext
} from "./order-payment-utils";
import type { OrderPaymentFilters, PaymentOrderRow, PaymentStatistics } from "./types";

type CashDeskRow = { id: number; name: string; is_active: boolean };

type Props = {
  tenantSlug: string;
};

function parseOrderIdsParam(raw: string | null): number[] {
  if (!raw?.trim()) return [];
  return raw
    .split(/[,]+/)
    .map((s) => Number.parseInt(s.trim(), 10))
    .filter((n) => Number.isFinite(n) && n > 0);
}

export function OrderPaymentWorkspace({ tenantSlug }: Props) {
  const router = useRouter();
  const searchParams = useSearchParams();
  const qc = useQueryClient();
  const hydrated = useAuthStoreHydrated();

  const clientIdParam = searchParams.get("client_id")?.trim() ?? "";
  const orderIdsParam = parseOrderIdsParam(searchParams.get("order_ids"));
  const amountParam = searchParams.get("amount")?.trim() ?? "";

  const [rows, setRows] = useState<PaymentOrderRow[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<OrderCashInContext["payment_methods"]>([]);
  const [prefillDone, setPrefillDone] = useState(false);
  const [filters, setFilters] = useState<OrderPaymentFilters>(() => ({
    paidAtLocal: defaultPaidAtLocal(),
    cashDeskId: "",
    errorOnly: false
  }));
  const [formErr, setFormErr] = useState<string | null>(null);

  const contextQ = useQuery({
    queryKey: [
      "order-cash-in-context",
      tenantSlug,
      clientIdParam,
      orderIdsParam.join(",")
    ],
    enabled: Boolean(tenantSlug) && hydrated && Boolean(clientIdParam),
    staleTime: STALE.detail,
    queryFn: async () => {
      const params = buildContextQuery(clientIdParam, orderIdsParam);
      const { data } = await api.get<{ data: OrderCashInContext }>(
        `/api/${tenantSlug}/payments/order-cash-in/context?${params.toString()}`
      );
      return data.data;
    }
  });

  const cashDesksQ = useQuery({
    queryKey: ["cash-desks", tenantSlug, "order-payment"],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: CashDeskRow[] }>(
        `/api/${tenantSlug}/cash-desks?is_active=true&limit=200&page=1`
      );
      return (data.data ?? []).filter((d) => d.is_active);
    }
  });

  useEffect(() => {
    if (!contextQ.data) return;
    const methods = contextQ.data.payment_methods;
    setPaymentMethods(methods);
    let next = contextQ.data.orders.map((o) => contextOrderToRow(o, methods));
    if (!prefillDone && amountParam) {
      const amt = Number.parseFloat(amountParam.replace(/\s/g, "").replace(",", "."));
      if (Number.isFinite(amt) && amt > 0) {
        next = prefillDraftFromTotalAmount(next, methods, amt);
      }
      setPrefillDone(true);
    }
    setRows(next);
  }, [contextQ.data, amountParam, prefillDone]);

  const filteredRows = useMemo(() => {
    if (!filters.errorOnly) return rows;
    return rows.filter((r) => r.hasError);
  }, [rows, filters.errorOnly]);

  const statistics: PaymentStatistics = useMemo(() => {
    const total = rows.reduce((s, o) => s + o.orderAmount, 0);
    const totalDebt = rows.reduce((s, o) => s + o.debt, 0);
    const received = rows.reduce((s, o) => s + sumTotalPaid(o), 0);
    const unpaid = rows.reduce((s, o) => s + o.unpaid, 0);
    return {
      total,
      received,
      totalDebt,
      remaining: Math.max(0, total - received),
      unpaid
    };
  }, [rows]);

  const onSuccessCount = useMemo(
    () => rows.filter((o) => o.unpaid === 0 && !o.hasError).length,
    [rows]
  );

  const onUpdateDraft = useCallback((orderId: number, methodId: string, value: number) => {
    setRows((prev) =>
      prev.map((o) => {
        if (o.id !== orderId) return o;
        return recomputeRowTotals({
          ...o,
          draftByMethodId: { ...o.draftByMethodId, [methodId]: value }
        });
      })
    );
  }, []);

  const onFillCellFromOrderAmount = useCallback((orderId: number, methodId: string) => {
    setRows((prev) =>
      prev.map((o) => (o.id === orderId ? fillCellDraftFromOrderAmount(o, methodId) : o))
    );
  }, []);

  const saveMut = useMutation({
    mutationFn: async () => {
      const cid = Number.parseInt(clientIdParam, 10);
      if (!Number.isFinite(cid) || cid < 1) throw new Error("NO_CLIENT");
      const deskRaw = filters.cashDeskId.trim();
      const deskId = deskRaw ? Number.parseInt(deskRaw, 10) : null;
      const cash_desk_id =
        deskId != null && Number.isFinite(deskId) && deskId > 0 ? deskId : null;
      const paid_at = toIsoFromLocal(filters.paidAtLocal);

      const methodById = new Map(paymentMethods.map((m) => [m.id, m]));
      const lines: Array<{ order_id: number; payment_type: string; amount: number }> = [];

      for (const row of rows) {
        for (const [methodId, amount] of Object.entries(row.draftByMethodId)) {
          if (!amount || amount <= 0) continue;
          const method = methodById.get(methodId);
          if (!method) continue;
          lines.push({
            order_id: row.id,
            payment_type: method.payment_type,
            amount
          });
        }
      }

      if (lines.length === 0) throw new Error("NO_LINES");

      await api.post(`/api/${tenantSlug}/payments/order-cash-in`, {
        client_id: cid,
        cash_desk_id,
        paid_at,
        lines
      });
    },
    onSuccess: async () => {
      setFormErr(null);
      await qc.invalidateQueries({ queryKey: ["payments", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["order-cash-in-context", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["dashboard-stats", tenantSlug] });
      router.push("/payments");
    },
    onError: (e: unknown) => {
      if (e instanceof Error && e.message === "NO_CLIENT") {
        setFormErr("Укажите клиента (перейдите из списка заявок с выбранными заказами).");
        return;
      }
      if (e instanceof Error && e.message === "NO_LINES") {
        setFormErr("Введите сумму хотя бы в одной ячейке.");
        return;
      }
      if (axios.isAxiosError(e)) {
        const code = (e.response?.data as { error?: string } | undefined)?.error;
        if (code === "BadCashDesk") {
          setFormErr("Указана несуществующая или неактивная касса.");
          return;
        }
        if (code === "BadOrder") {
          setFormErr("Заказ не найден или не принадлежит клиенту.");
          return;
        }
        if (code === "BadPaymentType") {
          setFormErr("Способ оплаты не найден в справочнике. Обновите страницу.");
          return;
        }
        if (code === "NoLines") {
          setFormErr("Нет строк для сохранения.");
          return;
        }
      }
      setFormErr(getUserFacingError(e, "Не удалось сохранить платежи."));
    }
  });

  const hasDraftLines = rows.some((r) => sumDraft(r) > 0);
  const clientName = contextQ.data?.client.name;

  return (
    <PageShell>
      <PageHeader
        title="Приход в кассу"
        description={
          clientIdParam
            ? orderIdsParam.length > 0
              ? `${clientName ?? "Клиент"} · выбранные заказы (${orderIdsParam.length})`
              : `${clientName ?? "Клиент"} · доставленные заказы`
            : "Выберите заказы в разделе «Заявки» → «Касса (выбранные)»"
        }
        actions={
          <Link
            href="/payments"
            className="text-sm text-muted-foreground underline-offset-2 hover:underline"
          >
            ← К списку платежей
          </Link>
        }
      />

      {!hydrated || !tenantSlug ? (
        <p className="text-sm text-muted-foreground">…</p>
      ) : !clientIdParam ? (
        <div className="rounded-xl border border-border bg-card p-6 text-sm text-muted-foreground">
          <p>Клиент не указан. Откройте страницу из списка заявок с выбранными заказами одного клиента.</p>
          <Link href="/orders" className="mt-3 inline-block text-teal-700 hover:underline dark:text-teal-400">
            Перейти к заявкам
          </Link>
        </div>
      ) : contextQ.isLoading ? (
        <p className="text-sm text-muted-foreground">Загрузка…</p>
      ) : contextQ.isError ? (
        <p className="text-sm text-destructive" role="alert">
          {getUserFacingError(contextQ.error, "Не удалось загрузить данные.")}
        </p>
      ) : paymentMethods.length === 0 ? (
        <div className="rounded-xl border border-border bg-card p-6 text-sm text-muted-foreground">
          <p>
            Нет активных способов оплаты. Настройте их в{" "}
            <Link href="/settings" className="text-teal-700 hover:underline dark:text-teal-400">
              Настройки → Финансы
            </Link>
            .
          </p>
        </div>
      ) : (
        <div className="space-y-5">
          <div className="flex flex-wrap items-center justify-between gap-3 text-sm text-muted-foreground">
            <span>
              Записей: <span className="font-medium text-foreground">{filteredRows.length}</span>
            </span>
            <span>
              Способов оплаты:{" "}
              <span className="font-medium text-foreground">{paymentMethods.length}</span>
            </span>
          </div>

          {formErr ? (
            <p className="text-sm text-destructive" role="alert">
              {formErr}
            </p>
          ) : null}

          <div className="overflow-hidden rounded-lg border border-border bg-card shadow-sm">
            <OrderPaymentTable
              orders={filteredRows}
              paymentMethods={paymentMethods}
              onUpdateDraft={onUpdateDraft}
              onFillCellFromOrderAmount={onFillCellFromOrderAmount}
              disabled={saveMut.isPending}
            />
            <OrderPaymentStatistics statistics={statistics} />
          </div>

          <OrderPaymentFilterBar
            filters={filters}
            onChange={setFilters}
            cashDesks={cashDesksQ.data ?? []}
            onSuccessCount={onSuccessCount}
            totalCount={rows.length}
            onSave={() => {
              setFormErr(null);
              saveMut.mutate();
            }}
            saving={saveMut.isPending}
            saveDisabled={!hasDraftLines || rows.some((r) => r.hasError)}
          />
        </div>
      )}
    </PageShell>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { buttonVariants } from "@/components/ui/button-variants";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { PageHeader } from "@/components/dashboard/page-header";
import { SettingsWorkspace } from "@/components/settings/settings-workspace";
import type { ProductRow } from "@/lib/product-types";
import { api } from "@/lib/api";
import { useAuthStore, useAuthStoreHydrated, useEffectiveRole } from "@/lib/auth-store";
import { isAdminOrOperatorLikeRole } from "@/lib/distribution-roles";
import { getUserFacingError } from "@/lib/error-utils";
import { cn } from "@/lib/utils";
import { downloadXlsxSheet } from "@/lib/download-xlsx";
import { QueryErrorState } from "@/components/common/query-error-state";
import { keepPreviousData, useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import Link from "next/link";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { Suspense, useEffect, useMemo, useRef, useState } from "react";
import { TableColumnSettingsDialog } from "@/components/data-table/table-column-settings-dialog";
import { TableRowActionGroup } from "@/components/data-table/table-row-actions";
import { useUserTablePrefs } from "@/hooks/use-user-table-prefs";
import {
  PRODUCT_ITEMS_COLUMNS,
  PRODUCT_ITEMS_COLUMN_IDS,
  PRODUCT_ITEMS_TABLE_ID,
  productItemsExportCell
} from "@/lib/products-catalog-columns";
import { formatGroupedInteger, formatNumberGrouped } from "@/lib/format-numbers";
import { STALE } from "@/lib/query-stale";
import { Ban, ListOrdered, Pencil, RefreshCw, RotateCcw } from "lucide-react";
import type { ReactNode } from "react";
import { CatalogInterchangeableTab } from "./catalog-interchangeable-tab";
import { CatalogSimpleTab } from "./catalog-simple-tab";
import { ProductQuickAddDialog } from "./product-quick-add-dialog";
import { ProductForm } from "./product-form";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog";

const TABS = [
  { id: "items", label: "Товар" },
  { id: "equipment-items", label: "Оборудование товары" },
  { id: "product-groups", label: "Группа товаров" },
  { id: "interchangeable", label: "Группа взаимозаменяемых" },
  { id: "brands", label: "Бренд" },
  { id: "manufacturers", label: "Производитель" },
  { id: "segments", label: "Сегменты" }
] as const;

type TabId = (typeof TABS)[number]["id"];

function isTabId(v: string | null): v is TabId {
  return TABS.some((t) => t.id === v);
}

function retailPriceLabel(row: ProductRow): string {
  const p = row.prices?.find((x) => x.price_type === "retail");
  return p != null ? p.price : "—";
}

type ItemsProps = {
  tenantSlug: string | null;
  isAdmin: boolean;
  statusTab: "active" | "inactive";
  search: string;
};

function EquipmentItemsTab({
  tenantSlug,
  isAdmin,
  statusTab,
  search
}: {
  tenantSlug: string | null;
  isAdmin: boolean;
  statusTab: "active" | "inactive";
  search: string;
}) {
  const qc = useQueryClient();
  const [savingId, setSavingId] = useState<number | null>(null);
  const [addOpen, setAddOpen] = useState(false);
  const [pickerSearch, setPickerSearch] = useState("");
  const [pickedIds, setPickedIds] = useState<Set<number>>(new Set());
  const [editOpen, setEditOpen] = useState(false);
  const [editRow, setEditRow] = useState<ProductRow | null>(null);
  const [editName, setEditName] = useState("");
  const [editSku, setEditSku] = useState("");
  const [editActive, setEditActive] = useState(true);
  const [msg, setMsg] = useState<string | null>(null);

  const isActiveFilter = statusTab === "active" ? "true" : "false";

  const listQ = useQuery({
    queryKey: ["products", tenantSlug, "equipment-mark-tab", statusTab, search],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    queryFn: async () => {
      const params = new URLSearchParams({
        page: "1",
        limit: "1000",
        is_active: isActiveFilter,
        is_equipment: "true"
      });
      if (search.trim()) params.set("search", search.trim());
      const { data } = await api.get<{ data: ProductRow[] }>(`/api/${tenantSlug}/products?${params}`);
      return data.data ?? [];
    }
  });

  const pickQ = useQuery({
    queryKey: ["products", tenantSlug, "equipment-picker", statusTab, pickerSearch],
    enabled: Boolean(tenantSlug) && addOpen,
    staleTime: STALE.list,
    queryFn: async () => {
      const params = new URLSearchParams({
        page: "1",
        limit: "1000"
      });
      if (pickerSearch.trim()) params.set("search", pickerSearch.trim());
      const { data } = await api.get<{ data: ProductRow[] }>(`/api/${tenantSlug}/products?${params}`);
      return (data.data ?? []).filter((r) => r.is_equipment !== true);
    }
  });

  async function toggleActive(row: ProductRow, next: boolean) {
    if (!tenantSlug) return;
    try {
      setSavingId(row.id);
      await api.put(`/api/${tenantSlug}/products/${row.id}`, { is_active: next });
      await qc.invalidateQueries({ queryKey: ["products", tenantSlug] });
      setMsg(null);
    } finally {
      setSavingId(null);
    }
  }

  const rows = listQ.data ?? [];
  const pickRows = pickQ.data ?? [];
  const selectedPickCount = pickedIds.size;

  function exportEquipmentItemsExcel() {
    const headers = ["Товар", "SKU", "Категория", "Статус"];
    const dataRows = rows.map((r) => [
      r.name ?? "",
      r.sku ?? "",
      r.category?.name ?? "",
      r.is_active ? "Активный" : "Не активный"
    ]);
    downloadXlsxSheet(
      `equipment_products_${new Date().toISOString().slice(0, 10)}.xlsx`,
      "Оборудование товары",
      headers,
      dataRows
    );
  }

  function openEdit(r: ProductRow) {
    setEditRow(r);
    setEditName(r.name);
    setEditSku(r.sku);
    setEditActive(r.is_active);
    setEditOpen(true);
    setMsg(null);
  }

  async function saveEdit() {
    if (!tenantSlug || !editRow) return;
    const name = editName.trim();
    const sku = editSku.trim();
    if (!name || !sku) {
      setMsg("Название ва SKU majburiy.");
      return;
    }
    try {
      setSavingId(editRow.id);
      await api.put(`/api/${tenantSlug}/products/${editRow.id}`, {
        name,
        sku,
        is_active: editActive
      });
      setEditOpen(false);
      setEditRow(null);
      await qc.invalidateQueries({ queryKey: ["products", tenantSlug] });
      // Nom o'zgargani uchun — uni nom bo'yicha ko'rsatadigan keshlar ham yangilansin.
      await qc.invalidateQueries({ queryKey: ["catalog-interchangeable", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["products-pick", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["interchangeable-live-names", tenantSlug] });
      setMsg(null);
    } finally {
      setSavingId(null);
    }
  }

  async function addPickedEquipment() {
    if (!tenantSlug) return;
    const ids = Array.from(pickedIds).filter((x) => Number.isFinite(x) && x > 0);
    if (ids.length === 0) {
      setMsg("Камида битта маҳсулотни танланг.");
      return;
    }
    try {
      setSavingId(-1);
      await Promise.all(ids.map((id) => api.put(`/api/${tenantSlug}/products/${id}`, { is_equipment: true })));
      setAddOpen(false);
      setPickedIds(new Set());
      setPickerSearch("");
      await qc.invalidateQueries({ queryKey: ["products", tenantSlug] });
      setMsg(null);
    } finally {
      setSavingId(null);
    }
  }

  return (
    <div className="space-y-3">
      <div className="rounded-md border border-border/70 bg-muted/20 px-3 py-2 text-xs text-muted-foreground">
        Бу жадвалда фақат `Оборудование` учун белгиланган товарлар кўринади. `Добавить` орқали актив ва неактив
        маҳсулотлардан танлаб қўшасиз; `Тahrirlash` билан номи/SKU ва активлиги ўзгаради.
      </div>
      <div className="flex flex-wrap items-center justify-between gap-2">
        <p className="text-sm text-muted-foreground">
          Статус: <span className="font-medium">{statusTab === "active" ? "Активный" : "Не активный"}</span> •
          Показано: {formatGroupedInteger(rows.length)}
        </p>
        <div className="flex flex-wrap items-center gap-2">
          <Button
            type="button"
            size="sm"
            variant="outline"
            onClick={exportEquipmentItemsExcel}
            disabled={rows.length === 0}
          >
            Excel
          </Button>
          <Button
            type="button"
            size="sm"
            onClick={() => {
              setPickedIds(new Set());
              setPickerSearch("");
              setAddOpen(true);
            }}
          >
            Добавить
          </Button>
        </div>
      </div>
      <div className="-mx-3 overflow-x-auto border-t border-border/80 sm:-mx-4">
        <table className="w-full min-w-[760px] text-sm">
          <thead className="app-table-thead text-left">
            <tr>
              <th className="px-3 py-2 font-medium">Товар</th>
              <th className="px-3 py-2 font-medium">SKU</th>
              <th className="px-3 py-2 font-medium">Категория</th>
              <th className="px-3 py-2 font-medium">Статус</th>
              <th className="px-3 py-2 text-right font-medium"> </th>
            </tr>
          </thead>
          <tbody>
            {listQ.isLoading ? (
              <tr>
                <td colSpan={5} className="px-3 py-8 text-center text-muted-foreground">
                  Загрузка…
                </td>
              </tr>
            ) : rows.length === 0 ? (
              <tr>
                <td colSpan={5} className="px-3 py-8 text-center text-muted-foreground">
                  Пусто
                </td>
              </tr>
            ) : (
              rows.map((r) => (
                <tr key={r.id} className="border-t">
                  <td className="px-3 py-2">{r.name}</td>
                  <td className="px-3 py-2 font-mono text-xs text-muted-foreground">{r.sku}</td>
                  <td className="px-3 py-2 text-xs text-muted-foreground">{r.category?.name ?? "—"}</td>
                  <td className="px-3 py-2 text-xs">{r.is_active ? "Активный" : "Не активный"}</td>
                  <td className="px-3 py-2">
                    <TableRowActionGroup className="justify-end" ariaLabel="Оборудование товар">
                      <Button
                        type="button"
                        variant="outline"
                        size="icon-sm"
                        className="text-muted-foreground hover:text-foreground"
                        title="Tahrirlash"
                        aria-label="Tahrirlash"
                        onClick={() => openEdit(r)}
                      >
                        <Pencil className="size-3.5" aria-hidden />
                      </Button>
                      {r.is_active ? (
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          className="h-7 px-2 text-xs"
                          disabled={savingId === r.id}
                          onClick={() => void toggleActive(r, false)}
                        >
                          Неактив қилиш
                        </Button>
                      ) : (
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          className="h-7 px-2 text-xs"
                          disabled={savingId === r.id}
                          onClick={() => void toggleActive(r, true)}
                        >
                          Фаоллаштириш
                        </Button>
                      )}
                    </TableRowActionGroup>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
      {msg ? <p className="text-sm text-destructive">{msg}</p> : null}

      <Dialog open={addOpen} onOpenChange={setAddOpen}>
        <DialogContent className="sm:max-w-[700px]" showCloseButton>
          <DialogHeader>
            <DialogTitle>Оборудование товарыга қўшиш</DialogTitle>
          </DialogHeader>
          <div className="grid gap-3">
            <div className="rounded-md border border-border/70 bg-muted/20 px-3 py-2 text-xs text-muted-foreground">
              Бир вақтда бир нечта маҳсулот танланади. Танланганлар:{" "}
              <span className="font-semibold text-foreground">{formatGroupedInteger(selectedPickCount)}</span>
            </div>
            <div className="flex flex-wrap items-center gap-2">
              <Input
                className="h-9 min-w-[220px] flex-1"
                value={pickerSearch}
                onChange={(e) => setPickerSearch(e.target.value)}
                placeholder="Маҳсулот қидириш (ном/SKU)"
              />
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="h-9"
                onClick={() => setPickedIds(new Set(pickRows.map((r) => r.id)))}
                disabled={pickRows.length === 0}
              >
                Ҳаммасини белгилаш
              </Button>
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="h-9"
                onClick={() => setPickedIds(new Set())}
                disabled={selectedPickCount === 0}
              >
                Белгини олиш
              </Button>
            </div>
            <div className="max-h-[360px] overflow-auto rounded-md border border-border/80 bg-background">
              {pickQ.isLoading ? (
                <div className="px-3 py-6 text-center text-sm text-muted-foreground">Загрузка…</div>
              ) : pickRows.length === 0 ? (
                <div className="px-3 py-6 text-center text-sm text-muted-foreground">Қидирув бўйича маҳсулот топилмади.</div>
              ) : (
                <div className="divide-y">
                  {pickRows.map((r) => {
                    const checked = pickedIds.has(r.id);
                    return (
                      <label
                        key={r.id}
                        className="flex cursor-pointer items-start gap-3 px-3 py-2 hover:bg-muted/40"
                      >
                        <input
                          type="checkbox"
                          className="mt-1 h-4 w-4"
                          checked={checked}
                          onChange={(e) => {
                            setPickedIds((prev) => {
                              const next = new Set(prev);
                              if (e.target.checked) next.add(r.id);
                              else next.delete(r.id);
                              return next;
                            });
                          }}
                        />
                        <div className="min-w-0">
                          <p className="truncate text-sm font-medium text-foreground">{r.name}</p>
                          <p className="text-xs text-muted-foreground">
                            SKU: <span className="font-mono">{r.sku}</span>
                            {r.category?.name ? ` • ${r.category.name}` : ""}
                            {` • ${r.is_active ? "Активный" : "Не активный"}`}
                          </p>
                        </div>
                      </label>
                    );
                  })}
                </div>
              )}
            </div>
            <div className="flex justify-end gap-2">
              <Button variant="outline" onClick={() => setAddOpen(false)}>
                Отмена
              </Button>
              <Button
                disabled={savingId != null || selectedPickCount === 0}
                onClick={() => void addPickedEquipment()}
              >
                Қўшиш ({formatGroupedInteger(selectedPickCount)})
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={editOpen} onOpenChange={setEditOpen}>
        <DialogContent className="sm:max-w-[520px]" showCloseButton>
          <DialogHeader>
            <DialogTitle>Оборудование товар — tahrirlash</DialogTitle>
          </DialogHeader>
          <div className="grid gap-3">
            <Input value={editName} onChange={(e) => setEditName(e.target.value)} placeholder="Название" />
            <Input value={editSku} onChange={(e) => setEditSku(e.target.value)} placeholder="SKU" />
            <label className="flex items-center justify-between rounded-md border px-3 py-2 text-sm">
              <span>Активный</span>
              <input type="checkbox" checked={editActive} onChange={(e) => setEditActive(e.target.checked)} />
            </label>
            <div className="flex justify-end gap-2">
              <Button variant="outline" onClick={() => setEditOpen(false)}>
                Отмена
              </Button>
              <Button disabled={savingId != null} onClick={() => void saveEdit()}>
                Сохранить
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function ItemsTab({ tenantSlug, isAdmin, statusTab, search }: ItemsProps) {
  const router = useRouter();
  const pathname = usePathname();
  const productsBasePath = pathname.startsWith("/settings/products")
    ? "/settings/products"
    : "/products";
  const qc = useQueryClient();
  const priceFileRef = useRef<HTMLInputElement>(null);
  const [page, setPage] = useState(1);
  const [categoryId, setCategoryId] = useState("");
  const [productGroupId, setProductGroupId] = useState("");
  const [importMsg, setImportMsg] = useState<string | null>(null);
  const [addMenuOpen, setAddMenuOpen] = useState(false);
  const [quickAddOpen, setQuickAddOpen] = useState(false);
  const [fullProductOpen, setFullProductOpen] = useState(false);
  const [fullProductId, setFullProductId] = useState<number | null>(null);
  const [columnDialogOpen, setColumnDialogOpen] = useState(false);

  const tablePrefs = useUserTablePrefs({
    tenantSlug,
    tableId: PRODUCT_ITEMS_TABLE_ID,
    defaultColumnOrder: [...PRODUCT_ITEMS_COLUMN_IDS],
    defaultPageSize: 10,
    allowedPageSizes: [10, 15, 20, 30, 50, 100]
  });
  const pageSize = tablePrefs.pageSize;

  const isActiveFilter = statusTab === "active" ? "true" : "false";

  const categoriesQ = useQuery({
    queryKey: ["product-categories", tenantSlug, "items-tab"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: { id: number; name: string }[] }>(
        `/api/${tenantSlug}/product-categories`
      );
      return data.data;
    }
  });

  const groupsQ = useQuery({
    queryKey: ["catalog-simple", "catalog/product-groups", tenantSlug, "items-filter"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const params = new URLSearchParams({ page: "1", limit: "500", is_active: "true" });
      const { data } = await api.get<{ data: { id: number; name: string }[] }>(
        `/api/${tenantSlug}/catalog/product-groups?${params}`
      );
      return data.data;
    }
  });

  const listQ = useQuery({
    queryKey: [
      "products",
      tenantSlug,
      "workspace",
      search,
      page,
      pageSize,
      categoryId,
      productGroupId,
      isActiveFilter
    ],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    placeholderData: keepPreviousData,
    queryFn: async () => {
      const params = new URLSearchParams({
        page: String(page),
        limit: String(pageSize),
        include_prices: "true",
        is_active: isActiveFilter
      });
      if (search.trim()) params.set("search", search.trim());
      if (categoryId) params.set("category_id", categoryId);
      if (productGroupId) params.set("product_group_id", productGroupId);
      const { data } = await api.get<{
        data: ProductRow[];
        total: number;
        page: number;
        limit: number;
      }>(`/api/${tenantSlug}/products?${params}`);
      return data;
    }
  });

  useEffect(() => {
    setPage(1);
  }, [search, statusTab, pageSize, categoryId, productGroupId]);

  /** API `DELETE` mahsulotni bazadan olib tashlamaydi — faqat neaktiv qiladi. */
  const deactivateMut = useMutation({
    mutationFn: async (id: number) => {
      await api.delete(`/api/${tenantSlug}/products/${id}`);
    },
    onSuccess: async () => {
      await qc.invalidateQueries({ queryKey: ["products", tenantSlug] });
    }
  });

  const activateMut = useMutation({
    mutationFn: async (id: number) => {
      await api.put(`/api/${tenantSlug}/products/${id}`, { is_active: true });
    },
    onSuccess: async () => {
      await qc.invalidateQueries({ queryKey: ["products", tenantSlug] });
    }
  });

  const priceImportMut = useMutation({
    mutationFn: async (file: File) => {
      const fd = new FormData();
      fd.append("file", file);
      const { data: body } = await api.post<{ upserted: number; errors: string[] }>(
        `/api/${tenantSlug}/products/prices/import`,
        fd
      );
      return body;
    },
    onSuccess: async (res) => {
      setImportMsg(`Narxlar: ${res.upserted}`);
      await qc.invalidateQueries({ queryKey: ["products", tenantSlug] });
      if (priceFileRef.current) priceFileRef.current.value = "";
    },
    onError: (e: unknown) => setImportMsg(getUserFacingError(e, "Narx import xatosi."))
  });

  const rows = listQ.data?.data ?? [];
  const total = listQ.data?.total ?? 0;
  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  function renderProductCell(colId: string, r: ProductRow): ReactNode {
    switch (colId) {
      case "name":
        return r.name;
      case "category":
        return <span className="text-xs text-muted-foreground">{r.category?.name ?? "—"}</span>;
      case "product_group":
        return <span className="text-xs text-muted-foreground">{r.product_group?.name ?? "—"}</span>;
      case "unit":
        return <span className="text-xs">{r.unit}</span>;
      case "qty_per_block":
        return r.qty_per_block != null ? (
          <span className="tabular-nums text-xs">
            {formatNumberGrouped(r.qty_per_block, { maxFractionDigits: 3 })}
          </span>
        ) : (
          <span className="text-xs text-muted-foreground">—</span>
        );
      case "sort_order":
        return (
          <span className="text-xs">
            {r.sort_order != null ? formatGroupedInteger(r.sort_order) : "—"}
          </span>
        );
      case "brand":
        return <span className="text-xs text-muted-foreground">{r.brand?.name ?? "—"}</span>;
      case "segment":
        return <span className="text-xs text-muted-foreground">{r.segment?.name ?? "—"}</span>;
      case "sku":
        return <span className="font-mono text-xs">{r.sku}</span>;
      case "ikpu_code":
        return <span className="font-mono text-xs">{r.ikpu_code ?? "—"}</span>;
      case "hs_code":
        return <span className="font-mono text-xs">{r.hs_code ?? "—"}</span>;
      case "price": {
        const pl = retailPriceLabel(r);
        return (
          <span className="font-mono text-xs">
            {pl === "—" ? pl : formatNumberGrouped(pl, { maxFractionDigits: 2 })}
          </span>
        );
      }
      default:
        return "—";
    }
  }

  function exportExcel() {
    const order = tablePrefs.visibleColumnOrder;
    const headers = order.map((id) => PRODUCT_ITEMS_COLUMNS.find((c) => c.id === id)?.label ?? id);
    const dataRows = rows.map((r) => order.map((colId) => productItemsExportCell(r, colId)));
    downloadXlsxSheet(
      `products_${new Date().toISOString().slice(0, 10)}.xlsx`,
      "Товары",
      headers,
      dataRows
    );
  }

  const inputCls =
    "flex h-9 rounded-md border border-input bg-background px-2 text-sm shadow-sm outline-none focus-visible:ring-2 focus-visible:ring-ring";

  return (
    <div className="space-y-3">
      <div className="flex flex-wrap items-end gap-2">
        <label className="grid shrink-0 gap-1 text-xs text-muted-foreground">
          <span className="leading-none">Sahifa</span>
          <select
            className={`${inputCls} h-9 min-w-[4rem]`}
            value={pageSize}
            onChange={(e) => {
              tablePrefs.setPageSize(Number(e.target.value));
              setPage(1);
            }}
          >
            {[10, 15, 20, 30, 50, 100].map((n) => (
              <option key={n} value={n}>
                {n}
              </option>
            ))}
          </select>
        </label>
        <label className="grid shrink-0 gap-1 text-xs text-muted-foreground">
          <span className="leading-none">Категория</span>
          <select
            className={`${inputCls} min-w-[9rem]`}
            value={categoryId}
            onChange={(e) => setCategoryId(e.target.value)}
          >
            <option value="">Все</option>
            {(categoriesQ.data ?? []).map((c) => (
              <option key={c.id} value={String(c.id)}>
                {c.name}
              </option>
            ))}
          </select>
        </label>
        <label className="grid shrink-0 gap-1 text-xs text-muted-foreground">
          <span className="leading-none">Группа товаров</span>
          <select
            className={`${inputCls} min-w-[9rem]`}
            value={productGroupId}
            onChange={(e) => setProductGroupId(e.target.value)}
          >
            <option value="">Все</option>
            {(groupsQ.data ?? []).map((c) => (
              <option key={c.id} value={String(c.id)}>
                {c.name}
              </option>
            ))}
          </select>
        </label>
        {isAdmin ? (
          <>
            <div className="relative shrink-0">
              <div className="flex">
                <Button
                  type="button"
                  size="sm"
                  className="h-9 rounded-r-none px-3"
                  onClick={() => {
                    setFullProductId(null);
                    setFullProductOpen(true);
                    setAddMenuOpen(false);
                  }}
                >
                  Добавить
                </Button>
                <Button
                  type="button"
                  size="sm"
                  className="h-9 rounded-l-none border-l border-primary-foreground/30 px-2"
                  onClick={() => setAddMenuOpen((o) => !o)}
                  aria-expanded={addMenuOpen}
                  aria-label="Добавить меню"
                >
                  ▾
                </Button>
              </div>
                {addMenuOpen ? (
                  <div
                    className="absolute right-0 z-50 mt-1 min-w-[240px] rounded-md border border-border bg-popover p-1 text-popover-foreground shadow-md"
                    role="menu"
                  >
                    <button
                      type="button"
                      role="menuitem"
                      className="block w-full rounded px-3 py-2 text-left text-sm hover:bg-muted"
                      onClick={() => {
                        setFullProductId(null);
                        setFullProductOpen(true);
                        setAddMenuOpen(false);
                      }}
                    >
                      Полная форма
                    </button>
                    <button
                      type="button"
                      role="menuitem"
                      className="block w-full rounded px-3 py-2 text-left text-sm hover:bg-muted"
                      onClick={() => {
                        setQuickAddOpen(true);
                        setAddMenuOpen(false);
                      }}
                    >
                      Быстрое добавление
                    </button>
                    <button
                      type="button"
                      role="menuitem"
                      className="block w-full rounded px-3 py-2 text-left text-sm hover:bg-muted"
                      onClick={() => {
                        setAddMenuOpen(false);
                        router.push(`${productsBasePath}/bulk`);
                      }}
                    >
                      Bir nechta qo‘shish
                    </button>
                    <button
                      type="button"
                      role="menuitem"
                      className="block w-full rounded px-3 py-2 text-left text-sm hover:bg-muted"
                      onClick={() => {
                        setAddMenuOpen(false);
                        router.push(`${productsBasePath}/excel`);
                      }}
                    >
                      Exceldan import
                    </button>
                  </div>
                ) : null}
            </div>
            <Button
              type="button"
              size="sm"
              variant="outline"
              className="h-9"
              onClick={() => priceFileRef.current?.click()}
              disabled={priceImportMut.isPending}
            >
              Narx import
            </Button>
          </>
        ) : null}
        <Button
          type="button"
          size="sm"
          variant="outline"
          className="h-9 gap-1"
          onClick={() => setColumnDialogOpen(true)}
        >
          <ListOrdered className="h-4 w-4" />
          Ustunlar
        </Button>
        <Button
          type="button"
          size="sm"
          variant="outline"
          className="h-9 gap-1"
          onClick={() => void listQ.refetch()}
        >
          <RefreshCw className="h-4 w-4" />
          Yangilash
        </Button>
        <Button
          type="button"
          size="sm"
          variant="outline"
          className="h-9"
          onClick={exportExcel}
          disabled={rows.length === 0}
        >
          Excel
        </Button>
        <input
          ref={priceFileRef}
          type="file"
          accept=".xlsx,.xls"
          className="hidden"
          onChange={(e) => {
            const f = e.target.files?.[0];
            if (f) priceImportMut.mutate(f);
          }}
        />
      </div>

      {importMsg ? <p className="text-xs text-muted-foreground">{importMsg}</p> : null}

      <TableColumnSettingsDialog
        open={columnDialogOpen}
        onOpenChange={setColumnDialogOpen}
        title="Ustunlarni boshqarish"
        description="Ko‘rinadigan ustunlar va tartib. Sizning akkauntingiz uchun saqlanadi (server)."
        columns={PRODUCT_ITEMS_COLUMNS}
        columnOrder={tablePrefs.columnOrder}
        hiddenColumnIds={tablePrefs.hiddenColumnIds}
        saving={tablePrefs.saving}
        onSave={(next) => tablePrefs.saveColumnLayout(next)}
        onReset={() => tablePrefs.resetColumnLayout()}
      />

      <p className="text-xs text-muted-foreground">
        <Link href="/settings/product-categories" className="text-primary underline-offset-4 hover:underline">
          Категория продукта
        </Link>{" "}
        — иерархия; здесь «группа товаров» — отдельный справочник (вкладка).
      </p>

      {listQ.isError ? (
        <QueryErrorState
          message={getUserFacingError(listQ.error, "Mahsulotlar yuklanmadi.")}
          onRetry={() => void listQ.refetch()}
        />
      ) : (
        <div className="-mx-3 overflow-x-auto border-t border-border/80 sm:-mx-4">
          <table className="w-full min-w-[720px] text-sm">
            <thead className="app-table-thead text-left">
              <tr>
                {tablePrefs.visibleColumnOrder.map((colId) => {
                  const label = PRODUCT_ITEMS_COLUMNS.find((c) => c.id === colId)?.label ?? colId;
                  return (
                    <th
                      key={colId}
                      className={cn("px-2 py-2 font-medium", colId === "price" && "text-right")}
                    >
                      {label}
                    </th>
                  );
                })}
                <th className="px-2 py-2 text-right font-medium"> </th>
              </tr>
            </thead>
            <tbody>
              {listQ.isLoading ? (
                <tr>
                  <td
                    colSpan={tablePrefs.visibleColumnOrder.length + 1}
                    className="px-3 py-6 text-center text-muted-foreground"
                  >
                    Загрузка…
                  </td>
                </tr>
              ) : rows.length === 0 ? (
                <tr>
                  <td
                    colSpan={tablePrefs.visibleColumnOrder.length + 1}
                    className="px-3 py-8 text-center text-muted-foreground"
                  >
                    Пусто
                  </td>
                </tr>
              ) : (
                rows.map((r) => (
                  <tr key={r.id} className="border-t">
                    {tablePrefs.visibleColumnOrder.map((colId) => (
                      <td
                        key={colId}
                        className={cn(
                          "px-2 py-1.5",
                          colId === "price" && "text-right"
                        )}
                      >
                        {renderProductCell(colId, r)}
                      </td>
                    ))}
                    <td className="px-2 py-1.5 text-right">
                      {isAdmin ? (
                        <TableRowActionGroup className="justify-end" ariaLabel="Mahsulot">
                          <Button
                            type="button"
                            size="icon-sm"
                            variant="outline"
                            className="text-muted-foreground hover:text-foreground"
                            title="Tahrirlash"
                            aria-label="Tahrirlash"
                            onClick={() => {
                              setFullProductId(r.id);
                              setFullProductOpen(true);
                            }}
                          >
                            <Pencil className="size-3.5" aria-hidden />
                          </Button>
                          {statusTab === "active" ? (
                            <Button
                              type="button"
                              size="icon-sm"
                              variant="outline"
                              className="text-amber-800 hover:bg-amber-500/15 hover:text-amber-900 dark:text-amber-200 dark:hover:bg-amber-500/20"
                              disabled={deactivateMut.isPending}
                              title="Neaktiv qilish"
                              aria-label="Neaktiv qilish"
                              onClick={() => {
                                if (
                                  window.confirm(
                                    `«${r.name}» neaktiv qilinsinmi? Ma’lumot o‘chirilmaydi — mahsulot «Не активный» ro‘yxatiga o‘tadi.`
                                  )
                                ) {
                                  deactivateMut.mutate(r.id);
                                }
                              }}
                            >
                              <Ban className="size-3.5" aria-hidden />
                            </Button>
                          ) : (
                            <Button
                              type="button"
                              size="icon-sm"
                              variant="outline"
                              className="text-emerald-800 hover:bg-emerald-500/15 hover:text-emerald-900 dark:text-emerald-200 dark:hover:bg-emerald-500/20"
                              disabled={activateMut.isPending}
                              title="Faollashtirish"
                              aria-label="Faollashtirish"
                              onClick={() => {
                                if (
                                  window.confirm(
                                    `«${r.name}» qayta faol qilinsinmi? U «Активный» ro‘yxatida ko‘rinadi.`
                                  )
                                ) {
                                  activateMut.mutate(r.id);
                                }
                              }}
                            >
                              <RotateCcw className="size-3.5" aria-hidden />
                            </Button>
                          )}
                        </TableRowActionGroup>
                      ) : null}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      <div className="flex flex-wrap items-center justify-between gap-2 text-xs text-muted-foreground">
        <span>
          {total
            ? `Показано ${formatGroupedInteger((page - 1) * pageSize + 1)}–${formatGroupedInteger(Math.min(page * pageSize, total))} / ${formatGroupedInteger(total)}`
            : ""}
        </span>
        <div className="flex gap-1">
          <Button
            type="button"
            variant="outline"
            size="sm"
            disabled={page <= 1}
            onClick={() => setPage((p) => Math.max(1, p - 1))}
          >
            ←
          </Button>
          <span className="px-2 py-1">
            {formatGroupedInteger(page)} / {formatGroupedInteger(totalPages)}
          </span>
          <Button
            type="button"
            variant="outline"
            size="sm"
            disabled={page >= totalPages}
            onClick={() => setPage((p) => p + 1)}
          >
            →
          </Button>
        </div>
      </div>

      <ProductQuickAddDialog
        open={quickAddOpen}
        onOpenChange={setQuickAddOpen}
        tenantSlug={tenantSlug}
        onDone={() => void qc.invalidateQueries({ queryKey: ["products", tenantSlug] })}
      />

      <Dialog
        open={fullProductOpen}
        onOpenChange={(o) => {
          setFullProductOpen(o);
          if (!o) setFullProductId(null);
        }}
      >
        <DialogContent
          className="max-h-[min(90vh,900px)] w-full max-w-2xl gap-0 overflow-y-auto p-0 sm:max-w-2xl"
          showCloseButton
        >
          <DialogHeader className="sr-only">
            <DialogTitle>
              {fullProductId != null ? "Редактировать товар" : "Новый товар"}
            </DialogTitle>
          </DialogHeader>
          {tenantSlug ? (
            <ProductForm
              tenantSlug={tenantSlug}
              mode={fullProductId != null ? "edit" : "create"}
              productId={fullProductId}
              layout="modal"
              onSuccess={() => {
                setFullProductOpen(false);
                setFullProductId(null);
                void qc.invalidateQueries({ queryKey: ["products", tenantSlug] });
              }}
              onCancel={() => {
                setFullProductOpen(false);
                setFullProductId(null);
              }}
            />
          ) : null}
        </DialogContent>
      </Dialog>
    </div>
  );
}

type WorkspaceProps = {
  /** Sozlamalar yon paneli (Категория продукта, …); PageHeader tashqarida bo‘lsa false */
  showSettingsNav?: boolean;
  hideOuterHeader?: boolean;
};

function ProductsCatalogWorkspaceInner({
  showSettingsNav = false,
  hideOuterHeader = false
}: WorkspaceProps) {
  const searchParams = useSearchParams();
  const pathname = usePathname();
  const router = useRouter();
  const qc = useQueryClient();
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const hydrated = useAuthStoreHydrated();
  const role = useEffectiveRole();
  const isAdmin = isAdminOrOperatorLikeRole(role);

  const tabRaw = searchParams.get("tab");
  const tab: TabId = isTabId(tabRaw) ? tabRaw : "items";

  const [statusTab, setStatusTab] = useState<"active" | "inactive">("active");
  const [search, setSearch] = useState("");
  const pageSize = 10;

  function setTab(next: TabId) {
    const p = new URLSearchParams(searchParams.toString());
    p.set("tab", next);
    router.replace(`${pathname}?${p}`, { scroll: false });
  }

  const main = useMemo(() => {
    switch (tab) {
      case "items":
        return (
          <ItemsTab
            tenantSlug={tenantSlug}
            isAdmin={isAdmin}
            statusTab={statusTab}
            search={search}
          />
        );
      case "equipment-items":
        return (
          <EquipmentItemsTab
            tenantSlug={tenantSlug}
            isAdmin={isAdmin}
            statusTab={statusTab}
            search={search}
          />
        );
      case "product-groups":
        return (
          <CatalogSimpleTab
            tenantSlug={tenantSlug}
            isAdmin={isAdmin}
            apiPath="catalog/product-groups"
            title="Справочник групп товаров"
            addLabel="Добавить"
            statusTab={statusTab}
            search={search}
            pageSize={pageSize}
          />
        );
      case "interchangeable":
        return (
          <CatalogInterchangeableTab
            tenantSlug={tenantSlug}
            isAdmin={isAdmin}
            statusTab={statusTab}
            search={search}
            pageSize={pageSize}
          />
        );
      case "brands":
        return (
          <CatalogSimpleTab
            tenantSlug={tenantSlug}
            isAdmin={isAdmin}
            apiPath="catalog/brands"
            title="Бренды"
            addLabel="Добавить"
            statusTab={statusTab}
            search={search}
            pageSize={pageSize}
          />
        );
      case "manufacturers":
        return (
          <CatalogSimpleTab
            tenantSlug={tenantSlug}
            isAdmin={isAdmin}
            apiPath="catalog/manufacturers"
            title="Производители"
            addLabel="Добавить"
            statusTab={statusTab}
            search={search}
            pageSize={pageSize}
          />
        );
      case "segments":
        return (
          <CatalogSimpleTab
            tenantSlug={tenantSlug}
            isAdmin={isAdmin}
            apiPath="catalog/segments"
            title="Сегменты"
            addLabel="Добавить"
            statusTab={statusTab}
            search={search}
            pageSize={pageSize}
          />
        );
      default:
        return null;
    }
  }, [tab, tenantSlug, isAdmin, statusTab, search, pageSize]);

  const headerBlock = hideOuterHeader ? null : (
    <PageHeader
      title="Продукты"
      description="Каталог и справочники. Категории: /settings/product-categories."
      actions={
        <Link className={cn(buttonVariants({ variant: "outline", size: "sm" }))} href="/dashboard">
          Панель управления
        </Link>
      }
    />
  );

  const shell = (
    <div className="space-y-4">
      {headerBlock}

      <div className="orders-hub-section orders-hub-section--table">
        <Card className="overflow-hidden rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
          <CardContent className="p-0">
            <div className="flex flex-wrap gap-1 border-b border-border bg-muted/25 px-3 py-2 sm:px-4">
              {TABS.map((t) => (
                <button
                  key={t.id}
                  type="button"
                  className={cn(
                    "rounded-md px-3 py-1.5 text-sm transition-colors",
                    tab === t.id
                      ? "bg-primary text-primary-foreground"
                      : "text-muted-foreground hover:bg-muted hover:text-foreground"
                  )}
                  onClick={() => setTab(t.id)}
                >
                  {t.label}
                </button>
              ))}
            </div>

            <div className="flex flex-wrap gap-1 border-b border-border/80 px-3 py-2 sm:px-4">
              <button
                type="button"
                className={cn(
                  "rounded px-2 py-1 text-xs",
                  statusTab === "active" ? "border-b-2 border-primary font-medium" : "text-muted-foreground"
                )}
                onClick={() => setStatusTab("active")}
              >
                Активный
              </button>
              <button
                type="button"
                className={cn(
                  "rounded px-2 py-1 text-xs",
                  statusTab === "inactive" ? "border-b-2 border-primary font-medium" : "text-muted-foreground"
                )}
                onClick={() => setStatusTab("inactive")}
              >
                Не активный
              </button>
            </div>

            <div className="table-toolbar flex flex-wrap items-end gap-2 border-b border-border/80 bg-muted/30 px-3 py-2 sm:px-4">
              <Input
                className="h-9 max-w-xs bg-background"
                placeholder="Поиск"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="h-9 shrink-0"
                onClick={() => {
                  void qc.invalidateQueries({ queryKey: ["products", tenantSlug] });
                  void qc.invalidateQueries({ queryKey: ["catalog-simple"] });
                  void qc.invalidateQueries({ queryKey: ["catalog-interchangeable", tenantSlug] });
                }}
              >
                Обновить
              </Button>
            </div>

            <div className="px-3 pb-3 pt-2 sm:px-4">
              {!hydrated ? (
                <p className="text-sm text-muted-foreground">Sessiya…</p>
              ) : !tenantSlug ? (
                <p className="text-sm text-destructive">Tenant yo‘q</p>
              ) : (
                main
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );

  if (showSettingsNav) {
    return <SettingsWorkspace>{shell}</SettingsWorkspace>;
  }
  return shell;
}

export function ProductsCatalogWorkspace(props: WorkspaceProps) {
  return (
    <Suspense fallback={<p className="text-sm text-muted-foreground">Загрузка…</p>}>
      <ProductsCatalogWorkspaceInner {...props} />
    </Suspense>
  );
}

"use client";

import { PageHeader } from "@/components/dashboard/page-header";
import { PageShell } from "@/components/dashboard/page-shell";
import { DateRangePopover, formatDateRangeButton } from "@/components/ui/date-range-popover";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { FilterSearchableSelect } from "@/components/ui/filter-searchable-select";
import { api } from "@/lib/api";
import { useAuthStore, useAuthStoreHydrated } from "@/lib/auth-store";
import { formatNumberGrouped } from "@/lib/format-numbers";
import {
  activePaymentMethodEntries,
  paymentMethodDbValue,
  type ProfilePaymentMethodEntry
} from "@/lib/payment-method-options";
import { STALE } from "@/lib/query-stale";
import { useQuery } from "@tanstack/react-query";
import { CalendarDays, ChevronDown, ChevronRight, Download, Filter, RotateCcw } from "lucide-react";
import { useMemo, useRef, useState } from "react";

type Option = { id: number; name: string };
type FilterOptions = {
  agents: Option[];
  expeditors: Option[];
  cashDesks: Option[];
  categories: string[];
  paymentMethods?: Array<{ value: string; label: string }>;
  paymentTypes: string[];
  tradeDirections: string[];
  territories1: string[];
  territories2: string[];
  territories3: string[];
  territory2By1?: Record<string, string[]>;
  territory3By2?: Record<string, string[]>;
  citiesByZoneRegion?: Record<string, string[]>;
  territory3By12?: Record<string, string[]>;
};
type ReportData = {
  summary: {
    total: number;
    by_payment_method?: Array<{ key: string; label: string; amount: number }>;
    items: Array<{ key: string; amount: number }>;
  };
  paymentTypeLabels?: Record<string, string>;
  paymentTypeKeys?: string[];
  period: Array<{ payment_type: string; amount: number }>;
  territories: Array<{ territory: string; byType: Record<string, number>; total: number }>;
  clients: Array<{ client_id: number; client_name: string; agent_name: string; territory: string; byType: Record<string, number>; total: number }>;
  agents: Array<{ agent_id: number; agent_name: string; byType: Record<string, number>; total: number }>;
};

type ReportFilters = {
  from: string;
  to: string;
  requestType: "regular" | "consignment" | "all";
  expeditorId: string;
  agentId: string;
  cashDeskId: string;
  category: string;
  paymentType: string;
  tradeDirection: string;
  t1: string;
  t2: string;
  t3: string;
};

const fmt = (n: number | string) => formatNumberGrouped(n, { minFractionDigits: 0, maxFractionDigits: 0 });
const SUMMARY_CARD_TONES = [
  "border-rose-300 bg-rose-50/40",
  "border-emerald-300 bg-emerald-50/40",
  "border-amber-300 bg-amber-50/40",
  "border-border bg-muted/40",
  "border-indigo-300 bg-indigo-50/40",
  "border-cyan-300 bg-cyan-50/40",
  "border-violet-300 bg-violet-50/40",
  "border-zinc-300 bg-zinc-50/40"
] as const;

function downloadBlob(blob: Blob, fileName: string) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = fileName;
  a.rel = "noopener";
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

export function IncomeReportWorkspace() {
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const hydrated = useAuthStoreHydrated();
  const enabled = Boolean(tenantSlug && hydrated);
  const today = new Date().toISOString().slice(0, 10);
  const defaultFilters: ReportFilters = useMemo(() => ({
    from: today,
    to: today,
    requestType: "all",
    expeditorId: "",
    agentId: "",
    cashDeskId: "",
    category: "",
    paymentType: "",
    tradeDirection: "",
    t1: "",
    t2: "",
    t3: ""
  }), [today]);
  const [draft, setDraft] = useState<ReportFilters>(defaultFilters);
  const [appliedFilters, setAppliedFilters] = useState<ReportFilters>(defaultFilters);
  const [dateRangeOpen, setDateRangeOpen] = useState(false);
  const dateAnchorRef = useRef<HTMLButtonElement | null>(null);
  const [openSection, setOpenSection] = useState<"period" | "territory" | "clients" | "agents" | null>("period");
  const [tableSearch, setTableSearch] = useState<Record<"period" | "territory" | "clients" | "agents", string>>({
    period: "",
    territory: "",
    clients: "",
    agents: ""
  });
  const [tablePageSize, setTablePageSize] = useState<Record<"period" | "territory" | "clients" | "agents", number>>({
    period: 10,
    territory: 10,
    clients: 10,
    agents: 10
  });
  const [tablePage, setTablePage] = useState<Record<"period" | "territory" | "clients" | "agents", number>>({
    period: 1,
    territory: 1,
    clients: 1,
    agents: 1
  });

  const optionsQ = useQuery({
    queryKey: ["income-report-options", tenantSlug],
    enabled,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: FilterOptions }>(`/api/${tenantSlug}/reports/income-report/filter-options`);
      return data.data;
    }
  });

  const profileQ = useQuery({
    queryKey: ["settings", "profile", tenantSlug, "income-report-methods"],
    enabled,
    staleTime: STALE.profile,
    queryFn: async () => {
      const { data } = await api.get<{
        references?: { payment_method_entries?: ProfilePaymentMethodEntry[]; payment_types?: string[] };
      }>(`/api/${tenantSlug}/settings/profile`);
      return data.references ?? {};
    }
  });

  const query = useMemo(() => {
    const p = new URLSearchParams({
      from: appliedFilters.from,
      to: appliedFilters.to,
      request_type: appliedFilters.requestType
    });
    if (appliedFilters.expeditorId) p.set("expeditor_id", appliedFilters.expeditorId);
    if (appliedFilters.agentId) p.set("agent_id", appliedFilters.agentId);
    if (appliedFilters.cashDeskId) p.set("cash_desk_id", appliedFilters.cashDeskId);
    if (appliedFilters.category) p.set("client_category", appliedFilters.category);
    if (appliedFilters.paymentType) p.set("payment_type", appliedFilters.paymentType);
    if (appliedFilters.tradeDirection) p.set("trade_direction", appliedFilters.tradeDirection);
    if (appliedFilters.t1) p.set("territory_1", appliedFilters.t1);
    if (appliedFilters.t2) p.set("territory_2", appliedFilters.t2);
    if (appliedFilters.t3) p.set("territory_3", appliedFilters.t3);
    return p.toString();
  }, [appliedFilters]);

  const territory2Options = useMemo(() => {
    const by1 = optionsQ.data?.territory2By1 ?? {};
    if (draft.t1 && by1[draft.t1]) return by1[draft.t1];
    return optionsQ.data?.territories2 ?? [];
  }, [optionsQ.data, draft.t1]);

  const territory3Options = useMemo(() => {
    const byZoneRegion = optionsQ.data?.citiesByZoneRegion ?? optionsQ.data?.territory3By12 ?? {};
    const byRegion = optionsQ.data?.territory3By2 ?? {};
    if (draft.t1 && draft.t2 && byZoneRegion[`${draft.t1}|||${draft.t2}`]) return byZoneRegion[`${draft.t1}|||${draft.t2}`];
    if (draft.t1 && draft.t2 && byZoneRegion[`${draft.t1}||${draft.t2}`]) return byZoneRegion[`${draft.t1}||${draft.t2}`];
    if (draft.t2 && byRegion[draft.t2]) return byRegion[draft.t2];
    if (draft.t1 && !draft.t2) {
      const keys = Object.keys(byZoneRegion).filter((k) => k.startsWith(`${draft.t1}|||`) || k.startsWith(`${draft.t1}||`));
      return Array.from(new Set(keys.flatMap((k) => byZoneRegion[k] ?? []))).sort();
    }
    return optionsQ.data?.territories3 ?? [];
  }, [optionsQ.data, draft.t1, draft.t2]);

  const reportQ = useQuery({
    queryKey: ["income-report-data", tenantSlug, query],
    enabled,
    staleTime: STALE.report,
    queryFn: async () => {
      const { data } = await api.get<{ data: ReportData }>(`/api/${tenantSlug}/reports/income-report?${query}`);
      return data.data;
    }
  });

  const exportSheet = async (kind: "period" | "territory" | "clients" | "agents") => {
    if (!tenantSlug) return;
    const res = await api.get<Blob>(`/api/${tenantSlug}/reports/income-report/export/${kind}?${query}`, { responseType: "blob" });
    const names: Record<typeof kind, string> = {
      period: "Отчёт по поступлениям (Поступления за период).xlsx",
      territory: "Отчёт по поступлениям (По территории).xlsx",
      clients: "Отчёт по поступлениям (Поступления по клиентам).xlsx",
      agents: "Отчёт по поступлениям (По агентам).xlsx"
    };
    downloadBlob(res.data as Blob, names[kind]);
  };

  const data = reportQ.data;
  const paymentTypeLabels = data?.paymentTypeLabels ?? {};

  const tenantPaymentCatalog = useMemo(() => {
    const fromProfile = activePaymentMethodEntries(profileQ.data).map((e) => ({
      key: paymentMethodDbValue(e),
      label: e.name.trim()
    }));
    if (fromProfile.length > 0) return fromProfile;
    const fromFilter = optionsQ.data?.paymentMethods ?? [];
    if (fromFilter.length > 0) {
      return fromFilter.map((m) => ({ key: m.value, label: m.label }));
    }
    return [];
  }, [profileQ.data, optionsQ.data?.paymentMethods]);

  const paymentMethodOptions = useMemo(() => {
    if (tenantPaymentCatalog.length > 0) {
      return tenantPaymentCatalog.map((c) => ({ value: c.key, label: c.label }));
    }
    return (optionsQ.data?.paymentTypes ?? []).map((value) => ({
      value,
      label: paymentTypeLabels[value] ?? value
    }));
  }, [tenantPaymentCatalog, optionsQ.data?.paymentTypes, paymentTypeLabels]);

  const summaryPaymentMethods = useMemo(() => {
    if (!data) return [];
    if (data.summary.by_payment_method?.length) {
      return data.summary.by_payment_method;
    }
    const amountByKey = new Map<string, number>();
    for (const row of data.period ?? []) {
      amountByKey.set(row.payment_type, row.amount);
    }
    if (tenantPaymentCatalog.length > 0) {
      return tenantPaymentCatalog.map(({ key, label }) => ({
        key,
        label,
        amount: amountByKey.get(key) ?? 0
      }));
    }
    return (data.period ?? [])
      .filter((r) => r.amount > 0)
      .map((r) => ({
        key: r.payment_type,
        label: paymentTypeLabels[r.payment_type] ?? r.payment_type,
        amount: r.amount
      }));
  }, [data, tenantPaymentCatalog, paymentTypeLabels]);

  const paymentColumns = useMemo(() => {
    if (!data) return [];
    const catalogKeys = tenantPaymentCatalog.map((c) => c.key);
    if (catalogKeys.length > 0) return catalogKeys;
    if (data.paymentTypeKeys?.length) return data.paymentTypeKeys;
    return Array.from(new Set((data.period ?? []).map((r) => r.payment_type)));
  }, [data, tenantPaymentCatalog]);

  const periodDisplayRows = useMemo(() => {
    if (!data) return [];
    const catalogKeys = new Set(tenantPaymentCatalog.map((c) => c.key));
    return (data.period ?? [])
      .filter((r) => r.amount > 0 && (catalogKeys.size === 0 || catalogKeys.has(r.payment_type)))
      .map((r) => ({
        ...r,
        label:
          paymentTypeLabels[r.payment_type] ??
          tenantPaymentCatalog.find((c) => c.key === r.payment_type)?.label ??
          r.payment_type
      }));
  }, [data, tenantPaymentCatalog, paymentTypeLabels]);

  const filteredData = useMemo(() => {
    if (!data) {
      return { period: [], territory: [], clients: [], agents: [] };
    }
    const s = {
      period: tableSearch.period.trim().toLowerCase(),
      territory: tableSearch.territory.trim().toLowerCase(),
      clients: tableSearch.clients.trim().toLowerCase(),
      agents: tableSearch.agents.trim().toLowerCase()
    };
    return {
      period: periodDisplayRows.filter((r) => !s.period || r.label.toLowerCase().includes(s.period)),
      territory: data.territories.filter((r) => !s.territory || r.territory.toLowerCase().includes(s.territory)),
      clients: data.clients.filter((r) => {
        if (!s.clients) return true;
        return (
          String(r.client_id).includes(s.clients) ||
          r.client_name.toLowerCase().includes(s.clients) ||
          r.agent_name.toLowerCase().includes(s.clients) ||
          r.territory.toLowerCase().includes(s.clients)
        );
      }),
      agents: data.agents.filter((r) => {
        if (!s.agents) return true;
        return String(r.agent_id).includes(s.agents) || r.agent_name.toLowerCase().includes(s.agents);
      })
    };
  }, [data, tableSearch, periodDisplayRows]);

  const paginate = <T,>(rows: T[], key: "period" | "territory" | "clients" | "agents") => {
    const pageSize = tablePageSize[key];
    const page = tablePage[key];
    const total = rows.length;
    const maxPage = Math.max(1, Math.ceil(total / pageSize));
    const safePage = Math.min(page, maxPage);
    const start = (safePage - 1) * pageSize;
    const end = start + pageSize;
    return { rows: rows.slice(start, end), total, page: safePage, maxPage };
  };

  return (
    <PageShell>
      <PageHeader title="Отчёт по приходам" description="Касса bo‘yicha kirimlar hisobotlari" />
      <Card className="shadow-panel">
        <CardContent className="space-y-2 p-3">
          <div className="flex flex-wrap items-center justify-end gap-2">
            <div className="w-[11rem] min-w-[11rem]">
              <FilterSearchableSelect
                emptyLabel="Обе"
                value={draft.requestType}
                onValueChange={(value) =>
                  setDraft((prev) => ({
                    ...prev,
                    requestType: (value || "all") as ReportFilters["requestType"]
                  }))
                }
                options={[
                  { value: "all", label: "Обе" },
                  { value: "regular", label: "Обычная" },
                  { value: "consignment", label: "Для консигнации" }
                ]}
                searchable={false}
                className="h-9 rounded-md px-2 text-sm"
              />
            </div>
            <button
              ref={dateAnchorRef}
              type="button"
              className="inline-flex h-9 min-w-[16rem] items-center justify-between rounded-md border bg-background px-2.5 text-sm"
              onClick={() => setDateRangeOpen((v) => !v)}
            >
              <span className="truncate">{formatDateRangeButton(draft.from, draft.to)}</span>
              <CalendarDays className="size-4 text-muted-foreground" />
            </button>
          </div>

          <div className="grid gap-2 md:grid-cols-6">
            <div className="w-full min-w-0">
              <FilterSearchableSelect
                emptyLabel="Экспедитор"
                value={draft.expeditorId}
                onValueChange={(value) => setDraft((prev) => ({ ...prev, expeditorId: value }))}
                options={(optionsQ.data?.expeditors ?? []).map((x) => ({ value: String(x.id), label: x.name }))}
                searchable
                className="h-9 rounded-md px-2 text-sm"
              />
            </div>
            <div className="w-full min-w-0">
              <FilterSearchableSelect
                emptyLabel="Агент"
                value={draft.agentId}
                onValueChange={(value) => setDraft((prev) => ({ ...prev, agentId: value }))}
                options={(optionsQ.data?.agents ?? []).map((x) => ({ value: String(x.id), label: x.name }))}
                searchable
                className="h-9 rounded-md px-2 text-sm"
              />
            </div>
            <div className="w-full min-w-0">
              <FilterSearchableSelect
                placeholderLabel="Касса"
                emptyLabel="Все"
                value={draft.cashDeskId}
                onValueChange={(value) => setDraft((prev) => ({ ...prev, cashDeskId: value }))}
                options={(optionsQ.data?.cashDesks ?? []).map((x) => ({ value: String(x.id), label: x.name }))}
                searchable
                className="h-9 rounded-md px-2 text-sm"
              />
            </div>
            <div className="w-full min-w-0">
              <FilterSearchableSelect
                emptyLabel="Категория клиента"
                value={draft.category}
                onValueChange={(value) => setDraft((prev) => ({ ...prev, category: value }))}
                options={(optionsQ.data?.categories ?? []).map((x) => ({ value: x, label: x }))}
                searchable
                className="h-9 rounded-md px-2 text-sm"
              />
            </div>
            <div className="w-full min-w-0">
              <FilterSearchableSelect
                emptyLabel="Способ оплаты"
                value={draft.paymentType}
                onValueChange={(value) => setDraft((prev) => ({ ...prev, paymentType: value }))}
                options={paymentMethodOptions.map((x) => ({ value: x.value, label: x.label }))}
                searchable
                className="h-9 rounded-md px-2 text-sm"
              />
            </div>
            <div className="w-full min-w-0">
              <FilterSearchableSelect
                emptyLabel="Направление торговли"
                value={draft.tradeDirection}
                onValueChange={(value) => setDraft((prev) => ({ ...prev, tradeDirection: value }))}
                options={(optionsQ.data?.tradeDirections ?? []).map((x) => ({ value: x, label: x }))}
                searchable
                className="h-9 rounded-md px-2 text-sm"
              />
            </div>
