                minPopoverWidth={200}
                maxListHeightClass="max-h-36"
                selectAllLabel="Выбрать все"
              />
            </div>
            <div className="min-w-0">
              <SearchableMultiSelectPanel
                label="Группа KPI"
                hideOuterLabel
                hidePopoverHeader
                triggerPlaceholder="KPI"
                triggerClassName="h-8 min-h-8 w-full text-xs font-normal shadow-sm"
                items={kpiGroupItems}
                selected={new Set(filters.kpiGroupIds.map(String))}
                onSelectedChange={(next) => {
                  const s = typeof next === "function" ? next(new Set(filters.kpiGroupIds.map(String))) : next;
                  setFilters((f) => ({
                    ...f,
                    kpiGroupIds: Array.from(s).map((x) => Number.parseInt(String(x), 10)).filter((n) => n > 0)
                  }));
                }}
                searchable
                searchPlaceholder="KPI"
                minPopoverWidth={200}
                maxListHeightClass="max-h-36"
                selectAllLabel="Выбрать все"
              />
            </div>
            <div className="min-w-0">
              <SearchableMultiSelectPanel
                label="Клиенты"
                hideOuterLabel
                hidePopoverHeader
                triggerPlaceholder="Клиент"
                triggerClassName="h-8 min-h-8 w-full text-xs font-normal shadow-sm"
                items={clientItems}
                selected={new Set(filters.clientIds.map(String))}
                onSelectedChange={(next) => {
                  const s = typeof next === "function" ? next(new Set(filters.clientIds.map(String))) : next;
                  setFilters((f) => ({
                    ...f,
                    clientIds: Array.from(s).map((x) => Number.parseInt(String(x), 10)).filter((n) => n > 0)
                  }));
                }}
                searchable
                searchPlaceholder="Клиент"
                minPopoverWidth={220}
                maxListHeightClass="max-h-36"
                selectAllLabel="Выбрать все"
              />
            </div>
            <div className="min-w-0">
              <SearchableMultiSelectPanel
                label="Зона"
                hideOuterLabel
                hidePopoverHeader
                triggerPlaceholder="Зона"
                triggerClassName="h-8 min-h-8 w-full text-xs font-normal shadow-sm"
                items={territory1Items}
                selected={new Set(filters.territoryLevel1Values)}
                onSelectedChange={(next) => {
                  const s = typeof next === "function" ? next(new Set(filters.territoryLevel1Values)) : next;
                  // Hierarchy: when zone changes, oblast/gorod selections must reset.
                  setFilters((f) => ({
                    ...f,
                    territoryLevel1Values: Array.from(s),
                    territoryLevel2Values: [],
                    territoryLevel3Values: []
                  }));
                }}
                searchable
                searchPlaceholder="Зона"
                minPopoverWidth={200}
                maxListHeightClass="max-h-36"
                selectAllLabel="Выбрать все"
              />
            </div>
            <div className="min-w-0">
              <SearchableMultiSelectPanel
                label="Область"
                hideOuterLabel
                hidePopoverHeader
                triggerPlaceholder="Область"
                triggerClassName="h-8 min-h-8 w-full text-xs font-normal shadow-sm"
                items={territory2Items}
                selected={new Set(filters.territoryLevel2Values)}
                onSelectedChange={(next) => {
                  const s = typeof next === "function" ? next(new Set(filters.territoryLevel2Values)) : next;
                  // Hierarchy: when oblast changes, gorod selection must reset.
                  setFilters((f) => ({
                    ...f,
                    territoryLevel2Values: Array.from(s),
                    territoryLevel3Values: []
                  }));
                }}
                searchable
                searchPlaceholder="Область"
                minPopoverWidth={200}
                maxListHeightClass="max-h-36"
                selectAllLabel="Выбрать все"
              />
            </div>
            <div className="min-w-0">
              <SearchableMultiSelectPanel
                label="Город"
                hideOuterLabel
                hidePopoverHeader
                triggerPlaceholder="Город"
                triggerClassName="h-8 min-h-8 w-full text-xs font-normal shadow-sm"
                items={territory3Items}
                selected={new Set(filters.territoryLevel3Values)}
                onSelectedChange={(next) => {
                  const s = typeof next === "function" ? next(new Set(filters.territoryLevel3Values)) : next;
                  setFilters((f) => ({ ...f, territoryLevel3Values: Array.from(s) }));
                }}
                searchable
                searchPlaceholder="Город"
                minPopoverWidth={200}
                maxListHeightClass="max-h-36"
                selectAllLabel="Выбрать все"
              />
            </div>
          </div>
        </CardContent> : null}
      </Card>

      {lastDataset?.truncated ? (
        <div className="rounded-md border border-amber-500/50 bg-amber-500/10 px-3 py-2 text-xs text-amber-950 dark:text-amber-100">
          Показано не более {lastDataset.cap.toLocaleString()} строк из {lastDataset.totalRowCount.toLocaleString()}. Сузьте
          фильтры или выгрузите текущую таблицу через «Экспорт» (Excel в браузере).
        </div>
      ) : null}

      <Card>
        <CardHeader className="py-3">
          <CardTitle className="text-base">Сводная таблица</CardTitle>
          <p className="text-xs text-muted-foreground">
            Перетащите поля в строки / столбцы / значения. Фильтрация по значениям доступна в заголовках колонок.
          </p>
        </CardHeader>
        <CardContent className="min-h-0 pt-0">
          <div className="mb-2 flex flex-wrap items-center justify-between gap-2 rounded border border-border bg-muted/30 p-2">
            <div className="flex flex-wrap items-center gap-1">
              <Button
                type="button"
                size="sm"
                variant="ghost"
                className="h-8 gap-1 text-xs"
                onClick={() => setSavedReportsDialogOpen(true)}
              >
                <FolderOpen className="h-3.5 w-3.5" />
                Отчёт
              </Button>
              <Button type="button" size="sm" variant="ghost" className="h-8 gap-1 text-xs" onClick={() => setSaveDialogOpen(true)}>
                <Save className="h-3.5 w-3.5" />
                Сохр. как
              </Button>
              <Button type="button" size="sm" variant="ghost" className="h-8 gap-1 text-xs" onClick={onBrowserExport}>
                <Download className="h-3.5 w-3.5" />
                Экспорт
              </Button>
              <Button
                type="button"
                size="sm"
                variant="ghost"
                className="h-8 gap-1 text-xs"
                onClick={onToggleHierarchy}
              >
                {hierarchyExpanded ? <Minimize2 className="h-3.5 w-3.5" /> : <Maximize2 className="h-3.5 w-3.5" />}
                {hierarchyExpanded ? "Свернуть всё" : "Развернуть всё"}
              </Button>
            </div>
            <div className="flex flex-wrap items-center gap-1">
              <div className="relative">
                <Button
                  type="button"
                  size="sm"
                  variant="ghost"
                  className="h-8 gap-1 text-xs"
                  onClick={() => setFormatMenuOpen((v) => !v)}
                >
                  <SlidersHorizontal className="h-3.5 w-3.5" />
                  Формат
                </Button>
                {formatMenuOpen ? (
                  <div
                    ref={formatMenuRef}
                    className="absolute left-0 top-full z-30 -mt-px min-w-[12rem] rounded-b-md border border-border bg-popover p-1 shadow-lg"
                  >
                    <button
                      type="button"
                      className="flex w-full items-center gap-2 rounded px-2 py-1.5 text-left text-xs hover:bg-muted"
                      onClick={() => {
                        setFormatMenuOpen(false);
                        setFormatCellsDialogOpen(true);
                      }}
                    >
                      <span className="text-muted-foreground">S/1.0</span>
                      Формат ячеек
                    </button>
                    <button
                      type="button"
                      className="flex w-full items-center gap-2 rounded px-2 py-1.5 text-left text-xs hover:bg-muted"
                      onClick={() => {
                        setFormatMenuOpen(false);
                        setConditionalDialogOpen(true);
                      }}
                    >
                      <span className="text-muted-foreground">123</span>
                      Условное форматирование
                    </button>
                  </div>
                ) : null}
              </div>
              <Button
                type="button"
                size="sm"
                variant="ghost"
                className="h-8 gap-1 text-xs"
                onClick={() => {
                  if (!runToolbarAction("options")) window.alert("Панель «Опции» пока недоступна");
                }}
              >
                <Settings2 className="h-3.5 w-3.5" />
                Опции
              </Button>
              <Button
                type="button"
                size="sm"
                variant="ghost"
                className="h-8 gap-1 text-xs"
                onClick={() => {
                  if (!runToolbarAction("fields")) window.alert("Панель «Поля» пока недоступна");
                }}
              >
                <ListFilter className="h-3.5 w-3.5" />
                Поля
              </Button>
              <Button type="button" size="sm" variant="ghost" className="h-8 gap-1 text-xs" onClick={onToggleFullscreen}>
                <Fullscreen className="h-3.5 w-3.5" />
                На весь экран
              </Button>
            </div>
          </div>
          <div
            ref={pivotWrapRef}
            className="wdr-host w-full max-w-full min-h-0 overflow-x-auto rounded border border-border bg-background"
            style={{ height: pivotViewportPx }}
          >
            <WebDataRocksReact.Pivot
              key={pivotMountKey}
              ref={pivotRef}
              toolbar
              localization="https://cdn.webdatarocks.com/loc/ru.json"
              beforetoolbarcreated={beforeToolbarCreated}
              width="100%"
              height={pivotViewportPx}
              report={initialReport as never}
              ready={() => {
                pivotReadyRef.current = true;
                syncPivotSnapshot();
                hideInternalToolbar();
                scheduleWdrLayoutRefresh(getPivotApi(pivotRef));
              }}
              reportcomplete={() => {
                syncPivotSnapshot();
                hideInternalToolbar();
                scheduleWdrLayoutRefresh(getPivotApi(pivotRef));
              }}
            />
          </div>
        </CardContent>
      </Card>

      <Dialog open={saveDialogOpen} onOpenChange={setSaveDialogOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Сохранить отчёт</DialogTitle>
          </DialogHeader>
          <div className="space-y-2">
            <p className="text-xs text-muted-foreground">Введите имя для текущей формы отчёта.</p>
            <Input
              className="h-9"
              placeholder="Например: Продажи по агентам"
              value={saveName}
              onChange={(e) => setSaveName(e.target.value)}
            />
          </div>
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => setSaveDialogOpen(false)}>
              Отмена
            </Button>
            <Button
              type="button"
              variant="secondary"
              disabled={saveMut.isPending || saveName.trim().length === 0}
              onClick={() => void onSave().then((ok) => ok && setSaveDialogOpen(false))}
            >
              {saveMut.isPending ? <Loader2 className="mr-1 h-3.5 w-3.5 animate-spin" /> : null}
              Сохранить
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={savedReportsDialogOpen} onOpenChange={setSavedReportsDialogOpen}>
        <DialogContent className="sm:max-w-2xl">
          <DialogHeader>
            <DialogTitle>Выберите отчёт для просмотра</DialogTitle>
          </DialogHeader>
          <div className="max-h-[55vh] overflow-y-auto pr-1">
            {(savedQ.data ?? []).length === 0 ? (
              <p className="text-sm text-muted-foreground">Пока нет сохранённых отчётов.</p>
            ) : (
              <div className="flex flex-wrap gap-2">
                <button
                  type="button"
                  className={cn(
                    "rounded-md border px-3 py-1.5 text-xs transition-colors",
                    activeSavedReportId === null
                      ? "border-blue-300 bg-blue-600 text-white"
                      : "border-blue-200 bg-blue-500/90 text-white hover:bg-blue-600"
                  )}
                  onClick={() => {
                    void loadDefaultReport()
                      .then(() => setSavedReportsDialogOpen(false))
                      .catch((err: unknown) =>
                        window.alert(getUserFacingError(err, "Ошибка загрузки отчёта по умолчанию"))
                      );
                  }}
                >
                  По умолчанию
                </button>
                {(savedQ.data ?? []).map((s) => (
                  <button
                    key={s.id}
                    type="button"
                    className={cn(
                      "rounded-md border px-3 py-1.5 text-xs transition-colors",
                      activeSavedReportId === s.id
                        ? "border-blue-300 bg-blue-600 text-white"
                        : "border-blue-200 bg-blue-500/90 text-white hover:bg-blue-600"
                    )}
                    onClick={() => {
                      void loadSaved(s.id)
                        .then(() => setSavedReportsDialogOpen(false))
                        .catch((err: unknown) => window.alert(getUserFacingError(err, "Ошибка загрузки")));
                    }}
                  >
                    {s.name}
                  </button>
                ))}
              </div>
            )}
          </div>
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => setSavedReportsDialogOpen(false)}>
              Закрыть
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={formatCellsDialogOpen} onOpenChange={setFormatCellsDialogOpen}>
        <DialogContent className="sm:max-w-xl">
          <DialogHeader>
            <DialogTitle className="text-lg font-semibold text-foreground">Форматирование</DialogTitle>
          </DialogHeader>
          <div className="grid grid-cols-[160px_1fr] gap-2 text-xs">
            <label className="self-center text-foreground">Выбрать</label>
            <select className="h-8 rounded border border-input bg-background px-2 text-foreground" value={formatValueScope} onChange={(e) => setFormatValueScope(e.target.value)}>
              <option value="selected">Выбрать значение</option>
              <option value="all">Все значения</option>
            </select>

            <label className="self-center text-foreground">Выравнивание текста</label>
            <select className="h-8 rounded border border-input bg-background px-2 text-foreground" value={formatAlign} onChange={(e) => setFormatAlign(e.target.value)}>
              <option value="left">Слева</option>
              <option value="center">По центру</option>
              <option value="right">Справа</option>
            </select>

            <label className="self-center text-foreground">Thousands separator</label>
            <select className="h-8 rounded border border-input bg-background px-2 text-foreground" value={formatThousands} onChange={(e) => setFormatThousands(e.target.value)}>
              <option value="space">(пробел)</option>
              <option value=",">,</option>
              <option value=".">.</option>
            </select>

            <label className="self-center text-foreground">Десятичный разделитель</label>
            <select className="h-8 rounded border border-input bg-background px-2 text-foreground" value={formatDecimalSep} onChange={(e) => setFormatDecimalSep(e.target.value)}>
              <option value=".">.</option>
              <option value=",">,</option>
            </select>

            <label className="self-center text-foreground">Десятичные знаки</label>
            <select className="h-8 rounded border border-input bg-background px-2 text-foreground" value={formatDecimalPlaces} onChange={(e) => setFormatDecimalPlaces(e.target.value)}>
              <option value="0">0</option>
              <option value="1">1</option>
              <option value="2">2</option>
              <option value="3">3</option>
              <option value="4">4</option>
            </select>

            <label className="self-center text-foreground">Negative number format</label>
            <select className="h-8 rounded border border-input bg-background px-2 text-foreground" value={formatNegatives} onChange={(e) => setFormatNegatives(e.target.value)}>
              <option value="-1">-1</option>
              <option value="(1)">(1)</option>
            </select>

            <label className="self-center text-foreground">Нулевое значение</label>
            <Input className="h-8" value={formatNullValue} onChange={(e) => setFormatNullValue(e.target.value)} />

            <label className="self-center text-foreground">Форматировать как проценты</label>
            <select className="h-8 rounded border border-input bg-background px-2 text-foreground" value={formatAsPercent} onChange={(e) => setFormatAsPercent(e.target.value)}>
              <option value="false">false</option>
              <option value="true">true</option>
            </select>

            <label className="self-center text-foreground">Шаблон числа</label>
            <Input className="h-8" value={cellFormatPattern} onChange={(e) => setCellFormatPattern(e.target.value)} placeholder="#,##0.00" />
          </div>
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => setFormatCellsDialogOpen(false)}>
              Отмена
            </Button>
            <Button
              type="button"
              onClick={() => {
                const wdr = getPivotApi(pivotRef);
                if (!wdr || !pivotReadyRef.current) {
                  window.alert("Таблица ещё не готова");
                  return;
                }
                const plain = tryGetWdrReportJson(wdr) ?? lastWdrReportRef.current;
                const next = {
                  ...plain,
                  savdoCustomFormat: {
                    ...((plain as Record<string, unknown>).savdoCustomFormat as Record<string, unknown>),
                    cellFormatPattern,
                    formatValueScope,
                    formatAlign,
                    formatThousands,
                    formatDecimalSep,
                    formatDecimalPlaces,
                    formatNegatives,
                    formatNullValue,
                    formatAsPercent
                  }
                } as WdrReportJson;
                lastWdrReportRef.current = next;
                wdr.setReport(next as never);
                scheduleWdrLayoutRefresh(wdr);
                setFormatCellsDialogOpen(false);
              }}
            >
              Применить
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={conditionalDialogOpen} onOpenChange={setConditionalDialogOpen}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle className="text-lg font-semibold text-foreground">Форматирование...</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 text-xs">
            <div className="flex items-center justify-between gap-2">
              <button
                type="button"
                className="rounded border border-input px-2 py-1 text-foreground hover:bg-muted"
                onClick={() =>
                  setConditionalRules((prev) => [
                    ...prev,
                    {
                      id: `r-${Date.now()}-${prev.length}`,
                      scope: "all",
                      operator: "lt",
                      threshold: "0",
                      fontName: "Arial",
                      fontSize: "12px",
                      color: "#ef4444"
                    }
                  ])
                }
              >
                +
              </button>
              <div className="ml-auto flex items-center gap-2">
                <Button
                  type="button"
                  size="sm"
                  className="h-8"
                  onClick={() => {
                    const host = pivotWrapRef.current;
                    if (host) applyConditionalFormattingToHost(host, conditionalRules);
                  }}
                >
                  ПРИМЕНИТЬ
                </Button>
                <Button type="button" size="sm" variant="outline" className="h-8" onClick={() => setConditionalDialogOpen(false)}>ОТМЕНИТЬ</Button>
              </div>
            </div>
            {conditionalRules.length === 0 ? (
              <div className="rounded border border-input p-4 text-center text-muted-foreground">
                <p>There are no active conditions.</p>
                <button
                  type="button"
                  className="mt-3 rounded border border-input px-3 py-1 hover:bg-muted"
                  onClick={() =>
                    setConditionalRules([
                      {
                        id: `r-${Date.now()}`,
                        scope: "all",
                        operator: "lt",
                        threshold: "0",
                        fontName: "Arial",
                        fontSize: "12px",
                        color: "#ef4444"
                      }
                    ])
                  }
                >
                  + Add condition
                </button>
              </div>
            ) : (
              conditionalRules.map((rule) => (
                <div key={rule.id} className="space-y-2 rounded border border-input p-2">
                  <div className="grid grid-cols-[80px_1fr_1fr_1fr_24px] items-center gap-2">
                    <label className="text-foreground">Значение:</label>
                    <select
                      className="h-8 rounded border border-input bg-background px-2 text-foreground"
                      value={rule.scope}
                      onChange={(e) =>
                        setConditionalRules((prev) => prev.map((x) => (x.id === rule.id ? { ...x, scope: e.target.value as "all" } : x)))
                      }
                    >
                      <option value="all">Все значения</option>
                    </select>
                    <select
                      className="h-8 rounded border border-input bg-background px-2 text-foreground"
                      value={rule.operator}
                      onChange={(e) =>
                        setConditionalRules((prev) =>
                          prev.map((x) => (x.id === rule.id ? { ...x, operator: e.target.value as "gt" | "lt" | "eq" } : x))
                        )
                      }
                    >
                      <option value="lt">Меньше чем</option>
                      <option value="gt">Больше чем</option>
                      <option value="eq">Равно</option>
                    </select>
                    <Input
                      className="h-8"
                      value={rule.threshold}
                      onChange={(e) =>
                        setConditionalRules((prev) => prev.map((x) => (x.id === rule.id ? { ...x, threshold: e.target.value } : x)))
                      }
                    />
                    <button
                      type="button"
                      className="text-muted-foreground hover:text-foreground"
                      onClick={() => setConditionalRules((prev) => prev.filter((x) => x.id !== rule.id))}
                    >
                      ✕
                    </button>
                  </div>
                  <div className="grid grid-cols-[80px_1fr_90px_36px_1fr] items-center gap-2">
                    <label className="text-foreground">Формат:</label>
                    <select
                      className="h-8 rounded border border-input bg-background px-2 text-foreground"
                      value={rule.fontName}
                      onChange={(e) =>
                        setConditionalRules((prev) => prev.map((x) => (x.id === rule.id ? { ...x, fontName: e.target.value } : x)))
                      }
                    >
                      <option value="Arial">Arial</option>
                      <option value="Inter">Inter</option>
                      <option value="Tahoma">Tahoma</option>
                    </select>
                    <select
                      className="h-8 rounded border border-input bg-background px-2 text-foreground"
                      value={rule.fontSize}
                      onChange={(e) =>
                        setConditionalRules((prev) => prev.map((x) => (x.id === rule.id ? { ...x, fontSize: e.target.value } : x)))
                      }
                    >
                      <option value="11px">11px</option>
                      <option value="12px">12px</option>
                      <option value="13px">13px</option>
                      <option value="14px">14px</option>
                    </select>
                    <div className="flex h-8 items-center justify-center rounded border border-input bg-muted text-foreground">A</div>
                    <Input
                      className="h-8"
                      value={rule.color}
                      onChange={(e) =>
                        setConditionalRules((prev) => prev.map((x) => (x.id === rule.id ? { ...x, color: e.target.value } : x)))
                      }
                    />
                  </div>
                </div>
              ))
            )}
          </div>
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => setConditionalDialogOpen(false)}>
              Отмена
            </Button>
            <Button
              type="button"
              onClick={() => {
                const wdr = getPivotApi(pivotRef);
                if (!wdr || !pivotReadyRef.current) {
                  window.alert("Таблица ещё не готова");
                  return;
                }
                const plain = tryGetWdrReportJson(wdr) ?? lastWdrReportRef.current;
                const next = {
                  ...plain,
                  savdoCustomFormat: {
                    ...(plain as Record<string, unknown>).savdoCustomFormat as Record<string, unknown>,
                    conditionalThreshold,
                    conditionalRules
                  }
                } as WdrReportJson;
                lastWdrReportRef.current = next;
                wdr.setReport(next as never);
                scheduleWdrLayoutRefresh(wdr);
                const hostEl = pivotWrapRef.current;
                if (hostEl) applyConditionalFormattingToHost(hostEl, conditionalRules);
                setConditionalDialogOpen(false);
              }}
            >
              Применить
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

export default WdrReportBuilder;

"use client";

import { useMemo, useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog";
import { INITIAL_SETUP_STEPS } from "@/lib/initial-setup/catalog";
import { applyBundleInOrder, type BundleApplyProgress } from "@/lib/initial-setup/apply-step";
import type { BundleParseResult } from "@/lib/initial-setup/bundle-xlsx";
import { getStepById } from "@/lib/initial-setup/catalog";
import { sortStepIdsByFlowOrder } from "@/lib/initial-setup/flow-order";
import { InitialSetupStepTable } from "@/components/settings/initial-setup/initial-setup-step-table";
import { doneStepIds } from "@/lib/initial-setup/progress";
import { cn } from "@/lib/utils";
import { CheckCircle2, Circle, Loader2, SkipForward } from "lucide-react";

type Props = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  tenantSlug: string;
  bundle: BundleParseResult;
  progressDone: ReadonlySet<string>;
  onComplete: (
    messages: string[],
    failed: { stepId: string; error: string }[],
    succeededIds: string[],
    skipped: string[]
  ) => void;
};

export function InitialSetupBundleDialog({
  open,
  onOpenChange,
  tenantSlug,
  bundle,
  progressDone,
  onComplete
}: Props) {
  const qc = useQueryClient();
  const stepIds = useMemo(
    () => sortStepIdsByFlowOrder(Object.keys(bundle).filter((id) => bundle[id]?.rows.length)),
    [bundle]
  );
  const [tab, setTab] = useState(stepIds[0] ?? "");
  const [busy, setBusy] = useState(false);
  const [applyLog, setApplyLog] = useState<BundleApplyProgress[]>([]);

  const activeStep = getStepById(tab);

  async function applyAll() {
    setBusy(true);
    setApplyLog([]);
    const order = INITIAL_SETUP_STEPS.filter((s) => stepIds.includes(s.id));
    const { ok, failed, succeededIds, skipped } = await applyBundleInOrder(
      tenantSlug,
      bundle,
      order,
      qc,
      progressDone,
      (p) => setApplyLog((prev) => [...prev.filter((x) => x.stepId !== p.stepId), p])
    );
    onComplete(ok, failed, succeededIds, skipped);
    setBusy(false);
    if (!failed.length) onOpenChange(false);
  }

  if (!stepIds.length) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="flex max-h-[92vh] max-w-5xl flex-col gap-0 overflow-hidden p-0">
        <DialogHeader className="border-b px-6 py-4">
          <DialogTitle>Импорт Excel — проверка</DialogTitle>
          <DialogDescription>
            {stepIds.length} листов. Применение идёт по порядку: Основа → Справочники → Продукты → Клиенты. Каждый
            шаг ждёт завершения предыдущих.
          </DialogDescription>
        </DialogHeader>

        <div className="flex min-h-0 flex-1 flex-col gap-0 md:flex-row">
          <div className="flex shrink-0 gap-1 overflow-x-auto border-b p-2 md:w-52 md:flex-col md:border-b-0 md:border-r">
            {stepIds.map((id, idx) => {
              const step = getStepById(id);
              const log = applyLog.find((x) => x.stepId === id);
              return (
                <button
                  key={id}
                  type="button"
                  className={cn(
                    "flex items-center gap-1.5 rounded px-2 py-1.5 text-left text-xs",
                    tab === id ? "bg-primary text-primary-foreground" : "hover:bg-muted"
                  )}
                  onClick={() => setTab(id)}
                >
                  <span className="tabular-nums opacity-60">{idx + 1}.</span>
                  <span className="min-w-0 flex-1 truncate">{step?.title ?? id}</span>
                  {log?.status === "running" ? (
                    <Loader2 className="size-3 shrink-0 animate-spin" />
                  ) : log?.status === "done" ? (
                    <CheckCircle2 className="size-3 shrink-0 text-emerald-500" />
                  ) : log?.status === "skipped" ? (
                    <SkipForward className="size-3 shrink-0 opacity-60" />
                  ) : (
                    <Circle className="size-3 shrink-0 opacity-30" />
                  )}
                </button>
              );
            })}
          </div>
          <div className="min-h-0 flex-1 overflow-auto p-4">
            {activeStep ? (
              <InitialSetupStepTable
                tenantSlug={tenantSlug}
                step={activeStep}
                enabled
                effectiveDoneIds={progressDone}
                externalPreview={bundle[tab] ?? null}
                onApplied={() => {}}
              />
            ) : null}
          </div>
        </div>

        {applyLog.length ? (
          <div className="max-h-28 overflow-auto border-t px-6 py-2 text-[11px] text-muted-foreground">
            {applyLog.map((l) => (
              <p key={l.stepId}>
                {l.title}: {l.status}
                {l.message ? ` — ${l.message}` : ""}
              </p>
            ))}
          </div>
        ) : null}

        <DialogFooter className="border-t px-6 py-4">
          <Button type="button" variant="outline" onClick={() => onOpenChange(false)} disabled={busy}>
            Закрыть
          </Button>
          <Button type="button" onClick={() => void applyAll()} disabled={busy}>
            {busy ? <Loader2 className="mr-2 size-4 animate-spin" /> : null}
            Применить по порядку
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { applyStepPreview } from "@/lib/initial-setup/apply-step";
import { isStepReady, missingDependencyTitles } from "@/lib/initial-setup/flow-order";
import {
  getStepTableConfig,
  type StepTableConfig
} from "@/lib/initial-setup/ref-table-config";
import {
  emptyPreview,
  flattenTerritoryNodes,
  mergePreview,
  previewFromRows,
  profileToPreview
} from "@/lib/initial-setup/profile-to-preview";
import {
  previewHasBlockingErrors,
  updatePreviewCell
} from "@/lib/initial-setup/preview-xlsx";
import { validateRowCells, reindexPreviewRows } from "@/lib/initial-setup/row-validation";
import type { InitialSetupPreviewState, InitialSetupStep } from "@/lib/initial-setup/types";
import { getUserFacingError } from "@/lib/error-utils";
import { STALE } from "@/lib/query-stale";
import { cn } from "@/lib/utils";
import { AlertCircle, CheckCircle2, Loader2, Plus, Trash2 } from "lucide-react";
import Link from "next/link";
import { buttonVariants } from "@/components/ui/button-variants";

type Props = {
  tenantSlug: string;
  step: InitialSetupStep;
  enabled: boolean;
  /** Bog‘liqlik bajarilgan qadamlar (progress + tizim) */
  effectiveDoneIds?: ReadonlySet<string>;
  /** Excel yoki bundle dan kelgan qatorlar — jadvalga yoziladi */
  externalPreview?: InitialSetupPreviewState | null;
  compact?: boolean;
  onApplied?: (message: string) => void;
};

export function InitialSetupStepTable({
  tenantSlug,
  step,
  enabled,
  effectiveDoneIds,
  externalPreview,
  compact,
  onApplied
}: Props) {
  const qc = useQueryClient();
  const config = getStepTableConfig(step.id);
  const [preview, setPreview] = useState<InitialSetupPreviewState | null>(null);
  const [busy, setBusy] = useState(false);
  const [msg, setMsg] = useState<string | null>(null);

  const profileQ = useQuery({
    queryKey: ["settings", "profile", tenantSlug],
    enabled: Boolean(config && (config.mode === "profile" || config.mode === "company-form" || config.stepId === "territory")),
    staleTime: STALE.profile,
    queryFn: async () => {
      const { data } = await api.get<{
        name: string;
        phone: string | null;
        address: string | null;
        references: Record<string, unknown>;
      }>(`/api/${tenantSlug}/settings/profile`);
      return data;
    }
  });

  const readonlyQ = useQuery({
    queryKey: ["initial-setup-readonly", step.id, tenantSlug],
    enabled: Boolean(config?.mode === "readonly-api" && config.readonlyFetchPath),
    staleTime: STALE.list,
    queryFn: async () => {
      const { data } = await api.get(`/api/${tenantSlug}${config!.readonlyFetchPath}`);
      return data;
    }
  });

  const loadedPreview = useMemo(() => {
    if (!config) return null;
    if (config.stepId === "territory") {
      const nodes = profileQ.data?.references?.territory_nodes;
      const rows = flattenTerritoryNodes(nodes);
      return rows.length ? previewFromRows(config, rows) : emptyPreview(config);
    }
    if (config.mode === "readonly-api") {
      const rows: { rowIndex: number; cells: Record<string, string> }[] = [];
      if (config.stepId === "warehouses") {
        const list = (readonlyQ.data as { data?: { name: string; code?: string | null; branch?: { name?: string } }[] })
          ?.data ?? [];
        list.forEach((w, i) => {
          rows.push({
            rowIndex: i + 1,
            cells: { name: w.name, code: w.code ?? "", branch: w.branch?.name ?? "" }
          });
        });
      } else if (config.stepId === "product-categories") {
        const list =
          (readonlyQ.data as { data?: { id: number; name: string; code?: string | null; parent_id?: number | null }[] })
            ?.data ?? [];
        const byId = new Map(list.map((x) => [x.id, x]));
        list.forEach((c, i) => {
          const pid = c.parent_id;
          const parent = pid != null ? byId.get(pid)?.name ?? "" : "";
          rows.push({
            rowIndex: i + 1,
            cells: { name: c.name, code: c.code ?? "", parent }
          });
        });
      }
      return previewFromRows(config, rows);
    }
    if (config.mode === "company-form" || config.mode === "profile") {
      const fromProfile = profileToPreview(
        config,
        profileQ.data?.references,
        profileQ.data
          ? { name: profileQ.data.name, phone: profileQ.data.phone, address: profileQ.data.address }
          : undefined
      );
      return fromProfile ?? emptyPreview(config);
    }
    return emptyPreview(config);
  }, [config, profileQ.data, readonlyQ.data, step.id]);

  useEffect(() => {
    if (!loadedPreview || !config) return;
    const merged = mergePreview(loadedPreview, externalPreview, config);
    setPreview({ ...merged, rows: reindexPreviewRows(merged.rows) });
  }, [loadedPreview, externalPreview, config]);

  const depsOk = useMemo(() => {
    if (!effectiveDoneIds) return true;
    return isStepReady(step, effectiveDoneIds).ok;
  }, [step, effectiveDoneIds]);

  const depsBlockedMsg = useMemo(() => {
    if (!effectiveDoneIds || depsOk) return null;
    return `Сначала выполните: ${missingDependencyTitles(step, effectiveDoneIds).join(" → ")}`;
  }, [step, effectiveDoneIds, depsOk]);

  const canApply = enabled && depsOk;

  const hasErrors = useMemo(() => (preview ? previewHasBlockingErrors(preview) : false), [preview]);

  const columnDefs = useMemo(() => {
    if (!config) return [];
    return preview?.columns.map((header, i) => ({
      header,
      key: config.columns[i]?.key ?? header
    })) ?? config.columns.map((c) => ({ header: c.header, key: c.key }));
  }, [config, preview?.columns]);

  if (!config) {
    return (
      <p className="text-xs text-muted-foreground">
        Vizual jadval mavjud emas.{" "}
        {step.settingsHref ? (
          <Link href={step.settingsHref} className="text-primary underline-offset-4 hover:underline">
            Asosiy sozlamalar
          </Link>
        ) : null}
      </p>
    );
  }

  const readOnly = config.mode === "readonly-api";

  function addRow() {
    if (!preview || readOnly) return;
    const cells: Record<string, string> = {};
    for (const col of config!.columns) cells[col.key] = "";
    const { errors } = validateRowCells(cells, undefined, config!);
    setPreview({
      ...preview,
      rows: [
        ...preview.rows,
        {
          rowIndex: preview.rows.reduce((m, r) => Math.max(m, r.rowIndex), 0) + 1,
          cells,
          errors,
          warnings: []
        }
      ]
    });
  }

  function removeRow(rowIndex: number) {
    if (!preview || readOnly) return;
    setPreview({ ...preview, rows: preview.rows.filter((r) => r.rowIndex !== rowIndex) });
  }

  async function apply() {
    if (!preview?.rows.length || hasErrors || !canApply) return;
    setBusy(true);
    setMsg(null);
    try {
      const message = await applyStepPreview(tenantSlug, step, preview, qc);
      setMsg(message);
      onApplied?.(message);
      await qc.invalidateQueries({ queryKey: ["settings", "profile", tenantSlug] });
    } catch (e) {
      setMsg(getUserFacingError(e, "Saqlash xatosi"));
    } finally {
      setBusy(false);
    }
  }

  const errorCount = preview?.rows.filter((r) => r.errors.length).length ?? 0;
  const loading = profileQ.isLoading || readonlyQ.isLoading;

  return (
    <div className={cn("mt-3 space-y-2", compact && "text-xs")}>
      {loading ? (
        <p className="text-xs text-muted-foreground">Tizimdan yuklanmoqda…</p>
      ) : null}

      {depsBlockedMsg ? (
        <p className="text-xs font-medium text-amber-700">{depsBlockedMsg}</p>
      ) : null}

      {readOnly ? (
        <p className="text-xs text-amber-800/90">
          Tizimdagi ma’lumot (o‘qish). Tahrirlash — asosiy sozlamalar sahifasida; u yerda saqlanganlar shu jadvalda
          ham ko‘rinadi.
          {step.settingsHref ? (
            <>
              {" "}
              <Link href={step.settingsHref} className="font-medium text-primary underline-offset-4 hover:underline">
                Ochish →
              </Link>
            </>
          ) : null}
        </p>
      ) : null}

      {preview && preview.rows.length > 0 ? (
        <>
          <div className="flex flex-wrap gap-2 text-[11px]">
            <span className="inline-flex items-center gap-1 text-emerald-700">
              <CheckCircle2 className="size-3" /> {preview.rows.length - errorCount} OK
            </span>
            {errorCount > 0 ? (
            <div className="w-full space-y-1">
              <span className="inline-flex items-center gap-1 text-destructive">
                <AlertCircle className="size-3" /> {errorCount} xato
              </span>
              {preview.rows
                .filter((r) => r.errors.length)
                .map((r) => (
                  <p key={r.rowIndex} className="text-[11px] text-destructive">
                    Qator {r.rowIndex}: {r.errors.join("; ")}
                  </p>
                ))}
            </div>
          ) : null}
          </div>
          <div className="max-h-64 overflow-auto rounded-lg border">
            <table className="w-full min-w-[480px] border-collapse text-xs">
              <thead>
                <tr className="bg-muted/50">
                  <th className="border-b px-2 py-1.5 text-left font-semibold">#</th>
                  {columnDefs.map((col) => (
                    <th key={col.key} className="border-b px-2 py-1.5 text-left font-semibold">
                      {col.header}
                      {config.columns.find((c) => c.key === col.key)?.required ? (
                        <span className="text-destructive"> *</span>
                      ) : null}
                    </th>
                  ))}
                  <th className="border-b px-2 py-1.5 text-left font-semibold">Статус</th>
                  {!readOnly ? <th className="border-b px-2 py-1.5 w-8" /> : null}
                </tr>
              </thead>
              <tbody>
                {preview.rows.map((row) => (
                  <tr
                    key={row.rowIndex}
                    className={cn(
                      row.errors.length ? "bg-destructive/5" : row.warnings.length ? "bg-amber-50/80" : ""
                    )}
                  >
                    <td className="border-b px-2 py-1 tabular-nums text-muted-foreground">{row.rowIndex}</td>
                    {columnDefs.map((col) => {
                      const isErr = row.errors.some((e) => e.includes(col.header));
                      return (
                        <td key={col.key} className="border-b px-1 py-1">
                          {readOnly ? (
                            <span>{row.cells[col.key] ?? "—"}</span>
                          ) : (
                            <Input
                              className={cn(
                                "h-7 min-w-[5rem] text-xs",
                                isErr && "border-destructive ring-1 ring-destructive/30"
                              )}
                              value={row.cells[col.key] ?? ""}
                              disabled={!enabled}
                              title={isErr ? row.errors.find((e) => e.includes(col.header)) : undefined}
                              onChange={(e) =>
                                setPreview((p) =>
                                  p ? updatePreviewCell(p, row.rowIndex, col.key, e.target.value, config) : p
                                )
                              }
                            />
                          )}
                        </td>
                      );
                    })}
                    <td className="border-b px-2 py-1 text-[11px] text-muted-foreground">
                      {row.errors.length ? (
                        <span className="text-destructive">{row.errors.join("; ")}</span>
                      ) : row.warnings.length ? (
                        row.warnings.join("; ")
                      ) : (
                        <span className="text-emerald-700">OK</span>
                      )}
                    </td>
                    {!readOnly ? (
                      <td className="border-b px-1 py-1">
                        <Button
                          type="button"
                          variant="ghost"
                          size="icon-sm"
                          className="size-7 text-muted-foreground"
                          disabled={!enabled}
                          onClick={() => removeRow(row.rowIndex)}
                        >
                          <Trash2 className="size-3.5" />
                        </Button>
                      </td>
                    ) : null}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      ) : (
        <p className="rounded-md border border-dashed bg-muted/30 px-3 py-4 text-center text-xs text-muted-foreground">
          {readOnly ? "Tizimda hali ma’lumot yo‘q" : "Excel yuklang yoki qator qo‘shing"}
        </p>
      )}

      <div className="flex flex-wrap items-center gap-2">
        {!readOnly ? (
          <>
            <Button type="button" variant="outline" size="sm" className="h-7 gap-1 text-xs" disabled={!enabled} onClick={addRow}>
              <Plus className="size-3.5" />
              Qator
            </Button>
            <Button
              type="button"
              size="sm"
              className="h-7 text-xs"
              disabled={!canApply || busy || hasErrors || !preview?.rows.length}
              onClick={() => void apply()}
            >
              {busy ? <Loader2 className="mr-1 size-3.5 animate-spin" /> : null}
              Qo‘llash (tizimga)
            </Button>
          </>
        ) : step.settingsHref ? (
          <Link
            href={step.settingsHref}
            className={cn(buttonVariants({ variant: "outline", size: "sm" }), "h-7 text-xs")}
          >
            Asosiy sozlamalarda tahrirlash
          </Link>
        ) : null}
      </div>

      {msg ? (
        <p className={cn("text-xs", msg.includes("xato") || msg.includes("Xato") ? "text-destructive" : "text-emerald-700")}>
          {msg}
        </p>
      ) : null}
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { isAxiosError } from "axios";
import { api } from "@/lib/api";
import {
  firstMessagePerField,
  firstValidationUserHint,
  getZodFlattenFromApiErrorBody
} from "@/lib/api-validation-details";
import { getUserFacingError, withApiSupportLine } from "@/lib/error-utils";
import { STALE } from "@/lib/query-stale";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog";
import { cn } from "@/lib/utils";
import { HistoryIcon, Loader2Icon, ScrollTextIcon } from "lucide-react";

export type WebStaffPositionPresetRow = {
  id: string;
  label: string;
  is_active: boolean;
  sort_order: number;
  created_at: string;
  created_by_user_id: number | null;
  created_by_label: string | null;
  deactivated_at: string | null;
  deactivated_by_user_id: number | null;
  deactivated_by_label: string | null;
  /** Saqlangan nom bo‘yicha: veb-panel xodimlari `position` maydoni mos keladiganlar soni */
  linked_operator_count: number;
};

type AuditHistoryRow = {
  id: number;
  action: string;
  payload: unknown;
  actor_user_id: number | null;
  actor_login: string | null;
  created_at: string;
};

type Props = { tenantSlug: string };

type PresetTab = "active" | "inactive";

function invalidateOperatorQueries(qc: ReturnType<typeof useQueryClient>, tenantSlug: string) {
  void qc.invalidateQueries({ queryKey: ["operators", tenantSlug] });
}

function formatDateTime(iso: string | null | undefined): string {
  if (!iso?.trim()) return "—";
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return "—";
  return new Intl.DateTimeFormat("uz-UZ", { dateStyle: "short", timeStyle: "short" }).format(d);
}

function pickZodLeaf(per: Record<string, string>, leaf: string): string | undefined {
  for (const [k, v] of Object.entries(per)) {
    if (k === leaf || k.endsWith(`.${leaf}`)) return v;
  }
  return undefined;
}

function actionLabelUz(action: string): string {
  switch (action) {
    case "create":
      return "Yaratildi";
    case "patch.label":
      return "Nomi o‘zgartirildi";
    case "deactivate":
      return "Nofaollashtirildi";
    case "reactivate":
      return "Faollashtirildi";
    default:
      return action;
  }
}

function payloadSummary(action: string, payload: unknown): string | null {
  if (payload == null || typeof payload !== "object") return null;
  const o = payload as Record<string, unknown>;
  if (action === "patch.label" && typeof o.from === "string" && typeof o.to === "string") {
    return `«${o.from}» → «${o.to}»`;
  }
  if (typeof o.label === "string") {
    return `«${o.label}»`;
  }
  return null;
}

export function WebStaffPositionPresetsWorkspace({ tenantSlug }: Props) {
  const qc = useQueryClient();
  const [presetTab, setPresetTab] = useState<PresetTab>("active");
  const [createOpen, setCreateOpen] = useState(false);
  const [createLabel, setCreateLabel] = useState("");
  const [createServerFieldErrs, setCreateServerFieldErrs] = useState<Record<string, string>>({});
  const [createMsg, setCreateMsg] = useState<string | null>(null);
  const [patchBanner, setPatchBanner] = useState<string | null>(null);
  const [patchLabelErrByPresetId, setPatchLabelErrByPresetId] = useState<Record<string, string>>({});
  const [drafts, setDrafts] = useState<Record<string, string>>({});
  const [historyPresetId, setHistoryPresetId] = useState<string | null>(null);

  const listQ = useQuery({
    queryKey: ["operators", tenantSlug, "position-presets-admin"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    queryFn: async () => {
      const { data } = await api.get<{ data: WebStaffPositionPresetRow[] }>(
        `/api/${tenantSlug}/operators/meta/position-presets`
      );
      return data.data;
    }
  });

  const historyQ = useQuery({
    queryKey: ["operators", tenantSlug, "position-preset-history", historyPresetId],
    enabled: Boolean(tenantSlug) && Boolean(historyPresetId),
    staleTime: STALE.detail,
    queryFn: async () => {
      const { data } = await api.get<{
        data: AuditHistoryRow[];
        total: number;
      }>(`/api/${tenantSlug}/operators/meta/position-presets/history/${historyPresetId}`);
      return data;
    }
  });

  const rows = listQ.data ?? [];
  const activeRows = useMemo(() => rows.filter((r) => r.is_active), [rows]);
  const inactiveRows = useMemo(() => rows.filter((r) => !r.is_active), [rows]);
  const subset = presetTab === "active" ? activeRows : inactiveRows;
  const mode = presetTab === "active" ? "active" : "inactive";

  useEffect(() => {
    const next: Record<string, string> = {};
    for (const r of rows) {
      next[r.id] = r.label;
    }
    setDrafts(next);
  }, [rows]);

  const createMut = useMutation({
    mutationFn: async (label: string) => {
      const { data } = await api.post<{ data: WebStaffPositionPresetRow }>(
        `/api/${tenantSlug}/operators/meta/position-presets`,
        { label }
      );
      return data.data;
    },
    onSuccess: async () => {
      setPresetTab("active");
      await listQ.refetch();
      invalidateOperatorQueries(qc, tenantSlug);
    }
  });

  const patchMut = useMutation({
    mutationFn: async (args: { presetId: string; body: { label?: string; is_active?: boolean } }) => {
      const { data } = await api.patch<{ data: WebStaffPositionPresetRow }>(
        `/api/${tenantSlug}/operators/meta/position-presets/${args.presetId}`,
        args.body
      );
      return data.data;
    },
    onSuccess: async (_, vars) => {
      setPatchBanner(null);
      if (vars.body.label !== undefined) {
        setPatchLabelErrByPresetId((prev) => {
          const next = { ...prev };
          delete next[vars.presetId];
          return next;
        });
      } else {
        setPatchLabelErrByPresetId({});
      }
      await listQ.refetch();
      invalidateOperatorQueries(qc, tenantSlug);
      void qc.invalidateQueries({
        queryKey: ["operators", tenantSlug, "position-preset-history", vars.presetId]
      });
      if (vars.body.is_active === false) setPresetTab("inactive");
      if (vars.body.is_active === true) setPresetTab("active");
    }
  });

  const dirtyById = useMemo(() => {
    const m: Record<string, boolean> = {};
    for (const r of rows) {
      const d = (drafts[r.id] ?? r.label).trim();
      m[r.id] = d !== r.label && d.length > 0;
    }
    return m;
  }, [rows, drafts]);

  function setDraft(id: string, v: string) {
    setDrafts((prev) => ({ ...prev, [id]: v }));
  }

  function submitCreate() {
    void (async () => {
      setCreateServerFieldErrs({});
      setCreateMsg(null);
      const t = createLabel.trim();
      if (!t) return;
      try {
        await createMut.mutateAsync(t);
        setCreateServerFieldErrs({});
        setCreateMsg(null);
        setCreateOpen(false);
        setCreateLabel("");
      } catch (e: unknown) {
        if (isAxiosError(e)) {
          const flat = getZodFlattenFromApiErrorBody(e.response?.data);
          if (flat) {
            const per = firstMessagePerField(flat);
            setCreateServerFieldErrs(per);
            const top = flat.formErrors.map((s) => s.trim()).find(Boolean);
            const hint = firstValidationUserHint(flat);
            const line = top ?? hint ?? Object.values(per).find((m) => m.trim() !== "");
            setCreateMsg(line ? withApiSupportLine(line, e) : getUserFacingError(e, "Yaratishda xatolik."));
            return;
          }
          setCreateServerFieldErrs({});
        } else {
          setCreateServerFieldErrs({});
        }
        setCreateMsg(getUserFacingError(e, "Yaratishda xatolik."));
      }
    })();
  }

  useEffect(() => {
    if (!createOpen) return;
    setCreateServerFieldErrs({});
    setCreateMsg(null);
  }, [createOpen]);

  const historyTitleRow = rows.find((r) => r.id === historyPresetId);

  const emptyMsg =
    mode === "active"
      ? "Faol lavozim yo‘q — «Yangi lavozim» bilan qo‘shing."
      : "Nofaol lavozim yo‘q.";

  const colCount = 8;

  return (
    <div className="space-y-4">
      {/* Huddi `agents-workspace`: ixcham pastki chiziqli yorliqlar + qo‘shish o‘ngda */}
      <div className="flex flex-wrap items-center justify-between gap-2">
        <div className="flex gap-2 border-b border-border" role="tablist" aria-label="Lavozimlar holati">
          <button
            type="button"
            role="tab"
            id="tab-preset-active"
            aria-selected={presetTab === "active"}
            className={cn(
              "-mb-px border-b-2 px-3 py-2 text-sm font-medium",
              presetTab === "active"
                ? "border-primary text-primary"
                : "border-transparent text-muted-foreground hover:text-foreground"
            )}
            onClick={() => setPresetTab("active")}
          >
            Faol{activeRows.length ? ` (${activeRows.length})` : ""}
          </button>
          <button
            type="button"
            role="tab"
            id="tab-preset-inactive"
            aria-selected={presetTab === "inactive"}
            className={cn(
              "-mb-px border-b-2 px-3 py-2 text-sm font-medium",
              presetTab === "inactive"
                ? "border-primary text-primary"
                : "border-transparent text-muted-foreground hover:text-foreground"
            )}
            onClick={() => setPresetTab("inactive")}
          >
            Nofaol{inactiveRows.length ? ` (${inactiveRows.length})` : ""}
          </button>
        </div>
        <Button type="button" size="sm" onClick={() => setCreateOpen(true)}>
          Yangi lavozim
        </Button>
      </div>

      {patchBanner ? <p className="text-sm text-destructive">{patchBanner}</p> : null}

      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Yangi lavozim</DialogTitle>
            <DialogDescription>
              Har bir lavozim alohida yaratiladi. Ro‘yxat veb xodimlar sahifasida tanlov sifatida ishlatiladi.
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-2">
            {createMsg ? <p className="text-sm text-destructive">{createMsg}</p> : null}
            <label className="text-xs font-medium text-muted-foreground" htmlFor="preset-create-label">
              Lavozim nomi
            </label>
            <Input
              id="preset-create-label"
              value={createLabel}
              placeholder="Masalan: Kassir"
              onChange={(e) => setCreateLabel(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") {
                  e.preventDefault();
                  submitCreate();
                }
              }}
            />
            {pickZodLeaf(createServerFieldErrs, "label") ? (
              <p className="text-xs text-destructive">{pickZodLeaf(createServerFieldErrs, "label")}</p>
            ) : null}
          </div>
          <DialogFooter className="border-0 bg-transparent p-0 sm:justify-end">
            <Button type="button" variant="outline" onClick={() => setCreateOpen(false)}>
              Bekor qilish
            </Button>
            <Button
              type="button"
              disabled={!createLabel.trim() || createMut.isPending}
              onClick={submitCreate}
            >
              {createMut.isPending ? "Yaratilmoqda…" : "Yaratish"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <div className="overflow-hidden rounded-xl border border-border/80 bg-card shadow-sm">
        <div
          className="overflow-x-auto"
          role="tabpanel"
          id={presetTab === "active" ? "panel-preset-active" : "panel-preset-inactive"}
          aria-labelledby={presetTab === "active" ? "tab-preset-active" : "tab-preset-inactive"}
        >
          <table className="w-full min-w-[880px] table-fixed text-sm">
            <thead className="app-table-thead text-left text-xs">
              <tr>
                <th className="w-9 px-1.5 py-2.5">№</th>
                <th className="w-[200px] max-w-[200px] px-2 py-2.5">Lavozim nomi</th>
                <th
                  className="w-[52px] px-1 py-2.5 text-center"
                  title="Veb xodimlar kartasidagi «Lavozim» maydoni saqlangan shablon nomi bilan mos keladigan akkauntlar soni"
                >
                  Bog‘langan
                </th>
                {mode === "active" ? (
                  <>
                    <th className="w-[128px] whitespace-nowrap px-2 py-2.5">Yaratilgan</th>
                    <th className="w-[120px] px-2 py-2.5">Kim yaratgan</th>
                  </>
                ) : (
                  <>
                    <th className="w-[128px] whitespace-nowrap px-2 py-2.5">Nofaollashtirilgan</th>
                    <th className="w-[120px] px-2 py-2.5">Kim nofaollashtirgan</th>
                  </>
                )}
                <th
                  className="w-11 px-1 py-2.5 text-center"
                  title="Tarix"
                >
                  <span className="sr-only">Tarix</span>
                  <HistoryIcon className="mx-auto size-3.5 opacity-70" aria-hidden />
                </th>
                <th className="w-[76px] px-1 py-2.5 text-center">Saqlash</th>
                <th className="w-[132px] px-1 py-2.5 text-center">
                  {mode === "active" ? (
                    <span title="Nofaollashtirish">Nofaol</span>
                  ) : (
                    <span title="Faollashtirish">Faol qilish</span>
                  )}
                </th>
              </tr>
            </thead>
            <tbody>
              {listQ.isLoading ? (
                <tr>
                  <td colSpan={colCount} className="px-4 py-10 text-center text-muted-foreground">
                    Загрузка…
                  </td>
                </tr>
              ) : subset.length === 0 ? (
                <tr>
                  <td colSpan={colCount} className="px-4 py-10 text-center text-muted-foreground">
                    {emptyMsg}
                  </td>
                </tr>
              ) : (
                subset.map((r, i) => (
                  <tr key={r.id} className="border-t border-border/50 transition-colors hover:bg-muted/25">
                    <td className="px-1.5 py-2 tabular-nums text-muted-foreground">{i + 1}</td>
                    <td className="w-[200px] max-w-[200px] px-2 py-2">
                      <div>
                        <Input
                          className="h-9 w-full max-w-[184px]"
                          value={drafts[r.id] ?? r.label}
                          placeholder="Lavozim nomi"
                          disabled={patchMut.isPending}
                          onChange={(e) => {
                            setPatchBanner(null);
                            setPatchLabelErrByPresetId((prev) => {
                              if (!prev[r.id]) return prev;
                              const next = { ...prev };
                              delete next[r.id];
                              return next;
                            });
                            setDraft(r.id, e.target.value);
                          }}
                        />
                        {patchLabelErrByPresetId[r.id] ? (
                          <p className="mt-0.5 max-w-[184px] text-xs text-destructive">{patchLabelErrByPresetId[r.id]}</p>
                        ) : null}
                      </div>
                    </td>
                    <td
                      className="px-1 py-2 text-center align-middle tabular-nums text-sm font-medium text-foreground"
                      title={
                        dirtyById[r.id]
                          ? "Hisob saqlangan lavozim nomi bo‘yicha; yangi nomni saqlagach yangilanadi"
                          : "Veb xodimlar «Lavozim» maydoni shu nom bilan mos keladigan akkauntlar"
                      }
                    >
                      {r.linked_operator_count ?? 0}
                    </td>
                    {mode === "active" ? (
                      <>
                        <td className="whitespace-nowrap px-2 py-2 text-xs text-muted-foreground">
                          {formatDateTime(r.created_at)}
                        </td>
                        <td className="truncate px-2 py-2 text-xs" title={r.created_by_label ?? undefined}>
                          {r.created_by_label ?? "—"}
                        </td>
                      </>
                    ) : (
                      <>
                        <td className="whitespace-nowrap px-2 py-2 text-xs text-muted-foreground">
                          {formatDateTime(r.deactivated_at)}
                        </td>
                        <td
                          className="truncate px-2 py-2 text-xs"
                          title={r.deactivated_by_label ?? undefined}
                        >
                          {r.deactivated_by_label ?? "—"}
                        </td>
                      </>
                    )}
                    <td className="px-1 py-2 text-center align-middle">
                      <Button
                        type="button"
                        size="icon-sm"
                        variant="ghost"
                        className="size-8 text-muted-foreground hover:text-foreground"
                        title="Tarix"
                        onClick={() => setHistoryPresetId(r.id)}
                      >
                        <HistoryIcon className="size-4" />
                        <span className="sr-only">Tarix</span>
                      </Button>
                    </td>
                    <td className="px-1 py-2 text-center align-middle">
                      <Button
                        type="button"
                        size="sm"
                        variant="secondary"
                        className="h-8 min-w-[4.5rem] px-2 text-xs"
                        disabled={!dirtyById[r.id] || patchMut.isPending}
                        onClick={() => {
                          void (async () => {
                            const t = (drafts[r.id] ?? r.label).trim();
                            if (!t) return;
                            setPatchBanner(null);
                            setPatchLabelErrByPresetId((prev) => {
                              const next = { ...prev };
                              delete next[r.id];
                              return next;
                            });
                            try {
                              await patchMut.mutateAsync({ presetId: r.id, body: { label: t } });
                              setPatchBanner(null);
                            } catch (e: unknown) {
                              if (isAxiosError(e)) {
                                const flat = getZodFlattenFromApiErrorBody(e.response?.data);
                                if (flat) {
                                  const per = firstMessagePerField(flat);
                                  const leaf = pickZodLeaf(per, "label");
                                  const top = flat.formErrors.map((s) => s.trim()).find(Boolean);
                                  const hint = firstValidationUserHint(flat);
                                  const line = top ?? hint ?? Object.values(per).find((m) => m.trim() !== "");
                                  if (leaf) {
                                    setPatchLabelErrByPresetId((prev) => ({ ...prev, [r.id]: leaf }));
                                  }
                                  setPatchBanner(
                                    line ? withApiSupportLine(line, e) : getUserFacingError(e, "Saqlashda xatolik.")
                                  );
                                  return;
                                }
                              }
                              setPatchBanner(getUserFacingError(e, "Saqlashda xatolik."));
                            }
                          })();
                        }}
                      >
                        Saqlash
                      </Button>
                    </td>
                    <td className="px-1 py-2 text-center align-middle">
                      {mode === "active" ? (
                        <Button
                          type="button"
                          size="sm"
                          variant="outline"
                          className="h-8 w-full min-w-0 px-2 text-xs whitespace-normal leading-snug"
                          disabled={patchMut.isPending}
                          onClick={() => {
                            void (async () => {
                              setPatchBanner(null);
                              setPatchLabelErrByPresetId({});
                              try {
                                await patchMut.mutateAsync({ presetId: r.id, body: { is_active: false } });
                              } catch (e: unknown) {
                                if (isAxiosError(e)) {
                                  const flat = getZodFlattenFromApiErrorBody(e.response?.data);
                                  if (flat) {
                                    const per = firstMessagePerField(flat);
                                    const top = flat.formErrors.map((s) => s.trim()).find(Boolean);
                                    const hint = firstValidationUserHint(flat);
                                    const line = top ?? hint ?? Object.values(per).find((m) => m.trim() !== "");
                                    setPatchBanner(line ? withApiSupportLine(line, e) : getUserFacingError(e, "Xatolik."));
                                    return;
                                  }
                                }
                                setPatchBanner(getUserFacingError(e, "Xatolik."));
                              }
                            })();
                          }}
                        >
                          Nofaollashtirish
                        </Button>
                      ) : (
                        <Button
                          type="button"
                          size="sm"
                          variant="outline"
                          className="h-8 w-full min-w-0 px-2 text-xs"
                          disabled={patchMut.isPending}
                          onClick={() => {
                            void (async () => {
                              setPatchBanner(null);
                              setPatchLabelErrByPresetId({});
                              try {
                                await patchMut.mutateAsync({ presetId: r.id, body: { is_active: true } });
                              } catch (e: unknown) {
                                if (isAxiosError(e)) {
                                  const flat = getZodFlattenFromApiErrorBody(e.response?.data);
                                  if (flat) {
                                    const per = firstMessagePerField(flat);
                                    const top = flat.formErrors.map((s) => s.trim()).find(Boolean);
                                    const hint = firstValidationUserHint(flat);
                                    const line = top ?? hint ?? Object.values(per).find((m) => m.trim() !== "");
                                    setPatchBanner(line ? withApiSupportLine(line, e) : getUserFacingError(e, "Xatolik."));
                                    return;
                                  }
                                }
                                setPatchBanner(getUserFacingError(e, "Xatolik."));
                              }
                            })();
                          }}
                        >
                          Faollashtirish
                        </Button>
                      )}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      <p className="text-xs text-muted-foreground">
        <span className="font-medium text-foreground">Qayerda ishlatiladi:</span> faol shablonlar{" "}
        <span className="whitespace-nowrap">«Veb xodimlar»</span> jadvalidagi lavozim filtri hamda xodim yaratish va
        tahrirlash oynalaridagi kiritish maydonining takliflari (datalist) orqali beriladi — backend bularni bitta
        ro‘yxatda birlashtiradi (<code className="text-foreground">filter-options</code> →{" "}
        <code className="text-foreground">positions</code>). «Bog‘langan» ustuni — veb xodimlar profilidagi lavozim
        matni shu shablon nomi bilan to‘liq mos (trim) keladigan akkauntlar soni. Nofaol shablonlar tanlovlarda
        chiqmaydi.
        «Nofaollashtirish» yozuvni o‘chirmaydi; JWT <code className="text-foreground">operator</code> rolini
        o‘zgartirmaydi.
      </p>

      <Dialog
        open={historyPresetId != null}
        onOpenChange={(open) => {
          if (!open) setHistoryPresetId(null);
        }}
      >
        <DialogContent className="gap-0 overflow-hidden p-0 sm:max-w-[420px]">
          <div className="flex items-start gap-3 border-b border-border/70 bg-gradient-to-b from-muted/50 to-transparent px-4 py-3.5">
            <div
              className="flex size-10 shrink-0 items-center justify-center rounded-xl bg-primary/12 text-primary shadow-inner ring-1 ring-primary/15"
              aria-hidden
            >
              <HistoryIcon className="size-[18px]" strokeWidth={2} />
            </div>
            <div className="min-w-0 flex-1 space-y-1">
              <DialogTitle className="text-left text-base font-semibold leading-tight">
                Lavozim tarixi
              </DialogTitle>
              <DialogDescription className="text-left text-xs leading-snug text-muted-foreground">
                {historyTitleRow ? (
                  <>
                    <span className="font-medium text-foreground">{historyTitleRow.label}</span>
                    <span className="text-muted-foreground"> — audit bo‘yicha o‘zgarishlar zanjiri</span>
                  </>
                ) : (
                  "Загрузка…"
                )}
              </DialogDescription>
            </div>
          </div>

          <div className="max-h-[min(52vh,300px)] overflow-y-auto px-4 py-4">
            {historyQ.isLoading ? (
              <div className="flex flex-col items-center justify-center gap-2 py-10 text-muted-foreground">
                <Loader2Icon className="size-8 animate-spin opacity-50" aria-hidden />
                <p className="text-xs">Загрузка…</p>
              </div>
            ) : historyQ.isError ? (
              <div className="rounded-lg border border-destructive/25 bg-destructive/5 px-3 py-3 text-center text-xs text-destructive">
                Tarixni yuklab bo‘lmadi. Internet yoki serverni tekshirib, yana «Tarix» ni bosing.
              </div>
            ) : !historyQ.data?.data.length ? (
              <div className="flex flex-col items-center justify-center gap-3 rounded-xl border border-dashed border-border/80 bg-muted/15 px-4 py-10 text-center">
                <ScrollTextIcon className="size-11 text-muted-foreground/35" strokeWidth={1.25} aria-hidden />
                <div className="space-y-1">
                  <p className="text-sm font-medium text-foreground">Hozircha yozuv yo‘q</p>
                  <p className="mx-auto max-w-[280px] text-xs leading-relaxed text-muted-foreground">
                    Yangi shablon yoki audit yoqilguncha bo‘sh. Keyingi yaratish, nom o‘zgartirish va
                    nofaollashtirish shu yerda paydo bo‘ladi.
                  </p>
                </div>
              </div>
            ) : (
              <ul className="relative space-y-0 text-sm before:absolute before:top-2 before:bottom-2 before:left-[6px] before:w-px before:bg-border/90">
                {[...historyQ.data.data].reverse().map((ev) => {
                  const extra = payloadSummary(ev.action, ev.payload);
                  return (
                    <li key={ev.id} className="relative pb-5 pl-6 last:pb-0">
                      <span
                        className="absolute top-1.5 left-0 size-2 rounded-full bg-primary shadow-[0_0_0_3px_var(--background)] ring-1 ring-primary/30"
                        aria-hidden
                      />
                      <div className="font-medium leading-snug text-foreground">{actionLabelUz(ev.action)}</div>
                      <div className="mt-1 text-xs text-muted-foreground">
                        {formatDateTime(ev.created_at)}
                        {ev.actor_login ? (
                          <span className="text-foreground/80"> · {ev.actor_login}</span>
                        ) : ev.actor_user_id ? (
                          <span> · ID {ev.actor_user_id}</span>
                        ) : null}
                      </div>
                      {extra ? (
                        <p className="mt-1.5 rounded-md bg-muted/50 px-2 py-1.5 text-[11px] leading-relaxed text-muted-foreground">
                          {extra}
                        </p>
                      ) : null}
                    </li>
                  );
                })}
              </ul>
            )}
          </div>

          <DialogFooter className="border-t border-border/70 bg-muted/25 px-4 py-3 sm:justify-end">
            <Button type="button" variant="secondary" size="sm" onClick={() => setHistoryPresetId(null)}>
              Yopish
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

﻿"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { api } from "@/lib/api";
import { messageFromAgentsBulkError, sanitizeMobileConfigPatch } from "@/lib/agents-bulk-errors";
import { formatApkVersion, formatDeviceName } from "@/lib/mobile-device-display";
import { STALE } from "@/lib/query-stale";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog";
import { cn } from "@/lib/utils";
import {
  Building2,
  Calendar,
  CheckCircle2,
  ChevronDown,
  ChevronRight,
  FileSpreadsheet,
  Filter,
  ListOrdered,
  MapPin,
  MoreHorizontal,
  Pencil,
  Plus,
  RefreshCw,
  Search,
  Settings as SettingsIcon,
  SlidersHorizontal,
  Smartphone,
  UserX,
  Users as UsersIcon,
  XCircle
} from "lucide-react";
import { AgentFormModal } from "@/components/staff/agent-form-modal";
import {
  AgentFilterSelect,
  AgentIconButton,
  AgentTabButton,
  formatAgentCreatedDate,
  formatAgentDateTime,
  parseAgentFio
} from "@/components/staff/agent-workspace-template-ui";
import { TableColumnSettingsDialog } from "@/components/data-table/table-column-settings-dialog";
import { useUserTablePrefs } from "@/hooks/use-user-table-prefs";
import { StaffActiveSessionsDialog } from "@/components/staff/staff-active-sessions-dialog";
import { downloadXlsxSheet } from "@/lib/download-xlsx";
import { FilterSelect } from "@/components/ui/filter-select";
import { SearchableMultiSelectPanel } from "@/components/ui/searchable-multi-select-panel";
import { AgentConfigurationsDialog } from "@/components/staff/agent-configurations-dialog";
import { SlotBadge } from "@/components/work-slots/slot-badge";
import { TableSearchField } from "@/components/ui/table-search-field";
import { DEFAULT_TABLE_PAGE_SIZES } from "@/lib/table-page-sizes";

export type AgentRow = {
  id: number;
  fio: string;
  product: string | null;
  agent_type: string | null;
  code: string | null;
  pinfl: string | null;
  consignment: boolean;
  consignment_limit_amount?: string | null;
  consignment_ignore_previous_months_debt?: boolean;
  consignment_updated_at?: string | null;
  apk_version: string | null;
  device_name: string | null;
  last_sync_at: string | null;
  phone: string | null;
  email: string | null;
  can_authorize: boolean;
  price_type: string | null;
  price_types: string[];
  warehouse: string | null;
  trade_direction_id: number | null;
  trade_direction: string | null;
  branch: string | null;
  position: string | null;
  created_at: string;
  app_access: boolean;
  territory: string | null;
  login: string;
  is_active: boolean;
  max_sessions: number;
  active_session_count: number;
  kpi_color: string | null;
  agent_entitlements: {
    price_types?: string[];
    product_rules?: Array<{ category_id: number; all: boolean; product_ids?: number[] }>;
    mobile_config?: unknown;
  };
  work_slot_id?: number | null;
  work_slot_code?: string | null;
};

type ProductCategoryRow = {
  id: number;
  name: string;
  parent_id: number | null;
  is_active: boolean;
};

type ProductListItem = {
  id: number;
  name: string;
  sku: string;
  category_id: number | null;
};

type TenantProfile = {
  references: {
    branches?: Array<{ id: string; name: string; active?: boolean }>;
    trade_directions?: string[];
    payment_method_entries?: Array<{
      id: string;
      name: string;
      code?: string | null;
      active?: boolean;
    }>;
  };
};

const COLS = [
  "Ф.И.О",
  "Продукт",
  "Тип агента",
  "Код",
  "ПИНФЛ",
  "Консигнация",
  "Версия APK",
  "Название устройства",
  "Последняя синхронизация",
  "Телефон",
  "Авторизоваться",
  "Тип цены",
  "Склад",
  "Направление торговли",
  "Филиал",
  "Должность",
  "Дата создания",
  "Доступ к приложение",
  "Количество активных сессий",
  "Максимальное количество сессий"
] as const;

const AGENT_TABLE_ID = "staff.agents.v1";

const AGENT_COLUMN_IDS = [
  "fio",
  "product",
  "agent_type",
  "code",
  "pinfl",
  "consignment",
  "apk_version",
  "device_name",
  "last_sync",
  "phone",
  "login",
  "price_types",
  "warehouse",
  "trade_direction",
  "branch",
  "position",
  "created_at",
  "app_access",
  "active_sessions",
  "max_sessions"
] as const;

const AGENT_COLUMNS = AGENT_COLUMN_IDS.map((id, i) => ({
  id,
  label: COLS[i] ?? id
}));
const AGENT_COLUMN_LABEL_BY_ID = new Map<string, string>(AGENT_COLUMNS.map((c) => [c.id, c.label]));

function agentExportCellString(r: AgentRow, colId: string): string {
  switch (colId) {
    case "fio":
      return r.fio;
    case "product":
      return r.product ?? "";
    case "agent_type":
      return r.agent_type ?? "";
    case "code":
      return r.code ?? "";
    case "pinfl":
      return r.pinfl ?? "";
    case "consignment":
      return r.consignment ? "Да" : "Нет";
    case "apk_version":
      return r.apk_version ?? "";
    case "device_name":
      return r.device_name ?? "";
    case "last_sync":
      return r.last_sync_at ? new Date(r.last_sync_at).toLocaleString("ru-RU") : "";
    case "phone":
      return r.phone ?? "";
    case "login":
      return r.login;
    case "price_types":
      return (r.price_types?.length ? r.price_types : r.price_type ? [r.price_type] : []).join(", ");
    case "warehouse":
      return r.warehouse ?? "";
    case "trade_direction":
      return r.trade_direction ?? "";
    case "branch":
      return r.branch ?? "";
    case "position":
      return r.position ?? "";
    case "created_at":
      return new Date(r.created_at).toLocaleDateString("ru-RU");
    case "app_access":
      return r.app_access ? "Да" : "Нет";
    case "active_sessions":
      return String(r.active_session_count);
    case "max_sessions":
      return String(r.max_sessions);
    default:
      return "";
  }
}

type Props = { tenantSlug: string };

function buildAgentSearchHaystack(r: AgentRow): string {
  return [
    r.fio,
    r.login,
    r.phone ?? "",
    r.code ?? "",
    r.pinfl ?? "",
    r.device_name ?? "",
    r.apk_version ?? "",
    r.branch ?? "",
    r.warehouse ?? "",
    r.agent_type ?? "",
    ...(r.price_types ?? [])
  ]
    .join(" ")
    .toLowerCase();
}

export function AgentsWorkspace({ tenantSlug }: Props) {
  const qc = useQueryClient();
  const [tab, setTab] = useState<"active" | "inactive">("active");
  const [draftBranch, setDraftBranch] = useState("");
  const [draftTd, setDraftTd] = useState("");
  const [draftPos, setDraftPos] = useState("");
  const [appliedBranch, setAppliedBranch] = useState("");
  const [appliedTd, setAppliedTd] = useState("");
  const [appliedPos, setAppliedPos] = useState("");
  const [search, setSearch] = useState("");
  const [columnDialogOpen, setColumnDialogOpen] = useState(false);

  const tablePrefs = useUserTablePrefs({
    tenantSlug,
    tableId: AGENT_TABLE_ID,
    defaultColumnOrder: [...AGENT_COLUMN_IDS],
    defaultPageSize: 10,
    allowedPageSizes: DEFAULT_TABLE_PAGE_SIZES
  });
  const pageSize = tablePrefs.pageSize;
  const [page, setPage] = useState(1);

  const [addOpen, setAddOpen] = useState(false);
  const [infoRow, setInfoRow] = useState<AgentRow | null>(null);
  const [editRow, setEditRow] = useState<AgentRow | null>(null);
  const [sessionAgent, setSessionAgent] = useState<AgentRow | null>(null);
  const [restrictAgent, setRestrictAgent] = useState<AgentRow | null>(null);
  const [configAgent, setConfigAgent] = useState<AgentRow | null>(null);
  const [deactivateAgent, setDeactivateAgent] = useState<AgentRow | null>(null);
  const [selectedIds, setSelectedIds] = useState<Set<number>>(() => new Set());
  const headerCbRef = useRef<HTMLInputElement>(null);
  const bulkMenuRef = useRef<HTMLDivElement>(null);
  const groupDialogRef = useRef<
    | null
    | "restrict"
    | "products"
    | "trade"
    | "consignment"
    | "sessions"
    | "limits"
    | "app_access"
    | "config"
  >(null);
  const [bulkMenuOpen, setBulkMenuOpen] = useState(false);
  const [groupDialog, setGroupDialog] = useState<
    | null
    | "restrict"
    | "products"
    | "trade"
    | "consignment"
    | "sessions"
    | "limits"
    | "app_access"
    | "config"
  >(null);

  useEffect(() => {
    groupDialogRef.current = groupDialog;
  }, [groupDialog]);

  const filterOptQ = useQuery({
    queryKey: ["agents-filter-options", tenantSlug],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{
        data: {
          branches: string[];
          trade_directions: string[];
          positions: string[];
          territories?: string[];
          territory_tokens?: string[];
        };
      }>(`/api/${tenantSlug}/agents/filter-options`);
      return data.data;
    }
  });

  const profileQ = useQuery({
    queryKey: ["settings", "profile", tenantSlug, "agents-workspace"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.profile,
    queryFn: async () => {
      const { data } = await api.get<TenantProfile>(`/api/${tenantSlug}/settings/profile`);
      return data;
    }
  });

  const branchOptions = useMemo(() => {
    const fromAgents = filterOptQ.data?.branches ?? [];
    const fromProfile = (profileQ.data?.references.branches ?? [])
      .filter((b) => b.active !== false)
      .map((b) => b.name.trim())
      .filter(Boolean);
    return Array.from(new Set([...fromProfile, ...fromAgents])).sort((a, b) => a.localeCompare(b, "ru"));
  }, [filterOptQ.data, profileQ.data]);

  const listQ = useQuery({
    queryKey: ["agent", tenantSlug, tab, appliedBranch, appliedTd, appliedPos],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    queryFn: async () => {
      const params = new URLSearchParams();
      params.set("is_active", tab === "active" ? "true" : "false");
      if (appliedBranch.trim()) params.set("branch", appliedBranch.trim());
      if (appliedTd.trim()) params.set("trade_direction", appliedTd.trim());
      if (appliedPos.trim()) params.set("position", appliedPos.trim());
      const { data } = await api.get<{ data: AgentRow[] }>(
        `/api/${tenantSlug}/agents?${params.toString()}`
      );
      return data.data;
    }
  });

  const warehousesQ = useQuery({
    queryKey: ["warehouses", tenantSlug, "agents-ws"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: { id: number; name: string }[] }>(
        `/api/${tenantSlug}/warehouses`
      );
      return data.data;
    }
  });

  const priceTypesQ = useQuery({
    queryKey: ["price-types", tenantSlug, "agents-ws"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: string[] }>(`/api/${tenantSlug}/price-types?kind=sale`);
      return data.data;
    }
  });

  const tradeDirectionsQ = useQuery({
    queryKey: ["trade-directions", tenantSlug, "agents-ws"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{
        data: Array<{ id: number; name: string; code: string | null; is_active: boolean }>;
      }>(`/api/${tenantSlug}/trade-directions?is_active=true`);
      return data.data;
    }
  });

  const tradeDirectionRows = useMemo(() => tradeDirectionsQ.data ?? [], [tradeDirectionsQ.data]);

  const categoriesQ = useQuery({
    queryKey: ["product-categories", tenantSlug, "agents-ws"],
    enabled:
      Boolean(tenantSlug) &&
      (Boolean(restrictAgent) || groupDialog === "restrict" || groupDialog === "products"),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: ProductCategoryRow[] }>(
        `/api/${tenantSlug}/product-categories`
      );
      return data.data.filter((c) => c.is_active);
    }
  });

  const patchMut = useMutation({
    mutationFn: async (vars: { id: number; body: Record<string, unknown> }) => {
      const { data } = await api.patch<AgentRow>(`/api/${tenantSlug}/agents/${vars.id}`, vars.body);
      return data;
    },
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: ["agent", tenantSlug] });
      void qc.invalidateQueries({ queryKey: ["agents-filter-options", tenantSlug] });
    }
  });

  const createMut = useMutation({
    mutationFn: async (body: Record<string, unknown>) => {
      const { data } = await api.post<AgentRow>(`/api/${tenantSlug}/agents`, body);
      return data;
    },
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: ["agent", tenantSlug] });
      void qc.invalidateQueries({ queryKey: ["agents-filter-options", tenantSlug] });
      setAddOpen(false);
    }
  });

  const deactivateMut = useMutation({
    mutationFn: async (id: number) => {
      await api.patch(`/api/${tenantSlug}/agents/${id}`, { is_active: false });
    },
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: ["agent", tenantSlug] });
      setDeactivateAgent(null);
    }
  });

  const bulkMut = useMutation({
    mutationFn: async (body: Record<string, unknown>) => {
      const { data } = await api.post<{ data: { updated: number } }>(`/api/${tenantSlug}/agents/bulk`, body);
      return data.data;
    },
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: ["agent", tenantSlug] });
      void qc.invalidateQueries({ queryKey: ["agents-filter-options", tenantSlug] });
      setGroupDialog(null);
      setBulkMenuOpen(false);
      setSelectedIds(new Set());
    },
    onError: (e: unknown) => {
      if (groupDialogRef.current === "config") return;
      window.alert(messageFromAgentsBulkError(e));
    }
  });

  useEffect(() => {
    if (!bulkMenuOpen) return;
    const onDoc = (e: MouseEvent) => {
      const el = bulkMenuRef.current;
      if (el && !el.contains(e.target as Node)) setBulkMenuOpen(false);
    };
    document.addEventListener("mousedown", onDoc);
    return () => document.removeEventListener("mousedown", onDoc);
  }, [bulkMenuOpen]);

  const rowsWithHaystack = useMemo(
    () => (listQ.data ?? []).map((r) => ({ r, haystack: buildAgentSearchHaystack(r) })),
    [listQ.data]
  );

  const filteredRows = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return listQ.data ?? [];
    return rowsWithHaystack.filter((x) => x.haystack.includes(q)).map((x) => x.r);
  }, [listQ.data, rowsWithHaystack, search]);

  const totalPages = Math.max(1, Math.ceil(filteredRows.length / pageSize));

  const pageRows = useMemo(() => {
    const start = (page - 1) * pageSize;
    return filteredRows.slice(start, start + pageSize);
  }, [filteredRows, pageSize, page]);

  useEffect(() => {
    setPage(1);
  }, [tab, search, appliedBranch, appliedTd, appliedPos, pageSize]);

  const selectedRows = useMemo(
    () => filteredRows.filter((r) => selectedIds.has(r.id)),
    [filteredRows, selectedIds]
  );

  useEffect(() => {
    setSelectedIds(new Set());
  }, [tab]);

  const allOnPageSelected = pageRows.length > 0 && pageRows.every((r) => selectedIds.has(r.id));
  const someOnPageSelected = pageRows.some((r) => selectedIds.has(r.id));
  useEffect(() => {
    const el = headerCbRef.current;
    if (!el) return;
    el.indeterminate = someOnPageSelected && !allOnPageSelected;
  }, [someOnPageSelected, allOnPageSelected]);

  const toggleAgentSelection = (id: number, checked: boolean) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (checked) next.add(id);
      else next.delete(id);
      return next;
    });
  };

  const toggleAllAgentsOnPage = (checked: boolean) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (checked) {
        for (const r of pageRows) next.add(r.id);
      } else {
        for (const r of pageRows) next.delete(r.id);
      }
      return next;
    });
  };

  const applyFilters = () => {
    setAppliedBranch(draftBranch);
    setAppliedTd(draftTd);
    setAppliedPos(draftPos);
  };

  const resetFilters = () => {
    setDraftBranch("");
    setDraftTd("");
    setDraftPos("");
    setAppliedBranch("");
    setAppliedTd("");
    setAppliedPos("");
  };

  function renderAgentFioCell(r: AgentRow) {
    const { last, first, middle } = parseAgentFio(r.fio);
    const kpiColor = r.kpi_color || "#64748b";
    return (
      <div className="flex items-center gap-3">
        <div
          className="grid h-9 w-9 shrink-0 place-items-center rounded-full text-xs font-bold text-white"
          style={{ backgroundColor: kpiColor }}
        >
          {(first[0] ?? "") + (last[0] ?? "")}
        </div>
        <div className="min-w-0">
          <p className="truncate font-medium text-slate-900">
            {String(r.id).padStart(2, "0")} ({first || r.fio})
          </p>
          <p className="truncate text-xs text-slate-500">
            {r.code ?? "—"} - [{last}] {middle ? `(${middle})` : ""}
          </p>
        </div>
      </div>
    );
  }

  function renderAgentDataCell(colId: string, r: AgentRow) {
    const priceList = r.price_types?.length ? r.price_types : r.price_type ? [r.price_type] : [];
    switch (colId) {
      case "fio":
        return renderAgentFioCell(r);
      case "product":
        return <span className="text-slate-700">{r.product ?? "—"}</span>;
      case "agent_type":
        return <span className="text-slate-700">{r.agent_type ?? "—"}</span>;
      case "code":
        return (
          <div className="flex flex-col gap-0.5">
            <span className="font-mono text-xs text-slate-900">{r.code ?? "—"}</span>
            {r.work_slot_code ? <SlotBadge code={r.work_slot_code} /> : null}
          </div>
        );
      case "pinfl":
        return <span className="font-mono text-xs text-slate-600">{r.pinfl ?? "—"}</span>;
      case "consignment":
        return r.consignment ? (
          <span className="inline-flex items-center gap-1 rounded-full bg-emerald-50 px-2 py-0.5 text-xs font-medium text-emerald-700 ring-1 ring-emerald-200">
            <CheckCircle2 className="h-3 w-3" /> Да
          </span>
        ) : (
          <span className="inline-flex items-center gap-1 rounded-full bg-muted px-2 py-0.5 text-xs font-medium text-slate-600 ring-1 ring-slate-200">
            <XCircle className="h-3 w-3" /> Нет
          </span>
        );
      case "apk_version":
        return (
          <span className="rounded-md bg-muted px-2 py-0.5 font-mono text-xs text-slate-700">
            {formatApkVersion(r.apk_version)}
          </span>
        );
      case "device_name":
        return (
          <div className="flex items-center gap-2">
            <Smartphone className="h-4 w-4 text-teal-600" />
            <div className="text-xs leading-tight">
              <p className="font-medium text-slate-900">{formatDeviceName(r.device_name)}</p>
            </div>
          </div>
        );
      case "last_sync":
        return <span className="text-xs text-slate-600">{formatAgentDateTime(r.last_sync_at)}</span>;
      case "phone":
        return <span className="font-mono text-xs text-slate-700">{r.phone || "—"}</span>;
      case "login":
        return <span className="font-mono text-xs text-slate-700">{r.login}</span>;
      case "price_types":
        return (
          <div className="flex flex-wrap gap-1">
            {priceList.slice(0, 2).map((p) => (
              <span
                key={p}
                className="rounded-md bg-teal-50 px-2 py-0.5 text-[11px] font-medium text-teal-700 ring-1 ring-teal-200"
              >
                {p}
              </span>
            ))}
            {priceList.length > 2 ? (
              <span className="rounded-md bg-muted px-2 py-0.5 text-[11px] text-slate-600">
                ещё {priceList.length - 2}
              </span>
            ) : null}
            {!priceList.length && "—"}
          </div>
        );
      case "warehouse":
        return (
          <div className="flex items-center gap-1.5 text-xs text-slate-700">
            <MapPin className="h-3.5 w-3.5 text-slate-400" />
            {r.warehouse ?? "—"}
          </div>
        );
      case "trade_direction":
        return r.trade_direction ? (
          <span className="rounded-md bg-indigo-50 px-2 py-0.5 text-xs font-medium text-indigo-700 ring-1 ring-indigo-200">
            {r.trade_direction}
          </span>
        ) : (
          "—"
        );
      case "branch":
        return (
          <div className="flex items-center gap-1.5 text-xs text-slate-700">
            <Building2 className="h-3.5 w-3.5 text-slate-400" />
            {r.branch ?? "—"}
          </div>
        );
      case "position":
        return <span className="text-xs text-slate-700">{r.position ?? "—"}</span>;
      case "created_at":
        return (
          <div className="flex items-center gap-1.5 text-xs text-slate-600">
            <Calendar className="h-3.5 w-3.5 text-slate-400" />
            {formatAgentCreatedDate(r.created_at)}
          </div>
        );
      case "app_access":
        return (
          <label className="inline-flex cursor-pointer items-center">
            <input
              type="checkbox"
              className="peer sr-only"
              checked={r.app_access}
              disabled={patchMut.isPending}
              onChange={() => {
                patchMut.mutate({ id: r.id, body: { app_access: !r.app_access } });
              }}
            />
            <div
              className={cn(
                "relative h-5 w-9 rounded-full bg-muted transition peer-checked:bg-teal-500",
                patchMut.isPending && "opacity-60"
              )}
            >
              <div className="absolute left-0.5 top-0.5 h-4 w-4 rounded-full bg-card shadow transition peer-checked:translate-x-4" />
            </div>
            <span className="ml-2 text-xs text-slate-600">{r.app_access ? "Вкл" : "Выкл"}</span>
          </label>
        );
      case "active_sessions":
        return (
          <div className="flex items-center gap-1.5">
            <UsersIcon className="h-3.5 w-3.5 text-slate-400" />
            <button
              type="button"
              className={cn(
                "text-sm font-semibold hover:underline",
                r.active_session_count >= r.max_sessions ? "text-rose-600" : "text-slate-900"
              )}
              onClick={() => setSessionAgent(r)}
            >
              {r.active_session_count}
            </button>
          </div>
        );
      case "max_sessions":
        return <span className="text-sm text-slate-600">{r.max_sessions}</span>;
      default:
        return "—";
    }
  }

  const paginationPages = useMemo(() => {
    const pages: number[] = [];
    const start = Math.max(1, page - 2);
    const end = Math.min(totalPages, start + 4);
    for (let i = start; i <= end; i++) pages.push(i);
    return pages;
  }, [page, totalPages]);

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap items-center justify-between gap-3 rounded-2xl bg-card p-5 shadow-sm ring-1 ring-slate-200">
        <div>
          <h1 className="text-2xl font-semibold text-slate-900">Агент</h1>
          <p className="mt-1 text-sm text-slate-500">
            Управление торговыми представителями и доступом к мобильному приложению
          </p>
        </div>
        <div className="flex items-center gap-2">
          <button
            type="button"
            onClick={() => setAddOpen(true)}
            className="flex items-center gap-2 rounded-lg bg-teal-600 px-4 py-2 text-sm font-medium text-white shadow-sm hover:bg-teal-700"
          >
            <Plus className="h-4 w-4" />
            Добавить агента
          </button>
          <button
            type="button"
            title="Управление столбцами"
            onClick={() => setColumnDialogOpen(true)}
            className="grid h-10 w-10 place-items-center rounded-lg bg-muted text-slate-600 hover:bg-muted"
          >
            <SlidersHorizontal className="h-4 w-4" />
          </button>
        </div>
      </div>

      <div className="rounded-2xl bg-card p-4 shadow-sm ring-1 ring-slate-200">
        <div className="flex flex-wrap items-center gap-3">
          <AgentFilterSelect
            label="Филиалы"
            value={draftBranch}
            onChange={setDraftBranch}
            emptyLabel="Все филиалы"
          >
            {branchOptions.map((b) => (
              <option key={b} value={b}>
                {b}
              </option>
            ))}
          </AgentFilterSelect>
          <AgentFilterSelect
            label="Направление торговли"
            value={draftTd}
            onChange={setDraftTd}
            emptyLabel="Все направления"
          >
            {(filterOptQ.data?.trade_directions ?? []).map((b) => (
              <option key={b} value={b}>
                {b}
              </option>
