function ymNow(): string {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  return `${y}-${m}`;
}

function formatYearMonthRu(ym: string): string {
  const m = /^(\d{4})-(\d{2})$/.exec(ym);
  if (!m) return ym;
  const mo = Number(m[2]);
  const y = m[1];
  if (mo < 1 || mo > 12) return ym;
  return `${RU_MONTHS_SHORT[mo - 1]} ${y}`;
}

const CURRENCY_LABEL = "So'm";

function normLimit(s: string | null | undefined): string {
  return (s ?? "").trim().replace(/\s/g, "").replace(",", ".");
}

/** Лимит задан и > 0 — тогда доступна опция «без долгов прошлых месяцев» */
function hasPositiveLimit(s: string | null | undefined): boolean {
  const n = normLimit(s);
  if (n === "") return false;
  const v = Number.parseFloat(n);
  return Number.isFinite(v) && v > 0;
}

/** Ввод лимита: только цифры и одна точка (в черновике — для API) */
function sanitizeLimitTyping(input: string): string {
  let t = input.replace(/\s/g, "").replace(",", ".");
  t = t.replace(/[^\d.]/g, "");
  const di = t.indexOf(".");
  if (di === -1) return t;
  const intp = t.slice(0, di);
  const frac = t.slice(di + 1).replace(/\./g, "");
  return `${intp}.${frac}`;
}

/** Чтение сумм: группы по 3 знака (как 2 434 342), ru-RU */
function formatAmountRuReadable(raw: string | null | undefined): string {
  const n = normLimit(raw ?? "");
  if (n === "") return "";
  const x = Number.parseFloat(n);
  if (!Number.isFinite(x)) return String(raw ?? "").trim();
  return x.toLocaleString("ru-RU", { minimumFractionDigits: 0, maximumFractionDigits: 2 });
}

function formatRemainingCell(raw: string | null | undefined): string {
  if (raw == null || raw === "" || raw === "—") return "—";
  return formatAmountRuReadable(raw);
}

function baseDraft(r: ConsignmentAgentApi): RowDraft {
  return {
    consignment: r.consignment,
    ignoreDebt: r.consignment_ignore_previous_months_debt,
    limitStr: r.consignment_limit_amount ?? ""
  };
}

function isRowDirty(r: ConsignmentAgentApi, d: RowDraft | undefined): boolean {
  if (!d) return false;
  const b = baseDraft(r);
  return (
    d.consignment !== b.consignment ||
    d.ignoreDebt !== b.ignoreDebt ||
    normLimit(d.limitStr) !== normLimit(b.limitStr)
  );
}

function buildConsignmentBulkRow(
  r: ConsignmentAgentApi,
  d: RowDraft
): {
  user_id: number;
  consignment: boolean;
  consignment_limit_amount: string | null;
  consignment_ignore_previous_months_debt: boolean;
} {
  const lim = normLimit(d.limitStr);
  const limitPayload = lim === "" ? null : d.limitStr.trim().replace(/\s/g, "").replace(",", ".");
  const ignorePayload = limitPayload == null || !d.consignment ? false : d.ignoreDebt;
  return {
    user_id: r.id,
    consignment: d.consignment,
    consignment_limit_amount: limitPayload,
    consignment_ignore_previous_months_debt: ignorePayload
  };
}

function parseSum(nums: (string | null | undefined)[]): string {
  let t = 0;
  for (const x of nums) {
    if (x == null || x === "" || x === "—") continue;
    const n = Number.parseFloat(String(x).replace(/\s/g, "").replace(",", "."));
    if (Number.isFinite(n)) t += n;
  }
  return t.toLocaleString("ru-RU", { maximumFractionDigits: 2 });
}

export function ConsignmentWorkspace({ tenantSlug }: { tenantSlug: string }) {
  const qc = useQueryClient();
  const importInputRef = useRef<HTMLInputElement>(null);
  const monthPickerAnchorRef = useRef<HTMLButtonElement>(null);
  const [monthPickerOpen, setMonthPickerOpen] = useState(false);
  const [yearMonth, setYearMonth] = useState(ymNow);
  const [supervisorSelected, setSupervisorSelected] = useState<Set<string>>(() => new Set());
  const [consFilter, setConsFilter] = useState<"" | "yes" | "no">("");
  const [search, setSearch] = useState("");
  const [drafts, setDrafts] = useState<Record<number, RowDraft>>({});
  const [toast, setToast] = useState<string | null>(null);
  const [groupSearch, setGroupSearch] = useState<Record<string, string>>({});
  const [savingGroupKey, setSavingGroupKey] = useState<string | null>(null);
  const [savingAll, setSavingAll] = useState(false);
  const [limitFocusedRowId, setLimitFocusedRowId] = useState<number | null>(null);

  const supervisorsQ = useQuery({
    queryKey: ["supervisors", tenantSlug, "consignment"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    queryFn: async () => {
      const { data } = await api.get<{ data: SupervisorRow[] }>(`/api/${tenantSlug}/supervisors`);
      return data.data;
    }
  });

  const supervisorPanelItems = useMemo(
    () => [
      { id: "__no_sup__", title: "Агенты без супервайзера" },
      ...(supervisorsQ.data ?? []).map((s) => ({ id: String(s.id), title: s.fio }))
    ],
    [supervisorsQ.data]
  );

  const supKeyForQuery = Array.from(supervisorSelected).sort().join(",");

  const listQ = useQuery({
    queryKey: ["consignment", tenantSlug, yearMonth, supKeyForQuery, consFilter, search],
    enabled: Boolean(tenantSlug),
    staleTime: 30_000,
    queryFn: async () => {
      const p = new URLSearchParams();
      p.set("year_month", yearMonth);
      if (consFilter === "yes" || consFilter === "no") p.set("consignment", consFilter);
      if (search.trim()) p.set("search", search.trim());
      if (supervisorSelected.has("__no_sup__")) {
        p.set("agents_without_supervisor", "1");
      } else {
        const raw = Array.from(supervisorSelected).find((x) => x !== "__no_sup__");
        if (raw) {
          const n = Number.parseInt(raw, 10);
          if (Number.isFinite(n) && n > 0) p.set("supervisor_user_id", String(n));
        }
      }
      const { data } = await api.get<{ data: ConsignmentAgentApi[] }>(
        `/api/${tenantSlug}/consignment/agents?${p.toString()}`
      );
      return data.data;
    }
  });

  const rows = listQ.data ?? [];

  /** После обновления списка с сервера — сбрасываем черновики, совпавшие с данными */
  useEffect(() => {
    setDrafts((prev) => {
      const next = { ...prev };
      let changed = false;
      for (const r of rows) {
        const d = next[r.id];
        if (d && !isRowDirty(r, d)) {
          delete next[r.id];
          changed = true;
        }
      }
      return changed ? next : prev;
    });
  }, [rows]);

  const grouped = useMemo(() => {
    const m = new Map<string, ConsignmentAgentApi[]>();
    for (const r of rows) {
      const key = r.supervisor_name?.trim() || "Без супервайзера";
      if (!m.has(key)) m.set(key, []);
      m.get(key)!.push(r);
    }
    return Array.from(m.entries()).sort((a, b) => a[0].localeCompare(b[0], "ru"));
  }, [rows]);

  const toggleSupervisorSingleSelect: Dispatch<SetStateAction<Set<string>>> = (action) => {
    setSupervisorSelected((prev) => {
      const next = typeof action === "function" ? action(prev) : action;
      if (next.size === 0) return next;
      const last = Array.from(next).at(-1)!;
      return new Set([last]);
    });
  };

  const updateDraft = (r: ConsignmentAgentApi, patch: Partial<RowDraft>) => {
    setDrafts((prev) => {
      const cur = prev[r.id] ?? baseDraft(r);
      let nextPatch = { ...patch };
      if (patch.consignment === false) {
        nextPatch = { ...nextPatch, ignoreDebt: false };
      }
      const merged = { ...cur, ...nextPatch };
      if (patch.limitStr !== undefined && !hasPositiveLimit(patch.limitStr)) {
        merged.ignoreDebt = false;
      }
      return { ...prev, [r.id]: merged };
    });
  };

  const patchAllDrafts = (list: ConsignmentAgentApi[], patch: Partial<RowDraft>) => {
    setDrafts((prev) => {
      const next = { ...prev };
      for (const r of list) {
        const cur = { ...(next[r.id] ?? baseDraft(r)), ...patch };
        if (patch.consignment === false) cur.ignoreDebt = false;
        if (patch.limitStr !== undefined && !hasPositiveLimit(patch.limitStr)) cur.ignoreDebt = false;
        next[r.id] = cur;
      }
      return next;
    });
  };

  /** Галочка «без долгов…» только при лимите & вкл. консигнации */
  const patchAllIgnoreDebtInGroup = (list: ConsignmentAgentApi[], value: boolean) => {
    setDrafts((prev) => {
      const next = { ...prev };
      for (const r of list) {
        const cur = next[r.id] ?? baseDraft(r);
        const limStr = cur.limitStr ?? r.consignment_limit_amount ?? "";
        if (!cur.consignment || !hasPositiveLimit(limStr)) {
          next[r.id] = { ...cur, ignoreDebt: false };
        } else {
          next[r.id] = { ...cur, ignoreDebt: value };
        }
      }
      return next;
    });
  };

  const rowConsignment = (r: ConsignmentAgentApi) =>
    drafts[r.id]?.consignment ?? r.consignment;
  const rowIgnoreDebt = (r: ConsignmentAgentApi) =>
    drafts[r.id]?.ignoreDebt ?? r.consignment_ignore_previous_months_debt;

  const cancelDraftsInList = (list: ConsignmentAgentApi[]) => {
    setDrafts((prev) => {
      const next = { ...prev };
      for (const r of list) delete next[r.id];
      return next;
    });
  };

  const saveGroupDrafts = async (groupTitle: string, visible: ConsignmentAgentApi[]) => {
    const dirty = visible.filter((r) => isRowDirty(r, drafts[r.id]));
    if (dirty.length === 0) return;
    setSavingGroupKey(groupTitle);
    try {
      const body = {
        rows: dirty.map((r) => buildConsignmentBulkRow(r, drafts[r.id]!))
      };
      await api.patch(`/api/${tenantSlug}/consignment/agents/bulk-rows`, body);
      cancelDraftsInList(dirty);
      setToast(`Сохранено строк: ${dirty.length}`);
      void qc.invalidateQueries({ queryKey: ["consignment", tenantSlug] });
      void qc.invalidateQueries({ queryKey: ["staff", tenantSlug, "agents"] });
    } catch {
      setToast("Ошибка сохранения — проверьте данные и права");
    } finally {
      setSavingGroupKey(null);
    }
  };

  const anyDirtyGlobal = useMemo(
    () => rows.some((r) => isRowDirty(r, drafts[r.id])),
    [rows, drafts]
  );

  const saveAllDrafts = async () => {
    const dirty = rows.filter((r) => isRowDirty(r, drafts[r.id]));
    if (dirty.length === 0) return;
    setSavingAll(true);
    try {
      const body = {
        rows: dirty.map((r) => buildConsignmentBulkRow(r, drafts[r.id]!))
      };
      await api.patch(`/api/${tenantSlug}/consignment/agents/bulk-rows`, body);
      cancelDraftsInList(dirty);
      setToast(`Сохранено изменений: ${dirty.length}`);
      void qc.invalidateQueries({ queryKey: ["consignment", tenantSlug] });
      void qc.invalidateQueries({ queryKey: ["staff", tenantSlug, "agents"] });
    } catch {
      setToast("Ошибка сохранения — проверьте данные и права");
    } finally {
      setSavingAll(false);
    }
  };

  const groupHasDirty = (visible: ConsignmentAgentApi[]) =>
    visible.some((r) => isRowDirty(r, drafts[r.id]));

  const exportExcel = async () => {
    const headers = [
      "Код",
      "Название Т.П.",
      "Валюта",
      "Вкл/откл консигнация",
      "Дата последнего изменения",
      "Лимит без учёта долгов за прошлые месяцы",
      "Установленный лимит",
      "Текущий лимит",
      "Супервайзер"
    ];
    const dataRows = rows.map((r) => [
      r.code ?? "",
      r.name,
      CURRENCY_LABEL,
      r.consignment ? "Да" : "Нет",
      r.consignment_updated_at
        ? new Date(r.consignment_updated_at).toLocaleString("ru-RU")
        : "",
      r.consignment_ignore_previous_months_debt ? "Да" : "Нет",
      r.consignment_limit_amount ?? "",
      r.remaining_limit ?? "",
      r.supervisor_name ?? "—"
    ]);
    await downloadXlsxSheet(
      `konsignatsiya-${yearMonth}.xlsx`,
      "Консигнация",
      headers,
      dataRows,
      { colWidths: [10, 28, 8, 12, 18, 14, 14, 14, 22] }
    );
  };

  const filterRowsInGroup = (groupKey: string, list: ConsignmentAgentApi[]) => {
    const q = (groupSearch[groupKey] ?? "").trim().toLowerCase();
    if (!q) return list;
    return list.filter(
      (r) =>
        (r.code ?? "").toLowerCase().includes(q) ||
        r.name.toLowerCase().includes(q)
    );
  };

  const limitStrForRow = (r: ConsignmentAgentApi) =>
    drafts[r.id]?.limitStr ?? r.consignment_limit_amount ?? "";

  const displayRow = (r: ConsignmentAgentApi) => {
    const d = drafts[r.id];
    const consignment = d?.consignment ?? r.consignment;
    const limitStr = d?.limitStr ?? r.consignment_limit_amount ?? "";
    const canIgnore = consignment && hasPositiveLimit(limitStr);
    const rawIgnore = d?.ignoreDebt ?? r.consignment_ignore_previous_months_debt;
    return {
      consignment,
      ignoreDebt: canIgnore && rawIgnore,
      limitStr,
      remaining: r.remaining_limit,
      ignoreStale:
        d != null &&
        canIgnore &&
        d.ignoreDebt !== r.consignment_ignore_previous_months_debt,
      canIgnoreDebt: canIgnore
    };
  };

  return (
    <div className="space-y-0">
      <div className="mb-4 flex flex-wrap items-center justify-between gap-3">
        <h1 className="text-xl font-semibold tracking-tight text-foreground">Консигнация</h1>
        <div className="flex flex-wrap items-center gap-2">
          <input
            ref={importInputRef}
            type="file"
            accept=".xlsx,.xls"
            className="hidden"
            onChange={() => {
              setToast("Импорт из Excel — в разработке");
              if (importInputRef.current) importInputRef.current.value = "";
            }}
          />
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="gap-1.5"
            onClick={() => void exportExcel()}
            disabled={rows.length === 0}
          >
            <FileSpreadsheet className="size-4" />
            Excel
          </Button>
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="gap-1.5"
            onClick={() => importInputRef.current?.click()}
          >
            <Upload className="size-4" />
            Импортировать с excel
          </Button>
        </div>
      </div>

      {toast ? (
        <p
          className="mb-3 rounded-md border border-border bg-muted/40 px-3 py-2 text-sm text-foreground"
          role="status"
        >
          {toast}{" "}
          <button type="button" className="ml-2 text-primary underline" onClick={() => setToast(null)}>
            закрыть
          </button>
        </p>
      ) : null}

      <div className="orders-hub-section orders-hub-section--filters mb-8 md:mb-10">
        <Card className="rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
          <CardContent className="p-5 sm:p-6">
            <p className="mb-4 text-xs font-semibold uppercase tracking-wide text-foreground/80">Фильтр</p>
            <div className="flex flex-wrap items-end gap-x-6 gap-y-4 md:gap-x-8">
              <div className="grid min-w-[10rem] max-w-[13.5rem] flex-[1_1_10rem] gap-2">
                <Label className="text-xs font-medium text-foreground/88">Месяц и год</Label>
                <button
                  ref={monthPickerAnchorRef}
                  type="button"
                  className={cn(
                    buttonVariants({ variant: "outline", size: "sm" }),
                    "h-9 w-full justify-start gap-2 font-normal",
                    monthPickerOpen && "border-primary/60 bg-primary/5"
                  )}
                  aria-expanded={monthPickerOpen}
                  aria-haspopup="dialog"
                  aria-label="Выбрать месяц отчёта"
                  onClick={() => setMonthPickerOpen((o) => !o)}
                >
                  <CalendarDays className="h-4 w-4 shrink-0 text-muted-foreground" />
                  <span className="min-w-0 truncate text-sm font-medium capitalize tabular-nums text-foreground">
                    {formatYearMonthRu(yearMonth)}
                  </span>
                </button>
                <MonthYearPickerPopover
                  open={monthPickerOpen}
                  onOpenChange={setMonthPickerOpen}
                  anchorRef={monthPickerAnchorRef}
                  value={yearMonth}
                  onChange={(ym) => setYearMonth(ym)}
                />
              </div>
              <div className="grid min-w-[12rem] max-w-[20rem] flex-[1_1_14rem] gap-2">
                <SearchableMultiSelectPanel
                  label="Супервайзер"
                  items={supervisorPanelItems}
                  selected={supervisorSelected}
                  onSelectedChange={toggleSupervisorSingleSelect}
                  loading={supervisorsQ.isLoading}
                  searchPlaceholder="Поиск"
                  triggerPlaceholder="Все"
                  emptyMessage="Нет супервайзеров"
                  className="w-full"
                  minPopoverWidth={320}
                />
              </div>
              <label className="grid min-w-[9.5rem] max-w-[11rem] flex-[0_1_auto] gap-2 text-xs font-medium text-foreground/88">
                <span>Консигнация</span>
                <FilterSelect
                  className="h-9 w-full"
                  emptyLabel="Все"
                  value={consFilter}
                  onChange={(e) => setConsFilter(e.target.value as "" | "yes" | "no")}
                >
                  <option value="yes">Да</option>
                  <option value="no">Нет</option>
                </FilterSelect>
              </label>
              <div className="grid min-w-[12rem] flex-[1_1_16rem] gap-2">
                <Label className="text-xs font-medium text-foreground/88">Поиск</Label>
                <div className="relative">
                  <Search className="absolute left-2.5 top-1/2 size-4 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    className="h-9 pl-9"
                    placeholder="Код, название Т.П.…"
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                  />
                </div>
              </div>
              <div className="flex shrink-0 flex-wrap items-end gap-3 border-border/50 pt-1 md:border-l md:pl-6 md:pt-0">
                <Button
                  type="button"
                  variant="default"
                  size="sm"
                  className="h-9 shrink-0 bg-emerald-600 px-4 text-white hover:bg-emerald-700 disabled:opacity-50"
                  disabled={!anyDirtyGlobal || savingAll || savingGroupKey != null}
                  onClick={() => void saveAllDrafts()}
                >
                  Сохранить всё
                </Button>
                <Button
                  type="button"
                  variant="secondary"
                  size="sm"
                  className="h-9 shrink-0 px-4"
                  disabled={savingAll || savingGroupKey != null}
                  onClick={() => void listQ.refetch()}
                >
                  Обновить
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {listQ.isLoading ? (
        <div className="mt-6 rounded-lg border bg-card py-12 text-center text-sm text-muted-foreground">
          Загрузка…
        </div>
      ) : null}
      {listQ.isError ? (
        <div className="mt-6 rounded-lg border border-destructive/40 bg-destructive/5 py-12 text-center text-sm text-destructive">
          Не удалось загрузить список
        </div>
      ) : null}

      {!listQ.isLoading && !listQ.isError && grouped.length === 0 ? (
        <div className="mt-6 rounded-lg border bg-card py-12 text-center text-sm text-muted-foreground">
          Нет данных
        </div>
      ) : null}

      <div className="mt-6 space-y-3 md:mt-8 md:space-y-4">
        {grouped.map(([groupTitle, groupRows]) => {
          const visible = filterRowsInGroup(groupTitle, groupRows);
          const consAllOn =
            visible.length > 0 && visible.every((r) => rowConsignment(r));
          const consSome = visible.some((r) => rowConsignment(r));
          const consMixed = consSome && !consAllOn;
          const ignEligible = visible.filter(
            (r) => rowConsignment(r) && hasPositiveLimit(limitStrForRow(r))
          );
          const ignAllOn =
            ignEligible.length > 0 && ignEligible.every((r) => rowIgnoreDebt(r));
          const ignSome = ignEligible.some((r) => rowIgnoreDebt(r));
          const ignMixed = ignSome && !ignAllOn;
          const dirty = groupHasDirty(visible);
          const sumEstablished = parseSum(visible.map((r) => r.consignment_limit_amount));
          const sumCurrent = parseSum(visible.map((r) => r.remaining_limit));
          return (
            <div
              key={groupTitle}
              className="orders-hub-section orders-hub-section--table !mb-3 overflow-hidden last:!mb-0"
            >
              <Card className="overflow-hidden rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
                <CardContent className="p-0">
              <div className="flex flex-col gap-2 border-b border-border/50 bg-muted/15 px-3 py-2 sm:flex-row sm:flex-wrap sm:items-center sm:justify-between sm:gap-x-3 sm:gap-y-2 sm:px-4">
                <div className="min-w-0 sm:pr-2">
                  <h3 className="truncate text-sm font-semibold leading-tight text-foreground">
                    {groupTitle}
                  </h3>
                </div>
                <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:gap-3">
                  <div className="relative w-full min-w-0 sm:w-[min(100%,240px)]">
                    <Search className="absolute left-2 top-1/2 size-3.5 -translate-y-1/2 text-muted-foreground" />
                    <Input
                      className="h-8 pl-8 text-xs"
                      placeholder="Поиск в группе…"
                      value={groupSearch[groupTitle] ?? ""}
                      onChange={(e) =>
                        setGroupSearch((g) => ({ ...g, [groupTitle]: e.target.value }))
                      }
                    />
                  </div>
                  <div className="flex shrink-0 flex-row flex-nowrap items-center gap-2">
                    <Button
                      type="button"
                      size="sm"
                      variant="default"
                      className="h-8 bg-emerald-600 text-white hover:bg-emerald-700"
                      disabled={
                        !dirty || savingGroupKey === groupTitle || savingAll
                      }
                      onClick={() => void saveGroupDrafts(groupTitle, visible)}
                    >
                      Сохранить
                    </Button>
                    <Button
                      type="button"
                      size="sm"
                      variant="outline"
                      className="h-8"
                      disabled={
                        !dirty || savingGroupKey === groupTitle || savingAll
                      }
                      onClick={() => cancelDraftsInList(visible)}
                    >
                      Отменить
                    </Button>
                  </div>
                </div>
              </div>

              <div className="overflow-x-auto bg-card">
                <table className="w-full min-w-[860px] border-collapse text-sm">
                  <thead>
                    <tr className="border-b border-border bg-muted/20 text-left text-[11px] font-semibold uppercase tracking-wide text-muted-foreground">
                      <th className="px-2 py-1.5">Код</th>
                      <th className="min-w-[12rem] px-2 py-1.5">Название Т.П.</th>
                      <th className="w-[5.5rem] px-2 py-1.5">Валюта</th>
                      <th className="w-[7rem] px-2 py-1.5 text-center align-middle normal-case">
                        <div className="flex flex-col items-center gap-1">
                          <input
                            type="checkbox"
                            className="size-4 rounded border-input accent-primary"
                            ref={(el) => {
                              if (el) el.indeterminate = consMixed;
                            }}
                            checked={consAllOn}
                            onChange={() => patchAllDrafts(visible, { consignment: !consAllOn })}
                            disabled={visible.length === 0}
                            aria-label="Включить или выключить консигнацию для всех строк группы"
                            title="Отметить все: консигнация вкл/откл"
                          />
                          <span className="text-[9px] font-semibold uppercase tracking-wide text-muted-foreground">
                            вкл/откл
                          </span>
                        </div>
                      </th>
                      <th className="min-w-[9rem] px-2 py-1.5">Дата изм.</th>
                      <th
                        className="w-[6rem] px-2 py-1.5 text-center align-middle leading-tight normal-case"
                        title="Без учёта долгов за прошлые месяцы"
                      >
                        <div className="flex flex-col items-center gap-1">
                          <input
                            type="checkbox"
                            className="size-4 rounded border-input accent-primary"
                            ref={(el) => {
                              if (el) el.indeterminate = ignMixed;
                            }}
                            checked={ignAllOn}
                            onChange={() => patchAllIgnoreDebtInGroup(visible, !ignAllOn)}
                            disabled={visible.length === 0 || ignEligible.length === 0}
                            aria-label="Включить опцию «без долгов прошлых месяцев» для всех строк группы (где задан лимит)"
                            title="Только для строк с лимитом и включённой консигнацией"
                          />
                          <span className="text-[9px] font-semibold uppercase tracking-wide text-muted-foreground leading-tight">
                            без долг.
                            <br />
                            прошл. мес.
                          </span>
                        </div>
                      </th>
                      <th className="min-w-[8rem] px-2 py-1.5 text-right">Установл. лимит</th>
                      <th className="min-w-[7rem] px-2 py-1.5 text-right">Текущий лимит</th>
                    </tr>
                  </thead>
                  <tbody>
                    {visible.length === 0 ? (
                      <tr>
                        <td colSpan={8} className="px-3 py-6 text-center text-muted-foreground">
                          Нет строк
                        </td>
                      </tr>
                    ) : null}
                    {visible.map((r) => {
                      const disp = displayRow(r);
                      const rowDirty = isRowDirty(r, drafts[r.id]);
                      return (
                        <tr
                          key={r.id}
                          className={cn(
                            "border-b border-border/60 hover:bg-muted/15",
                            rowDirty && "bg-amber-500/5"
                          )}
                        >
                          <td className="px-2 py-1.5 font-mono text-xs align-middle">{r.code ?? "—"}</td>
                          <td className="px-2 py-1.5 align-middle">{r.name}</td>
                          <td className="px-2 py-1.5 align-middle text-xs text-muted-foreground">
                            {CURRENCY_LABEL}
                          </td>
                          <td className="px-2 py-1.5 text-center align-middle">
                            <input
                              type="checkbox"
                              className="size-4 rounded border-input accent-primary"
                              checked={disp.consignment}
                              onChange={(e) => updateDraft(r, { consignment: e.target.checked })}
                              title="Консигнация для агента"
                            />
                          </td>
                          <td className="px-2 py-1.5 align-middle text-xs text-muted-foreground tabular-nums">
                            {r.consignment_updated_at
                              ? new Date(r.consignment_updated_at).toLocaleString("ru-RU")
                              : "—"}
                          </td>
                          <td className="px-2 py-1.5 text-center align-middle">
                            <input
                              type="checkbox"
                              className="size-4 rounded border-input accent-primary disabled:opacity-40"
                              checked={disp.ignoreDebt}
                              disabled={!disp.canIgnoreDebt}
                              onChange={(e) => updateDraft(r, { ignoreDebt: e.target.checked })}
                              title={
                                disp.canIgnoreDebt
                                  ? "Лимит без учёта долгов за прошлые месяцы (только с лимитом и вкл. консигнацией)"
                                  : "Сначала включите консигнацию и укажите лимит > 0"
                              }
                            />
                          </td>
                          <td className="px-2 py-1.5 text-right align-middle">
                            <Input
                              className="h-7 w-full min-w-[7.5rem] text-right text-xs tabular-nums disabled:opacity-50"
                              inputMode="decimal"
                              value={
                                limitFocusedRowId === r.id
                                  ? disp.limitStr
                                  : formatAmountRuReadable(disp.limitStr)
                              }
                              disabled={!disp.consignment}
                              onFocus={() => setLimitFocusedRowId(r.id)}
                              onBlur={() => setLimitFocusedRowId(null)}
                              onChange={(e) =>
                                updateDraft(r, { limitStr: sanitizeLimitTyping(e.target.value) })
                              }
                              placeholder="—"
                              title={
                                disp.consignment
                                  ? "Установленный лимит (группы по 3 цифры при просмотре)"
                                  : "Включите консигнацию для строки"
                              }
                            />
                          </td>
                          <td
                            className={cn(
                              "px-2 py-1.5 text-right text-xs tabular-nums align-middle",
                              disp.remaining != null &&
                                disp.remaining !== "" &&
                                disp.remaining !== "—" &&
                                Number.parseFloat(
                                  String(disp.remaining).replace(/\s/g, "").replace(",", ".")
                                ) < 0
                                ? "font-semibold text-destructive"
                                : "text-foreground"
                            )}
                            title={
                              disp.ignoreStale
                                ? "После сохранения «без долгов…» пересчитается на сервере"
                                : undefined
                            }
                          >
                            {formatRemainingCell(disp.remaining)}
                            {disp.ignoreStale ? (
                              <span className="ml-0.5 text-[10px] text-amber-600">*</span>
                            ) : null}
                          </td>
                        </tr>
                      );
                    })}
                    {visible.length > 0 ? (
                      <tr className="border-t border-border bg-muted/35 font-semibold">
                        <td colSpan={6} className="px-2 py-1.5 text-right text-sm text-foreground">
                          Итого по группе:
                        </td>
                        <td className="px-2 py-1.5 text-right font-mono text-sm text-sky-700 dark:text-sky-400 tabular-nums">
                          {sumEstablished}
                        </td>
                        <td className="px-2 py-1.5 text-right font-mono text-sm text-teal-700 dark:text-teal-400 tabular-nums">
                          {sumCurrent}
                        </td>
                      </tr>
                    ) : null}
                  </tbody>
                </table>
              </div>
                </CardContent>
              </Card>
            </div>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { api } from "@/lib/api";
import { STALE } from "@/lib/query-stale";
import { cn } from "@/lib/utils";
import { formatGroupedInteger } from "@/lib/format-numbers";
import { FilterSelect, filterSelectClassName } from "@/components/ui/filter-select";
import { downloadXlsxSheet } from "@/lib/download-xlsx";
import { Button } from "@/components/ui/button";
import { buttonVariants } from "@/components/ui/button-variants";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog";
import { WebOperatorCreateWorkspace } from "@/components/staff/web-operator-create-workspace";
import { KeyRound, ListOrdered, MonitorSmartphone, Pencil, RefreshCw, UserRoundCheck, UserRoundX } from "lucide-react";
import Link from "next/link";
import { TableColumnSettingsDialog } from "@/components/data-table/table-column-settings-dialog";
import { TableRowActionGroup } from "@/components/data-table/table-row-actions";
import { StaffActiveSessionsDialog } from "@/components/staff/staff-active-sessions-dialog";
import { useUserTablePrefs } from "@/hooks/use-user-table-prefs";
import { TableSearchField } from "@/components/ui/table-search-field";
import { DEFAULT_TABLE_PAGE_SIZES } from "@/lib/table-page-sizes";
import { WEB_ACCESS_ROLE_LABELS } from "@/lib/distribution-roles";

const POSITION_PRESETS_SETTINGS_HREF = "/settings/web-staff-position-presets";

type WebStaffRow = {
  id: number;
  kind: string;
  fio: string;
  first_name?: string | null;
  last_name?: string | null;
  middle_name?: string | null;
  login: string;
  phone: string | null;
  email: string | null;
  code: string | null;
  pinfl: string | null;
  branch: string | null;
  position: string | null;
  is_active: boolean;
  can_authorize: boolean;
  app_access: boolean;
  active_session_count: number;
  max_sessions: number;
};

type FilterOptions = { branches: string[]; positions: string[]; position_presets: string[] };

const OPERATOR_TABLE_ID = "staff.operators.v1";

const OPERATOR_COLUMN_IDS = [
  "fio",
  "login",
  "code",
  "pinfl",
  "email",
  "position",
  "kind",
  "phone",
  "branch",
  "active_sessions",
  "max_sessions",
  "app_access",
  "can_authorize"
] as const;

const OPERATOR_COLUMNS = OPERATOR_COLUMN_IDS.map((id) => ({
  id,
  label:
    {
      fio: "F.I.Sh",
      login: "Login",
      code: "Kod",
      pinfl: "PINFL",
      email: "Email",
      position: "Lavozim",
      kind: "Tizim roli",
      phone: "Telefon",
      branch: "Filial",
      active_sessions: "Faol sessiyalar",
      max_sessions: "Maks. sessiya",
      app_access: "Mobil ilova",
      can_authorize: "Kirish"
    }[id] ?? id
}));

function operatorExportCellString(r: WebStaffRow, colId: string): string {
  switch (colId) {
    case "fio":
      return r.fio;
    case "login":
      return r.login;
    case "code":
      return r.code ?? "";
    case "pinfl":
      return r.pinfl ?? "";
    case "email":
      return r.email ?? "";
    case "position":
      return r.position ?? "";
    case "kind":
      return WEB_ACCESS_ROLE_LABELS[r.kind] ?? r.kind;
    case "phone":
      return r.phone ?? "";
    case "branch":
      return r.branch ?? "";
    case "active_sessions":
      return String(r.active_session_count);
    case "max_sessions":
      return String(r.max_sessions);
    case "app_access":
      return r.app_access ? "Ha" : "Yo‘q";
    case "can_authorize":
      return r.can_authorize ? "Ha" : "Yo‘q";
    default:
      return "";
  }
}

function renderOperatorDataCell(colId: string, r: WebStaffRow) {
  switch (colId) {
    case "fio":
      return r.fio;
    case "login":
      return <span className="font-mono text-xs">{r.login}</span>;
    case "code":
      return <span className="text-xs">{r.code ?? "—"}</span>;
    case "pinfl":
      return <span className="text-xs">{r.pinfl ?? "—"}</span>;
    case "email":
      return <span className="text-xs">{r.email ?? "—"}</span>;
    case "position":
      return <span className="text-xs">{r.position?.trim() || "—"}</span>;
    case "kind":
      return (
        <span className="text-xs text-muted-foreground">{WEB_ACCESS_ROLE_LABELS[r.kind] ?? r.kind}</span>
      );
    case "phone":
      return <span className="text-xs">{r.phone ?? "—"}</span>;
    case "branch":
      return <span className="text-xs">{r.branch ?? "—"}</span>;
    case "max_sessions":
      return (
        <span className="text-xs tabular-nums">{formatGroupedInteger(r.max_sessions)}</span>
      );
    case "app_access":
      return <span className="text-xs">{r.app_access ? "Ha" : "Yo‘q"}</span>;
    case "can_authorize":
      return <span className="text-xs">{r.can_authorize ? "Ha" : "Yo‘q"}</span>;
    default:
      return "—";
  }
}

type Props = { tenantSlug: string };

export function OperatorsWorkspace({ tenantSlug }: Props) {
  const qc = useQueryClient();
  const [tab, setTab] = useState<"active" | "inactive">("active");
  const [search, setSearch] = useState("");
  const [filterBranch, setFilterBranch] = useState("");
  const [filterPosition, setFilterPosition] = useState("");
  const [appliedBranch, setAppliedBranch] = useState("");
  const [appliedPosition, setAppliedPosition] = useState("");

  const [selected, setSelected] = useState<Set<number>>(() => new Set());
  const [editRow, setEditRow] = useState<WebStaffRow | null>(null);
  const [passwordRow, setPasswordRow] = useState<WebStaffRow | null>(null);
  const [bulkRevokeOpen, setBulkRevokeOpen] = useState(false);
  const [bulkLimitsOpen, setBulkLimitsOpen] = useState(false);
  /** Modallarda qulflash: ochilgan paytdagi qatorlar (tanlov yoki joriy ro‘yxat) */
  const [bulkRevokeRows, setBulkRevokeRows] = useState<WebStaffRow[] | null>(null);
  const [bulkLimitsRows, setBulkLimitsRows] = useState<WebStaffRow[] | null>(null);
  const [limitsDraft, setLimitsDraft] = useState<Record<number, number>>({});
  const [columnDialogOpen, setColumnDialogOpen] = useState(false);
  const [sessionRow, setSessionRow] = useState<WebStaffRow | null>(null);
  const [createOperatorOpen, setCreateOperatorOpen] = useState(false);
  const [createOperatorFormKey, setCreateOperatorFormKey] = useState(0);

  const tablePrefs = useUserTablePrefs({
    tenantSlug,
    tableId: OPERATOR_TABLE_ID,
    defaultColumnOrder: [...OPERATOR_COLUMN_IDS],
    defaultPageSize: 10,
    allowedPageSizes: DEFAULT_TABLE_PAGE_SIZES
  });
  const pageSize = tablePrefs.pageSize;

  const filterOptsQ = useQuery({
    queryKey: ["operators", tenantSlug, "filter-options"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: FilterOptions }>(
        `/api/${tenantSlug}/operators/meta/filter-options`
      );
      return data.data;
    }
  });

  const listQ = useQuery({
    queryKey: ["operators", tenantSlug, tab, appliedBranch, appliedPosition],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.live,
    refetchInterval: 45_000,
    queryFn: async () => {
      const params = new URLSearchParams();
      params.set("is_active", tab === "active" ? "true" : "false");
      if (appliedBranch.trim()) params.set("branch", appliedBranch.trim());
      if (appliedPosition.trim()) params.set("position", appliedPosition.trim());
      const { data } = await api.get<{ data: WebStaffRow[] }>(
        `/api/${tenantSlug}/operators?${params.toString()}`
      );
      return data.data;
    }
  });

  const bulkRevokeMut = useMutation({
    mutationFn: async (userIds: number[]) => {
      await api.post(`/api/${tenantSlug}/operators/bulk/sessions/revoke`, { user_ids: userIds });
    },
    onSuccess: async () => {
      await qc.invalidateQueries({ queryKey: ["operators", tenantSlug] });
      setBulkRevokeOpen(false);
      setBulkRevokeRows(null);
      setSelected(new Set());
    }
  });

  const bulkLimitsMut = useMutation({
    mutationFn: async (updates: { user_id: number; max_sessions: number }[]) => {
      await api.post(`/api/${tenantSlug}/operators/bulk/max-sessions`, { updates });
    },
    onSuccess: async () => {
      await qc.invalidateQueries({ queryKey: ["operators", tenantSlug] });
      setBulkLimitsOpen(false);
      setBulkLimitsRows(null);
      setSelected(new Set());
    }
  });

  const deactivateMut = useMutation({
    mutationFn: async (row: WebStaffRow) => {
      await api.patch(`/api/${tenantSlug}/operators/${row.id}`, {
        is_active: !row.is_active
      });
    },
    onSuccess: async () => {
      await qc.invalidateQueries({ queryKey: ["operators", tenantSlug] });
    }
  });

  const rows = useMemo(() => {
    const src = listQ.data ?? [];
    const q = search.trim().toLowerCase();
    if (!q) return src;
    return src.filter(
      (r) =>
        r.fio.toLowerCase().includes(q) ||
        r.login.toLowerCase().includes(q) ||
        (r.phone ?? "").toLowerCase().includes(q) ||
        (r.email ?? "").toLowerCase().includes(q) ||
        (r.code ?? "").toLowerCase().includes(q) ||
        (r.pinfl ?? "").toLowerCase().includes(q)
    );
  }, [listQ.data, search]);

  const pageRows = useMemo(() => rows.slice(0, pageSize), [rows, pageSize]);

  useEffect(() => {
    setSelected(new Set());
  }, [tab, appliedBranch, appliedPosition]);

  /** Guruh amali: tanlov bo‘lsa faqat tanlanganlar, aks holda joriy jadvaldagi hammasi */
  function computeBulkTargets(): WebStaffRow[] {
    if (selected.size > 0) return rows.filter((r) => selected.has(r.id));
    return rows;
  }

  const allOnPageSelected = pageRows.length > 0 && pageRows.every((r) => selected.has(r.id));

  function toggleAllOnPage() {
    if (allOnPageSelected) {
      setSelected((prev) => {
        const next = new Set(prev);
        for (const r of pageRows) next.delete(r.id);
        return next;
      });
    } else {
      setSelected((prev) => {
        const next = new Set(prev);
        for (const r of pageRows) next.add(r.id);
        return next;
      });
    }
  }

  function toggleOne(id: number) {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }

  function openBulkLimits() {
    const targets = computeBulkTargets();
    if (!targets.length) return;
    const draft: Record<number, number> = {};
    for (const r of targets) {
      draft[r.id] = r.max_sessions;
    }
    setLimitsDraft(draft);
    setBulkLimitsRows(targets);
    setBulkLimitsOpen(true);
  }

  function openBulkRevoke() {
    const targets = computeBulkTargets();
    if (!targets.length) return;
    setBulkRevokeRows(targets);
    setBulkRevokeOpen(true);
  }

  function adjustLimit(id: number, delta: number) {
    setLimitsDraft((d) => {
      const cur = d[id] ?? 1;
      const next = Math.min(99, Math.max(1, cur + delta));
      return { ...d, [id]: next };
    });
  }

  function setAllLimitsTo(n: number) {
    if (!Number.isFinite(n) || n < 1 || n > 99) return;
    setLimitsDraft((d) => {
      const next = { ...d };
      for (const id of Object.keys(next).map(Number)) {
        next[id] = n;
      }
      return next;
    });
  }

  function bumpAllLimits(delta: number) {
    setLimitsDraft((d) => {
      const next = { ...d };
      for (const id of Object.keys(next).map(Number)) {
        next[id] = Math.min(99, Math.max(1, (next[id] ?? 1) + delta));
      }
      return next;
    });
  }

  return (
    <div className="space-y-4">
      {rows.length > 0 ? (
        <div className="rounded-md border border-amber-500/35 bg-amber-500/10 px-3 py-2 text-xs leading-relaxed text-foreground/90">
          <span className="font-medium text-foreground">Guruh amallari qamrovi: </span>
          {selected.size > 0 ? (
            <>
              <strong>{selected.size}</strong> ta xodim tanlangan — sessiya yopish / limitlar{" "}
              <strong>faqat shu tanlanganlarga</strong> qo‘llanadi.
            </>
          ) : (
            <>
              Hech qanday qator belgilanmagan — sessiya yopish yoki limit o‘zgartirish{" "}
              <strong>joriy jadvaldagi barcha {rows.length} ta</strong> xodimga qo‘llanadi (yuqoridagi filtr
              «Qo‘llash» va qidiruv natijasidagi qatorlar).
            </>
          )}
        </div>
      ) : null}

      <div className="orders-hub-section orders-hub-section--filters orders-hub-section--stack-tight">
        <Card className="rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
          <CardContent className="space-y-3 p-4 sm:p-5">
            <div className="flex flex-col gap-3 sm:flex-row sm:flex-wrap sm:items-end sm:justify-between">
              <div className="flex flex-wrap items-end gap-2">
                <div className="flex gap-1 border-b border-border pb-1">
                  <button
                    type="button"
                    className={cn(
                      "rounded px-2 py-1 text-xs font-medium text-foreground",
                      tab === "active" ? "border-b-2 border-primary" : "text-foreground/65"
                    )}
                    onClick={() => setTab("active")}
                  >
                    Faol
                  </button>
                  <button
                    type="button"
                    className={cn(
                      "rounded px-2 py-1 text-xs font-medium text-foreground",
                      tab === "inactive" ? "border-b-2 border-primary" : "text-foreground/65"
                    )}
                    onClick={() => setTab("inactive")}
                  >
                    Nofaol
                  </button>
                </div>
                <label className="grid gap-0.5 text-xs font-medium text-foreground/88">
                  <span className="sr-only">Filial</span>
                  <FilterSelect
                    aria-label="Filial"
                    emptyLabel="Filial"
                    value={filterBranch}
                    onChange={(e) => setFilterBranch(e.target.value)}
                  >
                    {(filterOptsQ.data?.branches ?? []).map((b) => (
                      <option key={b} value={b}>
                        {b}
                      </option>
                    ))}
                  </FilterSelect>
                </label>
                <label className="grid gap-0.5 text-xs font-medium text-foreground/88">
                  <span className="sr-only">Lavozim</span>
                  <FilterSelect
                    aria-label="Lavozim"
                    emptyLabel="Lavozim"
                    value={filterPosition}
                    onChange={(e) => setFilterPosition(e.target.value)}
                  >
                    {(filterOptsQ.data?.positions ?? []).map((p) => (
                      <option key={p} value={p}>
                        {p}
                      </option>
                    ))}
                  </FilterSelect>
                </label>
              </div>
              <Button
                type="button"
                size="sm"
                variant="secondary"
                className="shrink-0 bg-teal-700 text-white hover:bg-teal-800"
                onClick={() => {
                  setAppliedBranch(filterBranch);
                  setAppliedPosition(filterPosition);
                }}
              >
                Qo‘llash
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>

      <TableColumnSettingsDialog
        open={columnDialogOpen}
        onOpenChange={setColumnDialogOpen}
        title="Ustunlar boshqaruvi"
        description="Ko‘rinadigan ustunlar va tartib akkauntingizga saqlanadi."
        columns={OPERATOR_COLUMNS}
        columnOrder={tablePrefs.columnOrder}
        hiddenColumnIds={tablePrefs.hiddenColumnIds}
        saving={tablePrefs.saving}
        onSave={(next) => tablePrefs.saveColumnLayout(next)}
        onReset={() => tablePrefs.resetColumnLayout()}
      />

      <div className="orders-hub-section orders-hub-section--table mt-4">
        <Card className="overflow-hidden rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
          <CardContent className="p-0">
            <div className="table-toolbar flex flex-wrap items-end gap-2 border-b border-border/80 bg-muted/30 px-3 py-2 sm:px-4">
              <label className="grid shrink-0 gap-1 text-xs font-medium text-foreground/85">
                <span className="whitespace-nowrap leading-none">Qator</span>
                <select
                  className="h-9 rounded-md border border-input bg-background px-2 text-xs text-foreground"
                  value={pageSize}
                  onChange={(e) => tablePrefs.setPageSize(Number.parseInt(e.target.value, 10))}
                >
                  {DEFAULT_TABLE_PAGE_SIZES.map((n) => (
                    <option key={n} value={n}>
                      {n}
                    </option>
                  ))}
                </select>
              </label>
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="h-9 gap-1 px-2 text-xs"
                title="Ustunlar va tartib"
                onClick={() => setColumnDialogOpen(true)}
              >
                <ListOrdered className="size-3.5" />
                Ustunlar
              </Button>
              <TableSearchField
                className="max-w-[240px] flex-none"
                placeholder="Qidiruv"
                onSearch={setSearch}
              />
              <Button
                type="button"
                size="sm"
                variant="outline"
                className="h-9 shrink-0"
                onClick={() => {
                  const order = tablePrefs.visibleColumnOrder;
                  const headers = order.map((id) => OPERATOR_COLUMNS.find((c) => c.id === id)?.label ?? id);
                  const dataRows = rows.map((r) => order.map((colId) => operatorExportCellString(r, colId)));
                  downloadXlsxSheet(
                    `veb_xodimlar_${tab}_${new Date().toISOString().slice(0, 10)}.xlsx`,
                    "Veb xodimlar",
                    headers,
                    dataRows
                  );
                }}
              >
                Excel
              </Button>
              <Button
                type="button"
                size="sm"
                variant="outline"
                className="h-9 w-9 shrink-0 p-0"
                title="Ro‘yxat va faol sessiyalar sonini yangilash"
                disabled={listQ.isFetching}
                onClick={() => void listQ.refetch()}
              >
                <RefreshCw className={cn("mx-auto size-3.5", listQ.isFetching && "animate-spin")} />
              </Button>
              <div className="shrink-0">
                <select
                  aria-label="Guruh ishlovi"
                  className={cn(filterSelectClassName, "min-w-[10rem] max-w-[14rem]")}
                  value=""
                  onChange={(e) => {
                    const v = e.target.value;
                    if (v === "revoke" && rows.length > 0) openBulkRevoke();
                    if (v === "limits" && rows.length > 0) openBulkLimits();
                    e.target.value = "";
                  }}
                >
                  <option value="">Guruh ishlovi…</option>
                  <option value="revoke" disabled={rows.length === 0}>
                    Sessiyalarni yopish
                  </option>
                  <option value="limits" disabled={rows.length === 0}>
                    Sessiya limitlari
                  </option>
                </select>
              </div>
              <Button
                type="button"
                size="sm"
                className="h-9 shrink-0"
                onClick={() => {
                  setCreateOperatorFormKey((k) => k + 1);
                  setCreateOperatorOpen(true);
                }}
              >
                + Qoʻshish
              </Button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full min-w-[1100px] text-sm">
          <thead className="app-table-thead text-left text-xs">
            <tr>
              <th className="w-10 px-2 py-2">
                <input
                  type="checkbox"
                  className="size-4 rounded border-input"
                  checked={allOnPageSelected}
                  onChange={toggleAllOnPage}
                  aria-label="Barchasini tanlash"
                />
              </th>
              {tablePrefs.visibleColumnOrder.map((colId) => {
                const meta = OPERATOR_COLUMNS.find((c) => c.id === colId);
                return (
                  <th key={colId} className="px-2 py-2">
                    {meta?.label ?? colId}
                  </th>
                );
              })}
              <th className="px-2 py-2 text-right">Amallar</th>
            </tr>
          </thead>
          <tbody>
            {listQ.isLoading ? (
              <tr>
                <td
                  colSpan={2 + tablePrefs.visibleColumnOrder.length}
                  className="px-3 py-6 text-center text-muted-foreground"
                >
                  Загрузка…
                </td>
              </tr>
            ) : rows.length === 0 ? (
              <tr>
                <td
                  colSpan={2 + tablePrefs.visibleColumnOrder.length}
                  className="px-3 py-8 text-center text-muted-foreground"
                >
                  Bo‘sh
                </td>
              </tr>
            ) : (
              pageRows.map((r) => (
                <tr key={r.id} className="border-t">
                  <td className="px-2 py-1.5">
                    <input
                      type="checkbox"
                      className="size-4 rounded border-input"
                      checked={selected.has(r.id)}
                      onChange={() => toggleOne(r.id)}
                      aria-label={`Tanlash ${r.login}`}
                    />
                  </td>
                  {tablePrefs.visibleColumnOrder.map((colId) => (
                    <td key={colId} className="px-2 py-1.5">
                      {colId === "active_sessions" ? (
                        <button
                          type="button"
                          className="text-xs font-medium text-primary tabular-nums underline-offset-2 hover:underline"
                          onClick={() => setSessionRow(r)}
                        >
                          {r.active_session_count}
                        </button>
                      ) : (
                        renderOperatorDataCell(colId, r)
                      )}
                    </td>
                  ))}
                  <td className="px-2 py-1.5 text-right">
                    <TableRowActionGroup className="justify-end" ariaLabel="Operator">
                      <Button
                        type="button"
                        size="icon-sm"
                        variant="outline"
                        className="text-muted-foreground hover:text-foreground"
                        title="Faol sessiyalar"
                        aria-label="Faol sessiyalar"
                        onClick={() => setSessionRow(r)}
                      >
                        <MonitorSmartphone className="size-3.5" aria-hidden />
                      </Button>
                      <Button
                        type="button"
                        size="icon-sm"
                        variant="outline"
                        className="text-muted-foreground hover:text-foreground"
                        title="Parolni o‘zgartirish"
                        aria-label="Parolni o‘zgartirish"
                        onClick={() => setPasswordRow(r)}
                      >
                        <KeyRound className="size-3.5" aria-hidden />
                      </Button>
                      <Button
                        type="button"
                        size="icon-sm"
                        variant="outline"
                        className="text-muted-foreground hover:text-foreground"
                        title="Maʼlumotlarni tahrirlash"
                        aria-label="Tahrirlash"
                        onClick={() => setEditRow(r)}
                      >
                        <Pencil className="size-3.5" aria-hidden />
                      </Button>
                      {tab === "active" ? (
                        <Button
                          type="button"
                          size="icon-sm"
                          variant="ghost"
                          className="text-destructive hover:bg-destructive/10 hover:text-destructive"
                          title="Nofaol qilish"
                          aria-label="Nofaol qilish"
                          disabled={deactivateMut.isPending}
                          onClick={() => {
                            if (
                              window.confirm(
                                `${r.fio} foydalanuvchini nofaol qilasizmi?`
                              )
                            ) {
                              deactivateMut.mutate(r);
                            }
                          }}
                        >
                          <UserRoundX className="size-3.5" aria-hidden />
                        </Button>
                      ) : (
                        <Button
                          type="button"
                          size="icon-sm"
                          variant="ghost"
                          className="text-primary hover:bg-primary/10"
                          title="Faollashtirish"
                          aria-label="Faollashtirish"
                          disabled={deactivateMut.isPending}
                          onClick={() => deactivateMut.mutate(r)}
                        >
                          <UserRoundCheck className="size-3.5" aria-hidden />
                        </Button>
                      )}
                    </TableRowActionGroup>
                  </td>
                </tr>
              ))
            )}
          </tbody>
              </table>
            </div>
            {rows.length > 0 ? (
              <div className="table-content-footer border-t border-border/80 bg-muted/25 px-3 py-2 text-xs text-muted-foreground sm:px-4">
                Ko‘rsatilmoqda {pageRows.length} / {rows.length}
              </div>
            ) : null}
          </CardContent>
        </Card>
      </div>

      <p className="text-xs text-muted-foreground">
        <strong className="text-foreground">Tizim roli</strong> hozircha faqat{" "}
        <code className="text-foreground">operator</code> (JWT).         <strong className="text-foreground">Lavozim</strong> maydoni — tashkiliy nomlar (masalan, kassir, menejer).
        Shablonlar ro‘yxati:{" "}
        <Link href="/settings/web-staff-position-presets" className="text-primary underline">
          Sozlamalar → Veb xodim lavozimlari
        </Link>
        . Kelajakda yangi veb-rol qo‘shish uchun backend{" "}
        <code className="text-foreground">WEB_PANEL_STAFF_ROLES</code> bilan moslang. Faol sessiyalar soni jadvalda{" "}
        <code className="text-foreground">~45 s</code> da avtomatik yangilanadi yoki yangilash tugmasi bilan.
      </p>

      <Dialog open={createOperatorOpen} onOpenChange={setCreateOperatorOpen}>
        <DialogContent
          className="max-h-[90vh] overflow-y-auto sm:max-w-2xl"
          showCloseButton
        >
          <DialogHeader>
            <DialogTitle>Yangi veb xodim</DialogTitle>
            <DialogDescription>
              Login va parol noyob bo‘lishi kerak. Filial va lavozim ro‘yxatdan tanlanadi.
            </DialogDescription>
          </DialogHeader>
          <WebOperatorCreateWorkspace
            key={createOperatorFormKey}
            tenantSlug={tenantSlug}
            layout="embedded"
            onCancel={() => setCreateOperatorOpen(false)}
            onCreated={() => setCreateOperatorOpen(false)}
          />
        </DialogContent>
      </Dialog>

      <WebStaffEditDialog
        row={editRow}
        tenantSlug={tenantSlug}
        filterOptions={filterOptsQ.data}
        onClose={() => setEditRow(null)}
        onDone={async () => {
          await qc.invalidateQueries({ queryKey: ["operators", tenantSlug] });
          setEditRow(null);
        }}
      />

      <WebStaffPasswordDialog
        row={passwordRow}
        tenantSlug={tenantSlug}
        onClose={() => setPasswordRow(null)}
        onDone={async () => {
          await qc.invalidateQueries({ queryKey: ["operators", tenantSlug] });
          setPasswordRow(null);
        }}
      />

      <StaffActiveSessionsDialog
        open={sessionRow != null}
        onOpenChange={(open) => {
          if (!open) setSessionRow(null);
        }}
        tenantSlug={tenantSlug}
        staffKind="operator"
        userId={sessionRow?.id ?? null}
        maxSessions={sessionRow?.max_sessions ?? 1}
        onPatched={() => {
          void qc.invalidateQueries({ queryKey: ["operators", tenantSlug] });
        }}
      />

      <Dialog
        open={bulkRevokeOpen}
        onOpenChange={(o) => {
          if (!o) {
            setBulkRevokeOpen(false);
            setBulkRevokeRows(null);
          }
        }}
      >
        <DialogContent className="max-w-lg" showCloseButton>
          <DialogHeader>
            <DialogTitle>Veb-sessiyalarni yopish</DialogTitle>
            <p className="text-xs font-normal text-muted-foreground">
              {bulkRevokeRows && bulkRevokeRows.length > 0 ? (
                <>
                  <strong className="text-foreground">{bulkRevokeRows.length}</strong> ta xodimning barcha faol
                  refresh-sessiyalari yopiladi.
                  {selected.size === 0 ? (
                    <span> (Tanlov qilinmagan — joriy ro‘yxatdagi hammasi.)</span>
                  ) : null}
                </>
              ) : null}
            </p>
          </DialogHeader>
          <ul className="max-h-64 space-y-2 overflow-y-auto text-sm">
            {(bulkRevokeRows ?? []).map((r) => (
              <li key={r.id} className="flex justify-between gap-2 rounded border px-2 py-1.5">
                <span>{r.fio}</span>
                <span className="tabular-nums text-muted-foreground">
                  faol sessiyalar: {r.active_session_count}
                </span>
              </li>
            ))}
          </ul>
          <DialogFooter className="flex-col gap-2 sm:flex-row">
            <Button
              type="button"
              variant="outline"
              onClick={() => {
                setBulkRevokeOpen(false);
                setBulkRevokeRows(null);
              }}
            >
              Bekor
            </Button>
            <Button
              type="button"
              variant="destructive"
              disabled={
                bulkRevokeMut.isPending || !bulkRevokeRows || bulkRevokeRows.length === 0
              }
              onClick={() => {
                if (!bulkRevokeRows?.length) return;
                bulkRevokeMut.mutate(bulkRevokeRows.map((r) => r.id));
              }}
            >
              {bulkRevokeMut.isPending ? "…" : "Sessiyalarni yopish"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog
        open={bulkLimitsOpen}
        onOpenChange={(o) => {
          if (!o) {
            setBulkLimitsOpen(false);
            setBulkLimitsRows(null);
          }
        }}
      >
        <DialogContent className="max-w-lg" showCloseButton>
          <DialogHeader>
            <DialogTitle>Sessiya limitlarini o‘zgartirish</DialogTitle>
            <p className="text-xs font-normal text-muted-foreground">
              {bulkLimitsRows && bulkLimitsRows.length > 0 ? (
                <>
                  <strong className="text-foreground">{bulkLimitsRows.length}</strong> ta xodim uchun maksimal
                  parallel sessiya yangilanadi.
                  {selected.size === 0 ? (
                    <span> (Tanlov qilinmagan — joriy ro‘yxatdagi hammasi.)</span>
                  ) : null}
                </>
              ) : null}
            </p>
          </DialogHeader>
          <div className="flex flex-wrap items-center gap-2 text-sm">
            <Button type="button" size="sm" variant="secondary" onClick={() => bumpAllLimits(-1)}>
              Hammasiga −1
            </Button>
            <Button type="button" size="sm" variant="secondary" onClick={() => bumpAllLimits(1)}>
              Hammasiga +1
            </Button>
            <span className="text-muted-foreground">yoki</span>
            <Input
              className="w-20"
              inputMode="numeric"
              placeholder="1–99"
              id="uniform-limit"
            />
            <Button
              type="button"
              size="sm"
              variant="outline"
              onClick={() => {
                const el = document.getElementById("uniform-limit") as HTMLInputElement | null;
                if (el) setAllLimitsTo(Number.parseInt(el.value, 10));
              }}
            >
              Qiymatni qo‘llash
            </Button>
          </div>
          <ul className="max-h-56 space-y-2 overflow-y-auto text-sm">
            {(bulkLimitsRows ?? []).map((r) => (
              <li key={r.id} className="flex flex-wrap items-center justify-between gap-2 rounded border px-2 py-1.5">
                <span className="min-w-0 flex-1 truncate">{r.fio}</span>
                <div className="flex items-center gap-1">
                  <Button type="button" size="sm" variant="outline" onClick={() => adjustLimit(r.id, -1)}>
                    −
                  </Button>
                  <span className="w-8 text-center tabular-nums">{limitsDraft[r.id] ?? r.max_sessions}</span>
                  <Button type="button" size="sm" variant="outline" onClick={() => adjustLimit(r.id, 1)}>
                    +
                  </Button>
                </div>
              </li>
            ))}
          </ul>
          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={() => {
                setBulkLimitsOpen(false);
                setBulkLimitsRows(null);
              }}
            >
              Bekor
            </Button>
            <Button
              type="button"
              disabled={
                bulkLimitsMut.isPending || !bulkLimitsRows || bulkLimitsRows.length === 0
              }
              onClick={() => {
                if (!bulkLimitsRows?.length) return;
                const updates = bulkLimitsRows.map((r) => ({
                  user_id: r.id,
                  max_sessions: limitsDraft[r.id] ?? r.max_sessions
                }));
                bulkLimitsMut.mutate(updates);
              }}
            >
              {bulkLimitsMut.isPending ? "…" : "Saqlash"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function WebStaffPasswordDialog({
  row,
  onClose,
  tenantSlug,
  onDone
}: {
  row: WebStaffRow | null;
  onClose: () => void;
  tenantSlug: string;
  onDone: () => void;
}) {
  const [password, setPassword] = useState("");

  useEffect(() => {
    setPassword("");
  }, [row?.id]);

  const mut = useMutation({
    mutationFn: async () => {
      if (!row) return;
      await api.patch(`/api/${tenantSlug}/operators/${row.id}`, { password });
    },
    onSuccess: () => void onDone()
  });

  if (!row) return null;

  return (
    <Dialog open onOpenChange={(o) => !o && onClose()}>
      <DialogContent className="max-w-sm" showCloseButton>
        <DialogHeader>
          <DialogTitle>Parolni o‘zgartirish — {row.login}</DialogTitle>
        </DialogHeader>
        <label className="grid gap-1 text-sm">
          <span className="text-xs text-muted-foreground">Yangi parol (min 6)</span>
          <Input type="password" value={password} onChange={(e) => setPassword(e.target.value)} autoComplete="new-password" />
        </label>
        <DialogFooter>
          <Button type="button" variant="outline" onClick={onClose}>
            Bekor
          </Button>
          <Button
            type="button"
            disabled={mut.isPending || password.trim().length < 6}
            onClick={() => mut.mutate()}
          >
            {mut.isPending ? "…" : "Saqlash"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

function WebStaffEditDialog({
  row,
  onClose,
  tenantSlug,
  filterOptions,
  onDone
}: {
  row: WebStaffRow | null;
  onClose: () => void;
  tenantSlug: string;
  filterOptions: FilterOptions | undefined;
  onDone: () => void;
}) {
  const [first_name, setFirst] = useState("");
  const [last_name, setLast] = useState("");
  const [middle_name, setMid] = useState("");
  const [phone, setPhone] = useState("");
  const [email, setEmail] = useState("");
  const [code, setCode] = useState("");
  const [pinfl, setPinfl] = useState("");
  const [branch, setBranch] = useState("");
  const [position, setPosition] = useState("");
  const [max_sessions, setMaxS] = useState("1");
  const [app_access, setAppAccess] = useState(false);
  const [can_authorize, setCanAuth] = useState(true);

  useEffect(() => {
    if (!row) return;
    setFirst((row.first_name ?? "").trim() || row.fio);
    setLast((row.last_name ?? "").trim());
    setMid((row.middle_name ?? "").trim());
    setPhone(row.phone ?? "");
    setEmail(row.email ?? "");
    setCode(row.code ?? "");
    setPinfl(row.pinfl ?? "");
    setBranch(row.branch ?? "");
    setPosition(row.position ?? "");
    setMaxS(String(row.max_sessions));
    setAppAccess(row.app_access);
    setCanAuth(row.can_authorize);
  }, [row]);

  const patchMut = useMutation({
    mutationFn: async () => {
      if (!row) return;
      const ms = Number.parseInt(max_sessions, 10);
      await api.patch(`/api/${tenantSlug}/operators/${row.id}`, {
        first_name: first_name.trim(),
        last_name: last_name.trim() || null,
        middle_name: middle_name.trim() || null,
        phone: phone.trim() || null,
        email: email.trim() || null,
        code: code.trim() || null,
        pinfl: pinfl.trim() || null,
        branch: branch.trim() || null,
        position: position.trim() || null,
        max_sessions: Number.isFinite(ms) ? ms : row.max_sessions,
        app_access,
        can_authorize
      });
    },
    onSuccess: () => void onDone()
  });

  if (!row) return null;

  return (
    <Dialog open onOpenChange={(o) => !o && onClose()}>
      <DialogContent className="max-h-[90vh] max-w-md overflow-y-auto" showCloseButton>
        <DialogHeader>
          <DialogTitle>Tahrirlash — {row.login}</DialogTitle>
        </DialogHeader>
        <div className="grid gap-2 text-sm">
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">Ism *</span>
            <Input value={first_name} onChange={(e) => setFirst(e.target.value)} />
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">Familiya</span>
            <Input value={last_name} onChange={(e) => setLast(e.target.value)} />
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">Otasining ismi</span>
            <Input value={middle_name} onChange={(e) => setMid(e.target.value)} />
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">Telefon</span>
            <Input value={phone} onChange={(e) => setPhone(e.target.value)} />
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">Email</span>
            <Input value={email} onChange={(e) => setEmail(e.target.value)} />
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">Kod</span>
            <Input value={code} onChange={(e) => setCode(e.target.value)} />
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">PINFL</span>
            <Input value={pinfl} onChange={(e) => setPinfl(e.target.value)} />
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">Filial</span>
            <Input
              list="webstaff-branches-edit"
              value={branch}
              onChange={(e) => setBranch(e.target.value)}
            />
            <datalist id="webstaff-branches-edit">
              {(filterOptions?.branches ?? []).map((b) => (
                <option key={b} value={b} />
              ))}
            </datalist>
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">Lavozim</span>
            <Input
              list="webstaff-positions-edit"
              value={position}
              onChange={(e) => setPosition(e.target.value)}
            />
            <datalist id="webstaff-positions-edit">
              {(filterOptions?.positions ?? []).map((p) => (
                <option key={p} value={p} />
              ))}
            </datalist>
            <span className="text-[11px] leading-snug text-muted-foreground">
              Shablonlar ro‘yxatini{" "}
              <Link
                href={POSITION_PRESETS_SETTINGS_HREF}
                className="text-primary underline underline-offset-2 hover:text-primary/90"
              >
                bu yerda
              </Link>{" "}
              boshqarasiz.
            </span>
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-muted-foreground">Maks. veb-sessiyalar</span>
            <Input
              inputMode="numeric"
              value={max_sessions}
              onChange={(e) => setMaxS(e.target.value.replace(/\D/g, ""))}
            />
          </label>
          <label className="flex items-center gap-2 text-xs">
            <input type="checkbox" checked={app_access} onChange={(e) => setAppAccess(e.target.checked)} />
            Mobil ilova
          </label>
          <label className="flex items-center gap-2 text-xs">
            <input type="checkbox" checked={can_authorize} onChange={(e) => setCanAuth(e.target.checked)} />
            Kirish ruxsati
          </label>
        </div>
        <DialogFooter>
          <Button type="button" variant="outline" onClick={onClose}>
            Bekor
          </Button>
          <Button type="button" disabled={patchMut.isPending} onClick={() => patchMut.mutate()}>
            {patchMut.isPending ? "…" : "Saqlash"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import type { AxiosError } from "axios";
import { useEffect, useMemo, useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { api } from "@/lib/api";
