      const params = new URLSearchParams();
      params.set("is_active", "true");
      params.set("page", "1");
      params.set("limit", "500");
      const { data } = await api.get<{ data: WarehousePickerRow[] }>(
        `/api/${tenantSlug}/warehouses/table?${params.toString()}`
