function goodsReceiptSaveErrorMessage(err: unknown): string {
  const ax = err as AxiosError<{ error?: string }>;
  const status = ax.response?.status;
  const code = ax.response?.data?.error;
  if (status === 401) {
    return "Сессия истекла или токен недействителен. Обновите страницу (F5) или войдите заново.";
  }
  if (status === 403 || code === "ForbiddenRole") {
    return "Недостаточно прав: создавать и проводить поступления могут только администратор или оператор.";
  }
  if (code === "ValidationError") {
    const flat = getZodFlattenFromApiErrorBody(ax.response?.data);
    const hint = flat != null ? firstValidationUserHint(flat) : undefined;
    if (hint) return withApiSupportLine(`Проверка данных: ${hint}`, err);
  }
  return getUserFacingError(err, "Не удалось сохранить. Проверьте склад, цены и количества.");
}

