      );
      return data.data.filter((c) => c.is_active);
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference
  });

  const flatCats = categoriesQ.data ?? [];

  const warehousesQ = useQuery({
    queryKey: ["warehouses", tenantSlug, "receipt-new"],
