      const { data } = await api.get<{ data: { id: number; name: string }[] }>(
        `/api/${tenantSlug}/warehouses`
      );
      return data.data;
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference
  });
  useEffect(() => {
    if (!warehouseId.trim()) return;
    const ok = (warehousesQ.data ?? []).some((w) => String(w.id) === warehouseId.trim());
    if (!ok) setWarehouseId("");
  }, [warehouseId, warehousesQ.data]);

  const suppliersQ = useQuery({
    queryKey: ["suppliers", tenantSlug],
    queryFn: async () => {
      const { data } = await api.get<{ data: { id: number; name: string }[] }>(
        `/api/${tenantSlug}/suppliers`
      );
      return data.data;
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference
  });

  const priceTypesQ = useQuery({
    queryKey: ["price-types", tenantSlug, "receipt"],
    queryFn: async () => {
      const { data } = await api.get<{ data: string[] }>(
        `/api/${tenantSlug}/price-types?kind=purchase`
      );
      if (data.data.length > 0) return data.data;
      const { data: all } = await api.get<{ data: string[] }>(`/api/${tenantSlug}/price-types`);
      return all.data;
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference
  });

  type ReceiptDetail = {
    id: number;
    status: string;
    created_at: string;
    comment: string | null;
    price_type: string;
    external_ref: string | null;
    warehouse: { id: number; name: string };
    supplier: { id: number; name: string } | null;
    lines: {
      product_id: number;
      category_id: number | null;
      qty: string;
      unit_price: string;
    }[];
  };

  const sourceReceiptQ = useQuery({
    queryKey: ["goods-receipt-detail", tenantSlug, sourceReceiptId],
    queryFn: async () => {
      const { data } = await api.get<{ data: ReceiptDetail }>(
        `/api/${tenantSlug}/goods-receipts/${sourceReceiptId}`
      );
      return data.data;
    },
    enabled: Boolean(tenantSlug) && isEditMode
  });

  const catIds = useMemo(() => Array.from(selectedCats), [selectedCats]);

  const catIdsKey = useMemo(
    () => [...catIds].sort((a, b) => a - b).join(","),
    [catIds]
  );

  const productQueries = useQueries({
    queries: catIds.map((cid) => ({
      queryKey: ["products-receipt-cat", tenantSlug, cid],
      queryFn: () => fetchAllProductsInCategory(tenantSlug, cid),
      enabled: Boolean(tenantSlug) && catIds.length > 0
    }))
  });

  const queriesDataFingerprint = productQueries
    .map((q) => `${q.dataUpdatedAt}:${q.fetchStatus}:${q.data?.length ?? 0}`)
    .join("|");

  const mergedProducts = useMemo(() => {
    const m = new Map<number, ProductRow>();
    for (const q of productQueries) {
      for (const p of q.data ?? []) {
        m.set(p.id, p);
      }
    }
    return Array.from(m.values()).sort((a, b) => a.name.localeCompare(b.name, "ru"));
  }, [catIdsKey, queriesDataFingerprint]);

  const filteredProducts = useMemo(() => {
    const q = productSearch.trim().toLowerCase();
    if (!q) return mergedProducts;
    return mergedProducts.filter(
      (p) => p.name.toLowerCase().includes(q) || p.sku.toLowerCase().includes(q)
    );
  }, [mergedProducts, productSearch]);

  useEffect(() => {
    setSelectedProducts((prev) => {
      const valid = new Set(filteredProducts.map((p) => p.id));
      const next = new Set<number>();
      for (const id of prev) {
        if (valid.has(id)) next.add(id);
      }
      return next;
    });
  }, [filteredProducts]);

  useEffect(() => {
    if (!priceType.trim()) return;
    setLines((prev) => {
      const next = { ...prev };
      for (const p of mergedProducts) {
        const pr = p.prices?.find((x: { price_type: string; price: string }) => x.price_type === priceType.trim());
        const existing = next[p.id];
        if (!existing) {
          next[p.id] = { qty: "", block: "", price: pr?.price ?? "" };
        } else if (!existing.price.trim() && pr) {
          next[p.id] = { ...existing, price: pr.price };
        }
      }
      return next;
    });
  }, [mergedProducts, priceType]);

  const createSupplierMut = useMutation({
    mutationFn: async (name: string) => {
      const { data } = await api.post<{ data: { id: number; name: string } }>(
        `/api/${tenantSlug}/suppliers`,
        { name }
      );
      return data.data;
    },
    onSuccess: async (row) => {
      await qc.invalidateQueries({ queryKey: ["suppliers", tenantSlug] });
      setSupplierId(String(row.id));
      setSupplierOpen(false);
      setNewSupplierName("");
    }
  });

  type CreateBody = {
    warehouse_id: number;
    supplier_id?: number | null;
    comment?: string | null;
    price_type: string;
    external_ref?: string | null;
    status: "draft" | "posted";
    lines: { product_id: number; qty: number; unit_price?: number | null; defect_qty?: number | null }[];
  };

  const createMut = useMutation({
    mutationFn: async (body: CreateBody) => {
      const { data } = await api.post<{ data: { id: number; number: string } }>(
        `/api/${tenantSlug}/goods-receipts`,
        body
      );
      return data.data;
    },
    onMutate: () => {
      setNotice(null);
    },
    onSuccess: async () => {
      await qc.invalidateQueries({ queryKey: ["goods-receipts", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["stock", tenantSlug] });
      router.push("/stock/receipts");
    },
    onError: (err) => {
      setNotice({ kind: "error", text: goodsReceiptSaveErrorMessage(err) });
    }
  });

  const updateMut = useMutation({
    mutationFn: async (body: CreateBody) => {
      const { data } = await api.put<{ data: { id: number; number: string } }>(
        `/api/${tenantSlug}/goods-receipts/${sourceReceiptId}`,
        body
      );
      return data.data;
    },
    onMutate: () => {
      setNotice(null);
    },
    onSuccess: async () => {
      await qc.invalidateQueries({ queryKey: ["goods-receipts", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["goods-receipt-detail", tenantSlug, sourceReceiptId] });
      await qc.invalidateQueries({ queryKey: ["stock", tenantSlug] });
      router.push("/stock/receipts");
    },
    onError: (err) => {
      setNotice({ kind: "error", text: goodsReceiptSaveErrorMessage(err) });
    }
  });

  useEffect(() => {
    if (!isEditMode) return;
    if (!sourceReceiptQ.data) return;
    if (prefetchedOnce.current) return;

    const detail = sourceReceiptQ.data;
    setWarehouseId(String(detail.warehouse.id));
    setSupplierId(detail.supplier?.id != null ? String(detail.supplier.id) : "");
    setComment(detail.comment ?? "");
    setPriceType(detail.price_type ?? "");
    setExternalRef(detail.external_ref ?? "");

    const nextProducts = new Set<number>();
    const nextCats = new Set<number>();
    const nextLines: Record<number, LineEdit> = {};
    for (const line of detail.lines) {
      nextProducts.add(line.product_id);
      if (line.category_id != null) nextCats.add(line.category_id);
      nextLines[line.product_id] = {
        qty: line.qty ?? "",
        block: "",
        price: line.unit_price ?? ""
      };
    }
    setSelectedProducts(nextProducts);
    setSelectedCats(nextCats);
    setLines(nextLines);
    prefetchedOnce.current = true;
  }, [isEditMode, sourceReceiptQ.data]);

  const toggleCat = useCallback((id: number) => {
    setSelectedCats((prev) => {
      const n = new Set(prev);
      if (n.has(id)) n.delete(id);
      else n.add(id);
      return n;
    });
  }, []);

  const selectAllCats = useCallback(() => {
    if (selectedCats.size === flatCats.length) setSelectedCats(new Set());
    else setSelectedCats(new Set(flatCats.map((c) => c.id)));
  }, [flatCats, selectedCats.size]);

  const updateLine = useCallback((productId: number, patch: Partial<LineEdit>) => {
    setLines((prev) => {
      const nextLine = { ...(prev[productId] ?? { qty: "", block: "", price: "" }), ...patch };
      const out = { ...prev, [productId]: nextLine };
      return out;
    });
    if (patch.qty != null) {
      const q = Number.parseFloat(String(patch.qty).replace(",", "."));
      if (Number.isFinite(q) && q > 0) {
        setSelectedProducts((prev) => {
          if (prev.has(productId)) return prev;
          const next = new Set(prev);
          next.add(productId);
          return next;
        });
      }
    }
  }, []);

  /** Blok soni o‘zgarganda: kartotekada «шт/блок» bo‘lsa, кол-во = blok × qty_per_block */
  const setBlockForProduct = useCallback((productId: number, blockStr: string, p: ProductRow) => {
    setLines((prev) => {
      const cur = prev[productId] ?? { qty: "", block: "", price: "" };
      const next: LineEdit = { ...cur, block: blockStr };
      const blocks = Number.parseFloat(blockStr.replace(",", "."));
      const qpb = p.qty_per_block;
      if (qpb != null && qpb > 0 && Number.isFinite(blocks) && blocks > 0) {
        const total = blocks * qpb;
        next.qty =
          Number.isInteger(total) && Number.isInteger(blocks) && Number.isInteger(qpb)
            ? String(total)
            : String(Math.round(total * 1000) / 1000);
      }
      const out = { ...prev, [productId]: next };
      const q = Number.parseFloat(String(next.qty).replace(",", "."));
      if (Number.isFinite(q) && q > 0) {
        setSelectedProducts((prevSel) => {
          if (prevSel.has(productId)) return prevSel;
          const n = new Set(prevSel);
          n.add(productId);
          return n;
        });
      }
      return out;
    });
  }, []);

  const buildPayloadLines = useCallback(() => {
    const payloadLines: {
      product_id: number;
      qty: number;
      unit_price?: number | null;
      defect_qty?: number | null;
    }[] = [];
    for (const p of mergedProducts) {
      const ln = lines[p.id];
      if (!ln) continue;
      const qty = Number.parseFloat(ln.qty.replace(",", "."));
      if (!Number.isFinite(qty) || qty <= 0) continue;
      const unitPriceRaw = ln.price.trim().replace(",", ".");
      const unitPrice =
        unitPriceRaw === "" ? null : Number.parseFloat(unitPriceRaw);
      payloadLines.push({
        product_id: p.id,
        qty,
        unit_price: unitPrice != null && Number.isFinite(unitPrice) ? unitPrice : null,
        defect_qty: null
      });
    }
    return payloadLines;
  }, [mergedProducts, lines, selectedProducts]);

  const grandTotals = useMemo(() => {
    let totalQty = 0;
    let totalVol = 0;
    let totalSum = 0;
    for (const p of mergedProducts) {
      const ln = lines[p.id] ?? { qty: "", block: "", price: "" };
      const qtyN = Number.parseFloat(ln.qty.replace(",", "."));
      const priceN = Number.parseFloat(ln.price.replace(",", "."));
      const volU = p.volume_m3 != null ? Number.parseFloat(p.volume_m3) : NaN;
      if (Number.isFinite(qtyN) && qtyN > 0) {
        totalQty += qtyN;
        if (Number.isFinite(priceN)) totalSum += qtyN * priceN;
        if (Number.isFinite(volU)) totalVol += qtyN * volU;
      }
    }
    return { totalQty, totalVol, totalSum };
  }, [mergedProducts, lines]);

  const filteredTotals = useMemo(() => {
    let totalQty = 0;
    let totalVol = 0;
    let totalSum = 0;
    for (const p of filteredProducts) {
      const ln = lines[p.id] ?? { qty: "", block: "", price: "" };
      const qtyN = Number.parseFloat(ln.qty.replace(",", "."));
      const priceN = Number.parseFloat(ln.price.replace(",", "."));
      const volU = p.volume_m3 != null ? Number.parseFloat(p.volume_m3) : NaN;
      if (Number.isFinite(qtyN) && qtyN > 0) {
        totalQty += qtyN;
        if (Number.isFinite(priceN)) totalSum += qtyN * priceN;
        if (Number.isFinite(volU)) totalVol += qtyN * volU;
      }
    }
    return { totalQty, totalVol, totalSum };
  }, [filteredProducts, lines]);

  const submit = useCallback(
    (status: "draft" | "posted") => {
      const wid = Number.parseInt(warehouseId, 10);
      if (!Number.isFinite(wid) || wid <= 0) {
        setNotice({ kind: "error", text: "Выберите склад." });
        return;
      }
      if (!priceType.trim()) {
        setNotice({ kind: "error", text: "Выберите тип цены." });
        return;
      }
      if (catIds.length === 0) {
        setNotice({ kind: "error", text: "Отметьте хотя бы одну категорию." });
        return;
      }
      const payloadLines = buildPayloadLines();
      if (!payloadLines.length) {
        setNotice({ kind: "error", text: "Укажите количество хотя бы у одного товара." });
        return;
      }
      const body: CreateBody = {
        warehouse_id: wid,
        supplier_id: supplierId ? Number.parseInt(supplierId, 10) : null,
        comment: comment.trim() || null,
        price_type: priceType.trim(),
        external_ref: externalRef.trim() || null,
        status,
        lines: payloadLines
      };
      if (isEditMode) updateMut.mutate(body);
      else createMut.mutate(body);
    },
    [
      warehouseId,
      supplierId,
      comment,
      priceType,
      externalRef,
      catIds.length,
      buildPayloadLines,
      createMut,
      isEditMode,
      updateMut
    ]
  );

  const productsLoading = productQueries.some((q) => q.isLoading);
  const allVisibleSelected =
    filteredProducts.length > 0 && filteredProducts.every((p) => selectedProducts.has(p.id));

  return (
    <PageShell>
      <PageHeader
        title={isEditMode ? "Изменить поступление" : "Добавить поступление"}
        description="Тип цены и склад; дата прихода ставится автоматически при сохранении. В колонке «Блок» — число упаковок; «Кол-во» считается из карточки товара (шт/блок), если задано."
      />
      <div className="mb-4 flex flex-wrap items-center gap-3">
        <Link href="/stock/receipts" className={cn(buttonVariants({ variant: "outline", size: "sm" }))}>
          ← К списку
        </Link>
      </div>

      {notice ? (
        <div
          className={cn(
            "mb-3 flex items-start justify-between gap-3 rounded-md border px-3 py-2 text-sm",
            notice.kind === "error"
              ? "border-destructive/40 bg-destructive/10 text-destructive"
              : "border-emerald-500/40 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
          )}
        >
          <span>{notice.text}</span>
          <button
            type="button"
            className="rounded p-0.5 opacity-80 hover:opacity-100"
            onClick={() => setNotice(null)}
            aria-label="Закрыть уведомление"
          >
            <X className="size-4" />
          </button>
        </div>
      ) : null}

      <div className="space-y-6">
        <section className={panel}>
          <h2 className="mb-5 text-lg font-semibold tracking-tight sm:text-xl">Реквизиты и категории</h2>
          <p className="mb-4 text-xs text-muted-foreground">
            Дата создания:{" "}
            {sourceReceiptQ.data?.created_at
              ? new Date(sourceReceiptQ.data.created_at).toLocaleString("ru-RU")
              : new Date().toLocaleString("ru-RU")}
          </p>
          <div className="grid gap-8 lg:grid-cols-[minmax(0,380px)_1fr] lg:gap-10">
            <div className="space-y-4">
              <div className="space-y-2">
                <div className="flex items-center justify-between gap-2">
                  <Label>Поставщик</Label>
                  <Button type="button" variant="ghost" size="sm" className="h-7 text-xs" onClick={() => setSupplierOpen(true)}>
                    + Новый
                  </Button>
                </div>
                <select
                  className={selectClass}
                  value={supplierId}
                  onChange={(e) => setSupplierId(e.target.value)}
                >
                  <option value="">—</option>
                  {(suppliersQ.data ?? []).map((s) => (
                    <option key={s.id} value={String(s.id)}>
                      {s.name}
                    </option>
                  ))}
                </select>
              </div>
              <div className="space-y-2">
                <Label>Склад *</Label>
                <select
                  className={selectClass}
                  value={warehouseId}
                  onChange={(e) => setWarehouseId(e.target.value)}
                >
                  <option value="">— выберите —</option>
                  {(warehousesQ.data ?? []).map((w) => (
                    <option key={w.id} value={String(w.id)}>
                      {w.name}
                    </option>
                  ))}
                </select>
              </div>
              <div className="space-y-2">
                <Label>Комментарий</Label>
                <textarea
                  className="border-input bg-background min-h-[88px] w-full rounded-md border px-3 py-2 text-sm shadow-sm outline-none focus-visible:ring-2 focus-visible:ring-ring"
                  value={comment}
                  onChange={(e) => setComment(e.target.value)}
                  rows={3}
                />
              </div>
              <div className="space-y-2">
                <Label>Тип цены *</Label>
                <select
                  className={selectClass}
                  value={priceType}
                  onChange={(e) => setPriceType(e.target.value)}
                >
                  <option value="">— выберите —</option>
                  {(priceTypesQ.data ?? []).map((pt) => (
                    <option key={pt} value={pt}>
                      {pt}
                    </option>
                  ))}
                </select>
                <p className="text-muted-foreground text-xs">Дата прихода проставляется автоматически в момент сохранения.</p>
              </div>
              <div className="space-y-2">
                <Label>Номер прихода 1С</Label>
                <Input className="h-10" value={externalRef} onChange={(e) => setExternalRef(e.target.value)} maxLength={128} />
              </div>
            </div>

            <div className="flex min-h-0 flex-col gap-3">
              <div className="flex flex-wrap items-center justify-between gap-2">
                <Label className="text-base">Категории товаров *</Label>
                <label className="text-muted-foreground flex cursor-pointer items-center gap-2 text-sm">
                  <input
                    type="checkbox"
                    className="border-input rounded"
                    checked={flatCats.length > 0 && selectedCats.size === flatCats.length}
                    onChange={() => selectAllCats()}
                  />
                  Выбрать все
                </label>
              </div>
              <div className="bg-muted/30 max-h-[min(280px,40vh)] overflow-y-auto rounded-lg border border-border p-3 sm:max-h-[320px]">
                {categoriesQ.isLoading ? (
                  <p className="text-muted-foreground text-sm">Загрузка категорий…</p>
                ) : flatCats.length === 0 ? (
                  <p className="text-muted-foreground text-sm">Нет категорий — создайте в настройках каталога.</p>
                ) : (
                  <div className="flex flex-wrap gap-2">
                    {flatCats.map((c) => (
                      <label
                        key={c.id}
                        className={cn(
                          "inline-flex cursor-pointer items-center gap-2 rounded-lg border px-3 py-2 text-sm transition-colors",
                          selectedCats.has(c.id)
                            ? "border-primary/40 bg-primary/10 text-foreground"
                            : "border-border bg-background text-muted-foreground hover:bg-muted/50"
                        )}
                      >
                        <input
                          type="checkbox"
                          className="sr-only"
                          checked={selectedCats.has(c.id)}
                          onChange={() => toggleCat(c.id)}
                        />
                        <span
                          className={cn(
                            "size-2 shrink-0 rounded-full",
                            selectedCats.has(c.id) ? "bg-primary" : "bg-muted-foreground/40"
                          )}
                        />
                        <span className="leading-tight">{c.name}</span>
                      </label>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        </section>

        <section className={panel}>
          <div className="mb-4 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
            <h2 className="text-base font-semibold">Товары</h2>
            <div className="relative max-w-md flex-1">
              <Search className="text-muted-foreground pointer-events-none absolute left-3 top-1/2 size-4 -translate-y-1/2" />
              <Input
                className="h-10 pl-9"
                placeholder="Поиск по названию или SKU…"
                value={productSearch}
                onChange={(e) => setProductSearch(e.target.value)}
              />
            </div>
          </div>

          <div className={tableShell}>
            <table className="w-full min-w-[760px] text-sm">
              <thead className="app-table-thead">
                <tr>
                  <th className="px-3 py-3 text-center">
                    <input
                      type="checkbox"
                      className="rounded border-input"
                      checked={allVisibleSelected}
                      onChange={(e) => {
                        setSelectedProducts((prev) => {
                          const next = new Set(prev);
                          if (e.target.checked) {
                            for (const p of filteredProducts) next.add(p.id);
                          } else {
                            for (const p of filteredProducts) next.delete(p.id);
                          }
                          return next;
                        });
                      }}
                    />
                  </th>
                  <th
                    scope="col"
                    className="text-muted-foreground px-3 py-3 text-left text-xs font-medium uppercase tracking-wide"
                  >
                    Товар
                  </th>
                  <th
                    scope="col"
                    className="text-muted-foreground px-3 py-3 text-right text-xs font-medium uppercase tracking-wide"
                  >
                    Цена
                  </th>
                  <th
                    scope="col"
                    className="text-muted-foreground px-3 py-3 text-right text-xs font-medium uppercase tracking-wide"
                    title="Число упаковок (блоков). Если в карточке товара задано «кол-во в блоке», кол-во пересчитается автоматически."
                  >
                    Блок
                  </th>
                  <th
                    scope="col"
                    className="text-muted-foreground px-3 py-3 text-right text-xs font-medium uppercase tracking-wide"
                  >
                    Кол-во
                  </th>
                  <th
                    scope="col"
                    className="text-muted-foreground px-3 py-3 text-right text-xs font-medium uppercase tracking-wide"
                  >
                    Объём
                  </th>
                  <th
                    scope="col"
                    className="text-muted-foreground px-3 py-3 text-right text-xs font-medium uppercase tracking-wide"
                  >
                    Общая сумма
                  </th>
                </tr>
              </thead>
              <tbody>
                {catIds.length === 0 ? (
                  <tr>
                    <td colSpan={7} className="text-muted-foreground px-3 py-10 text-center">
                      Отметьте категории — список товаров появится здесь.
                    </td>
                  </tr>
                ) : productsLoading ? (
                  <tr>
                    <td colSpan={7} className="text-muted-foreground px-3 py-10 text-center">
                      Загрузка товаров…
                    </td>
                  </tr>
                ) : mergedProducts.length === 0 ? (
                  <tr>
                    <td colSpan={7} className="text-muted-foreground px-3 py-10 text-center">
                      В выбранных категориях нет активных товаров.
                    </td>
                  </tr>
                ) : filteredProducts.length === 0 ? (
                  <tr>
                    <td colSpan={7} className="text-muted-foreground px-3 py-10 text-center">
                      Ничего не найдено по запросу.
                    </td>
                  </tr>
                ) : (
                  filteredProducts.map((p) => {
                    const ln = lines[p.id] ?? { qty: "", block: "", price: "" };
                    const qtyN = Number.parseFloat(ln.qty.replace(",", "."));
                    const priceN = Number.parseFloat(ln.price.replace(",", "."));
                    const volU = p.volume_m3 != null ? Number.parseFloat(p.volume_m3) : NaN;
                    const lineVol =
                      Number.isFinite(qtyN) && Number.isFinite(volU) ? qtyN * volU : null;
                    const sum =
                      Number.isFinite(qtyN) && Number.isFinite(priceN) ? qtyN * priceN : null;
                    return (
                      <tr key={p.id} className="hover:bg-muted/40 border-b">
                        <td className="px-3 py-2 text-center">
                          <input
                            type="checkbox"
                            className="rounded border-input"
                            checked={selectedProducts.has(p.id)}
                            onChange={(e) =>
                              setSelectedProducts((prev) => {
                                const next = new Set(prev);
                                if (e.target.checked) next.add(p.id);
                                else next.delete(p.id);
                                return next;
                              })
                            }
                          />
                        </td>
                        <td className="max-w-[280px] px-3 py-2">
                          <div className="leading-tight font-medium">{p.name}</div>
                          <div className="text-muted-foreground flex flex-wrap items-center gap-x-2 font-mono text-xs">
                            <span>{p.sku}</span>
                            {p.qty_per_block != null && p.qty_per_block > 0 ? (
                              <span>• {p.qty_per_block} шт/блок</span>
                            ) : null}
                          </div>
                        </td>
                        <td className="px-3 py-2 text-right">
                          <Input
                            className="ml-auto h-8 w-24 text-right tabular-nums"
                            inputMode="decimal"
                            value={ln.price}
                            onChange={(e) => updateLine(p.id, { price: e.target.value })}
                            placeholder="авто"
                          />
                        </td>
                        <td className="px-3 py-2 text-right">
                          <Input
                            className="ml-auto h-8 w-20 text-right tabular-nums"
                            inputMode="decimal"
                            value={ln.block}
                            placeholder={p.qty_per_block != null && p.qty_per_block > 0 ? "упак." : "—"}
                            onChange={(e) => setBlockForProduct(p.id, e.target.value, p)}
                          />
                        </td>
                        <td className="px-3 py-2 text-right">
                          <Input
                            className="ml-auto h-8 w-20 text-right tabular-nums"
                            inputMode="decimal"
                            value={ln.qty}
                            onChange={(e) => updateLine(p.id, { qty: e.target.value })}
                          />
                        </td>
                        <td className="text-muted-foreground px-3 py-2 text-right text-xs tabular-nums">
                          {lineVol != null && Number.isFinite(lineVol)
                            ? `${formatGroupedDecimal(lineVol, 4)} м³`
                            : "—"}
                        </td>
                        <td className="px-3 py-2 text-right font-medium tabular-nums">
                          {sum != null && Number.isFinite(sum) ? formatGroupedDecimal(sum, 2) : "0"}
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
              {catIds.length > 0 && !productsLoading && mergedProducts.length > 0 && filteredProducts.length > 0 ? (
                <tfoot>
                  <tr className="bg-muted/40 border-t font-medium">
                    <td className="px-3 py-3" />
                    <td className="px-3 py-3">Итого</td>
                    <td className="px-3 py-3" />
                    <td className="px-3 py-3" />
                    <td className="px-3 py-3 text-right tabular-nums">
                      {filteredTotals.totalQty > 0
                        ? formatGroupedDecimal(filteredTotals.totalQty, 0)
                        : "—"}
                    </td>
                    <td className="px-3 py-3 text-right tabular-nums text-sm">
                      {filteredTotals.totalVol > 0
                        ? `${formatGroupedDecimal(filteredTotals.totalVol, 4)} м³`
                        : "—"}
                    </td>
                    <td className="px-3 py-3 text-right tabular-nums">
                      {filteredTotals.totalSum > 0 ? formatGroupedDecimal(filteredTotals.totalSum, 2) : "0"}
                    </td>
                  </tr>
                </tfoot>
              ) : null}
            </table>
          </div>

          <div className="mt-6 grid gap-4 sm:grid-cols-3">
            <div className="bg-muted/20 flex items-center gap-3 rounded-xl border border-border px-4 py-4">
              <div className="flex size-11 items-center justify-center rounded-lg bg-emerald-500/15 text-emerald-600 dark:text-emerald-400">
                <Box className="size-5" />
              </div>
              <div>
                <p className="text-muted-foreground text-xs">Общий объём</p>
                <p className="text-lg font-semibold tabular-nums">
                  {grandTotals.totalVol > 0
                    ? `${formatGroupedDecimal(grandTotals.totalVol, 4)} м³`
                    : "0 м³"}
                </p>
              </div>
            </div>
            <div className="bg-muted/20 flex items-center gap-3 rounded-xl border border-border px-4 py-4">
              <div className="flex size-11 items-center justify-center rounded-lg bg-amber-500/15 text-amber-600 dark:text-amber-400">
                <Package className="size-5" />
              </div>
              <div>
                <p className="text-muted-foreground text-xs">Общее количество</p>
                <p className="text-lg font-semibold tabular-nums">
                  {grandTotals.totalQty > 0
                    ? `${formatGroupedInteger(Math.round(grandTotals.totalQty))} шт`
                    : "0 шт"}
                </p>
              </div>
            </div>
            <div className="bg-muted/20 flex items-center gap-3 rounded-xl border border-border px-4 py-4">
              <div className="flex size-11 items-center justify-center rounded-lg bg-sky-500/15 text-sky-600 dark:text-sky-400">
                <Coins className="size-5" />
              </div>
              <div>
                <p className="text-muted-foreground text-xs">Общая сумма</p>
                <p className="text-lg font-semibold tabular-nums">
                  {grandTotals.totalSum > 0 ? formatGroupedDecimal(grandTotals.totalSum, 2) : "0"}
                </p>
              </div>
            </div>
          </div>

          <div className="mt-6 flex flex-wrap items-center justify-end gap-3 border-t pt-6">
            <Link href="/stock/receipts" className={cn(buttonVariants({ variant: "outline" }))}>
              Отмена
            </Link>
            <Button
              type="button"
              variant="outline"
              disabled={createMut.isPending || updateMut.isPending}
              onClick={() => submit("draft")}
            >
              {createMut.isPending || updateMut.isPending
                ? "…"
                : isEditMode
                  ? "Сохранить"
                  : "Создать"}
            </Button>
            <Button
              type="button"
              disabled={createMut.isPending || updateMut.isPending}
              onClick={() => submit("posted")}
            >
              {createMut.isPending || updateMut.isPending
                ? "Сохранение…"
                : isEditMode
                  ? "Сохранить и отправить"
                  : "Создать и отправить"}
            </Button>
          </div>
        </section>
      </div>

      <Dialog open={supplierOpen} onOpenChange={setSupplierOpen}>
        <DialogContent className="sm:max-w-md" showCloseButton>
          <DialogHeader>
            <DialogTitle>Новый поставщик</DialogTitle>
          </DialogHeader>
          <Input
            placeholder="Название"
            value={newSupplierName}
            onChange={(e) => setNewSupplierName(e.target.value)}
          />
          <DialogFooter className="gap-2 sm:justify-end">
            <Button type="button" variant="outline" onClick={() => setSupplierOpen(false)}>
              Отмена
            </Button>
            <Button
              type="button"
              disabled={!newSupplierName.trim() || createSupplierMut.isPending}
              onClick={() => createSupplierMut.mutate(newSupplierName.trim())}
            >
              Создать
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </PageShell>
  );
}

"use client";

import { PageHeader } from "@/components/dashboard/page-header";
import { PageShell } from "@/components/dashboard/page-shell";
import { TableColumnSettingsDialog } from "@/components/data-table/table-column-settings-dialog";
import { Button } from "@/components/ui/button";
import { buttonVariants } from "@/components/ui/button-variants";
import { Card, CardContent } from "@/components/ui/card";
import { Dialog, DialogContent, DialogDescription, DialogTitle } from "@/components/ui/dialog";
import { DateRangePopover, formatDateRangeButton } from "@/components/ui/date-range-popover";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useUserTablePrefs } from "@/hooks/use-user-table-prefs";
import { cn } from "@/lib/utils";
import { formatGroupedDecimal } from "@/lib/format-numbers";
import { api } from "@/lib/api";
import { downloadXlsxSheet } from "@/lib/download-xlsx";
import { STALE } from "@/lib/query-stale";
import { useEffectiveRole } from "@/lib/auth-store";
import { isAdminOrOperatorLikeRole } from "@/lib/distribution-roles";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { CalendarDays, Download, FileSpreadsheet, LayoutGrid, ListFilter, Pencil, RefreshCw, Search, Upload, X } from "lucide-react";
import Link from "next/link";
import type { ReactNode } from "react";
import { useCallback, useRef, useState } from "react";

const TABLE_ID = "goods_receipts.list.v1";
const COLS = [
  { id: "created_at", label: "Дата создания" },
  { id: "receipt_at", label: "Дата прихода" },
  { id: "total_qty", label: "Кол-во" },
  { id: "total_sum", label: "Сумма" },
  { id: "total_volume_m3", label: "Объём" },
  { id: "total_weight_kg", label: "Вес" },
  { id: "status", label: "Статус" },
  { id: "warehouse_name", label: "Склад" },
  { id: "comment", label: "Комментарий" },
  { id: "external_ref", label: "Номер прихода 1С" },
  { id: "supplier_name", label: "Поставщики" },
  { id: "number", label: "Номер" },
  { id: "price_type", label: "Тип цены" }
] as const;
const DEFAULT_ORDER = COLS.map((c) => c.id);
const NUMERIC = new Set(["total_qty", "total_sum", "total_volume_m3", "total_weight_kg"]);

export type GoodsReceiptRow = {
  id: number;
  number: string;
  status: string;
  created_at: string;
  receipt_at: string | null;
  total_qty: string;
  total_sum: string;
  total_volume_m3: string;
  total_weight_kg: string;
  comment: string | null;
  price_type: string;
  external_ref: string | null;
  warehouse_id: number;
  warehouse_name: string;
  supplier_id: number | null;
  supplier_name: string | null;
  deleted_at?: string | null;
};

function colLabel(id: string): string {
  return COLS.find((c) => c.id === id)?.label ?? id;
}

function fmtDt(iso: string | null): string {
  if (!iso) return "—";
  try {
    const d = new Date(iso);
    return new Intl.DateTimeFormat("ru-RU", {
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit"
    }).format(d);
  } catch {
    return iso;
  }
}

function statusLabel(s: string): string {
  switch (s) {
    case "draft":
      return "Новый";
    case "editing":
      return "Редактирование";
    case "posted":
      return "Одобренный";
    case "cancelled":
      return "Отменен";
    default:
      return s;
  }
}

function canChangeReceiptStatus(current: string): boolean {
  return current !== "cancelled";
}

function statusOptionsForRow(current: string): Array<{ value: string; label: string }> {
  if (current === "draft") {
    return [
      { value: "editing", label: "Редактирование" },
      { value: "posted", label: "Одобренный" },
      { value: "cancelled", label: "Отменен" }
    ];
  }
  if (current === "editing") {
    return [
      { value: "draft", label: "Новый" },
      { value: "posted", label: "Одобренный" },
      { value: "cancelled", label: "Отменен" }
    ];
  }
  if (current === "posted") {
    return [{ value: "cancelled", label: "Отменен" }];
  }
  if (current === "cancelled") {
    return [];
  }
  return [];
}

function renderCell(row: GoodsReceiptRow, colId: string): ReactNode {
  switch (colId) {
    case "created_at":
      return fmtDt(row.created_at);
    case "receipt_at":
      return fmtDt(row.receipt_at);
    case "total_qty": {
      const raw = row.total_qty;
      const n = Number.parseFloat(String(raw).replace(",", "."));
      if (!Number.isFinite(n)) return <span className="tabular-nums">{raw}</span>;
      return <span className="tabular-nums">{formatGroupedDecimal(n, 0)}</span>;
    }
    case "total_sum": {
      const raw = row.total_sum;
      const n = Number.parseFloat(String(raw).replace(",", "."));
      if (!Number.isFinite(n)) return <span className="tabular-nums">{raw}</span>;
      return <span className="tabular-nums">{formatGroupedDecimal(n, 2)}</span>;
    }
    case "total_volume_m3":
    case "total_weight_kg": {
      const raw = row[colId as keyof GoodsReceiptRow] as string;
      const n = Number.parseFloat(String(raw).replace(",", "."));
      if (!Number.isFinite(n)) return <span className="tabular-nums">{raw}</span>;
      return <span className="tabular-nums">{formatGroupedDecimal(n, 4)}</span>;
    }
    case "status":
      return statusLabel(row.status);
    case "warehouse_name":
      return row.warehouse_name;
    case "comment":
      return row.comment ? <span className="max-w-[200px] truncate">{row.comment}</span> : "—";
    case "external_ref":
      return row.external_ref ?? "—";
    case "supplier_name":
      return row.supplier_name ?? "—";
    case "number":
      return <span className="font-mono text-xs">{row.number}</span>;
    case "price_type":
      return row.price_type;
    default:
      return "—";
  }
}

type Props = { tenantSlug: string };

export function GoodsReceiptsWorkspace({ tenantSlug }: Props) {
  const role = useEffectiveRole();
  const canWrite = isAdminOrOperatorLikeRole(role);
  const qc = useQueryClient();

  const [draftWh, setDraftWh] = useState("");
  const [draftSupplier, setDraftSupplier] = useState("");
  const [draftStatus, setDraftStatus] = useState("");
  const [draftFrom, setDraftFrom] = useState("");
  const [draftTo, setDraftTo] = useState("");
  const [draftRangeOpen, setDraftRangeOpen] = useState(false);
  const draftRangeAnchorRef = useRef<HTMLButtonElement>(null);
  const [searchDraft, setSearchDraft] = useState("");
  const [uploading, setUploading] = useState(false);
  const [uploadReport, setUploadReport] = useState<{ applied: number; errors: string[] } | null>(null);
  const importFileRef = useRef<HTMLInputElement | null>(null);
  const [applied, setApplied] = useState({
    warehouseId: "",
    supplierId: "",
    status: "",
    dateFrom: "",
    dateTo: "",
    q: ""
  });
  const [page, setPage] = useState(1);
  const [columnOpen, setColumnOpen] = useState(false);
  const [statusBusyId, setStatusBusyId] = useState<number | null>(null);
  const [notice, setNotice] = useState<{ kind: "error" | "success"; text: string } | null>(null);
  const [exportOpen, setExportOpen] = useState(false);
  const [exportBusy, setExportBusy] = useState(false);

  const tablePrefs = useUserTablePrefs({
    tenantSlug,
    tableId: TABLE_ID,
    defaultColumnOrder: DEFAULT_ORDER,
    defaultPageSize: 25,
    allowedPageSizes: [10, 25, 50, 100]
  });
  const visible = tablePrefs.visibleColumnOrder;

  const applyFilters = useCallback(() => {
    setApplied({
      warehouseId: draftWh,
      supplierId: draftSupplier,
      status: draftStatus,
      dateFrom: draftFrom,
      dateTo: draftTo,
      q: searchDraft.trim()
    });
    setPage(1);
  }, [draftWh, draftSupplier, draftStatus, draftFrom, draftTo, searchDraft]);

  const resetFilters = useCallback(() => {
    setDraftWh("");
    setDraftSupplier("");
    setDraftStatus("");
    setDraftFrom("");
    setDraftTo("");
    setSearchDraft("");
    setApplied({
      warehouseId: "",
      supplierId: "",
      status: "",
      dateFrom: "",
      dateTo: "",
      q: ""
    });
    setPage(1);
  }, []);

  const warehousesQ = useQuery({
    queryKey: ["warehouses", tenantSlug],
    queryFn: async () => {
      const { data } = await api.get<{ data: { id: number; name: string }[] }>(
        `/api/${tenantSlug}/warehouses`
      );
      return data.data;
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference
  });

  const suppliersQ = useQuery({
    queryKey: ["suppliers", tenantSlug],
    queryFn: async () => {
      const { data } = await api.get<{ data: { id: number; name: string }[] }>(
        `/api/${tenantSlug}/suppliers`
      );
      return data.data;
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference
  });

  const listQ = useQuery({
    queryKey: [
      "goods-receipts",
      tenantSlug,
      applied,
      page,
      tablePrefs.pageSize
    ],
    queryFn: async () => {
      const p = new URLSearchParams();
      p.set("page", String(page));
      p.set("limit", String(tablePrefs.pageSize));
      if (applied.warehouseId) p.set("warehouse_id", applied.warehouseId);
      if (applied.supplierId) p.set("supplier_id", applied.supplierId);
      if (applied.status) p.set("status", applied.status);
      if (applied.dateFrom) p.set("date_from", applied.dateFrom);
      if (applied.dateTo) p.set("date_to", applied.dateTo);
      if (applied.q) p.set("q", applied.q);
      const { data } = await api.get<{ data: GoodsReceiptRow[]; total: number }>(
        `/api/${tenantSlug}/goods-receipts?${p.toString()}`
      );
      return data;
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list
  });

  const rows = listQ.data?.data ?? [];
  const total = listQ.data?.total ?? 0;
  const totalPages = Math.max(1, Math.ceil(total / tablePrefs.pageSize));

  const exportExcelSummary = useCallback(() => {
    const headers = visible.map(colLabel);
    const data = rows.map((row) =>
      visible.map((cid) => {
        switch (cid) {
          case "created_at":
            return fmtDt(row.created_at);
          case "receipt_at":
            return fmtDt(row.receipt_at);
          case "status":
            return statusLabel(row.status);
          case "comment":
            return row.comment ?? "";
          case "supplier_name":
            return row.supplier_name ?? "";
          case "external_ref":
            return row.external_ref ?? "";
          default:
            return String((row as Record<string, unknown>)[cid] ?? "");
        }
      })
    );
    downloadXlsxSheet(
      `postupleniya_${new Date().toISOString().slice(0, 10)}`,
      "Поступление",
      headers,
      data
    );
    setExportOpen(false);
  }, [rows, visible]);

  const exportExcelDetailed = useCallback(async () => {
    if (!rows.length) return;
    setExportBusy(true);
    try {
      const detailRows = await Promise.all(
        rows.map(async (row) => {
          const { data } = await api.get<{
            data: {
              id: number;
              number: string;
              status: string;
              created_at: string;
              receipt_at: string | null;
              warehouse: { id: number; name: string };
              supplier: { id: number; name: string } | null;
              price_type: string;
              external_ref: string | null;
              comment: string | null;
              lines: {
                product_id: number;
                sku: string;
                product_name: string;
                qty: string;
                unit_price: string;
                line_total: string;
              }[];
            };
          }>(`/api/${tenantSlug}/goods-receipts/${row.id}`);
          return data.data;
        })
      );

      const headers = [
        "Номер документа",
        "Статус",
        "Дата прихода",
        "Дата создания",
        "Склад",
        "Поставщик",
        "Тип цены",
        "Номер прихода 1С",
        "Комментарий",
        "SKU",
        "Товар",
        "Кол-во",
        "Цена",
        "Сумма строки"
      ];
      const data = detailRows.flatMap((doc) =>
        doc.lines.map((ln) => [
          doc.number,
          statusLabel(doc.status),
          fmtDt(doc.receipt_at),
          fmtDt(doc.created_at),
          doc.warehouse.name,
          doc.supplier?.name ?? "",
          doc.price_type,
          doc.external_ref ?? "",
          doc.comment ?? "",
          ln.sku,
          ln.product_name,
          ln.qty,
          ln.unit_price,
          ln.line_total
        ])
      );

      downloadXlsxSheet(
        `postupleniya_batafsil_${new Date().toISOString().slice(0, 10)}`,
        "Поступление (строки)",
        headers,
        data
      );
      setExportOpen(false);
    } finally {
      setExportBusy(false);
    }
  }, [rows, tenantSlug]);

  const colCount = Math.max(1, visible.length);

  async function importFromExcel(file: File) {
    if (!tenantSlug) return;
    setUploading(true);
    setUploadReport(null);
    try {
      const fd = new FormData();
      fd.append("file", file);
      const { data } = await api.post<{ applied: number; errors: string[] }>(
        `/api/${tenantSlug}/stock/import`,
        fd
      );
      setUploadReport(data);
      if (data.errors.length > 0) {
        setNotice({ kind: "error", text: `Импорт: есть ошибки (${data.errors.length}).` });
      } else {
        setNotice({ kind: "success", text: `Импорт завершён: применено ${data.applied} строк.` });
      }
      await qc.invalidateQueries({ queryKey: ["goods-receipts", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["stock", tenantSlug] });
      await listQ.refetch();
    } finally {
      setUploading(false);
    }
  }

  async function changeStatus(id: number, status: "draft" | "editing" | "posted" | "cancelled") {
    setStatusBusyId(id);
    try {
      await api.post(`/api/${tenantSlug}/goods-receipts/${id}/status`, { status });
      await qc.invalidateQueries({ queryKey: ["goods-receipts", tenantSlug] });
      await qc.invalidateQueries({ queryKey: ["stock", tenantSlug] });
    } catch {
      setNotice({ kind: "error", text: "Статусni o‘zgartirib bo‘lmadi (workflow cheklovi yoki ruxsat)." });
    } finally {
      setStatusBusyId(null);
    }
  }

  return (
    <PageShell>
      <PageHeader
        title="Поступление"
        description="Документы оприходования на склад: связь со складом, остатками и каталогом (тип цены, номенклатура)."
        actions={
          canWrite ? (
            <div className="flex flex-wrap items-center gap-2">
              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={() => importFileRef.current?.click()}
                disabled={uploading}
              >
                <Upload className="mr-1 size-3.5" />
                {uploading ? "Импорт..." : "Импортировать с excel"}
              </Button>
              <Link
                href="/stock/receipts/new"
                className={cn(buttonVariants({ size: "sm" }), "bg-teal-600 text-white hover:bg-teal-700")}
              >
                Добавить
              </Link>
              <Button type="button" variant="outline" size="sm" onClick={() => setExportOpen(true)}>
                <Download className="mr-1 size-3.5" />
                Excel
              </Button>
              <input
                ref={importFileRef}
                type="file"
                accept=".xlsx,.xlsm"
                className="hidden"
                onChange={(e) => {
                  const f = e.target.files?.[0];
                  e.target.value = "";
                  if (f) void importFromExcel(f);
                }}
              />
            </div>
          ) : null
        }
      />

      <div className="mb-4 flex flex-wrap items-center gap-2">
        <Link className={cn(buttonVariants({ variant: "outline", size: "sm" }))} href="/stock">
          ← Kirim / qoldiq
        </Link>
        <Link className={cn(buttonVariants({ variant: "outline", size: "sm" }))} href="/stock/balances">
          Остатки товаров
        </Link>
        <Link className={cn(buttonVariants({ variant: "outline", size: "sm" }))} href="/stock/warehouses">
          Склады
        </Link>
      </div>

      {notice ? (
        <div
          className={cn(
            "mb-3 flex items-start justify-between gap-3 rounded-md border px-3 py-2 text-sm",
            notice.kind === "error"
              ? "border-destructive/40 bg-destructive/10 text-destructive"
              : "border-emerald-500/40 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
          )}
        >
          <span>{notice.text}</span>
          <button
            type="button"
            className="rounded p-0.5 opacity-80 hover:opacity-100"
            onClick={() => setNotice(null)}
            aria-label="Закрыть уведомление"
          >
            <X className="size-4" />
          </button>
        </div>
      ) : null}

      <Card className="border-border/60 shadow-sm">
        <CardContent className="space-y-4 p-4">
          <p className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">Filter Panel</p>
          <div className="flex flex-wrap items-end justify-between gap-3">
            <div className="flex min-w-0 flex-1 flex-wrap items-end gap-3">
            <div className="grid min-w-[9rem] gap-1.5">
              <Label className="text-xs">Склад</Label>
              <select
                className="flex h-9 w-full rounded-md border border-input bg-background px-2 text-sm"
                value={draftWh}
                onChange={(e) => setDraftWh(e.target.value)}
              >
                <option value="">Все</option>
                {(warehousesQ.data ?? []).map((w) => (
                  <option key={w.id} value={String(w.id)}>
                    {w.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="grid min-w-[9rem] gap-1.5">
              <Label className="text-xs">Поставщики</Label>
              <select
                className="flex h-9 w-full rounded-md border border-input bg-background px-2 text-sm"
                value={draftSupplier}
                onChange={(e) => setDraftSupplier(e.target.value)}
              >
                <option value="">Все</option>
                {(suppliersQ.data ?? []).map((s) => (
                  <option key={s.id} value={String(s.id)}>
                    {s.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="grid min-w-[9rem] gap-1.5">
              <Label className="text-xs">Статус</Label>
              <select
                className="flex h-9 w-full rounded-md border border-input bg-background px-2 text-sm"
                value={draftStatus}
                onChange={(e) => setDraftStatus(e.target.value)}
              >
                <option value="">Все</option>
                <option value="draft">Новый</option>
                <option value="editing">Редактирование</option>
                <option value="posted">Одобренный</option>
                <option value="cancelled">Отменен</option>
              </select>
            </div>
            <div className="grid min-w-[11rem] max-w-[16rem] gap-1.5">
              <Label className="text-xs">Период</Label>
              <button
                ref={draftRangeAnchorRef}
                type="button"
                className={cn(
                  buttonVariants({ variant: "outline", size: "sm" }),
                  "h-9 w-full justify-start gap-2 font-normal",
                  draftRangeOpen && "border-primary/60 bg-primary/5"
                )}
                aria-expanded={draftRangeOpen}
                aria-haspopup="dialog"
                onClick={() => setDraftRangeOpen((o) => !o)}
              >
                <CalendarDays className="h-4 w-4 shrink-0" />
                <span className="truncate text-sm">{formatDateRangeButton(draftFrom, draftTo)}</span>
              </button>
            </div>
            <Button
              type="button"
              variant="outline"
              size="icon"
              className="h-9 w-9 shrink-0"
              title="Сбросить фильтры"
              onClick={() => resetFilters()}
            >
              <ListFilter className="size-4" />
            </Button>
            </div>
            <div className="flex shrink-0 items-end">
            <Button
              type="button"
              className="h-9 min-w-[7.5rem] shrink-0 bg-teal-600 px-4 text-white hover:bg-teal-700"
              onClick={() => applyFilters()}
            >
              Применить
            </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="flex flex-wrap items-end gap-2 border-b border-border/50 pb-3">
        <select
          className="h-9 rounded-md border border-input bg-background px-2 text-sm"
          value={String(tablePrefs.pageSize)}
          onChange={(e) => {
            tablePrefs.setPageSize(Number(e.target.value));
            setPage(1);
          }}
        >
          {[10, 25, 50, 100].map((n) => (
            <option key={n} value={n}>
              {n}
            </option>
          ))}
        </select>
        <Button
          type="button"
          variant="outline"
          size="icon"
          className="h-9 w-9"
          title="Управление столбцами"
          onClick={() => setColumnOpen(true)}
        >
          <LayoutGrid className="size-4" />
        </Button>
        <div className="relative min-w-[180px] max-w-xs flex-1">
          <Search className="pointer-events-none absolute left-2.5 top-1/2 size-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            className="h-9 pl-8"
            placeholder="Поиск"
            value={searchDraft}
            onChange={(e) => setSearchDraft(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") applyFilters();
            }}
          />
        </div>
        <Button type="button" variant="outline" size="sm" className="h-9" onClick={() => setExportOpen(true)}>
          <Download className="mr-1 size-3.5" />
          Excel
        </Button>
        <Button
          type="button"
          variant="outline"
          size="icon"
          className="h-9 w-9"
          title="Обновить"
          onClick={() => void listQ.refetch()}
        >
          <RefreshCw className={cn("size-4", listQ.isFetching && "animate-spin")} />
        </Button>
      </div>

      <TableColumnSettingsDialog
        open={columnOpen}
        onOpenChange={setColumnOpen}
        title="Управление столбцами"
        description="Видимые столбцы и порядок сохраняются для вашей учётной записи."
        columns={[...COLS]}
        columnOrder={tablePrefs.columnOrder}
        hiddenColumnIds={tablePrefs.hiddenColumnIds}
        saving={tablePrefs.saving}
        onSave={(next) => tablePrefs.saveColumnLayout(next)}
        onReset={() => tablePrefs.resetColumnLayout()}
      />

      <div className="overflow-x-auto rounded-lg border border-border/60 bg-card shadow-sm">
        <table className="w-full min-w-[960px] border-collapse text-sm">
          {visible.length === 0 ? (
            <tbody>
              <tr>
                <td className="p-8 text-center text-muted-foreground">
                  Нет видимых столбцов. Откройте «Управление столбцами».
                </td>
              </tr>
            </tbody>
          ) : (
            <>
              <thead className="app-table-thead">
                <tr className="border-b border-border bg-muted/40 text-left text-xs font-medium text-muted-foreground">
                  {visible.map((colId) => (
                    <th
                      key={colId}
                      className={cn(
                        "whitespace-nowrap px-3 py-2.5",
                        NUMERIC.has(colId) && "text-right"
                      )}
                    >
                      {colLabel(colId)}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {listQ.isLoading ? (
                  <tr>
                    <td colSpan={colCount} className="p-8 text-center text-muted-foreground">
                      Загрузка…
                    </td>
                  </tr>
                ) : rows.length === 0 ? (
                  <tr>
                    <td colSpan={colCount} className="p-8 text-center text-muted-foreground">
                      Пусто
                    </td>
                  </tr>
                ) : (
                  rows.map((row) => (
                    <tr key={row.id} className="border-b border-border/70 hover:bg-muted/20">
                      {visible.map((colId) => (
                        <td
                          key={colId}
                          className={cn("px-3 py-2", NUMERIC.has(colId) && "text-right")}
                        >
                          {colId === "status" && canWrite ? (
                            <div className="flex items-center gap-1">
                              <select
                                className="h-8 min-w-[8rem] rounded-md border border-input bg-background px-2 text-xs"
                                value={row.status}
                                disabled={statusBusyId === row.id || !canChangeReceiptStatus(row.status)}
                                onChange={(e) => {
                                  const next = e.target.value as "draft" | "editing" | "posted" | "cancelled";
                                  if (next === row.status) return;
                                  void changeStatus(row.id, next);
                                }}
                              >
                                <option value={row.status} hidden>
                                  {statusLabel(row.status)}
                                </option>
                                {statusOptionsForRow(row.status).map((opt) => (
                                  <option key={`${row.id}-${opt.value}`} value={opt.value}>
                                    {opt.label}
                                  </option>
                                ))}
                              </select>
                              {(row.status === "draft" || row.status === "editing") && canWrite ? (
                                <Link
                                  href={`/stock/receipts/new?source_receipt_id=${row.id}`}
                                  className={cn(
                                    buttonVariants({ variant: "outline", size: "icon" }),
                                    "h-8 w-8"
                                  )}
                                  title="Редактировать"
                                >
                                  <Pencil className="size-3.5" />
                                </Link>
                              ) : null}
                            </div>
                          ) : (
                            renderCell(row, colId)
                          )}
                        </td>
                      ))}
                    </tr>
                  ))
                )}
              </tbody>
            </>
          )}
        </table>
      </div>

      <div className="flex flex-wrap items-center justify-between gap-2 text-xs text-muted-foreground">
        <span>
          Всего: {total} · стр. {page} / {totalPages}
        </span>
        <div className="flex gap-1">
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-7"
            disabled={page <= 1}
            onClick={() => setPage((p) => Math.max(1, p - 1))}
          >
            ←
          </Button>
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="h-7"
            disabled={page >= totalPages}
            onClick={() => setPage((p) => p + 1)}
          >
            →
          </Button>
        </div>
      </div>
      {uploadReport ? (
        <div className="rounded-md border border-border/70 bg-muted/20 px-3 py-2 text-xs text-muted-foreground">
          Импорт завершён: применено {uploadReport.applied} строк, ошибок: {uploadReport.errors.length}
        </div>
      ) : null}
      <DateRangePopover
        open={draftRangeOpen}
        onOpenChange={setDraftRangeOpen}
        anchorRef={draftRangeAnchorRef}
        dateFrom={draftFrom}
        dateTo={draftTo}
        onApply={({ dateFrom, dateTo }) => {
          setDraftFrom(dateFrom);
          setDraftTo(dateTo);
        }}
      />
      <Dialog open={exportOpen} onOpenChange={setExportOpen}>
        <DialogContent className="gap-0 overflow-hidden border-0 p-0 shadow-lg sm:max-w-lg" showCloseButton>
          <div className="border-b bg-gradient-to-br from-primary/12 via-primary/5 to-background px-5 py-4">
            <div className="flex gap-3">
              <div className="flex size-11 shrink-0 items-center justify-center rounded-xl bg-primary/15 text-primary ring-1 ring-primary/20">
                <FileSpreadsheet className="size-5" />
              </div>
              <div className="min-w-0 space-y-1 pr-6">
                <DialogTitle className="text-base font-semibold leading-tight">Excel eksport</DialogTitle>
                <DialogDescription className="text-xs leading-relaxed text-muted-foreground">
                  Joriy sahifa va filtrlangan qatorlar eksport qilinadi. Fayl{" "}
                  <span className="font-medium text-foreground/80">.xlsx</span> formatida.
                </DialogDescription>
              </div>
            </div>
          </div>
          <div className="space-y-2.5 p-4">
            <button
              type="button"
              disabled={exportBusy || rows.length === 0}
              onClick={() => exportExcelSummary()}
              className={cn(
                "flex w-full flex-col gap-0.5 rounded-xl border border-border/80 bg-card px-4 py-3.5 text-left shadow-sm transition-colors",
                "hover:border-primary/35 hover:bg-muted/35",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                "disabled:pointer-events-none disabled:opacity-45"
              )}
            >
              <span className="text-sm font-medium">Umumiy ro‘yxat</span>
              <span className="text-xs text-muted-foreground">
                Hujjatlar ro‘yxati: status, sana, sklad, summalar va izoh
              </span>
            </button>
            <button
              type="button"
              disabled={exportBusy || rows.length === 0}
              onClick={() => void exportExcelDetailed()}
              className={cn(
                "flex w-full flex-col gap-0.5 rounded-xl border border-border/80 bg-card px-4 py-3.5 text-left shadow-sm transition-colors",
                "hover:border-primary/35 hover:bg-muted/35",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                "disabled:pointer-events-none disabled:opacity-45"
              )}
            >
              <span className="text-sm font-medium">
                {exportBusy ? "Загрузка…" : "Batafsil (mahsulot qatorlari)"}
              </span>
              <span className="text-xs text-muted-foreground">
                Har hujjat ichidagi barcha product qatorlari bilan eksport
              </span>
            </button>
            {rows.length === 0 ? (
              <p className="rounded-lg bg-muted/50 px-3 py-2 text-center text-xs text-muted-foreground">
                Eksport uchun jadvalda kamida bitta qator bo‘lishi kerak.
              </p>
            ) : null}
          </div>
        </DialogContent>
      </Dialog>
    </PageShell>
  );
}

"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { api } from "@/lib/api";
import { STALE } from "@/lib/query-stale";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { DateRangePopover, formatDateRangeButton } from "@/components/ui/date-range-popover";
import { PageHeader } from "@/components/dashboard/page-header";
import { PageShell } from "@/components/dashboard/page-shell";
import {
  CalendarDays,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  ChevronUp,
  Download,
  RefreshCw
} from "lucide-react";

type WarehouseOpt = { id: number; name: string };
type CategoryOpt = { id: number; name: string };
type ProductOpt = { id: number; name: string; sku: string };
type Row = {
  product_id: number;
  category_name?: string | null;
  product_name: string;
  beginning_stock: string;
  incoming_receipt: string;
  correction_plus: string;
  return_from_shelf: string;
  inventory_plus: string;
  transfer_plus: string;
  partial_return: string;
  sale_out: string;
  supplier_return: string;
  correction_minus: string;
  bonus_out: string;
  writeoff_out: string;
  transfer_minus: string;
  inventory_minus: string;
  canceled_receipt: string;
  ending_stock: string;
  volume_m3: string;
};
type Payload = { data: Row[]; total: number; page: number; limit: number };
type SortKey =
  | "product_name"
  | "beginning_stock"
  | "incoming_receipt"
  | "sale_out"
  | "ending_stock"
  | "volume_m3";
type SortDir = "asc" | "desc";

function todayYmd() {
  return new Date().toISOString().slice(0, 10);
}

function fmt(v: string) {
  const n = Number(v);
  if (!Number.isFinite(n)) return v;
  return n.toLocaleString("ru-RU", { maximumFractionDigits: 3 });
}

export function MaterialReportWorkspace({ tenantSlug }: { tenantSlug: string }) {
  const [dateFrom, setDateFrom] = useState(todayYmd());
  const [dateTo, setDateTo] = useState(todayYmd());
  const [warehouseId, setWarehouseId] = useState("");
  const [categoryId, setCategoryId] = useState("");
  const [productId, setProductId] = useState("");
  const [qtyMode, setQtyMode] = useState<"all" | "positive" | "zero">("all");
  const [q, setQ] = useState("");
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(50);
  const [dateOpen, setDateOpen] = useState(false);
  const [excelMenuOpen, setExcelMenuOpen] = useState(false);
  const [openCategory, setOpenCategory] = useState<string | null>(null);
  const [sortKey, setSortKey] = useState<SortKey>("product_name");
  const [sortDir, setSortDir] = useState<SortDir>("asc");
  const dateAnchorRef = useRef<HTMLButtonElement | null>(null);
  const excelMenuRef = useRef<HTMLDivElement | null>(null);

  const warehousesQ = useQuery({
    queryKey: ["warehouses", tenantSlug, "material-report"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: WarehouseOpt[] }>(`/api/${tenantSlug}/warehouses`);
      return data.data;
    }
  });
  const categoriesQ = useQuery({
    queryKey: ["categories", tenantSlug, "material-report"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: CategoryOpt[] }>(`/api/${tenantSlug}/product-categories`);
      return data.data;
    }
  });
  const productsQ = useQuery({
    queryKey: ["products", tenantSlug, "material-report"],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: ProductOpt[] }>(
        `/api/${tenantSlug}/products?page=1&limit=300&is_active=true`
      );
      return data.data;
    }
  });

  const listQ = useQuery({
    queryKey: ["material-report", tenantSlug, dateFrom, dateTo, warehouseId, categoryId, productId, qtyMode, q, page],
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list,
    queryFn: async () => {
      const p = new URLSearchParams({
        date_from: dateFrom,
        date_to: dateTo,
        qty_mode: qtyMode,
        page: String(page),
        limit: String(limit)
      });
      if (warehouseId) p.set("warehouse_id", warehouseId);
      if (categoryId) p.set("category_id", categoryId);
      if (productId) p.set("product_id", productId);
      if (q.trim()) p.set("q", q.trim());
      const { data } = await api.get<Payload>(`/api/${tenantSlug}/stock/material-report?${p.toString()}`);
      return data;
    }
  });

  const rows = listQ.data?.data ?? [];
  const total = listQ.data?.total ?? 0;
  const pages = Math.max(1, Math.ceil(total / limit));
  const sortedRows = useMemo(() => {
    const copy = [...rows];
    copy.sort((a, b) => {
      if (sortKey === "product_name") {
        const cmp = a.product_name.localeCompare(b.product_name, undefined, { sensitivity: "base" });
        return sortDir === "asc" ? cmp : -cmp;
      }
      const av = Number(a[sortKey]) || 0;
      const bv = Number(b[sortKey]) || 0;
      return sortDir === "asc" ? av - bv : bv - av;
    });
    return copy;
  }, [rows, sortDir, sortKey]);
  const groupedRows = useMemo(() => {
    const map = new Map<string, Row[]>();
    for (const row of sortedRows) {
      const key = row.category_name?.trim() ? row.category_name : "Без категории";
      if (!map.has(key)) map.set(key, []);
      map.get(key)!.push(row);
    }
    return [...map.entries()].map(([category, items]) => ({ category, items }));
  }, [sortedRows]);
  const totals = useMemo(() => {
    const sum = (k: keyof Row) => sortedRows.reduce((a, r) => a + (Number(r[k]) || 0), 0);
    return {
      beginning: sum("beginning_stock"),
      inRec: sum("incoming_receipt"),
      corrP: sum("correction_plus"),
      ret: sum("return_from_shelf"),
      invP: sum("inventory_plus"),
      trP: sum("transfer_plus"),
      part: sum("partial_return"),
      sale: sum("sale_out"),
      corrM: sum("correction_minus"),
      bonus: sum("bonus_out"),
      trM: sum("transfer_minus"),
      invM: sum("inventory_minus"),
      cancel: sum("canceled_receipt"),
      ending: sum("ending_stock"),
      volume: sum("volume_m3")
    };
  }, [sortedRows]);
  const categoryTotals = useMemo(() => {
    const byCat: Record<string, ReturnType<typeof categoryAggInit>> = {};
    for (const g of groupedRows) {
      byCat[g.category] = g.items.reduce((acc, r) => categoryAggAdd(acc, r), categoryAggInit());
    }
    return byCat;
  }, [groupedRows]);

  async function exportExcel(mode: "detailed" | "summary") {
    const p = new URLSearchParams({ date_from: dateFrom, date_to: dateTo, qty_mode: qtyMode, mode });
    if (warehouseId) p.set("warehouse_id", warehouseId);
    if (categoryId) p.set("category_id", categoryId);
    if (productId) p.set("product_id", productId);
    if (q.trim()) p.set("q", q.trim());
    const res = await api.get<Blob>(`/api/${tenantSlug}/stock/material-report/export?${p.toString()}`, { responseType: "blob" });
    const u = URL.createObjectURL(res.data);
    const a = document.createElement("a");
    a.href = u;
    a.download = `material-report-${mode}-${dateFrom}-${dateTo}.xlsx`;
    a.click();
    URL.revokeObjectURL(u);
  }

  function onSort(key: SortKey) {
    if (sortKey === key) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
      return;
    }
    setSortKey(key);
    setSortDir(key === "product_name" ? "asc" : "desc");
  }
  function sortIcon(key: SortKey) {
    if (sortKey !== key) return <ChevronDown className="ml-1 size-3 opacity-40" />;
    return sortDir === "asc" ? <ChevronUp className="ml-1 size-3" /> : <ChevronDown className="ml-1 size-3" />;
  }
  function shiftDateRange(days: number) {
    const from = new Date(`${dateFrom}T00:00:00`);
    const to = new Date(`${dateTo}T00:00:00`);
    from.setDate(from.getDate() + days);
    to.setDate(to.getDate() + days);
    setDateFrom(from.toISOString().slice(0, 10));
    setDateTo(to.toISOString().slice(0, 10));
    setPage(1);
  }

  useEffect(() => {
    if (!excelMenuOpen) return;
    const onDocClick = (e: MouseEvent) => {
      const target = e.target as Node;
      if (excelMenuRef.current?.contains(target)) return;
      setExcelMenuOpen(false);
    };
    document.addEventListener("mousedown", onDocClick);
    return () => document.removeEventListener("mousedown", onDocClick);
  }, [excelMenuOpen]);

  return (
    <PageShell>
      <PageHeader title="Материальный отчёт" />
      <Card className="rounded-lg border bg-card shadow-sm">
        <CardContent className="space-y-0 p-3 sm:p-4">
          <div className="rounded-md border bg-muted/20 p-2.5 sm:p-3">
            <div className="mb-2 flex flex-wrap items-center justify-between gap-2">
              <h3 className="text-base font-semibold">Материальный отчет</h3>
              <div className="flex items-center gap-1.5">
                <div className="flex items-center gap-1.5">
                  <Button type="button" variant="outline" size="icon" className="h-8 w-8" onClick={() => shiftDateRange(-1)}>
                    <ChevronLeft className="size-4" />
                  </Button>
                  <button
                    ref={dateAnchorRef}
                    type="button"
                    className="inline-flex h-8 min-w-[13rem] items-center justify-between rounded-md border border-input bg-background px-2 text-xs"
                    onClick={() => setDateOpen((v) => !v)}
                  >
                    <span className="truncate">{formatDateRangeButton(dateFrom, dateTo)}</span>
                    <CalendarDays className="size-3.5 shrink-0 text-muted-foreground" />
                  </button>
                  <Button type="button" variant="outline" size="icon" className="h-8 w-8" onClick={() => shiftDateRange(1)}>
                    <ChevronRight className="size-4" />
                  </Button>
                </div>
              </div>
            </div>
            <div className="flex flex-wrap items-end gap-2">
            <select
              className="h-8 min-w-[11rem] rounded-md border border-input bg-background px-2 text-xs"
              value={categoryId}
              onChange={(e) => {
                setCategoryId(e.target.value);
                setPage(1);
              }}
            >
              <option value="">Категория продукта</option>
              {(categoriesQ.data ?? []).map((c) => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
            <select
              className="h-8 min-w-[9rem] rounded-md border border-input bg-background px-2 text-xs"
              value={qtyMode}
              onChange={(e) => {
                setQtyMode(e.target.value as "all" | "positive" | "zero");
                setPage(1);
              }}
            >
              <option value="all">Кол-во / количество</option>
              <option value="positive">С остатком</option>
              <option value="zero">Нулевые</option>
            </select>
            <select
              className="h-8 min-w-[9rem] rounded-md border border-input bg-background px-2 text-xs"
              value={warehouseId}
              onChange={(e) => {
                setWarehouseId(e.target.value);
                setPage(1);
              }}
            >
              <option value="">Склад</option>
              {(warehousesQ.data ?? []).map((w) => <option key={w.id} value={w.id}>{w.name}</option>)}
            </select>
            <select
              className="h-8 min-w-[11rem] rounded-md border border-input bg-background px-2 text-xs"
              value={productId}
              onChange={(e) => {
                setProductId(e.target.value);
                setPage(1);
              }}
            >
              <option value="">Продукт</option>
              {(productsQ.data ?? []).map((p) => <option key={p.id} value={p.id}>{p.sku} · {p.name}</option>)}
            </select>
            <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => void listQ.refetch()}><RefreshCw className={listQ.isFetching ? "animate-spin" : ""} /></Button>
            <div className="relative ml-auto" ref={excelMenuRef}>
              <Button
                variant="outline"
                className="h-8 text-xs"
                onClick={() => setExcelMenuOpen((v) => !v)}
              >
                <Download className="mr-1.5 size-3.5" />
                Excel
                <ChevronDown className="ml-1.5 size-3.5" />
              </Button>
              {excelMenuOpen ? (
                <div className="absolute left-0 top-9 z-20 min-w-[10.5rem] rounded-md border bg-popover p-1 shadow-md">
                  <button
                    type="button"
                    className="block w-full rounded px-2 py-1.5 text-left text-xs hover:bg-muted"
                    onClick={() => {
                      setExcelMenuOpen(false);
                      void exportExcel("summary");
                    }}
                  >
                    Excel (Общий)
                  </button>
                  <button
                    type="button"
                    className="block w-full rounded px-2 py-1.5 text-left text-xs hover:bg-muted"
                    onClick={() => {
                      setExcelMenuOpen(false);
                      void exportExcel("detailed");
                    }}
                  >
                    Excel (Детальный)
                  </button>
                </div>
              ) : null}
            </div>
            </div>
          </div>

          <div className="h-4" />

          <div className="rounded-md border bg-background p-1 shadow-sm sm:p-1.5">
            <div className="overflow-auto rounded-md border bg-background">
            <table className="min-w-[1800px] w-full text-xs">
              <thead className="bg-muted/40">
                <tr className="border-b">
                  <th rowSpan={2} className="px-2 py-2 text-left">
                    <button type="button" className="inline-flex items-center" onClick={() => onSort("product_name")}>Категория товара {sortIcon("product_name")}</button>
                  </th>
                  <th rowSpan={2} className="px-2 py-2 text-right">
                    <button type="button" className="inline-flex items-center" onClick={() => onSort("beginning_stock")}>Остаток на начало {sortIcon("beginning_stock")}</button>
                  </th>
                  <th colSpan={6} className="bg-emerald-500/10 px-2 py-2 text-center text-emerald-700 dark:text-emerald-300">Приход</th>
                  <th colSpan={8} className="bg-rose-500/10 px-2 py-2 text-center text-rose-700 dark:text-rose-300">Расход</th>
                  <th rowSpan={2} className="px-2 py-2 text-right">
                    <button type="button" className="inline-flex items-center" onClick={() => onSort("ending_stock")}>Остаток на конец {sortIcon("ending_stock")}</button>
                  </th>
                  <th rowSpan={2} className="px-2 py-2 text-right">
                    <button type="button" className="inline-flex items-center" onClick={() => onSort("volume_m3")}>Объем {sortIcon("volume_m3")}</button>
                  </th>
                </tr>
                <tr className="border-b">
                  <th className="bg-emerald-500/5 px-2 py-2 text-right">Поступление</th>
                  <th className="bg-emerald-500/5 px-2 py-2 text-right">Корректировка+</th>
                  <th className="bg-emerald-500/5 px-2 py-2 text-right">Возврат с полки</th>
                  <th className="bg-emerald-500/5 px-2 py-2 text-right">Инвентаризация+</th>
                  <th className="bg-emerald-500/5 px-2 py-2 text-right">Перемещения+</th>
                  <th className="bg-emerald-500/5 px-2 py-2 text-right">Частичный возврат</th>
                  <th className="border-l-2 border-rose-300 bg-rose-500/5 px-2 py-2 text-right">
                    <button type="button" className="inline-flex items-center" onClick={() => onSort("sale_out")}>Продажа {sortIcon("sale_out")}</button>
                  </th>
                  <th className="bg-rose-500/5 px-2 py-2 text-right">Возврат поставщика</th>
                  <th className="bg-rose-500/5 px-2 py-2 text-right">Корректировка-</th>
                  <th className="bg-rose-500/5 px-2 py-2 text-right">Бонус</th>
                  <th className="bg-rose-500/5 px-2 py-2 text-right">Списание</th>
                  <th className="bg-rose-500/5 px-2 py-2 text-right">Перемещения-</th>
                  <th className="bg-rose-500/5 px-2 py-2 text-right">Инвентаризация-</th>
                  <th className="bg-rose-500/5 px-2 py-2 text-right">Отмена поступления</th>
                </tr>
              </thead>
              <tbody>
                {groupedRows.flatMap((g) => {
                  const isOpen = openCategory === g.category;
                  const agg = categoryTotals[g.category];
                  const rowsOut = [
                    <tr key={`cat-${g.category}`} className="border-b bg-muted/25">
                      <td colSpan={18} className="px-2 py-1.5">
                        <button
                          type="button"
                          className="flex w-full items-center justify-between text-left font-medium"
                          onClick={() => setOpenCategory((prev) => (prev === g.category ? null : g.category))}
                        >
                          <span>{g.category} ({g.items.length})</span>
                          {isOpen ? <ChevronUp className="size-4" /> : <ChevronDown className="size-4" />}
                        </button>
                      </td>
                    </tr>
                  ];
                  if (isOpen) {
                    rowsOut.push(
                      ...g.items.map((r) => (
                        <tr key={`product-${g.category}-${r.product_id}`} className="border-b">
                          <td className="px-2 py-1">{r.product_name}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.beginning_stock)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.incoming_receipt)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.correction_plus)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.return_from_shelf)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.inventory_plus)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.transfer_plus)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.partial_return)}</td>
                          <td className="border-l-2 border-rose-200 px-2 py-1 text-right">{fmt(r.sale_out)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.supplier_return)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.correction_minus)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.bonus_out)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.writeoff_out)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.transfer_minus)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.inventory_minus)}</td>
                          <td className="px-2 py-1 text-right">{fmt(r.canceled_receipt)}</td>
                          <td className="px-2 py-1 text-right font-medium">{fmt(r.ending_stock)}</td>
                          <td className="px-2 py-1 text-right">{Number(r.volume_m3).toLocaleString("ru-RU", { maximumFractionDigits: 6 })}</td>
                        </tr>
                      ))
                    );
                  }
                  return rowsOut;
                })}
                <tr className="bg-muted/30 font-semibold">
                  <td className="px-2 py-2">Общий</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.beginning))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.inRec))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.corrP))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.ret))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.invP))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.trP))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.part))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.sale))}</td>
                  <td className="px-2 py-2 text-right">0</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.corrM))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.bonus))}</td>
                  <td className="px-2 py-2 text-right">0</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.trM))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.invM))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.cancel))}</td>
                  <td className="px-2 py-2 text-right">{fmt(String(totals.ending))}</td>
                  <td className="px-2 py-2 text-right">{totals.volume.toLocaleString("ru-RU", { maximumFractionDigits: 6 })}</td>
                </tr>
              </tbody>
            </table>
            </div>
          </div>

          <div className="mt-3 flex items-center justify-between rounded-md border bg-muted/10 px-2 py-1.5 text-xs text-muted-foreground">
            <span>Показано {rows.length} / {total}</span>
            <div className="flex items-center gap-2">
              <select
                className="h-8 rounded-md border border-input bg-background px-2 text-xs"
                value={limit}
                onChange={(e) => {
                  setLimit(Number(e.target.value));
                  setPage(1);
                }}
              >
                <option value={25}>25 / стр</option>
                <option value={50}>50 / стр</option>
                <option value={100}>100 / стр</option>
              </select>
              <div className="flex gap-1">
              <Button size="sm" variant="outline" disabled={page <= 1} onClick={() => setPage((p) => p - 1)}>←</Button>
              <span className="px-2 py-1">{page}/{pages}</span>
              <Button size="sm" variant="outline" disabled={page >= pages} onClick={() => setPage((p) => p + 1)}>→</Button>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>
      <DateRangePopover
        open={dateOpen}
        onOpenChange={setDateOpen}
        anchorRef={dateAnchorRef}
        dateFrom={dateFrom}
        dateTo={dateTo}
        onApply={({ dateFrom: from, dateTo: to }) => {
          setDateFrom(from);
          setDateTo(to);
          setDateOpen(false);
          setPage(1);
        }}
      />
    </PageShell>
  );
}

function categoryAggInit() {
  return {
    beginning: 0,
    inRec: 0,
    sale: 0,
    ending: 0
  };
}

function categoryAggAdd(acc: ReturnType<typeof categoryAggInit>, r: Row) {
  acc.beginning += Number(r.beginning_stock) || 0;
  acc.inRec += Number(r.incoming_receipt) || 0;
  acc.sale += Number(r.sale_out) || 0;
  acc.ending += Number(r.ending_stock) || 0;
  return acc;
}

"use client";

import { PageHeader } from "@/components/dashboard/page-header";
import { PageShell } from "@/components/dashboard/page-shell";
import { TableColumnSettingsDialog } from "@/components/data-table/table-column-settings-dialog";
import { DateRangePopover, formatDateRangeButton, localYmd } from "@/components/ui/date-range-popover";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { FilterSearchableSelect } from "@/components/ui/filter-searchable-select";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useUserTablePrefs } from "@/hooks/use-user-table-prefs";
import { api } from "@/lib/api";
import { STALE } from "@/lib/query-stale";
import { cn } from "@/lib/utils";
import { useQuery } from "@tanstack/react-query";
import {
  ArrowDown,
  ArrowUp,
  ArrowUpDown,
  CalendarDays,
  CalendarRange,
  Download,
  Hourglass,
  LayoutGrid,
  ListFilter,
  RefreshCw,
  Search
} from "lucide-react";
import { useMemo, useRef, useState } from "react";

type WarehouseOpt = { id: number; name: string; stock_purpose: string };
type CategoryOpt = { id: number; name: string };
type ProductOpt = { id: number; sku: string; name: string };

type RecommendedRow = {
  product_id: number;
  sku: string;
  category_name: string | null;
  product_name: string;
  stock_qty: string;
  avg_daily_sales: string;
  coverage_days: string;
  rec_stock_6: string;
  rec_stock_10: string;
  rec_stock_30: string;
  rec_stock_month_end: string;
  category_share_pct: string;
  sold_qty: string;
  risk_level: "low" | "medium" | "healthy" | "overstock";
};

type Payload = {
  data: RecommendedRow[];
  total: number;
  page: number;
  limit: number;
  kpi: { total_days: number; passed_days: number; remaining_days: number };
};

type QtyMode = "all" | "positive" | "zero";
type SortBy = "sku" | "category" | "name" | "stock" | "avg" | "coverage" | "r6" | "r10" | "r30" | "rme" | "share";
type SortDir = "asc" | "desc";

const TABLE_ID = "stock.recommended.v1";
const COLS = [
  { id: "sku", label: "Код" },
  { id: "category", label: "Категория" },
  { id: "name", label: "Ассортимент" },
  { id: "stock", label: "Товар на складе" },
  { id: "avg", label: "Сред. дневные продажи" },
  { id: "coverage", label: "Текущ. запас хватит на... дней" },
  { id: "r6", label: "Рек. запас на 6 дней" },
  { id: "r10", label: "Рек. запас на 10 дней" },
  { id: "r30", label: "Рек. запас на 30 дней" },
  { id: "rme", label: "Рек. запас до конца месяца" },
  { id: "share", label: "Доля в категории, %" }
] as const;
const DEFAULT_ORDER = COLS.map((c) => c.id);
const NUMERIC = new Set(["stock", "avg", "coverage", "r6", "r10", "r30", "rme", "share"]);

function monthStartYmd(): string {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-01`;
}

function colLabel(id: string): string {
  return COLS.find((c) => c.id === id)?.label ?? id;
}

function fmtNum(v: string, digits = 2): string {
  const n = Number(v);
  if (!Number.isFinite(n)) return "0";
  return n.toLocaleString("ru-RU", { minimumFractionDigits: 0, maximumFractionDigits: digits });
}

function rowRiskClass(r: RecommendedRow): string {
  if (r.risk_level === "low") return "bg-destructive/10 hover:bg-destructive/15";
  if (r.risk_level === "overstock") return "bg-amber-500/12 hover:bg-amber-500/18";
  if (r.risk_level === "medium") return "bg-yellow-500/10 hover:bg-yellow-500/15";
  return "hover:bg-muted/20";
}

function coverageClass(r: RecommendedRow): string {
  if (r.risk_level === "low") return "text-destructive font-semibold";
  if (r.risk_level === "overstock") return "text-amber-700 dark:text-amber-400 font-semibold";
  if (r.risk_level === "medium") return "text-yellow-700 dark:text-yellow-400 font-semibold";
  return "text-emerald-700 dark:text-emerald-400 font-semibold";
}

export function StockRecommendedWorkspace({ tenantSlug }: { tenantSlug: string }) {
  const today = localYmd(new Date());
  const [draftDateFrom, setDraftDateFrom] = useState(monthStartYmd);
  const [draftDateTo, setDraftDateTo] = useState(today);
  const [draftWarehouseId, setDraftWarehouseId] = useState("");
  const [draftCategoryId, setDraftCategoryId] = useState("");
  const [draftProductId, setDraftProductId] = useState("");
  const [draftQtyMode, setDraftQtyMode] = useState<QtyMode>("all");
  const [searchDraft, setSearchDraft] = useState("");
  const [sortBy, setSortBy] = useState<SortBy>("category");
  const [sortDir, setSortDir] = useState<SortDir>("asc");
  const [filters, setFilters] = useState({
    dateFrom: monthStartYmd(),
    dateTo: today,
    warehouseId: "",
    categoryId: "",
    productId: "",
    qtyMode: "all" as QtyMode,
    q: ""
  });
  const [page, setPage] = useState(1);
  const [dateOpen, setDateOpen] = useState(false);
  const [columnDialogOpen, setColumnDialogOpen] = useState(false);
  const [exporting, setExporting] = useState(false);
  const dateAnchorRef = useRef<HTMLButtonElement | null>(null);

  const prefs = useUserTablePrefs({
    tenantSlug,
    tableId: TABLE_ID,
    defaultColumnOrder: DEFAULT_ORDER,
    defaultPageSize: 25,
    allowedPageSizes: [10, 25, 50, 100]
  });

  const warehousesQ = useQuery({
    queryKey: ["warehouses", tenantSlug, "recommended"],
    queryFn: async () => {
      const { data } = await api.get<{ data: WarehouseOpt[] }>(`/api/${tenantSlug}/warehouses`);
      return data.data.filter((w) => w.stock_purpose === "sales");
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference
  });
  const categoriesQ = useQuery({
    queryKey: ["product-categories", tenantSlug, "recommended"],
    queryFn: async () => {
      const { data } = await api.get<{ data: CategoryOpt[] }>(`/api/${tenantSlug}/product-categories`);
      return data.data;
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference
  });
  const productsQ = useQuery({
    queryKey: ["products-recommended", tenantSlug],
    queryFn: async () => {
      const out: ProductOpt[] = [];
      let cur = 1;
      const limit = 200;
      for (;;) {
        const { data } = await api.get<{ data: ProductOpt[]; total: number }>(
          `/api/${tenantSlug}/products?page=${cur}&limit=${limit}&is_active=true`
        );
        out.push(...data.data);
        if (out.length >= data.total || data.data.length < limit) break;
        cur += 1;
      }
      return out;
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.reference
  });

  const listQ = useQuery({
    queryKey: [
      "stock-recommended",
      tenantSlug,
      filters.dateFrom,
      filters.dateTo,
      filters.warehouseId,
      filters.categoryId,
      filters.productId,
      filters.qtyMode,
      filters.q,
      sortBy,
      sortDir,
      page,
      prefs.pageSize
    ],
    queryFn: async () => {
      const p = new URLSearchParams({
        date_from: filters.dateFrom,
        date_to: filters.dateTo,
        qty_mode: filters.qtyMode,
        sort_by: sortBy,
        sort_dir: sortDir,
        page: String(page),
        limit: String(prefs.pageSize)
      });
      if (filters.warehouseId) p.set("warehouse_id", filters.warehouseId);
      if (filters.categoryId) p.set("category_id", filters.categoryId);
      if (filters.productId) p.set("product_id", filters.productId);
      if (filters.q.trim()) p.set("q", filters.q.trim());
      const { data } = await api.get<Payload>(`/api/${tenantSlug}/stock/recommended?${p.toString()}`);
      return data;
    },
    enabled: Boolean(tenantSlug),
    staleTime: STALE.list
  });

  const visibleCols = prefs.visibleColumnOrder;
  const rows = listQ.data?.data ?? [];
  const total = listQ.data?.total ?? 0;
  const totalPages = Math.max(1, Math.ceil(total / prefs.pageSize));
  const kpi = listQ.data?.kpi ?? { total_days: 0, passed_days: 0, remaining_days: 0 };

  function applyFilters() {
    setFilters({
      dateFrom: draftDateFrom,
      dateTo: draftDateTo,
      warehouseId: draftWarehouseId,
      categoryId: draftCategoryId,
      productId: draftProductId,
      qtyMode: draftQtyMode,
      q: searchDraft.trim()
    });
    setPage(1);
  }

  function resetFilters() {
    const from = monthStartYmd();
    const to = localYmd(new Date());
    setDraftDateFrom(from);
    setDraftDateTo(to);
    setDraftWarehouseId("");
    setDraftCategoryId("");
    setDraftProductId("");
    setDraftQtyMode("all");
    setSearchDraft("");
    setFilters({
      dateFrom: from,
      dateTo: to,
      warehouseId: "",
      categoryId: "",
      productId: "",
      qtyMode: "all",
      q: ""
    });
    setPage(1);
  }

  async function downloadExcel() {
    setExporting(true);
    try {
      const p = new URLSearchParams({
        date_from: filters.dateFrom,
        date_to: filters.dateTo,
        qty_mode: filters.qtyMode
      });
      if (filters.warehouseId) p.set("warehouse_id", filters.warehouseId);
      if (filters.categoryId) p.set("category_id", filters.categoryId);
      if (filters.productId) p.set("product_id", filters.productId);
      if (filters.q.trim()) p.set("q", filters.q.trim());
      p.set("sort_by", sortBy);
      p.set("sort_dir", sortDir);
      const res = await api.get(`/api/${tenantSlug}/stock/recommended/export?${p.toString()}`, {
        responseType: "arraybuffer"
      });
      const blob = new Blob([res.data], {
        type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
      });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = "recommended-stock.xlsx";
      a.click();
      URL.revokeObjectURL(url);
    } finally {
      setExporting(false);
    }
  }

  const from = total === 0 ? 0 : (page - 1) * prefs.pageSize + 1;
  const to = Math.min(page * prefs.pageSize, total);
  const SORT_BY_COL: Partial<Record<string, SortBy>> = {
    sku: "sku",
    category: "category",
    name: "name",
    stock: "stock",
    avg: "avg",
    coverage: "coverage",
    r6: "r6",
    r10: "r10",
    r30: "r30",
    rme: "rme",
    share: "share"
  };

  function toggleSort(colId: string) {
    const mapped = SORT_BY_COL[colId];
    if (!mapped) return;
    setPage(1);
    if (sortBy === mapped) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
      return;
    }
    setSortBy(mapped);
    setSortDir("asc");
  }

  const colRender = useMemo(
    () => ({
      sku: (r: RecommendedRow) => r.sku,
      category: (r: RecommendedRow) => r.category_name ?? "—",
      name: (r: RecommendedRow) => r.product_name,
      stock: (r: RecommendedRow) => fmtNum(r.stock_qty, 3),
      avg: (r: RecommendedRow) => fmtNum(r.avg_daily_sales, 3),
      coverage: (r: RecommendedRow) => <span className={coverageClass(r)}>{fmtNum(r.coverage_days, 2)}</span>,
      r6: (r: RecommendedRow) => fmtNum(r.rec_stock_6, 3),
      r10: (r: RecommendedRow) => fmtNum(r.rec_stock_10, 3),
      r30: (r: RecommendedRow) => fmtNum(r.rec_stock_30, 3),
      rme: (r: RecommendedRow) => fmtNum(r.rec_stock_month_end, 3),
      share: (r: RecommendedRow) => fmtNum(r.category_share_pct, 2)
    }),
    []
  );

  return (
    <PageShell>
      <PageHeader
        title="Остатки товара на складе (рекомендованный запас)"
        description="Forecast по складу: среднесуточные продажи, покрытие запаса и рекомендованный объём пополнения."
      />

      <div className="orders-hub-section orders-hub-section--filters orders-hub-section--stack-tight">
        <Card className="rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
          <CardContent className="space-y-2 p-3.5 sm:p-4">
            <div className="flex flex-wrap items-center justify-between gap-2">
              <p className="text-xs font-semibold uppercase tracking-wide text-foreground/80">Фильтр</p>
              <button
                ref={dateAnchorRef}
                type="button"
                className="inline-flex h-9 min-w-[14rem] items-center justify-between rounded-md border border-input bg-background px-2.5 text-xs sm:min-w-[15rem]"
                onClick={() => setDateOpen((v) => !v)}
              >
                <span className="truncate">{formatDateRangeButton(draftDateFrom, draftDateTo)}</span>
                <CalendarDays className="size-3.5 shrink-0 text-muted-foreground" />
              </button>
            </div>
            <div className="flex flex-wrap items-end gap-2">
              <div className="w-[12rem] min-w-[12rem]">
                <FilterSearchableSelect
                  emptyLabel="Категория"
                  value={draftCategoryId}
                  onValueChange={setDraftCategoryId}
                  options={(categoriesQ.data ?? []).map((c) => ({
                    value: String(c.id),
                    label: c.name
                  }))}
                  searchPlaceholder="Поиск категории"
                  minPopoverWidth={280}
                  className="h-8 rounded-md px-2 text-xs"
                  emptyMessage="Категория не найдена"
                  searchable
                />
              </div>
              <div className="w-[12rem] min-w-[12rem]">
                <FilterSearchableSelect
                  emptyLabel="Склад"
                  value={draftWarehouseId}
                  onValueChange={setDraftWarehouseId}
                  options={(warehousesQ.data ?? []).map((w) => ({
                    value: String(w.id),
                    label: w.name
                  }))}
                  searchPlaceholder="Поиск склада"
                  minPopoverWidth={300}
                  className="h-8 rounded-md px-2 text-xs"
                  emptyMessage="Склад не найден"
                  searchable
                />
              </div>
              <div className="w-[12rem] min-w-[12rem]">
                <FilterSearchableSelect
                  emptyLabel="Ассортимент"
                  value={draftProductId}
                  onValueChange={setDraftProductId}
                  options={(productsQ.data ?? []).map((p) => ({
                    value: String(p.id),
                    label: p.name
                  }))}
                  searchPlaceholder="Поиск ассортимента"
                  minPopoverWidth={320}
                  className="h-8 rounded-md px-2 text-xs"
                  emptyMessage="Ассортимент не найден"
                  searchable
                />
              </div>
              <div className="w-[12rem] min-w-[12rem]">
                <FilterSearchableSelect
                  emptyLabel="Количество"
                  value={draftQtyMode}
                  onValueChange={(v) => setDraftQtyMode((v || "all") as QtyMode)}
                  options={[
                    { value: "all", label: "Количество" },
                    { value: "positive", label: "С остатком" },
                    { value: "zero", label: "Нулевые" }
                  ]}
                  searchable={false}
                  minPopoverWidth={220}
                  className="h-8 rounded-md px-2 text-xs"
                />
              </div>
              <div className="ml-auto flex items-center gap-1.5">
                  <Button
                    type="button"
                    variant="outline"
                    size="icon"
                    className="h-8 w-8 shrink-0"
                    onClick={resetFilters}
                    title="Сбросить фильтры"
                  >
                    <ListFilter className="size-4" />
                  </Button>
                  <Button
                    type="button"
                    className="h-8 min-w-[6.75rem] bg-teal-600 px-3 text-xs text-white hover:bg-teal-700"
                    onClick={applyFilters}
                  >
                    Применить
                  </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="mt-3 grid gap-3 md:grid-cols-3">
        <Card className="border-border/60">
          <CardContent className="flex items-center gap-3 p-3">
            <span className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md bg-cyan-500 text-white">
              <CalendarRange className="size-4" />
            </span>
            <div>
              <p className="text-xl font-semibold leading-none">{kpi.total_days}</p>
              <p className="mt-1 text-xs text-muted-foreground">Всего дней</p>
            </div>
          </CardContent>
        </Card>
        <Card className="border-border/60">
          <CardContent className="flex items-center gap-3 p-3">
            <span className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md bg-lime-500 text-white">
              <CalendarDays className="size-4" />
            </span>
            <div>
              <p className="text-xl font-semibold leading-none">{kpi.passed_days}</p>
              <p className="mt-1 text-xs text-muted-foreground">Пройдено дней</p>
            </div>
          </CardContent>
        </Card>
        <Card className="border-border/60">
          <CardContent className="flex items-center gap-3 p-3">
            <span className="inline-flex h-8 w-8 shrink-0 items-center justify-center rounded-md bg-fuchsia-500 text-white">
              <Hourglass className="size-4" />
            </span>
            <div>
              <p className="text-xl font-semibold leading-none">{kpi.remaining_days}</p>
              <p className="mt-1 text-xs text-muted-foreground">Осталось дней</p>
            </div>
          </CardContent>
        </Card>
      </div>

      <TableColumnSettingsDialog
        open={columnDialogOpen}
        onOpenChange={setColumnDialogOpen}
        title="Управление столбцами"
        description="Видимые столбцы и порядок сохраняются для вашей учётной записи."
        columns={[...COLS]}
        columnOrder={prefs.columnOrder}
        hiddenColumnIds={prefs.hiddenColumnIds}
        saving={prefs.saving}
        onSave={(next) => prefs.saveColumnLayout(next)}
        onReset={() => prefs.resetColumnLayout()}
      />

      <div className="orders-hub-section orders-hub-section--table mt-4">
        <Card className="overflow-hidden rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
          <CardContent className="p-0">
            <div className="table-toolbar flex flex-wrap items-end justify-between gap-3 border-b border-border/80 bg-muted/30 px-3 py-2 sm:px-4">
              <div className="flex flex-wrap items-end gap-2">
                <select
                  className="h-9 rounded-md border border-input bg-background px-2 text-sm"
                  value={String(prefs.pageSize)}
                  onChange={(e) => {
                    prefs.setPageSize(Number(e.target.value));
                    setPage(1);
                  }}
                >
                  <option value="10">10</option>
                  <option value="25">25</option>
                  <option value="50">50</option>
                  <option value="100">100</option>
                </select>
                <Button type="button" variant="outline" size="icon" className="h-9 w-9" onClick={() => setColumnDialogOpen(true)}>
                  <LayoutGrid className="size-4" />
                </Button>
                <div className="relative min-w-[180px] max-w-xs flex-1">
                  <Search className="pointer-events-none absolute left-2.5 top-1/2 size-4 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    className="h-9 bg-background pl-8"
                    placeholder="Поиск"
                    value={searchDraft}
                    onChange={(e) => setSearchDraft(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && applyFilters()}
                  />
                </div>
                <Button type="button" variant="outline" size="sm" className="h-9" disabled={exporting} onClick={() => void downloadExcel()}>
                  <Download className="mr-1 size-3.5" />
                  {exporting ? "…" : "Excel"}
                </Button>
                <Button type="button" variant="outline" size="icon" className="h-9 w-9" onClick={() => void listQ.refetch()}>
                  <RefreshCw className={cn("size-4", listQ.isFetching && "animate-spin")} />
                </Button>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full min-w-[1200px] border-collapse text-sm">
                {visibleCols.length === 0 ? (
                  <tbody>
                    <tr>
                      <td className="px-3 py-10 text-center text-muted-foreground">Нет видимых столбцов.</td>
                    </tr>
                  </tbody>
                ) : (
                  <>
                    <thead className="app-table-thead">
                      <tr className="text-left">
                        {visibleCols.map((colId) => {
                          const mapped = SORT_BY_COL[colId];
                          const active = mapped != null && sortBy === mapped;
                          return (
                            <th key={colId} className={cn("px-3 py-2.5 font-semibold", NUMERIC.has(colId) && "text-right")}>
                              {mapped ? (
                                <button
                                  type="button"
                                  onClick={() => toggleSort(colId)}
                                  className={cn(
                                    "inline-flex items-center gap-1 hover:text-foreground",
                                    NUMERIC.has(colId) && "ml-auto"
                                  )}
                                  title="Сортировка по столбцу"
                                >
                                  <span>{colLabel(colId)}</span>
                                  {active ? (
                                    sortDir === "asc" ? (
                                      <ArrowUp className="size-3.5" />
                                    ) : (
                                      <ArrowDown className="size-3.5" />
                                    )
                                  ) : (
                                    <ArrowUpDown className="size-3.5 text-muted-foreground" />
                                  )}
                                </button>
                              ) : (
                                colLabel(colId)
                              )}
                            </th>
                          );
                        })}
                      </tr>
                    </thead>
                    <tbody>
                      {listQ.isLoading ? (
                        <tr><td colSpan={visibleCols.length} className="px-3 py-10 text-center text-muted-foreground">Загрузка…</td></tr>
                      ) : rows.length === 0 ? (
                        <tr><td colSpan={visibleCols.length} className="px-3 py-10 text-center text-muted-foreground">Пусто</td></tr>
                      ) : (
                        rows.map((row) => (
                          <tr key={row.product_id} className={cn("border-b border-border/70", rowRiskClass(row))}>
                            {visibleCols.map((colId) => (
                              <td key={colId} className={cn("px-3 py-2", NUMERIC.has(colId) && "text-right tabular-nums")}>
                                {colRender[colId as keyof typeof colRender](row)}
                              </td>
                            ))}
                          </tr>
                        ))
                      )}
                    </tbody>
                  </>
                )}
              </table>
            </div>
            <div className="table-content-footer flex flex-wrap items-center justify-between gap-2 border-t border-border/80 bg-muted/25 px-3 py-3 text-xs sm:px-4">
              <span className="text-foreground/80">Показано {from}–{to} / {total}</span>
              <div className="flex items-center gap-1">
                <Button type="button" variant="outline" size="sm" className="h-7 px-2" disabled={page <= 1} onClick={() => setPage((p) => Math.max(1, p - 1))}>←</Button>
                <span className="tabular-nums text-foreground">{page} / {totalPages}</span>
                <Button type="button" variant="outline" size="sm" className="h-7 px-2" disabled={page >= totalPages} onClick={() => setPage((p) => p + 1)}>→</Button>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <DateRangePopover
        open={dateOpen}
        onOpenChange={setDateOpen}
        anchorRef={dateAnchorRef}
        dateFrom={draftDateFrom}
        dateTo={draftDateTo}
        onApply={({ dateFrom, dateTo }) => {
          setDraftDateFrom(dateFrom);
          setDraftDateTo(dateTo);
        }}
      />
    </PageShell>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { buttonVariants } from "@/components/ui/button-variants";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { apiFetch, useTenant } from "@/lib/api-client";
import { getUserFacingError } from "@/lib/error-utils";
import { useAuthStore, useAuthStoreHydrated, useEffectiveRole } from "@/lib/auth-store";
import { isAdminOrOperatorLikeRole } from "@/lib/distribution-roles";
import { cn } from "@/lib/utils";
import { formatNumberGrouped } from "@/lib/format-numbers";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useCallback, useEffect, useMemo, useState } from "react";

type Warehouse = { id: number; name: string };
type AgentPick = { id: number; fio: string; login: string; is_active: boolean };

type CategoryRow = { id: number; name: string; parent_id: number | null; is_active: boolean };

type ProductRow = {
  id: number;
  sku: string;
  name: string;
  unit: string;
  barcode: string | null;
  is_active: boolean;
  qty_per_block: number | null;
  category: { id: number; name: string } | null;
};

type LineDraft = { qty: string; block: string; batch_no: string; line_comment: string };

const emptyDraft = (): LineDraft => ({ qty: "", block: "", batch_no: "", line_comment: "" });

async function fetchAllProductsInCategory(
  tenant: string,
  categoryId: number,
  signal?: AbortSignal
): Promise<ProductRow[]> {
  const out: ProductRow[] = [];
  let page = 1;
  const limit = 100;
  for (;;) {
    if (signal?.aborted) throw new DOMException("Aborted", "AbortError");
    const params = new URLSearchParams({
      category_id: String(categoryId),
      limit: String(limit),
      page: String(page),
      is_active: "true",
    });
    const res = await apiFetch<{ data?: ProductRow[]; total?: number }>(
      `/api/${tenant}/products?${params}`,
      { signal }
    );
    const chunk = res.data ?? [];
    out.push(...chunk);
    const total = res.total ?? 0;
    if (chunk.length < limit || out.length >= total) break;
    page += 1;
  }
  return out.sort((a, b) => a.name.localeCompare(b.name, "uz"));
}

function parseQty(s: string): number {
  const n = Number.parseFloat(String(s).trim().replace(",", "."));
  return Number.isFinite(n) ? n : NaN;
}

function blockHint(p: ProductRow): string {
  const qpb = p.qty_per_block;
  if (qpb != null && qpb > 0) {
    return `${qpb} ${p.unit} / blok`;
  }
  return "—";
}

type StockApiRow = {
  product_id: number;
  qty: string;
  reserved_qty: string;
};

function parseDec(s: string): number {
  const n = Number.parseFloat(String(s).replace(",", "."));
  return Number.isFinite(n) ? n : 0;
}

export function TransferAmaliyotWorkspace() {
  const router = useRouter();
  const tenant = useTenant();
  const hydrated = useAuthStoreHydrated();
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const role = useEffectiveRole();
  const canWrite = isAdminOrOperatorLikeRole(role);

  const [warehouses, setWarehouses] = useState<Warehouse[]>([]);
  const [agents, setAgents] = useState<AgentPick[]>([]);
  const [agentFilterId, setAgentFilterId] = useState("");
  const [loadWh, setLoadWh] = useState(true);
  const [whError, setWhError] = useState<string | null>(null);

  const [categories, setCategories] = useState<CategoryRow[]>([]);
  const [loadCats, setLoadCats] = useState(true);
  const [catError, setCatError] = useState<string | null>(null);

  const [sourceId, setSourceId] = useState<string>("");
  const [destId, setDestId] = useState<string>("");
  const [comment, setComment] = useState("");
  const [plannedDate, setPlannedDate] = useState("");

  const [categoryId, setCategoryId] = useState<string>("");
  const [products, setProducts] = useState<ProductRow[]>([]);
  const [loadProducts, setLoadProducts] = useState(false);
  const [prodError, setProdError] = useState<string | null>(null);
  const [rowFilter, setRowFilter] = useState("");
  const [drafts, setDrafts] = useState<Record<number, LineDraft>>({});

  const [submitting, setSubmitting] = useState(false);
  const [formError, setFormError] = useState<string | null>(null);

  const [stockRows, setStockRows] = useState<StockApiRow[]>([]);
  const [loadStock, setLoadStock] = useState(false);
  const [stockError, setStockError] = useState<string | null>(null);

  useEffect(() => {
    if (!hydrated || !tenant || !sourceId) {
      setStockRows([]);
      setStockError(null);
      setLoadStock(false);
      return;
    }
    const wid = Number.parseInt(sourceId, 10);
    if (!Number.isFinite(wid)) return;
    let cancelled = false;
    setLoadStock(true);
    setStockError(null);
    void (async () => {
      try {
        const res = await apiFetch<{ data?: StockApiRow[] }>(
          `/api/${tenant}/stock?warehouse_id=${wid}`
        );
        if (!cancelled) setStockRows(res.data ?? []);
      } catch (e) {
        if (!cancelled) {
          setStockRows([]);
          setStockError(getUserFacingError(e, "Qoldiq yuklanmadi"));
        }
      } finally {
        if (!cancelled) setLoadStock(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [hydrated, tenant, sourceId]);

  const stockByProductId = useMemo(() => {
    const m = new Map<number, { qty: string; reserved: string; available: string }>();
    for (const r of stockRows) {
      const q = parseDec(r.qty);
      const resv = parseDec(r.reserved_qty);
      const av = Math.max(0, q - resv);
      m.set(r.product_id, {
        qty: r.qty,
        reserved: r.reserved_qty,
        available: av.toString(),
      });
    }
    return m;
  }, [stockRows]);

  useEffect(() => {
    if (!hydrated || !tenant) return;
    let cancelled = false;
    (async () => {
      setLoadWh(true);
      setWhError(null);
      try {
        const params = new URLSearchParams();
        if (agentFilterId.trim()) params.set("selected_agent_id", agentFilterId.trim());
        const qs = params.toString();
        const res = await apiFetch<{ data?: Warehouse[] }>(
          `/api/${tenant}/warehouses${qs ? `?${qs}` : ""}`
        );
        if (!cancelled) setWarehouses(res.data ?? []);
      } catch (e) {
        if (!cancelled) {
          setWhError(getUserFacingError(e, "Omborlar yuklanmadi"));
          setWarehouses([]);
        }
      } finally {
        if (!cancelled) setLoadWh(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [hydrated, tenant, agentFilterId]);

  useEffect(() => {
    if (!hydrated || !tenant) return;
    let cancelled = false;
    (async () => {
      try {
        const res = await apiFetch<{ data?: AgentPick[] }>(`/api/${tenant}/agents?is_active=true`);
        if (!cancelled) setAgents((res.data ?? []).filter((a) => a.is_active));
      } catch {
        if (!cancelled) setAgents([]);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [hydrated, tenant]);

  useEffect(() => {
    if (!sourceId.trim()) return;
    if (!warehouses.some((w) => String(w.id) === sourceId.trim())) setSourceId("");
  }, [sourceId, warehouses]);
  useEffect(() => {
    if (!destId.trim()) return;
    if (!warehouses.some((w) => String(w.id) === destId.trim())) setDestId("");
  }, [destId, warehouses]);

  useEffect(() => {
    if (!hydrated || !tenant) return;
    let cancelled = false;
    (async () => {
      setLoadCats(true);
      setCatError(null);
      try {
        const res = await apiFetch<{ data?: CategoryRow[] }>(`/api/${tenant}/product-categories`);
        const rows = (res.data ?? [])
          .filter((c) => c.is_active)
          .sort((a, b) => a.name.localeCompare(b.name, "uz"));
        if (!cancelled) setCategories(rows);
      } catch (e) {
        if (!cancelled) {
          setCatError(getUserFacingError(e, "Kategoriyalar yuklanmadi"));
          setCategories([]);
        }
      } finally {
        if (!cancelled) setLoadCats(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [hydrated, tenant]);

  useEffect(() => {
    if (!hydrated || !tenant || !categoryId) {
      setProducts([]);
      setProdError(null);
      setLoadProducts(false);
      return;
    }
    const cid = Number.parseInt(categoryId, 10);
    if (!Number.isFinite(cid)) return;

    const ac = new AbortController();
    setLoadProducts(true);
    setProdError(null);
    void (async () => {
      try {
        const list = await fetchAllProductsInCategory(tenant, cid, ac.signal);
        if (!ac.signal.aborted) {
          setProducts(list);
          setDrafts({});
          setRowFilter("");
        }
      } catch (e) {
        if (e instanceof Error && e.name === "AbortError") return;
        if (!ac.signal.aborted) {
          setProducts([]);
          setDrafts({});
          setProdError(getUserFacingError(e, "Mahsulotlar yuklanmadi"));
        }
      } finally {
        if (!ac.signal.aborted) setLoadProducts(false);
      }
    })();
    return () => ac.abort();
  }, [hydrated, tenant, categoryId]);

  const selectedCategoryName = useMemo(() => {
    const id = Number.parseInt(categoryId, 10);
    return categories.find((c) => c.id === id)?.name ?? null;
  }, [categories, categoryId]);

  const filteredProducts = useMemo(() => {
    const q = rowFilter.trim().toLowerCase();
    if (!q) return products;
    return products.filter(
      (p) =>
        p.name.toLowerCase().includes(q) ||
        p.sku.toLowerCase().includes(q) ||
        (p.barcode && p.barcode.toLowerCase().includes(q))
    );
  }, [products, rowFilter]);

  const summary = useMemo(() => {
    let withQty = 0;
    let sumQty = 0;
    let withBron = 0;
    for (const p of products) {
      const st = stockByProductId.get(p.id);
      if (st && parseDec(st.reserved) > 0) withBron += 1;
      const d = drafts[p.id] ?? emptyDraft();
      const q = parseQty(d.qty);
      if (Number.isFinite(q) && q > 0) {
        withQty += 1;
        sumQty += q;
      }
    }
    return {
      totalInCategory: products.length,
      linesWithQty: withQty,
      sumQty,
      withBron,
    };
  }, [products, drafts, stockByProductId]);

  const updateDraft = useCallback((productId: number, patch: Partial<LineDraft>) => {
    setDrafts((prev) => ({
      ...prev,
      [productId]: { ...(prev[productId] ?? emptyDraft()), ...patch },
    }));
  }, []);

  const setBlockForProduct = useCallback((productId: number, blockStr: string, p: ProductRow) => {
    setDrafts((prev) => {
      const cur = prev[productId] ?? emptyDraft();
      const next: LineDraft = { ...cur, block: blockStr };
      const blocks = Number.parseFloat(blockStr.replace(",", "."));
      const qpb = p.qty_per_block;
      if (qpb != null && qpb > 0 && Number.isFinite(blocks) && blocks > 0) {
        const total = blocks * qpb;
        next.qty =
          Number.isInteger(total) && Number.isInteger(blocks) && Number.isInteger(qpb)
            ? String(total)
            : String(Math.round(total * 1000) / 1000);
      }
      return { ...prev, [productId]: next };
    });
  }, []);

  const clearQuantities = useCallback(() => {
    setDrafts((prev) => {
      const next = { ...prev };
      for (const p of products) {
        next[p.id] = emptyDraft();
      }
      return next;
    });
  }, [products]);

  const destOptions = useMemo(() => {
    const sid = Number.parseInt(sourceId, 10);
    if (!Number.isFinite(sid)) return warehouses;
    return warehouses.filter((w) => w.id !== sid);
  }, [warehouses, sourceId]);

  const onSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormError(null);
    const src = Number.parseInt(sourceId, 10);
    const dst = Number.parseInt(destId, 10);
    if (!Number.isFinite(src) || !Number.isFinite(dst)) {
      setFormError("Manba va qabul omborini tanlang.");
      return;
    }
    if (src === dst) {
      setFormError("Manba va qabul ombori bir xil bo‘lmasligi kerak.");
      return;
    }
    const payloadLines: {
      product_id: number;
      qty: number;
      batch_no: string | null;
      comment: string | null;
    }[] = [];
    for (const p of products) {
      const d = drafts[p.id] ?? emptyDraft();
      const qty = parseQty(d.qty);
      if (!Number.isFinite(qty) || qty <= 0) continue;
      payloadLines.push({
        product_id: p.id,
        qty,
        batch_no: d.batch_no.trim() || null,
        comment: d.line_comment.trim() || null,
      });
    }
    if (payloadLines.length === 0) {
      setFormError("Kamida bitta mahsulot uchun miqdor kiriting (0 dan katta).");
      return;
    }
    const eps = 1e-6;
    for (const line of payloadLines) {
      const st = stockByProductId.get(line.product_id);
      const av = st ? parseDec(st.available) : 0;
      if (line.qty > av + eps) {
        const p = products.find((x) => x.id === line.product_id);
        setFormError(
          `${p?.sku ?? line.product_id}: ko‘chirish ${line.qty}, mavjud (qoldiq − bron) ${av}. Bron ostidagi miqdor yuborilmaydi.`
        );
        return;
      }
    }
    setSubmitting(true);
    try {
      await apiFetch<{ id: number; number: string }>(`/api/${tenant}/transfers`, {
        method: "POST",
        body: JSON.stringify({
          source_warehouse_id: src,
          destination_warehouse_id: dst,
          comment: comment.trim() || null,
          planned_date: plannedDate.trim() || null,
          lines: payloadLines,
        }),
      });
      router.push("/stock/transfers");
    } catch (err) {
      setFormError(getUserFacingError(err, "Saqlashda xato"));
    } finally {
      setSubmitting(false);
    }
  };

  if (!hydrated || !tenantSlug) {
    return <p className="text-sm text-muted-foreground p-4">Загрузка…</p>;
  }

  if (!canWrite) {
    return (
      <div className="space-y-2 p-4">
        <p className="text-sm text-muted-foreground">Huquqlar yetarli emas.</p>
        <Link href="/stock/transfers" className="text-sm text-primary underline">
          Ro‘yxatga qaytish
        </Link>
      </div>
    );
  }

  return (
    <div className="mx-auto w-full max-w-[1600px] space-y-4 pb-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div className="min-w-0">
          <h1 className="text-2xl font-bold tracking-tight">О перемещение</h1>
          <p className="mt-1 max-w-2xl text-sm text-muted-foreground">
            Перемещение товаров между складами. Количество не может превышать доступный остаток.
          </p>
        </div>
        <Link
          href="/stock/transfers"
          className={cn(buttonVariants({ variant: "outline" }), "shrink-0 self-start sm:self-center")}
        >
          Jurnalga
        </Link>
      </div>

      <form onSubmit={(e) => void onSubmit(e)} className="space-y-4">
        <div className="grid items-start gap-4 lg:grid-cols-[1fr_minmax(260px,300px)] xl:grid-cols-[1fr_320px]">
          <div className="order-1 min-w-0 space-y-4">
            <section className="rounded-xl border border-border bg-card px-4 py-3 shadow-sm">
              <div className="flex flex-wrap items-center justify-between gap-2">
                <h2 className="text-sm font-semibold text-foreground">Склады</h2>
                {loadWh && (
                  <span className="text-xs text-muted-foreground">Загрузка…</span>
                )}
              </div>
              {whError && <p className="mt-2 text-sm text-destructive">{whError}</p>}
              <div className="mt-3 grid gap-3 sm:grid-cols-2">
                <div className="space-y-1.5">
                  <Label className="text-xs text-muted-foreground">Со склада</Label>
                  <Select
                    value={sourceId}
                    onValueChange={(v) => {
                      setSourceId(v);
                      if (v && v === destId) setDestId("");
                    }}
                    disabled={loadWh}
                  >
                    <SelectTrigger className="h-9">
                      <SelectValue placeholder={loadWh ? "Загрузка…" : "Выберите"} />
                    </SelectTrigger>
                    <SelectContent>
                      {warehouses.map((w) => (
                        <SelectItem key={w.id} value={String(w.id)}>
                          {w.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-1.5">
                  <Label className="text-xs text-muted-foreground">На склад</Label>
                  <Select value={destId} onValueChange={setDestId} disabled={loadWh || !sourceId}>
                    <SelectTrigger className="h-9">
                      <SelectValue placeholder="Выберите" />
                    </SelectTrigger>
                    <SelectContent>
                      {destOptions.map((w) => (
                        <SelectItem key={w.id} value={String(w.id)}>
                          {w.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="mt-3 grid gap-3 sm:grid-cols-2">
                <div className="space-y-1.5 sm:col-span-2">
                  <Label htmlFor="comment-inline" className="text-xs text-muted-foreground">
                    Комментарий
                  </Label>
                  <Input
                    id="comment-inline"
                    className="h-9"
                    value={comment}
                    onChange={(e) => setComment(e.target.value)}
                    placeholder="Комментарий"
                  />
                </div>
              </div>
            </section>

            <Card className="border-border bg-card shadow-sm">
              <CardHeader className="space-y-1 pb-3">
                <CardTitle className="text-base">Товары</CardTitle>
                <p className="text-xs text-muted-foreground">
                  Доступно = остаток − бронь. Поле «Блок» автоматически пересчитывает количество.
                </p>
              </CardHeader>
              <CardContent className="space-y-3 pt-0">
                {!sourceId && (
                  <div className="rounded-lg border border-amber-500/35 bg-amber-500/10 px-3 py-2 text-xs text-amber-950 dark:text-amber-100">
                    <strong className="font-medium">Выберите склад-источник</strong> — остаток и бронь считаются
                    только по нему.
                  </div>
                )}
                {sourceId && loadStock && (
                  <p className="text-sm text-muted-foreground">Загрузка остатков…</p>
                )}
                {stockError && <p className="text-sm text-destructive">{stockError}</p>}
                {catError && <p className="text-sm text-destructive">{catError}</p>}

                <div
                  className={cn(
                    "flex min-h-[min(24rem,50vh)] flex-col overflow-hidden rounded-xl border border-border bg-background sm:min-h-[min(28rem,calc(100vh-13rem))] md:flex-row"
                  )}
                >
                  {/* Chap: kategoriyalar (vertikal) */}
                  <aside
                    className={cn(
                      "flex w-full shrink-0 flex-col border-border bg-card md:w-[min(13.5rem,32vw)] md:border-r lg:w-56"
                    )}
                  >
                    <div className="border-b border-border bg-muted/20 px-3 py-2">
                      <p className="text-[11px] font-semibold uppercase tracking-wide text-muted-foreground">
                        Kategoriyalar
                      </p>
                    </div>
                    <div className="max-h-44 overflow-y-auto p-2 md:max-h-none md:flex-1 md:overflow-y-auto">
                      {loadCats ? (
                        <p className="px-1 py-2 text-sm text-muted-foreground">Загрузка…</p>
                      ) : categories.length === 0 ? (
                        <p className="px-1 py-2 text-sm text-muted-foreground">Нет активных категорий.</p>
                      ) : (
                        <nav className="flex flex-col gap-0.5" aria-label="Mahsulot kategoriyalari">
                          {categories.map((c) => {
                            const active = categoryId === String(c.id);
                            return (
                              <button
                                key={c.id}
                                type="button"
                                onClick={() => setCategoryId(String(c.id))}
                                className={cn(
                                  "w-full rounded-md px-2.5 py-2 text-left text-sm leading-snug transition-colors",
                                  active
                                    ? "bg-primary font-medium text-primary-foreground shadow-sm"
                                    : "text-foreground hover:bg-muted/90"
                                )}
                              >
                                <span className="line-clamp-3">{c.name}</span>
                              </button>
                            );
                          })}
                        </nav>
                      )}
                    </div>
                  </aside>

                  {/* O‘ng: qidiruv + jadval */}
                  <div className="flex min-w-0 flex-1 flex-col bg-background">
                    <div className="flex flex-col gap-2 border-b border-border p-2 sm:flex-row sm:items-center sm:gap-2">
                      <div className="min-w-0 flex-1 space-y-1">
                        <Label htmlFor="row-filter" className="text-xs text-muted-foreground">
                          Qidiruv
                        </Label>
                        <Input
                          id="row-filter"
                          className="h-9"
                          value={rowFilter}
                          onChange={(e) => setRowFilter(e.target.value)}
                          placeholder="SKU, nom, shtrix…"
                          disabled={!categoryId || loadProducts}
                        />
                      </div>
                      {categoryId && !loadProducts && products.length > 0 && (
                        <div className="flex shrink-0 flex-wrap items-center gap-2 sm:pt-5">
                          <Button type="button" variant="outline" size="sm" onClick={clearQuantities}>
                            Miqdorlarni tozalash
                          </Button>
                          {filteredProducts.length !== products.length && (
                            <span className="text-xs text-muted-foreground whitespace-nowrap">
                              {filteredProducts.length} / {products.length}
                            </span>
                          )}
                        </div>
                      )}
                    </div>

                    <div className="min-h-0 flex-1 overflow-auto p-2">
                      {prodError && (
                        <p className="mb-2 text-sm text-destructive">{prodError}</p>
                      )}

                      {!categoryId && !loadCats && categories.length > 0 && (
                        <div className="flex min-h-[12rem] items-center justify-center rounded-lg border border-dashed border-border/80 bg-muted/20 px-4 py-8 text-center text-sm text-muted-foreground">
                          Выберите категорию слева — товары появятся здесь.
                        </div>
                      )}

                      {categoryId && loadProducts && (
                        <p className="py-6 text-center text-sm text-muted-foreground">
                          Mahsulotlar Загрузка…
                        </p>
                      )}

                      {categoryId && !loadProducts && products.length === 0 && (
                        <p className="py-6 text-center text-sm text-muted-foreground">
                          В этой категории нет активных товаров.
                        </p>
                      )}

                      {categoryId && !loadProducts && filteredProducts.length > 0 && (
                        <div className="overflow-x-auto rounded-lg border border-border/80">
                          <Table>
                            <TableHeader>
                              <TableRow>
                                <TableHead className="w-10">№</TableHead>
                                <TableHead className="w-[100px]">Kod</TableHead>
                                <TableHead>Nomi</TableHead>
                                <TableHead className="w-28">Blok</TableHead>
                                <TableHead className="w-32 text-xs font-normal text-muted-foreground">
                                  1 blok
                                </TableHead>
                                <TableHead className="w-24 text-right">Qoldiq</TableHead>
                                <TableHead className="w-24 text-right">Bron</TableHead>
                                <TableHead className="w-24 text-right">Mavjud</TableHead>
                                <TableHead className="w-28">Ko‘chirish</TableHead>
                                <TableHead className="w-28">Partiya</TableHead>
                                <TableHead className="min-w-[120px]">Izoh</TableHead>
                              </TableRow>
                            </TableHeader>
                            <TableBody>
                              {filteredProducts.map((p, idx) => {
                                const d = drafts[p.id] ?? emptyDraft();
                                const st = stockByProductId.get(p.id);
                                const qDisplay = st?.qty ?? (sourceId ? "0" : "—");
                                const rDisplay = st?.reserved ?? (sourceId ? "0" : "—");
                                const aDisplay = st?.available ?? (sourceId ? "0" : "—");
                                const want = parseQty(d.qty);
                                const availN = st ? parseDec(st.available) : 0;
                                const over =
                                  sourceId &&
                                  Number.isFinite(want) &&
                                  want > 0 &&
                                  want > availN + 1e-6;
                                return (
                                  <TableRow
                                    key={p.id}
                                    className={
                                      over ? "bg-destructive/10 dark:bg-destructive/20" : undefined
                                    }
                                  >
                                    <TableCell className="text-muted-foreground text-sm">
                                      {idx + 1}
                                    </TableCell>
                                    <TableCell className="font-mono text-xs align-top">{p.sku}</TableCell>
                                    <TableCell className="align-top">
                                      <div className="font-medium text-sm leading-snug">{p.name}</div>
                                      <div className="text-xs text-muted-foreground mt-0.5">
                                        {p.unit}
                                        {p.barcode ? ` · ${p.barcode}` : ""}
                                      </div>
                                    </TableCell>
                                    <TableCell className="align-top">
                                      <Input
                                        className="h-8"
                                        value={d.block}
                                        onChange={(e) => setBlockForProduct(p.id, e.target.value, p)}
                                        inputMode="decimal"
                                        placeholder="0"
                                        disabled={p.qty_per_block == null || p.qty_per_block <= 0}
                                        title={
                                          p.qty_per_block != null && p.qty_per_block > 0
                                            ? "Blok soni — miqdor avto"
                                            : "Bu mahsulotda blok o‘lchami yo‘q"
                                        }
                                      />
                                    </TableCell>
                                    <TableCell className="text-xs text-muted-foreground align-top">
                                      {blockHint(p)}
                                    </TableCell>
                                    <TableCell className="text-right font-mono text-xs align-top tabular-nums">
                                      {qDisplay}
                                    </TableCell>
                                    <TableCell className="text-right font-mono text-xs align-top tabular-nums">
                                      {rDisplay}
                                    </TableCell>
                                    <TableCell className="text-right font-mono text-xs font-medium align-top tabular-nums">
                                      {aDisplay}
                                    </TableCell>
                                    <TableCell className="align-top">
                                      <Input
                                        className={cn("h-8", over && "border-destructive")}
                                        value={d.qty}
                                        onChange={(e) => updateDraft(p.id, { qty: e.target.value })}
                                        inputMode="decimal"
                                        placeholder="0"
                                        title={sourceId ? `Maks. ${aDisplay}` : undefined}
                                      />
                                      {over && (
                                        <p className="text-[10px] text-destructive mt-0.5">
                                          Mavjuddan oshiq
                                        </p>
                                      )}
                                    </TableCell>
                                    <TableCell className="align-top">
                                      <Input
                                        className="h-8"
                                        value={d.batch_no}
                                        onChange={(e) => updateDraft(p.id, { batch_no: e.target.value })}
                                      />
                                    </TableCell>
                                    <TableCell className="align-top">
                                      <Input
                                        className="h-8"
                                        value={d.line_comment}
                                        onChange={(e) =>
                                          updateDraft(p.id, { line_comment: e.target.value })
                                        }
                                      />
                                    </TableCell>
                                  </TableRow>
                                );
                              })}
                            </TableBody>
                          </Table>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </CardContent>
        </Card>
          </div>

          <aside className="order-2 lg:sticky lg:top-16 lg:self-start">
            <Card className="border-border bg-card shadow-md">
              <CardHeader className="border-b border-border bg-muted/10 pb-3">
                <CardTitle className="text-base">Сводка</CardTitle>
                <p className="text-xs font-normal text-muted-foreground">
                  Быстрая проверка перед сохранением.
                </p>
              </CardHeader>
              <CardContent className="space-y-4 pt-4">
                <div className="border-t border-border/60 pt-3">
                  <p className="mb-2 text-xs font-medium text-muted-foreground">Сводка</p>
                  {!categoryId ? (
                    <p className="rounded-md bg-muted/40 px-2.5 py-2 text-xs text-muted-foreground">
                      Выберите категорию — статистика появится здесь.
                    </p>
                  ) : (
                    <div className="grid grid-cols-2 gap-2">
                      <div className="rounded-lg border border-border/60 bg-muted/25 px-2.5 py-2">
                        <p className="text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
                          Категория
                        </p>
                        <p className="mt-0.5 truncate text-sm font-semibold" title={selectedCategoryName ?? ""}>
                          {loadProducts ? "…" : (selectedCategoryName ?? "—")}
                        </p>
                      </div>
                      <div className="rounded-lg border border-border/60 bg-muted/25 px-2.5 py-2">
                        <p className="text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
                          Товаров в каталоге
                        </p>
                        <p className="mt-0.5 text-sm font-semibold tabular-nums">
                          {loadProducts ? "…" : summary.totalInCategory}
                        </p>
                      </div>
                      <div className="rounded-lg border border-border/60 bg-muted/25 px-2.5 py-2">
                        <p className="text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
                          Изменённых строк
                        </p>
                        <p className="mt-0.5 text-sm font-semibold tabular-nums">
                          {loadProducts ? "—" : summary.linesWithQty}
                        </p>
                      </div>
                      <div className="rounded-lg border border-border/60 bg-muted/25 px-2.5 py-2">
                        <p className="text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
                          Общее кол-во
                        </p>
                        <p className="mt-0.5 text-sm font-semibold tabular-nums">
                          {loadProducts ? "—" : formatNumberGrouped(summary.sumQty, { maxFractionDigits: 3 })}
                        </p>
                      </div>
                      <div className="col-span-2 rounded-lg border border-border/60 bg-muted/25 px-2.5 py-2">
                        <p className="text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
                          Позиции с бронью
                        </p>
                        <p className="mt-0.5 text-sm font-semibold tabular-nums">
                          {loadProducts ? "—" : `${summary.withBron} шт`}
                        </p>
                      </div>
                    </div>
                  )}
                </div>

                {formError && (
                  <p className="rounded-lg border border-destructive/30 bg-destructive/5 px-3 py-2 text-sm text-destructive">
                    {formError}
                  </p>
                )}

                <div className="flex flex-col gap-2 border-t border-border/60 pt-3 sm:flex-row sm:flex-wrap sm:justify-end">
                  <Link
                    href="/stock/transfers"
                    className={cn(
                      buttonVariants({ variant: "outline" }),
                      "h-9 w-full justify-center sm:w-auto"
                    )}
                  >
                    Назад
                  </Link>
                  <Button
                    type="submit"
                    className="h-9 w-full sm:w-auto"
                    disabled={submitting || loadWh || (Boolean(sourceId) && loadStock)}
                  >
                  {submitting ? "Сохранение…" : "Сохранить"}
                  </Button>
                </div>
              </CardContent>
            </Card>
          </aside>
        </div>
      </form>
    </div>
  );
}

"use client";

import { TableColumnSettingsDialog, type ColumnDefItem } from "@/components/data-table/table-column-settings-dialog";
import { PageHeader } from "@/components/dashboard/page-header";
import { PageShell } from "@/components/dashboard/page-shell";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { DateRangePopover, formatDateRangeButton } from "@/components/ui/date-range-popover";
import { filterSelectClassName } from "@/components/ui/filter-select";
import { Input } from "@/components/ui/input";
import { api } from "@/lib/api";
import { useAuthStore, useAuthStoreHydrated } from "@/lib/auth-store";
import { downloadXlsxSheet } from "@/lib/download-xlsx";
import { formatNumberGrouped } from "@/lib/format-numbers";
import { paymentMethodSelectOptions, type ProfilePaymentMethodEntry } from "@/lib/payment-method-options";
import { STALE } from "@/lib/query-stale";
import { cn } from "@/lib/utils";
import { useUserTablePrefs } from "@/hooks/use-user-table-prefs";
import { useQuery } from "@tanstack/react-query";
import { CalendarDays, Download, LayoutGrid, RefreshCw, RotateCcw } from "lucide-react";
import Link from "next/link";
import { useCallback, useMemo, useRef, useState } from "react";

type SupplierOpt = { id: number; name: string; code: string | null };

type TenantProfile = {
  payment_method_entries?: ProfilePaymentMethodEntry[];
  payment_types?: string[];
};

type RecLine = {
  date: string;
  kind: string;
  type_label: string;
  label: string;
  ref: string;
  payment_method: string | null;
  comment: string | null;
  debit: string;
  credit: string;
  balance: string;
};

type RecPayload = {
  supplier: { id: number; name: string; code: string | null; opening_balance_note: string | null };
  opening_balance: string;
  supplier_opening_balance?: string;
  purchases_total: string;
  payments_total: string;
  closing_balance: string;
  lines: RecLine[];
};

/** v2: «Поставщик» в таблице, новый порядок столбцов по умолчанию */
const REC_TABLE_ID = "suppliers.reconciliation.v2";
const REC_COL_DEFS: ColumnDefItem[] = [
  { id: "supplier_name", label: "Поставщик" },
  { id: "date", label: "Дата" },
  { id: "type_label", label: "Тип" },
  { id: "payment_method", label: "Способ оплаты" },
  { id: "debit", label: "Долг" },
  { id: "credit", label: "Кредит" },
  { id: "balance", label: "Баланс" },
  { id: "memo", label: "Документ / комментарий" }
];
const REC_DEFAULT_ORDER = REC_COL_DEFS.map((c) => c.id);
const REC_NUMERIC_COLS = new Set(["debit", "credit", "balance"]);

function recColLabel(id: string): string {
  return REC_COL_DEFS.find((c) => c.id === id)?.label ?? id;
}

function monthRangeStrings(d: Date): { from: string; to: string } {
  const y = d.getFullYear();
  const m = d.getMonth();
  const from = `${y}-${String(m + 1).padStart(2, "0")}-01`;
  const lastDay = new Date(y, m + 1, 0).getDate();
  const to = `${y}-${String(m + 1).padStart(2, "0")}-${String(lastDay).padStart(2, "0")}`;
  return { from, to };
}

function isSummaryRow(kind: string): boolean {
  return kind === "turnover" || kind === "total";
}

function fmtCell(v: string, opts?: { minFractionDigits?: number; maxFractionDigits?: number }): string {
  const n = Number(String(v).replace(/\s/g, "").replace(",", "."));
  if (!Number.isFinite(n) || n === 0) return "—";
  return formatNumberGrouped(v, {
    minFractionDigits: opts?.minFractionDigits ?? 2,
    maxFractionDigits: opts?.maxFractionDigits ?? 2
  });
}

export function SuppliersReconciliationWorkspace() {
  const tenantSlug = useAuthStore((s) => s.tenantSlug);
  const hydrated = useAuthStoreHydrated();
  const defaultRange = useMemo(() => monthRangeStrings(new Date()), []);

  const [draftSupplier, setDraftSupplier] = useState("");
  const [draftPaymentMethod, setDraftPaymentMethod] = useState("");
  const [draftFrom, setDraftFrom] = useState(defaultRange.from);
  const [draftTo, setDraftTo] = useState(defaultRange.to);
  const [appliedSupplier, setAppliedSupplier] = useState("");
  const [appliedPaymentMethod, setAppliedPaymentMethod] = useState("");
  const [appliedFrom, setAppliedFrom] = useState(defaultRange.from);
  const [appliedTo, setAppliedTo] = useState(defaultRange.to);

  const [dateOpen, setDateOpen] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [tableSearch, setTableSearch] = useState("");
  const [columnDialogOpen, setColumnDialogOpen] = useState(false);
  const dateAnchorRef = useRef<HTMLButtonElement | null>(null);

  const prefs = useUserTablePrefs({
    tenantSlug,
    tableId: REC_TABLE_ID,
    defaultColumnOrder: REC_DEFAULT_ORDER,
    defaultPageSize: 10,
    allowedPageSizes: [10, 20, 50, 100]
  });

  const profileQ = useQuery({
    queryKey: ["settings-profile", tenantSlug, "supplier-reconciliation"],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<TenantProfile>(`/api/${tenantSlug}/settings/profile`);
      return data;
    }
  });

  const payMethodOpts = useMemo(
    () => paymentMethodSelectOptions(profileQ.data, profileQ.data?.payment_types),
    [profileQ.data]
  );

  const suppliersQ = useQuery({
    queryKey: ["suppliers", tenantSlug, "reconciliation-pick"],
    enabled: Boolean(tenantSlug) && hydrated,
    staleTime: STALE.reference,
    queryFn: async () => {
      const { data } = await api.get<{ data: SupplierOpt[] }>(`/api/${tenantSlug}/suppliers?status=active`);
      return data.data ?? [];
    }
  });

  const sid = useMemo(() => {
    const n = Number.parseInt(appliedSupplier, 10);
    return Number.isFinite(n) && n > 0 ? n : 0;
  }, [appliedSupplier]);

  const recQ = useQuery({
    queryKey: ["suppliers-reconciliation", tenantSlug, sid, appliedFrom, appliedTo, appliedPaymentMethod],
    enabled: Boolean(tenantSlug) && hydrated && sid > 0,
    staleTime: STALE.list,
    queryFn: async () => {
      const p = new URLSearchParams();
      p.set("supplier_id", String(sid));
      if (appliedFrom.trim()) p.set("date_from", appliedFrom.trim());
      if (appliedTo.trim()) p.set("date_to", appliedTo.trim());
      if (appliedPaymentMethod.trim()) p.set("payment_method", appliedPaymentMethod.trim());
      const { data } = await api.get<{ data: RecPayload }>(
        `/api/${tenantSlug}/suppliers/accounting/reconciliation?${p.toString()}`
      );
      return data.data;
    }
  });

  const applyFilters = useCallback(() => {
    setAppliedSupplier(draftSupplier);
    setAppliedPaymentMethod(draftPaymentMethod);
    setAppliedFrom(draftFrom);
    setAppliedTo(draftTo);
    setTableSearch("");
  }, [draftSupplier, draftPaymentMethod, draftFrom, draftTo]);

  const resetFilters = useCallback(() => {
    const r = monthRangeStrings(new Date());
    setDraftSupplier("");
    setDraftPaymentMethod("");
    setDraftFrom(r.from);
    setDraftTo(r.to);
    setAppliedSupplier("");
    setAppliedPaymentMethod("");
    setAppliedFrom(r.from);
    setAppliedTo(r.to);
    setTableSearch("");
  }, []);

  const exportXlsx = useCallback(async () => {
    const rec = recQ.data;
    if (!rec || sid <= 0) return;
    setExporting(true);
    try {
      const supplierLabel = rec.supplier.code
        ? `${rec.supplier.name} (${rec.supplier.code})`
        : rec.supplier.name;
      await downloadXlsxSheet(
        `supplier-reconciliation-${sid}-${appliedFrom}-${appliedTo}.xlsx`,
        "Акт сверки",
        ["Поставщик", "Дата", "Тип", "Способ оплаты", "Долг", "Кредит", "Баланс", "Документ", "Комментарий"],
        (rec.lines ?? []).map((row) => [
          supplierLabel,
          row.date ? row.date.slice(0, 19).replace("T", " ") : "—",
          row.type_label,
          row.payment_method ?? "",
          row.debit,
          row.credit,
          row.balance,
          row.label,
          row.comment ?? ""
        ]),
        { colWidths: [26, 20, 28, 14, 14, 14, 14, 28, 28] }
      );
    } finally {
      setExporting(false);
    }
  }, [recQ.data, sid, appliedFrom, appliedTo]);

  const supplierTableLabel = useMemo(() => {
    const r = recQ.data;
    if (!r?.supplier) return "—";
    return r.supplier.code ? `${r.supplier.name} (${r.supplier.code})` : r.supplier.name;
  }, [recQ.data]);

  const filteredLines = useMemo(() => {
    const rows = recQ.data?.lines ?? [];
    const q = tableSearch.trim().toLowerCase();
    if (!q) return rows;
    return rows.filter((row) => {
      if (isSummaryRow(row.kind) || row.kind === "period_opening") return true;
      const hay = [
        supplierTableLabel,
        row.type_label,
        row.label,
        row.payment_method ?? "",
        row.comment ?? ""
      ]
        .join(" ")
        .toLowerCase();
      return hay.includes(q);
    });
  }, [recQ.data?.lines, tableSearch, supplierTableLabel]);

  const recColRender = useMemo(
    () => ({
      supplier_name: (_row: RecLine) => (
        <span className="block max-w-[min(100%,14rem)] truncate sm:max-w-[18rem]" title={supplierTableLabel}>
          {supplierTableLabel}
        </span>
      ),
      date: (row: RecLine) => (row.date ? row.date.slice(0, 19).replace("T", " ") : "—"),
      type_label: (row: RecLine) => row.type_label,
      payment_method: (row: RecLine) => row.payment_method?.trim() || "—",
      debit: (row: RecLine) => fmtCell(row.debit),
      credit: (row: RecLine) => fmtCell(row.credit),
      balance: (row: RecLine) =>
        formatNumberGrouped(row.balance, { minFractionDigits: 2, maxFractionDigits: 2 }),
      memo: (row: RecLine) => (
        <span className="max-w-[240px] truncate">{[row.comment, row.label].filter(Boolean).join(" · ") || "—"}</span>
      )
    }),
    [supplierTableLabel]
  );

  if (!hydrated) {
    return (
      <PageShell>
        <p className="text-sm text-muted-foreground">Загрузка…</p>
      </PageShell>
    );
  }
  if (!tenantSlug) {
    return (
      <PageShell>
        <p className="text-sm text-destructive">
          <Link href="/login" className="underline">
            Войти
          </Link>
        </p>
      </PageShell>
    );
  }

  const rec = recQ.data;
  const visibleCols = prefs.visibleColumnOrder;

  return (
    <PageShell className="space-y-4">
      <PageHeader
        title="Акт сверки с поставщиком"
        description="Остаток на начало периода, приходы и оплаты; баланс = долг − кредит по строкам. Способ оплаты фильтрует только строки оплат в периоде."
      />

      <div className="orders-hub-section orders-hub-section--filters orders-hub-section--stack-tight">
        <Card className="rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
          <CardContent className="p-3 sm:p-4">
            <div className="flex flex-col gap-3 lg:flex-row lg:items-end lg:justify-between lg:gap-4">
              <div className="flex min-w-0 flex-1 flex-col gap-3 sm:flex-row sm:flex-wrap sm:items-end">
                <label className="orders-filter-field-label min-w-0 w-full sm:w-[min(100%,17rem)] sm:max-w-[20rem]">
                  Период
                  <button
                    ref={dateAnchorRef}
                    type="button"
                    className={cn(
                      filterSelectClassName,
                      "inline-flex max-w-none min-w-0 items-center justify-between text-left font-medium"
                    )}
                    onClick={() => setDateOpen((v) => !v)}
                  >
                    <span className="min-w-0 flex-1 truncate">{formatDateRangeButton(draftFrom, draftTo)}</span>
                    <CalendarDays className="ml-1 size-3.5 shrink-0 text-muted-foreground" />
                  </button>
                </label>

                <label className="orders-filter-field-label min-w-0 w-full sm:w-[min(100%,17rem)] sm:max-w-[20rem]">
                  Поставщик
                  <select
                    className={cn(filterSelectClassName, "max-w-none")}
                    value={draftSupplier}
                    onChange={(e) => setDraftSupplier(e.target.value)}
                  >
                    <option value="">Не выбран</option>
                    {(suppliersQ.data ?? []).map((s) => (
                      <option key={s.id} value={String(s.id)}>
                        {s.name}
                        {s.code ? ` (${s.code})` : ""}
                      </option>
                    ))}
                  </select>
                </label>

                <label className="orders-filter-field-label min-w-0 w-full sm:w-[min(100%,17rem)] sm:max-w-[20rem]">
                  Способ оплаты
                  <select
                    className={cn(filterSelectClassName, "max-w-none")}
                    value={draftPaymentMethod}
                    onChange={(e) => setDraftPaymentMethod(e.target.value)}
                  >
                    <option value="">Все способы</option>
                    {payMethodOpts.map((o) => (
                      <option key={o.value} value={o.value}>
                        {o.label}
                      </option>
                    ))}
                  </select>
                </label>
              </div>

              <div className="flex shrink-0 flex-wrap items-center justify-end gap-2 border-t border-border/50 pt-3 lg:border-t-0 lg:pt-0">
                <Button type="button" variant="outline" size="icon" className="h-9 w-9 shrink-0" title="Сброс" onClick={resetFilters}>
                  <RotateCcw className="size-4" />
                </Button>
                <Button type="button" size="sm" className="h-9 min-w-[7rem] bg-teal-600 px-4 hover:bg-teal-700" onClick={applyFilters}>
                  Применить
                </Button>
              </div>
            </div>

            <DateRangePopover
              open={dateOpen}
              onOpenChange={setDateOpen}
              anchorRef={dateAnchorRef}
              dateFrom={draftFrom}
              dateTo={draftTo}
              onApply={({ dateFrom, dateTo }) => {
                setDraftFrom(dateFrom);
                setDraftTo(dateTo);
              }}
            />
          </CardContent>
        </Card>
      </div>

      <TableColumnSettingsDialog
        open={columnDialogOpen}
        onOpenChange={setColumnDialogOpen}
        title="Управление столбцами"
        description="Видимые столбцы и порядок сохраняются для вашей учётной записи. Порядок строк акта фиксирован (сортировка по данным отключена)."
        columns={[...REC_COL_DEFS]}
        columnOrder={prefs.columnOrder}
        hiddenColumnIds={prefs.hiddenColumnIds}
        saving={prefs.saving}
        onSave={(next) => prefs.saveColumnLayout(next)}
        onReset={() => prefs.resetColumnLayout()}
      />

      {rec ? (
        <div className="mt-6 min-w-0 space-y-4 sm:mb-10 sm:space-y-5">
          {rec.supplier.opening_balance_note ? (
            <p className="text-balance break-words text-xs leading-relaxed text-muted-foreground">
              Примечание к нач. балансу (справочник): {rec.supplier.opening_balance_note}
            </p>
          ) : null}

          <div className="grid gap-4 sm:gap-5 [grid-template-columns:repeat(auto-fit,minmax(min(100%,15.5rem),1fr))] sm:[grid-template-columns:repeat(auto-fit,minmax(min(100%,17rem),1fr))]">
            <Card className="min-w-0 overflow-hidden shadow-sm">
              <CardHeader className="gap-2 border-0 px-4 py-4 sm:px-5 sm:py-5">
                <CardDescription className="text-balance text-xs leading-snug text-muted-foreground">
                  Остаток на начало периода
                </CardDescription>
                <CardTitle className="min-w-0 break-words text-balance text-base font-semibold leading-snug tabular-nums tracking-normal sm:text-lg">
                  {formatNumberGrouped(rec.opening_balance, { minFractionDigits: 2, maxFractionDigits: 2 })}
                </CardTitle>
              </CardHeader>
            </Card>

            {rec.supplier_opening_balance != null ? (
              <Card className="min-w-0 overflow-hidden shadow-sm">
                <CardHeader className="gap-2 border-0 px-4 py-4 sm:px-5 sm:py-5">
                  <CardDescription className="text-balance text-xs leading-snug text-muted-foreground">
                    Нач. баланс (карточка)
                  </CardDescription>
                  <CardTitle className="min-w-0 break-words text-balance text-base font-semibold leading-snug tabular-nums tracking-normal text-muted-foreground sm:text-lg">
                    {formatNumberGrouped(rec.supplier_opening_balance, { minFractionDigits: 2, maxFractionDigits: 2 })}
                  </CardTitle>
                </CardHeader>
              </Card>
            ) : null}

            <Card className="min-w-0 overflow-hidden shadow-sm">
              <CardHeader className="gap-2 border-0 px-4 py-4 sm:px-5 sm:py-5">
                <CardDescription className="text-balance text-xs leading-snug text-muted-foreground">
                  Приходы за период
                </CardDescription>
                <CardTitle className="min-w-0 break-words text-balance text-base font-semibold leading-snug tabular-nums tracking-normal sm:text-lg">
                  {formatNumberGrouped(rec.purchases_total, { minFractionDigits: 2, maxFractionDigits: 2 })}
                </CardTitle>
              </CardHeader>
            </Card>

            <Card className="min-w-0 overflow-hidden shadow-sm">
              <CardHeader className="gap-2 border-0 px-4 py-4 sm:px-5 sm:py-5">
                <CardDescription className="text-balance text-xs leading-snug text-muted-foreground">Оплаты за период</CardDescription>
                <CardTitle className="min-w-0 break-words text-balance text-base font-semibold leading-snug tabular-nums tracking-normal sm:text-lg">
                  {formatNumberGrouped(rec.payments_total, { minFractionDigits: 2, maxFractionDigits: 2 })}
                </CardTitle>
              </CardHeader>
            </Card>

            <Card className="min-w-0 overflow-hidden border-2 border-green-600/70 bg-card shadow-md ring-1 ring-green-600/15 dark:border-green-500/75 dark:ring-green-500/20">
              <CardHeader className="gap-2 border-0 px-4 py-4 sm:px-5 sm:py-5">
                <CardDescription className="text-balance text-xs font-medium leading-snug text-muted-foreground">
                  Итог на конец
                </CardDescription>
                <CardTitle className="min-w-0 break-words text-balance text-base font-semibold leading-snug tabular-nums tracking-normal text-green-700 dark:text-green-400 sm:text-lg">
                  {formatNumberGrouped(rec.closing_balance, { minFractionDigits: 2, maxFractionDigits: 2 })}
                </CardTitle>
              </CardHeader>
            </Card>
          </div>
        </div>
      ) : null}

      {sid > 0 ? (
        <div className="orders-hub-section orders-hub-section--table mt-2 min-w-0 sm:mt-4">
          <Card className="overflow-hidden rounded-none border-0 bg-transparent shadow-none hover:shadow-none">
            <CardContent className="p-0">
          <div className="table-toolbar flex flex-wrap items-center justify-between gap-2 border-b border-border/80 bg-muted/30 px-3 py-2 sm:px-4">
            <div className="relative min-w-0 max-w-xs flex-1">
              <Input
                className="h-9 text-sm"
                placeholder="Поиск по таблице"
                value={tableSearch}
                onChange={(e) => setTableSearch(e.target.value)}
              />
            </div>
            <div className="flex shrink-0 flex-wrap items-center gap-2">
              <Button
                type="button"
                variant="outline"
                size="icon"
                className="h-9 w-9 shrink-0"
                title="Столбцы"
                onClick={() => setColumnDialogOpen(true)}
              >
                <LayoutGrid className="size-4" />
              </Button>
              <Button
                type="button"
                size="sm"
                variant="outline"
                disabled={exporting || !rec}
                className="h-9 gap-1 border-green-600/40 text-green-700 hover:bg-green-50 dark:text-green-400 dark:hover:bg-green-950/30"
                onClick={() => void exportXlsx()}
              >
                <Download className="size-3.5" />
                {exporting ? "…" : "Excel"}
              </Button>
              <Button
                type="button"
                variant="outline"
                size="icon"
                className="h-9 w-9 shrink-0"
                title="Обновить"
                onClick={() => void recQ.refetch()}
              >
                <RefreshCw className={cn("size-4", recQ.isFetching && "animate-spin")} />
              </Button>
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full min-w-[1000px] border-collapse text-sm sm:min-w-[1040px]">
              {visibleCols.length === 0 ? (
                <tbody>
                  <tr>
                    <td className="px-3 py-8 text-center text-muted-foreground">Нет видимых столбцов.</td>
                  </tr>
                </tbody>
              ) : (
                <>
                  <thead className="app-table-thead text-left">
                    <tr>
                      {visibleCols.map((colId) => (
                        <th
                          key={colId}
                          className={cn(
                            "px-3 py-2.5",
                            REC_NUMERIC_COLS.has(colId) && "text-right",
                            colId === "date" && "whitespace-nowrap",
                            colId === "supplier_name" && "min-w-[10rem] max-w-[14rem] sm:max-w-[18rem]"
                          )}
                        >
                          {recColLabel(colId)}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {recQ.isLoading ? (
                      <tr>
                        <td colSpan={visibleCols.length} className="px-3 py-8 text-center text-muted-foreground">
                          Загрузка…
                        </td>
                      </tr>
                    ) : !rec || (rec.lines?.length ?? 0) === 0 ? (
                      <tr>
                        <td colSpan={visibleCols.length} className="px-3 py-8 text-center text-muted-foreground">
                          Нет данных
                        </td>
                      </tr>
                    ) : (
                      filteredLines.map((row, idx) => (
                        <tr
                          key={`${row.kind}-${row.ref}-${idx}`}
                          className={cn(
                            "border-t even:bg-muted/20",
                            isSummaryRow(row.kind) && "bg-muted/40 font-semibold",
                            row.kind === "period_opening" && "bg-muted/20"
                          )}
                        >
                          {visibleCols.map((colId) => {
                            const render = recColRender[colId as keyof typeof recColRender];
                            return (
                              <td
                                key={colId}
                                className={cn(
                                  "px-3 py-2",
                                  colId === "date" && "whitespace-nowrap text-muted-foreground",
                                  colId === "supplier_name" && "max-w-[14rem] sm:max-w-[18rem]",
                                  colId === "payment_method" && "text-muted-foreground",
                                  REC_NUMERIC_COLS.has(colId) && "text-right tabular-nums",
                                  colId === "balance" && "font-medium"
                                )}
                              >
                                {render ? render(row) : null}
                              </td>
                            );
                          })}
                        </tr>
                      ))
                    )}
                  </tbody>
                </>
              )}
            </table>
          </div>
            </CardContent>
          </Card>
        </div>
      ) : (
        <p className="text-sm text-muted-foreground">Выберите поставщика и нажмите «Применить», чтобы построить акт.</p>
      )}

      {recQ.isError ? (
        <p className="text-sm text-destructive">Не удалось загрузить акт (проверьте доступ и поставщика).</p>
      ) : null}
    </PageShell>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import { CalendarDays, ChevronLeft, ChevronRight } from "lucide-react";
import {
  useCallback,
  useEffect,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
  type RefObject
} from "react";
import { createPortal } from "react-dom";

function pad2(n: number): string {
  return String(n).padStart(2, "0");
}

const RU_MONTH_SHORT = [
  "Янв.",
  "Февр.",
  "Март",
  "Апр.",
  "Май",
  "Июнь",
  "Июль",
  "Авг.",
  "Сент.",
  "Окт.",
  "Нояб.",
  "Дек."
] as const;

const RU_WD = ["пн", "вт", "ср", "чт", "пт", "сб", "вс"];

function daysMatrix(year: number, month: number): (number | null)[][] {
  const first = new Date(year, month, 1);
  let start = first.getDay() - 1;
  if (start < 0) start = 6;
  const dim = new Date(year, month + 1, 0).getDate();
  const cells: (number | null)[] = [];
  for (let i = 0; i < start; i++) cells.push(null);
  for (let d = 1; d <= dim; d++) cells.push(d);
  while (cells.length % 7 !== 0) cells.push(null);
  const rows: (number | null)[][] = [];
  for (let i = 0; i < cells.length; i += 7) rows.push(cells.slice(i, i + 7));
  return rows;
}

function shiftMonthYm(y: number, m0: number, delta: number): { y: number; m: number } {
  const d = new Date(y, m0 + delta, 1);
  return { y: d.getFullYear(), m: d.getMonth() };
}

function parseLocalDateTime(value: string): Date {
  if (!value?.trim()) return new Date();
  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? new Date() : d;
}

export function localValueToDatetimeInput(d: Date): string {
  return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())}T${pad2(d.getHours())}:${pad2(d.getMinutes())}`;
}

/** «11 Апр. 2024 20:44» — Lalaku-style */
export function formatRuDateTimeShort(value: string): string {
  const d = parseLocalDateTime(value);
  const day = d.getDate();
  const mon = RU_MONTH_SHORT[d.getMonth()] ?? "";
  const y = d.getFullYear();
  const capMon = mon ? mon.charAt(0).toUpperCase() + mon.slice(1) : "";
  return `${day} ${capMon} ${y} ${pad2(d.getHours())}:${pad2(d.getMinutes())}`;
}

/** «11 Апр. 2024» — faqat sana */
export function formatRuDateShort(value: string): string {
  const d = parseLocalDateTime(value);
  const day = d.getDate();
  const mon = RU_MONTH_SHORT[d.getMonth()] ?? "";
  const y = d.getFullYear();
  const capMon = mon ? mon.charAt(0).toUpperCase() + mon.slice(1) : "";
  return `${day} ${capMon} ${y}`;
}

function SingleMonthCalendar({
  year,
  month,
  selectedYmd,
  onPick,
  onShiftMonth
}: {
  year: number;
  month: number;
  selectedYmd: string;
  onPick: (iso: string) => void;
  onShiftMonth: (delta: number) => void;
}) {
  const title = new Date(year, month, 1).toLocaleDateString("ru-RU", {
    month: "short",
    year: "numeric"
  });
  const matrix = useMemo(() => daysMatrix(year, month), [year, month]);

  return (
    <div className="w-[12rem] shrink-0 sm:w-[12.25rem]">
      <div className="mb-0.5 flex items-center justify-between gap-0.5">
        <Button
          type="button"
          variant="outline"
          size="icon-sm"
          className="h-6 w-6 shrink-0"
          aria-label="Предыдущий месяц"
          onClick={() => onShiftMonth(-1)}
        >
          <ChevronLeft className="h-3 w-3" />
        </Button>
        <div className="min-w-0 flex-1 truncate px-0.5 text-center text-[0.7rem] font-medium capitalize text-foreground">
          {title}
        </div>
        <Button
          type="button"
          variant="outline"
          size="icon-sm"
          className="h-6 w-6 shrink-0"
          aria-label="Следующий месяц"
          onClick={() => onShiftMonth(1)}
        >
          <ChevronRight className="h-3 w-3" />
        </Button>
      </div>
      <div className="grid grid-cols-7 gap-px text-[0.6rem] text-muted-foreground">
        {RU_WD.map((w) => (
          <div key={w} className="py-0.5 text-center font-medium">
            {w}
          </div>
        ))}
        {matrix.flatMap((row, ri) =>
          row.map((day, ci) => {
            if (day == null) {
              return <div key={`e-${ri}-${ci}`} className="h-6" />;
            }
            const iso = `${year}-${pad2(month + 1)}-${pad2(day)}`;
            const sel = iso === selectedYmd;
            return (
              <button
                key={iso}
                type="button"
                onClick={() => onPick(iso)}
                className={cn(
                  "flex h-6 items-center justify-center rounded-sm text-[0.65rem] transition-colors",
                  sel && "bg-primary font-medium text-primary-foreground hover:bg-primary/90",
                  !sel && "hover:bg-muted"
                )}
              >
                {day}
              </button>
            );
          })
        )}
      </div>
    </div>
  );
}

export type DateTimeQuickPreset = {
  label: string;
  /** ISO `YYYY-MM-DDTHH:mm` yoki to‘liq `Date` */
  value: string | Date;
};

type DateTimePickerFieldProps = {
  id?: string;
  value: string;
  onChange: (next: string) => void;
  disabled?: boolean;
  className?: string;
  "aria-invalid"?: boolean;
  /** true: faqat sana, tungi 00:00 saqlanadi, popoverda vaqt yo‘q */
  dateOnly?: boolean;
  /** vaqt paneli joylashuvi: pastda yoki kalendar yonida */
  timePlacement?: "bottom" | "side";
  /** soat/daqiqani mouse wheel bilan o‘zgartirish */
  wheelTimeAdjust?: boolean;
  /** Kalendar popover ichida (vaqt ustuni yonida) tezkor tanlov */
  quickPresets?: DateTimeQuickPreset[];
};

/**
 * Bir sana-vaqt: ichki tugmalar (kun ±1), kalendar popover, vaqt — standart input type="time".
 * Qiymat: `YYYY-MM-DDTHH:mm` (datetime-local format).
 */
export function DateTimePickerField({
  id,
  value,
  onChange,
  disabled,
  className,
  "aria-invalid": ariaInvalid,
  dateOnly = false,
  timePlacement = "bottom",
  wheelTimeAdjust = false,
  quickPresets
}: DateTimePickerFieldProps) {
  const TIME_ROW_H = 28;
  const anchorRef = useRef<HTMLDivElement>(null);
  const [open, setOpen] = useState(false);
  const panelRef = useRef<HTMLDivElement>(null);
  const hourListRef = useRef<HTMLDivElement>(null);
  const minuteListRef = useRef<HTMLDivElement>(null);
  const hourSnapTimerRef = useRef<number | null>(null);
  const minuteSnapTimerRef = useRef<number | null>(null);
  const syncingScrollRef = useRef(false);
  const [box, setBox] = useState({ top: 0, left: 0 });

  const base = useMemo(() => parseLocalDateTime(value), [value]);
  const selectedYmd = `${base.getFullYear()}-${pad2(base.getMonth() + 1)}-${pad2(base.getDate())}`;

  const [viewYm, setViewYm] = useState(() => ({
    y: base.getFullYear(),
    m: base.getMonth()
  }));

  const [panelTime, setPanelTime] = useState(() => `${pad2(base.getHours())}:${pad2(base.getMinutes())}`);
  const [panelYmd, setPanelYmd] = useState(selectedYmd);

  useEffect(() => {
    if (!open) return;
    const d = parseLocalDateTime(value);
    setViewYm({ y: d.getFullYear(), m: d.getMonth() });
    setPanelTime(`${pad2(d.getHours())}:${pad2(d.getMinutes())}`);
    setPanelYmd(`${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())}`);
  }, [open, value]);

  const shiftDay = useCallback(
    (delta: number) => {
      const d = parseLocalDateTime(value);
      d.setDate(d.getDate() + delta);
      if (dateOnly) {
        d.setHours(0, 0, 0, 0);
      }
      onChange(localValueToDatetimeInput(d));
    },
    [value, onChange, dateOnly]
  );

  const reposition = useCallback(() => {
    if (!open) return;
    const el = anchorRef.current;
    if (!el) return;
    const r = el.getBoundingClientRect();
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    const measured = panelRef.current?.getBoundingClientRect().width ?? 0;
    const panelW = measured > 48 ? measured : 280;
    let left = r.left;
    if (left + panelW > vw - 8) left = Math.max(8, vw - 8 - panelW);
    if (left < 8) left = 8;
    let top = r.bottom + 6;
    const maxH = Math.max(200, vh - top - 10);
    if (top + maxH > vh - 8) {
      top = Math.max(8, r.top - 8 - Math.min(maxH, 320));
    }
    setBox({ top, left });
  }, [open]);

  useLayoutEffect(() => {
    if (!open) return;
    reposition();
    const idRaf = requestAnimationFrame(() => requestAnimationFrame(() => reposition()));
    return () => cancelAnimationFrame(idRaf);
  }, [open, reposition]);

  useEffect(() => {
    if (!open) return;
    const onResize = () => reposition();
    window.addEventListener("resize", onResize);
    window.addEventListener("scroll", onResize, true);
    return () => {
      window.removeEventListener("resize", onResize);
      window.removeEventListener("scroll", onResize, true);
    };
  }, [open, reposition]);

  useEffect(() => {
    if (!open || !panelRef.current) return;
    const ro = new ResizeObserver(() => reposition());
    ro.observe(panelRef.current);
    return () => ro.disconnect();
  }, [open, reposition]);

  useEffect(() => {
    if (!open) return;
    const onDoc = (e: MouseEvent) => {
      const t = e.target as Node;
      if (panelRef.current?.contains(t)) return;
      if (anchorRef.current?.contains(t)) return;
      setOpen(false);
    };
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") setOpen(false);
    };
    document.addEventListener("mousedown", onDoc);
    document.addEventListener("keydown", onKey);
    return () => {
      document.removeEventListener("mousedown", onDoc);
      document.removeEventListener("keydown", onKey);
    };
  }, [open]);

  const commitValue = useCallback(
    (raw: string | Date) => {
      const next = raw instanceof Date ? raw : parseLocalDateTime(raw);
      if (!Number.isNaN(next.getTime())) {
        onChange(localValueToDatetimeInput(next));
      }
      setOpen(false);
    },
    [onChange]
  );

  const applyPanel = useCallback(() => {
    let next: Date;
    if (dateOnly) {
      next = new Date(`${panelYmd}T00:00:00`);
    } else {
      const [hh, mm] = panelTime.split(":").map((x) => Number.parseInt(x, 10));
      const h = Number.isFinite(hh) ? Math.min(23, Math.max(0, hh)) : 0;
      const m = Number.isFinite(mm) ? Math.min(59, Math.max(0, mm)) : 0;
      next = new Date(`${panelYmd}T${pad2(h)}:${pad2(m)}:00`);
    }
    commitValue(next);
  }, [panelTime, panelYmd, commitValue, dateOnly]);

  const display = dateOnly ? formatRuDateShort(value) : formatRuDateTimeShort(value);
  const hourValue = panelTime.slice(0, 2);
  const minuteValue = panelTime.slice(3, 5);
  const hourOptions = Array.from({ length: 24 }, (_, i) => pad2(i));
  const minuteOptions = Array.from({ length: 60 }, (_, i) => pad2(i));

  const getCenterOffset = useCallback((el: HTMLDivElement | null) => {
    const h = el?.clientHeight ?? 0;
    return Math.max(0, (h - TIME_ROW_H) / 2);
  }, []);

  const syncPickerScroll = useCallback(
    (part: "hour" | "minute", val: string, behavior: ScrollBehavior = "auto") => {
      const el = part === "hour" ? hourListRef.current : minuteListRef.current;
      if (!el) return;
      const idx = Number.parseInt(val, 10);
      if (!Number.isFinite(idx)) return;
      const centerOffset = getCenterOffset(el);
      syncingScrollRef.current = true;
      el.scrollTo({ top: idx * TIME_ROW_H - centerOffset, behavior });
      window.setTimeout(() => {
        syncingScrollRef.current = false;
      }, behavior === "smooth" ? 200 : 0);
    },
    [getCenterOffset]
  );

  const snapAndPick = useCallback(
    (part: "hour" | "minute") => {
      const el = part === "hour" ? hourListRef.current : minuteListRef.current;
      if (!el) return;
      const centerOffset = getCenterOffset(el);
      const raw = (el.scrollTop + centerOffset) / TIME_ROW_H;
      const maxIdx = part === "hour" ? 23 : 59;
      const idx = Math.max(0, Math.min(maxIdx, Math.round(raw)));
      const next = pad2(idx);
      const [h, m] = panelTime.split(":");
      const nextH = part === "hour" ? next : h;
      const nextM = part === "minute" ? next : m;
      setPanelTime(`${nextH}:${nextM}`);
      syncingScrollRef.current = true;
      el.scrollTo({ top: idx * TIME_ROW_H - centerOffset, behavior: "smooth" });
      window.setTimeout(() => {
        syncingScrollRef.current = false;
      }, 220);
    },
    [getCenterOffset, panelTime]
  );

  const wheelAdjustPart = useCallback(
    (part: "hour" | "minute", delta: number) => {
      const [rawH, rawM] = panelTime.split(":");
      let h = Number.parseInt(rawH ?? "0", 10);
      let m = Number.parseInt(rawM ?? "0", 10);
      if (!Number.isFinite(h)) h = 0;
      if (!Number.isFinite(m)) m = 0;
      if (part === "hour") {
        h = (h + delta + 24) % 24;
      } else {
        m = (m + delta + 60) % 60;
      }
      setPanelTime(`${pad2(h)}:${pad2(m)}`);
    },
    [panelTime]
  );

  useEffect(() => {
    if (!open || dateOnly || timePlacement !== "side") return;
    syncPickerScroll("hour", hourValue, "auto");
    syncPickerScroll("minute", minuteValue, "auto");
  }, [open, dateOnly, timePlacement, hourValue, minuteValue, syncPickerScroll]);

  useEffect(() => {
    return () => {
      if (hourSnapTimerRef.current != null) window.clearTimeout(hourSnapTimerRef.current);
      if (minuteSnapTimerRef.current != null) window.clearTimeout(minuteSnapTimerRef.current);
    };
  }, []);

  return (
    <>
      <div
        ref={anchorRef}
        id={id}
        className={cn(
          "flex h-10 w-full min-w-0 items-stretch overflow-hidden rounded-md border border-input bg-background shadow-sm outline-none transition-[color,box-shadow] focus-within:border-ring focus-within:ring-[3px] focus-within:ring-ring/50",
          disabled && "pointer-events-none opacity-50",
          ariaInvalid && "border-destructive ring-destructive/20",
          className
        )}
      >
        <button
          type="button"
          className="flex h-full w-9 shrink-0 items-center justify-center border-r border-border/80 text-muted-foreground hover:bg-muted/60"
          aria-label="Открыть календарь"
          disabled={disabled}
          onClick={() => setOpen((o) => !o)}
        >
          <CalendarDays className="h-4 w-4" />
        </button>
        <button
          type="button"
          className="flex h-full w-8 shrink-0 items-center justify-center border-r border-border/80 text-muted-foreground hover:bg-muted/60"
          aria-label="На день назад"
          disabled={disabled}
          onClick={() => shiftDay(-1)}
        >
          <ChevronLeft className="h-4 w-4" />
        </button>
        <button
          type="button"
          className="min-w-0 flex-1 truncate px-2 text-left text-sm text-foreground hover:bg-muted/40"
          disabled={disabled}
          onClick={() => setOpen(true)}
        >
          {display}
        </button>
        <button
          type="button"
          className="flex h-full w-8 shrink-0 items-center justify-center border-l border-border/80 text-muted-foreground hover:bg-muted/60"
          aria-label="На день вперёд"
          disabled={disabled}
          onClick={() => shiftDay(1)}
        >
          <ChevronRight className="h-4 w-4" />
        </button>
      </div>

      {open && typeof document !== "undefined"
        ? createPortal(
            <div
              ref={panelRef}
              className="fixed z-[100] w-max max-w-[min(calc(100vw-1rem),28rem)] rounded-lg border border-border/80 bg-popover p-3 text-popover-foreground shadow-lg ring-1 ring-black/5"
              style={{ top: box.top, left: box.left }}
            >
              <div className={cn("flex gap-3", !dateOnly && timePlacement === "side" ? "items-start" : "items-stretch")}>
                <SingleMonthCalendar
                  year={viewYm.y}
                  month={viewYm.m}
                  selectedYmd={panelYmd}
                  onPick={(ymd) => setPanelYmd(ymd)}
                  onShiftMonth={(delta) => setViewYm((v) => shiftMonthYm(v.y, v.m, delta))}
                />
                {!dateOnly && quickPresets && quickPresets.length > 0 ? (
                  <div className="flex w-[5.5rem] shrink-0 flex-col gap-1 border-l border-border/60 pl-2">
                    <span className="text-[10px] font-medium text-muted-foreground">Tez</span>
                    {quickPresets.map((p) => (
                      <Button
                        key={p.label}
                        type="button"
                        variant="outline"
                        size="sm"
                        className="h-7 justify-start px-2 text-[11px]"
                        onClick={() => commitValue(p.value)}
                      >
                        {p.label}
                      </Button>
                    ))}
                  </div>
                ) : null}
                {!dateOnly && timePlacement === "side" ? (
                  <div className="w-[6.5rem]">
                    <div className="grid grid-cols-[1fr_auto_1fr] items-stretch gap-1">
                      <div
                        ref={hourListRef}
                        className="h-[9.25rem] overflow-y-auto scroll-smooth [scrollbar-width:none] [-ms-overflow-style:none] [&::-webkit-scrollbar]:hidden"
                        onScroll={() => {
                          if (syncingScrollRef.current) return;
                          if (hourSnapTimerRef.current != null) window.clearTimeout(hourSnapTimerRef.current);
                          hourSnapTimerRef.current = window.setTimeout(() => snapAndPick("hour"), 100);
                        }}
                        onWheel={(e) => {
                          if (!wheelTimeAdjust) return;
                          // Native wheel scroll gives smoother inertial movement.
                        }}
                      >
                        {hourOptions.map((h) => (
                          <button
                            key={h}
                            type="button"
                            className={cn(
                              "flex h-7 w-full items-center justify-center text-center font-mono text-sm transition-colors",
                              h === hourValue
                                ? "bg-primary/15 font-semibold text-primary"
                                : "text-foreground/80 hover:bg-muted/50"
                            )}
                            onClick={() => setPanelTime(`${h}:${minuteValue}`)}
                          >
                            {h}
                          </button>
                        ))}
                      </div>
                      <div className="flex h-[9.25rem] items-center justify-center">
                        <span className="text-center text-base text-muted-foreground">:</span>
                      </div>
                      <div
                        ref={minuteListRef}
                        className="h-[9.25rem] overflow-y-auto scroll-smooth [scrollbar-width:none] [-ms-overflow-style:none] [&::-webkit-scrollbar]:hidden"
                        onScroll={() => {
                          if (syncingScrollRef.current) return;
                          if (minuteSnapTimerRef.current != null) window.clearTimeout(minuteSnapTimerRef.current);
                          minuteSnapTimerRef.current = window.setTimeout(() => snapAndPick("minute"), 100);
                        }}
                        onWheel={(e) => {
                          if (!wheelTimeAdjust) return;
                          // Native wheel scroll gives smoother inertial movement.
                        }}
                      >
                        {minuteOptions.map((m) => (
                          <button
                            key={m}
                            type="button"
                            className={cn(
                              "flex h-7 w-full items-center justify-center text-center font-mono text-sm transition-colors",
                              m === minuteValue
                                ? "bg-primary/15 font-semibold text-primary"
                                : "text-foreground/80 hover:bg-muted/50"
                            )}
                            onClick={() => setPanelTime(`${hourValue}:${m}`)}
                          >
                            {m}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>
                ) : null}
              </div>
              {!dateOnly && timePlacement !== "side" ? (
                <div className="mt-3 flex items-center gap-2 border-t border-border/60 pt-3">
                  <span className="shrink-0 text-xs text-muted-foreground">Время</span>
                  <Input
                    type="time"
                    className="h-8 flex-1 font-mono text-sm"
                    value={panelTime}
                    onChange={(e) => setPanelTime(e.target.value)}
                  />
                </div>
              ) : null}
              <div className={cn("mt-3 flex justify-end gap-2")}>
                <Button type="button" variant="outline" size="sm" className="h-7 text-xs" onClick={() => setOpen(false)}>
                  Отмена
                </Button>
                <Button type="button" size="sm" className="h-7 text-xs" onClick={() => applyPanel()}>
                  Применить
                </Button>
              </div>
            </div>,
            document.body
          )
        : null}
    </>
  );
}

