      return data.data;
    }
  });

  const detailQ = useQuery({
    queryKey: ["warehouse-detail", tenantSlug, initial?.id],
    enabled: Boolean(tenantSlug) && open && canWrite && initial != null,
    staleTime: STALE.detail,
    queryFn: async () => {
