              </tr>
            </thead>
            <tbody>
              {listQ.isLoading ? (
                <tr>
                  <td
                    colSpan={tablePrefs.visibleColumnOrder.length + (canWrite ? 1 : 0)}
                    className="px-3 py-10 text-center text-muted-foreground"
                  >
                    Загрузка…
                  </td>
                </tr>
              ) : rows.length === 0 ? (
                <tr>
                  <td
                    colSpan={tablePrefs.visibleColumnOrder.length + (canWrite ? 1 : 0)}
                    className="px-3 py-10 text-center text-muted-foreground"
                  >
                    Нет данных
                  </td>
                </tr>
              ) : (
                rows.map((r, idx) => (
                  <tr
                    key={r.id}
                    className={cn(
                      "border-b border-border/80 transition-colors",
                      idx % 2 === 1 ? "bg-muted/20" : "bg-background",
                      "hover:bg-muted/35"
                    )}
                  >
                    {tablePrefs.visibleColumnOrder.map((colId) => (
                      <td key={colId} className="px-3 py-2 align-top text-xs">
                        {colId === "name" ? (
                          <span className="font-medium text-foreground">{r.name}</span>
                        ) : colId === "type" ? (
                          <span>{r.type?.trim() ? r.type : DEFAULT_WAREHOUSE_TYPE_LABEL}</span>
                        ) : colId === "code" ? (
                          r.code ?? "—"
                        ) : colId === "roles" ? (
                          <RoleBreakdownCell breakdown={r.breakdown} />
                        ) : colId === "user_total" ? (
                          <span className="tabular-nums">{formatGroupedInteger(r.user_total)}</span>
                        ) : colId === "payment_method" ? (
                          r.payment_method ?? "—"
                        ) : colId === "location" ? (
                          r.address ? (
                            <span className="line-clamp-2 max-w-[10rem]">{r.address}</span>
                          ) : (
                            "—"
                          )
                        ) : colId === "van_selling" ? (
                          r.van_selling ? "Да" : "Нет"
                        ) : null}
                      </td>
                    ))}
                    {canWrite ? (
                      <td className="px-2 py-2 text-right align-top">
                        <TableRowActionGroup className="justify-end" ariaLabel="Действия">
                          <Button
                            type="button"
                            variant="outline"
                            size="icon-sm"
                            className="text-amber-700 hover:bg-amber-500/10 hover:text-amber-800 dark:text-amber-400"
                            title="Редактировать"
                            onClick={() => {
                              setEditing(r);
                              setFormOpen(true);
                            }}
                          >
                            <Pencil className="size-3.5" aria-hidden />
                          </Button>
                          {tab === "active" ? (
                            <Button
                              type="button"
                              variant="ghost"
                              size="icon-sm"
                              className="text-muted-foreground hover:bg-muted hover:text-foreground"
                              title="Деактивировать"
                              onClick={() => setDeactivateTarget(r)}
                            >
                              <UserMinus className="size-3.5" aria-hidden />
                            </Button>
                          ) : (
                            <Button
                              type="button"
                              variant="ghost"
                              size="icon-sm"
                              className="text-primary hover:bg-primary/10"
                              title="Активировать"
                              disabled={activateMut.isPending}
                              onClick={() => activateMut.mutate(r.id)}
                            >
                              <RotateCcw className="size-3.5" aria-hidden />
                            </Button>
                          )}
                        </TableRowActionGroup>
                      </td>
                    ) : null}
                  </tr>
                ))
              )}
            </tbody>
          </table>
            </div>

            <div className="table-content-footer flex flex-wrap items-center justify-between gap-2 border-t border-border/80 bg-muted/25 px-3 py-3 text-xs text-muted-foreground sm:px-4">
              <span>
                Показано {from} - {to} / {total}
              </span>
              <div className="flex items-center gap-1">
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  className="h-7 px-2"
                  disabled={page <= 1}
                  onClick={() => setPage((p) => Math.max(1, p - 1))}
                >
                  ←
                </Button>
                {(() => {
                  const buttons: number[] = [];
                  const windowSize = 5;
                  let start = Math.max(1, page - Math.floor(windowSize / 2));
                  const end = Math.min(totalPages, start + windowSize - 1);
                  start = Math.max(1, end - windowSize + 1);
                  for (let p = start; p <= end; p++) buttons.push(p);
                  return buttons.map((p) => (
                    <Button
                      key={p}
                      type="button"
                      variant={page === p ? "default" : "outline"}
                      size="sm"
                      className="h-7 min-w-7 px-2"
                      onClick={() => setPage(p)}
                    >
                      {p}
                    </Button>
                  ));
                })()}
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  className="h-7 px-2"
                  disabled={page >= totalPages}
                  onClick={() => setPage((p) => p + 1)}
                >
                  →
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <WarehouseFormDialog
        open={formOpen}
        onOpenChange={(o) => {
          setFormOpen(o);
          if (!o) setEditing(null);
        }}
        initial={editing}
        canWrite={canWrite}
        tenantSlug={tenantSlug}
        onSaved={() => {}}
      />

      <Dialog open={deactivateTarget != null} onOpenChange={(o) => !o && setDeactivateTarget(null)}>
        <DialogContent className="max-w-sm" showCloseButton>
          <DialogHeader>
            <DialogTitle>Деактивировать склад?</DialogTitle>
          </DialogHeader>
          <p className="text-sm text-muted-foreground">
            {deactivateTarget
              ? `«${deactivateTarget.name}» будет скрыт из активного списка. Повторно включить можно на вкладке «Не активный».`
              : null}
          </p>
          <DialogFooter className="flex flex-row justify-end gap-2">
            <Button type="button" variant="outline" onClick={() => setDeactivateTarget(null)}>
              Отмена
            </Button>
            <Button
              type="button"
              disabled={deactivateMut.isPending}
              onClick={() => {
                if (deactivateTarget) deactivateMut.mutate(deactivateTarget.id);
              }}
            >
              Деактивировать
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </PageShell>
  );
}

"use client";

import { resolveApiOrigin } from "@/lib/api";
import { useAuthStore } from "@/lib/auth-store";
import { activityPathInfo } from "@/lib/activity-path-map";
import { usePathname } from "next/navigation";
import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useRef,
  type ReactNode
} from "react";

export type TrackIntentInput = {
  /** form_open | form_abandon | view_intent */
  eventType: "form_open" | "form_abandon" | "view_intent";
  /** Berilmasa joriy sahifa modul/bo'limi ishlatiladi. */
  module?: string;
  section?: string;
  entityType?: string;
  entityId?: string | number;
  label?: string;
  meta?: Record<string, unknown>;
};

type ActivityEventPayload = {
  event_type: string;
  module: string;
  section?: string;
  entity_type?: string;
  entity_id?: string;
  route?: string;
  label?: string;
  duration_ms?: number;
  meta?: Record<string, unknown>;
};

type TrackerCtx = {
  trackIntent: (input: TrackIntentInput) => void;
};

const Ctx = createContext<TrackerCtx>({ trackIntent: () => {} });

export function useActivityTracker(): TrackerCtx {
  return useContext(Ctx);
}

/**
 * Forma/dialog "ochildi → saqlamasdan yopildi" niyatini kuzatadi.
 * Mount'da `form_open`, unmount'da (agar `markSaved` chaqirilmagan bo'lsa) `form_abandon`.
 * Misol: agent klient tahrir formasini ochdi, lekin o'zgartirmasdan chiqdi.
 */
export function useFormIntentTracking(params: {
  active?: boolean;
  module?: string;
  section?: string;
  entityType?: string;
  entityId?: string | number;
  label?: string;
}): { markSaved: () => void } {
  const { trackIntent } = useActivityTracker();
  const savedRef = useRef(false);
  const active = params.active ?? true;
  // params'ni ref orqali barqaror saqlaymiz (effekt qayta ishlamasin).
  const paramsRef = useRef(params);
  paramsRef.current = params;

  useEffect(() => {
    if (!active) return;
    savedRef.current = false;
    const p = paramsRef.current;
    trackIntent({
      eventType: "form_open",
      module: p.module,
      section: p.section,
      entityType: p.entityType,
      entityId: p.entityId,
      label: p.label
    });
    return () => {
      if (savedRef.current) return;
      const pp = paramsRef.current;
      trackIntent({
        eventType: "form_abandon",
        module: pp.module,
        section: pp.section,
        entityType: pp.entityType,
        entityId: pp.entityId,
        label: pp.label
      });
    };
  }, [active, trackIntent]);

  return {
    markSaved: () => {
      savedRef.current = true;
    }
  };
}

const FLUSH_INTERVAL_MS = 15_000;

export function ActivityTrackerProvider({ children }: { children: ReactNode }) {
  const pathname = usePathname();
  const buffer = useRef<ActivityEventPayload[]>([]);
  const currentRef = useRef<{ info: ReturnType<typeof activityPathInfo>; route: string; enteredAt: number } | null>(null);

  const flush = useCallback((useKeepalive = false) => {
    if (buffer.current.length === 0) return;
    const tenantSlug = useAuthStore.getState().tenantSlug;
    const token = useAuthStore.getState().accessToken;
    if (!tenantSlug || !token) {
      buffer.current = [];
      return;
    }
    const events = buffer.current;
    buffer.current = [];
    const url = `${resolveApiOrigin()}/api/${tenantSlug}/activity/track`;
    try {
      void fetch(url, {
        method: "POST",
        keepalive: useKeepalive,
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ events })
      }).catch(() => {
        /* best-effort: kuzatuv xatosi ilovaga ta'sir qilmaydi */
      });
    } catch {
      /* ignore */
    }
  }, []);

  const enqueue = useCallback((event: ActivityEventPayload) => {
    buffer.current.push(event);
    if (buffer.current.length >= 20) flush(false);
  }, [flush]);

  const trackIntent = useCallback(
    (input: TrackIntentInput) => {
      const info = currentRef.current?.info;
      const module = input.module ?? info?.module;
      if (!module) return;
      enqueue({
        event_type: input.eventType,
        module,
        section: input.section ?? info?.section,
        entity_type: input.entityType ?? info?.entityType,
        entity_id: input.entityId != null ? String(input.entityId) : info?.entityId,
        route: currentRef.current?.route,
        label: input.label,
        meta: input.meta
      });
    },
    [enqueue]
  );

  // Sahifa o'zgarishi: oldingi page_view davomiyligini yozib, yangisini boshlaymiz.
  useEffect(() => {
    const now = Date.now();
    const prev = currentRef.current;
    if (prev?.info) {
      enqueue({
        event_type: "page_view",
        module: prev.info.module,
        section: prev.info.section,
        entity_type: prev.info.entityType,
        entity_id: prev.info.entityId,
        route: prev.route,
        duration_ms: now - prev.enteredAt
      });
    }
    const info = activityPathInfo(pathname || "/");
    currentRef.current = info ? { info, route: pathname || "/", enteredAt: now } : null;
  }, [pathname, enqueue]);

  // Davriy flush + sahifa yashirilganda/yopilganda yakuniy flush (duration bilan).
  useEffect(() => {
    const interval = setInterval(() => flush(false), FLUSH_INTERVAL_MS);
    const finalize = () => {
      const prev = currentRef.current;
      if (prev?.info) {
        enqueue({
          event_type: "page_view",
          module: prev.info.module,
          section: prev.info.section,
          entity_type: prev.info.entityType,
          entity_id: prev.info.entityId,
          route: prev.route,
          duration_ms: Date.now() - prev.enteredAt
        });
        currentRef.current = { ...prev, enteredAt: Date.now() };
      }
      flush(true);
    };
    const onVisibility = () => {
      if (document.visibilityState === "hidden") finalize();
    };
    document.addEventListener("visibilitychange", onVisibility);
    window.addEventListener("pagehide", finalize);
    return () => {
      clearInterval(interval);
      document.removeEventListener("visibilitychange", onVisibility);
      window.removeEventListener("pagehide", finalize);
      flush(false);
    };
  }, [flush, enqueue]);

  return <Ctx.Provider value={{ trackIntent }}>{children}</Ctx.Provider>;
}

import {
  INITIAL_SETUP_GROUPS,
  INITIAL_SETUP_STEPS,
  canStartStep,
  getStepById
} from "@/lib/initial-setup/catalog";
import type { InitialSetupStep } from "@/lib/initial-setup/types";
import { flattenTerritoryNodes } from "@/lib/initial-setup/profile-to-preview";

/** Boshlang‘ich sozlash oqimidagi barcha qadamlar — `order` bo‘yicha. */
export function getColdStartSteps(): InitialSetupStep[] {
  const ids = new Set(
    INITIAL_SETUP_GROUPS.filter((g) => g.inColdStartFlow).flatMap((g) => g.stepIds)
  );
  return INITIAL_SETUP_STEPS.filter((s) => ids.has(s.id)).sort((a, b) => a.order - b.order);
}

export function sortStepsByFlowOrder(steps: InitialSetupStep[]): InitialSetupStep[] {
  const order = new Map(getColdStartSteps().map((s) => [s.id, s.order]));
  return [...steps].sort((a, b) => (order.get(a.id) ?? a.order) - (order.get(b.id) ?? b.order));
}

export function sortStepIdsByFlowOrder(stepIds: string[]): string[] {
  const order = new Map(getColdStartSteps().map((s) => [s.id, s.order]));
  return [...stepIds].sort((a, b) => (order.get(a) ?? 999) - (order.get(b) ?? 999));
}

export type ProfileReadiness = {
  name?: string;
  phone?: string | null;
  address?: string | null;
  references?: Record<string, unknown>;
};

/** Tizimda allaqachon to‘ldirilgan qadamlar — progress belgilanmasa ham bog‘liqlik ochiladi. */
export function systemSatisfiedStepIds(
  profile?: ProfileReadiness | null,
  extras?: {
    warehousesCount?: number;
    productCategoriesCount?: number;
    tradeDirectionsCount?: number;
    salesChannelsCount?: number;
  }
): Set<string> {
  const ids = new Set<string>();
  const refs = profile?.references ?? {};

  if (profile?.name?.trim()) ids.add("company");

  const territoryRows = flattenTerritoryNodes(refs.territory_nodes);
  if (territoryRows.length) ids.add("territory");

  if (Array.isArray(refs.branches) && refs.branches.length) ids.add("branches");
  if (Array.isArray(refs.unit_measures) && refs.unit_measures.length) ids.add("units");
  if (Array.isArray(refs.currency_entries) && refs.currency_entries.length) ids.add("currencies");
  if (Array.isArray(refs.payment_method_entries) && refs.payment_method_entries.length) {
    ids.add("payment-methods");
  }
  if (Array.isArray(refs.price_type_entries) && refs.price_type_entries.length) ids.add("price-types");
  if (Array.isArray(refs.client_format_entries) && refs.client_format_entries.length) {
    ids.add("client-formats");
  }
  if (Array.isArray(refs.client_type_entries) && refs.client_type_entries.length) ids.add("client-types");
  if (Array.isArray(refs.client_category_entries) && refs.client_category_entries.length) {
    ids.add("client-categories");
  }

  if ((extras?.tradeDirectionsCount ?? 0) > 0) ids.add("trade-directions");
  if ((extras?.salesChannelsCount ?? 0) > 0) ids.add("sales-channels");
  if ((extras?.warehousesCount ?? 0) > 0) ids.add("warehouses");
  if ((extras?.productCategoriesCount ?? 0) > 0) ids.add("product-categories");

  return ids;
}

export function effectiveDoneIds(
  progressDone: ReadonlySet<string>,
  systemDone: ReadonlySet<string>
): Set<string> {
  return new Set([...progressDone, ...systemDone]);
}

export function isStepReady(
  step: InitialSetupStep,
  doneIds: ReadonlySet<string>
): { ok: boolean; missing: string[] } {
  return canStartStep(step, doneIds);
}

/** Navbatdagi birinchi bajarilmagan qadam (bog‘liqlik bo‘yicha tayyor yoki yo‘q). */
export function getCurrentFlowStep(
  progressDone: ReadonlySet<string>,
  systemDone: ReadonlySet<string>
): InitialSetupStep | undefined {
  const done = effectiveDoneIds(progressDone, systemDone);
  return getColdStartSteps().find((s) => !progressDone.has(s.id));
}

/** Keyingi qo‘llash mumkin bo‘lgan qadam (bog‘liqlik bajarilgan). */
export function getNextReadyStep(
  progressDone: ReadonlySet<string>,
  systemDone: ReadonlySet<string>
): InitialSetupStep | undefined {
  const done = effectiveDoneIds(progressDone, systemDone);
  return getColdStartSteps().find((s) => !progressDone.has(s.id) && isStepReady(s, done).ok);
}

export function missingDependencyTitles(step: InitialSetupStep, doneIds: ReadonlySet<string>): string[] {
  return step.dependsOn
    .filter((id) => !doneIds.has(id))
    .map((id) => getStepById(id)?.title ?? id);
}
